INSERT INTO `care_guide` VALUES (1,1,'all','watering','龟背竹浇水指南','当土壤顶部2-3英寸感觉干燥时给龟背竹浇水。夏季通常意味着每7-10天浇水一次。冬季减少到每2-3周一次。始终彻底浇水，直到水从底部流出。','[\"使用室温水\", \"30分钟后清空托盘\", \"在浇水之间给叶片喷雾\"]','[\"过度浇水会导致叶片发黄和根腐病\", \"使用冷水会刺激根部\", \"不检查土壤就按照严格时间表浇水\"]',0,'2026-05-20 11:51:40','2026-05-21 10:43:11'),(2,1,'all','light','龟背竹光照要求','龟背竹在明亮、间接光下茁壮成长，但适应性惊人。靠近朝东或朝西窗户的位置是理想的。在自然界中，它们在树冠下生长，所以是斑驳的光而不是直射阳光。','[\"每月旋转植物以保证均匀生长\", \"每月清洁叶片以更好地吸收光线\", \"在黑暗房间补充生长灯\"]','[\"下午直射阳光会灼伤叶片\", \"光照不足会导致徒长和无孔洞\", \"频繁移动植物会使其压力过大\"]',0,'2026-05-20 11:51:40','2026-05-21 10:43:11'),(3,1,'all','general','龟背竹通用护理','龟背竹是生长旺盛的植物，使用苔藓柱或格子架支撑有益。修剪徒长的茎以促进更茂密的生长。每1-2年春季换盆一次，使用块状天南星科混合土。','[\"提供苔藓柱供攀爬\", \"春季修剪效果最好\", \"在水中扦插繁殖\"]','[\"冬季换盆会使植物压力过大\", \"使用普通盆栽土会保留太多水分\", \"不提供支撑会导致生长失控\"]',0,'2026-05-20 11:51:40','2026-05-21 10:43:11'),(4,3,'all','watering','虎皮兰浇水指南','虎皮兰非常耐旱。只在土壤完全干燥时浇水——夏季通常每2-3周一次，冬季每月一次。如有疑问，等更长时间。','[\"将手指插入土壤2英寸检查干燥度\", \"冬季减少浇水\", \"使用有排水孔的花盆\"]','[\"过度浇水是虎皮兰的头号杀手\", \"喷雾会导致叶片腐烂\", \"浸泡在水中会立即导致根腐病\"]',0,'2026-05-20 11:51:40','2026-05-21 10:43:11'),(5,3,'all','general','虎皮兰护理指南','虎皮兰是完美的初学者植物。它们耐受疏忽、低光和不规律的浇水。偶尔用湿布擦拭叶片以清除灰尘。春季分株过密的植物。','[\"非常适合卧室——夜间产生氧气\", \"可以数周不浇水\", \"从叶片扦插繁殖\"]','[\"换入过大的容器会保留水分\", \"与高湿度植物放在一起\", \"忽略叶腋中的粉蚧\"]',0,'2026-05-20 11:51:40','2026-05-21 10:43:11'),(6,21,'all','watering','散尾葵浇水指南','保持土壤均匀湿润，但不要积水。春夏季节每周浇水1-2次，秋冬减少到每10-14天一次。','[\"使用室温水\", \"确保排水良好\", \"定期给叶片喷雾增加湿度\"]','[\"过度浇水导致根腐\", \"冬季浇水过多\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(7,21,'all','light','散尾葵光照要求','散尾葵喜欢明亮的间接光，能耐受中等光照。避免直射阳光，否则叶尖会变棕。','[\"放在朝东或朝北的窗户附近\", \"如果光线不足，叶片会变黄\", \"夏季注意遮阴\"]','[\"直射阳光灼伤叶片\", \"长期阴暗导致生长不良\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(8,22,'all','watering','春羽浇水指南','春羽喜欢湿润的环境，但不耐水涝。春夏保持土壤微湿，秋冬等表土干燥后再浇水。','[\"浇水前检查表土2-3厘米\", \"使用排水良好的盆土\", \"定期喷雾增加湿度\"]','[\"积水导致根腐\", \"空气过于干燥导致叶尖干枯\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(9,22,'all','light','春羽光照要求','春羽喜欢明亮的散射光，能耐受低光环境。避免强烈直射阳光。','[\"放在有遮挡的窗边\", \"低光照下也能生长但速度较慢\", \"夏季适当遮阴\"]','[\"强光直射导致叶片灼伤\", \"光照不足导致叶片变小\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(10,26,'all','watering','袖珍椰子浇水指南','袖珍椰子喜欢湿润环境，但怕积水。春夏每周浇水1次，秋冬每10天左右一次。','[\"保持土壤微湿\", \"定期给叶片喷雾\", \"使用排水良好的土壤\"]','[\"过度浇水导致根部腐烂\", \"空气太干燥导致叶尖干枯\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(11,26,'all','light','袖珍椰子光照要求','袖珍椰子耐阴性好，适合室内低光环境。也能适应中等光照。','[\"适合放在浴室或北向窗户\", \"避免强烈直射阳光\", \"散射光最佳\"]','[\"强光直射导致叶片灼伤\", \"完全无光影响生长\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(12,27,'all','watering','豆瓣绿浇水指南','豆瓣绿喜欢微湿的土壤环境。春夏保持土壤湿润，秋冬等表土干燥后浇水。','[\"浇水要浇透\", \"避免叶片积水\", \"使用室温水\"]','[\"过度浇水导致根腐\", \"冬季浇水过多\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(13,27,'all','light','豆瓣绿光照要求','豆瓣绿喜欢明亮的散射光，能耐受半阴环境。','[\"放在明亮的室内\", \"避免强烈阳光直射\", \"可以放在书桌或茶几上\"]','[\"强光直射导致叶片灼伤\", \"光照不足导致叶片褪色\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(14,30,'all','watering','合果芋浇水指南','合果芋喜欢湿润环境。春夏保持土壤湿润，秋冬减少浇水频率。','[\"浇水前检查表土\", \"使用排水良好的盆土\", \"定期喷雾增加湿度\"]','[\"过度浇水导致根腐\", \"空气干燥导致叶尖干枯\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(15,30,'all','light','合果芋光照要求','合果芋喜欢中等至明亮的散射光，也能适应低光环境。','[\"放在有散射光的地方\", \"避免直射阳光\", \"低光下也能生长\"]','[\"强光直射灼伤叶片\", \"光照不足导致生长缓慢\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(16,34,'all','watering','仙客来浇水指南','仙客来从下方浇水，避免浇到球茎顶部。保持土壤湿润但不积水。','[\"使用托盘底部浇水\", \"水温保持室温\", \"避免水接触叶片和花茎\"]','[\"从上方浇水导致球茎腐烂\", \"浇水过多导致根腐\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(17,34,'all','light','仙客来光照要求','仙客来喜欢明亮的散射光，忌强烈直射阳光。适宜温度15-20°C。','[\"放在朝东的窗边\", \"夏季注意遮阴降温\", \"花期保持充足光照\"]','[\"高温导致休眠\", \"强光直射灼伤叶片\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(18,35,'all','watering','倒挂金钟浇水指南','倒挂金钟喜欢湿润的土壤。春夏保持土壤湿润，秋冬减少浇水。','[\"浇水要均匀\", \"避免积水\", \"定期给叶片喷雾\"]','[\"过度浇水导致根腐\", \"缺水导致花蕾脱落\"]',1,'2026-05-21 11:06:36','2026-05-21 11:06:36'),(19,35,'all','light','倒挂金钟光照要求','倒挂金钟喜欢明亮的散射光，忌强烈直射阳光。适宜温度15-25°C。','[\"放在朝东或朝北的窗边\", \"夏季必须遮阴\", \"冬季可接受更多光照\"]','[\"强光直射灼伤叶片\", \"高温导致生长不良\"]',2,'2026-05-21 11:06:36','2026-05-21 11:06:36');
