INSERT INTO `category` VALUES (1,'多肉植物','succulents','储水奇兵，非常适合初学者和阳光充足的空间',NULL,1,'2026-05-20 11:51:40','2026-05-21 10:40:32'),(2,'热带植物','tropical','茂密、充满活力的植物，将雨林带入室内',NULL,2,'2026-05-20 11:51:40','2026-05-21 10:40:32'),(3,'香草植物','herbs','芳香的烹饪香草，适合厨房花园',NULL,3,'2026-05-20 11:51:40','2026-05-21 10:40:32'),(4,'蕨类植物','ferns','优雅、羽毛状的叶片，在潮湿环境中茁壮成长',NULL,4,'2026-05-20 11:51:40','2026-05-21 10:40:32'),(5,'开花植物','flowering','美丽的开花植物，带来色彩和芬芳',NULL,5,'2026-05-20 11:51:40','2026-05-21 10:40:32'),(6,'室内树木','trees','室内树木，在任何房间都能成为焦点',NULL,6,'2026-05-20 11:51:40','2026-05-21 10:40:32');
