-- Dumping data for table `plant`
--

LOCK TABLES `plant` WRITE;
/*!40000 ALTER TABLE `plant` DISABLE KEYS */;
INSERT INTO `plant` VALUES (1,'龟背竹','蓬莱蕉、电线兰','Monstera deliciosa','monstera-deliciosa','天南星科','龟背竹属','藤本','多年生','观叶','中美洲','龟背竹为常绿大型藤本植物，因其成熟叶片具有形似龟甲的羽状深裂和孔洞而得名。它不仅株形优美，而且极为耐阴，是室内大型盆栽植物的代表之一，深受现代家居装饰的喜爱。','独特羽裂叶片，北欧风室内大型植物。','心形至卵形，成熟叶片有深裂 and 孔洞','深绿色，有光泽','粗壮绿色茎干，带有气生根','佛焰苞花序，白色或乳白色','白色','4-7月 / 全年可开花','秋季','株形高大，叶片巨大下垂，呈辐射状散开，整体极具热带雨林风情。','medium',4,6,'喜充足的散射光，忌强光直射，在半阴环境下生长良好。','weekly',7,10,'春秋两季保持盆土微潮，夏季可适当增加浇水，冬季则需控水。','见干见湿','每周1次','每周2次','每10天1次','每2周1次','忌积水、忌浇叶心','室温自来水即可','high','喜高湿环境，经常向叶面及周围喷水以增加空气湿度。',18,30,10,35,0,'客厅、书房、明亮窗边','喜温暖湿润，怕寒冷，忌强光曝晒，喜肥沃排水良好的壤土。','喜温暖，不耐严寒。冬季需移入室内保温，夏季高温时需注意通风降温。','平衡20-20-20','biweekly','生长期每两周施用一次稀薄液肥，入秋后减少，冬季停肥。','春季和夏季','平衡氮磷钾液肥','高磷肥促进开花',1,'忌浓肥、生肥','叶片发黄、生长缓慢、新叶变小','春季','黄叶、过长枝条、枯死气生根','在节点上方修剪','避免在冬季重剪','{\"fall\": \"逐渐减少浇水量，停止施氮肥，增加光照准备越冬。\", \"spring\": \"换盆好时机，逐步增加浇水与施肥，保持散射光。\", \"summer\": \"遮阴防曝晒，多向叶面喷水降温，保持环境通风。\", \"winter\": \"移入室内防止冻伤，严格控水，停止施肥。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"叶背出现密集微小红点，有细丝网\", \"treatment\": \"喷洒螨危或用肥皂水擦洗叶片\"}], \"diseases\": [{\"name\": \"叶斑病\", \"cause\": \"通风不良、湿度过大\", \"symptom\": \"叶片出现褐色斑点，边缘发黄\", \"treatment\": \"剪除病叶，喷洒多菌灵溶液\"}], \"prevention\": \"保持环境通风，定期清理叶片灰尘，避免盆土长期积水。\"}','微毒','汁液、叶片','含草酸钙针晶，误食会导致口腔肿胀、流涎、灼烧感','对猫狗及儿童有毒，汁液具刺激性，应放在儿童和宠物触碰不到的高处。','{\"leggy\": \"光照严重不足，导致茎干细长、叶片变小且开裂减少。\", \"noBloom\": \"室内养护光照不足，或植株未达到成熟年龄（通常需多年养护）。\", \"drooping\": \"严重缺水或换盆后未缓苗成功，根系无法吸收水分。\", \"mainTaboo\": \"盆土长期积水导致根部窒息腐烂。\", \"beginnerTip\": \"以为它喜湿就每天浇水，导致积水烂根；或直接放在烈日下暴晒导致叶片灼伤。\", \"yellowLeaves\": \"盆土长期积水导致烂根，或空气过于干燥、缺少阳光。\"}','大型热带观叶植物，叶片独特，能营造时尚的北欧风和热带雨林感。','能有效去除空气中的甲醛、苯、TVOC等有害气体，并能提高室内湿度。','果实成熟后可食用，但未成熟时有毒，室内盆栽极难结果。','在传统医学中其根具有消炎、解毒的效果（请勿盲目自行使用）。','象征健康、长寿、好运与加官进爵。','客厅、办公室、酒店大堂、玄关','排水良好的盆栽土','泥炭土:珍珠岩:树皮 = 2:1:1','陶盆或塑料盆均可','口径15-25cm','每1-2年换盆一次',5.5,7.0,'easy','moderate',300,1,0,0,1,'/images/plants/monstera.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(2,'绿萝','魔鬼藤、黄金葛','Epipremnum aureum','pothos','天南星科','麒麟叶属','藤本','多年生','观叶','所罗门群岛','绿萝是一种十分缠绕的常绿藤本植物，其叶片呈心形，翠绿有光泽。由于其生命力极其顽强，对环境适应能力强，且具有极高的空气净化能力，成为了最受欢迎和普及的室内初学养殖植物之一。','生命力顽强，室内遇水即活的净化先锋。','卵状心形，成熟后会变大且可能出现羽状分裂','翠绿色或带有黄色斑纹（黄金葛）','蔓性茎，能攀援生长，节间常长出气生根','佛焰苞花序，但在室内盆栽环境中极难开花','淡绿色或白色','罕见开花','无','枝蔓飘逸，垂吊生长时如绿色瀑布，攀附生长时则显得挺拔茂密。','low',2,4,'极耐阴，喜明亮的散射光，忌阳光直射，强光下叶片易灼伤枯黄。','weekly',5,7,'生长期保持盆土湿润，但不能积水，遵循见干见湿原则；水培则需定期换水。','见干见湿','每周1次','每周2次','每5-7天1次','每10-14天1次','忌盆土长期积水，防止根部腐烂窒息','室温自来水即可','medium','对空气湿度要求适中，干燥季节可向叶面喷水增加环境湿度。',15,28,10,35,0,'客厅、书房、明亮窗边、厨房、洗手间、书架顶部','喜温暖湿润环境，生命力强，遇水即活，忌烈日曝晒。','喜温暖，越冬温度不宜低于10℃，北方冬季需移入暖气房防冻。','平衡20-20-20','monthly','春夏生长期每月施一次稀薄的观叶植物液肥或复合肥，冬日停肥。','春季和夏季','平衡氮磷钾液肥，可配合叶面肥提升光泽','无需专门催花，以观叶为主',1,'忌施浓肥、生肥，避免烧根','叶片颜色变淡、变小，生长明显停滞','春季','枯黄叶片、过长或过密的剪除','在节点下方直接剪断，剪下的枝条可用于扦插水培','避免在冬季气温过低时重剪即可','{\"fall\": \"气温降低后逐渐减少浇水量，停止施肥，增加光照。\", \"spring\": \"恢复生长，开始正常浇水和施肥，可进行修剪和扦插繁殖。\", \"summer\": \"注意遮阴防晒，增加环境浇水与喷水频率，保持室内通风良好。\", \"winter\": \"注意防寒保暖，严格控水，盆土不干不浇。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"叶面产生细小黄点，叶背有网丝\", \"treatment\": \"用清水冲洗叶片，或喷洒阿维菌素防治\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"土壤长期过湿、积水，通风不良\", \"symptom\": \"根系变黑腐烂，叶片发黄萎蔫、脱落\", \"treatment\": \"剪除烂根，更换排水良好的新土，并喷洒多菌灵消毒\"}], \"prevention\": \"控制浇水，避免积水，保持养护环境通风良好，定期擦拭叶片。\"}','微毒','汁液','汁液中含有草酸钙晶体，皮肤接触可能引起瘙痒，误食会导致口腔灼伤、肿胀和恶心','对猫狗及儿童有毒，建议将其摆放在高处或采用吊盆悬挂养护。','{\"leggy\": \"长期缺乏光照，导致节间距拉长、叶片变小变稀疏。\", \"noBloom\": \"本植物在室内条件下几乎不具备开花条件，无需强求开花。\", \"drooping\": \"土壤严重缺水干旱，或根系受损腐烂无法吸收水分。\", \"mainTaboo\": \"盆土长期积水且环境密闭通风不良。\", \"beginnerTip\": \"误以为绿萝是水生植物而盲目频繁给盆栽浇水，导致积水烂根。\", \"yellowLeaves\": \"最常见原因是浇水过多积水烂根，其次是长期缺水或光照过强曝晒。\"}','经典的室内常绿悬垂植物，能柔化室内线条，营造绿意盎然的氛围。','被称为“绿色净化器”，能高效吸收室内的甲醛、苯、三氯乙烯等有害气体。','无食用价值','无确切家庭药用价值','寓意守望幸福、坚韧不拔，有招财聚气、净化磁场之说。','客厅、书房、明亮窗边、办公室、洗手间、前台','排水良好的盆栽土','泥炭土:珍珠岩 = 3:1，或直接使用通用营养土','塑料盆、吊盆或陶瓷盆','口径12-20cm','每1-2年换盆一次',6.0,7.0,'easy','fast',200,1,0,0,1,'/images/plants/pothos.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(3,'虎皮兰','虎尾兰、千岁兰、锦兰','Dracaena trifasciata','snake-plant','天门冬科','虎尾兰属','肉质','多年生','观叶','非洲西部','虎皮兰是一种常绿肉质草本植物，具匍匐根状茎。叶片直立革质，常有白绿相间的横带斑纹，形似虎尾。它对环境适应性极强，极端耐旱，是著名的“懒人植物”，深受极简现代家居风格青睐。','极度耐旱，坚挺直立的防辐射净化专家。','剑形、直立、坚挺、肥厚革质','暗绿色与浅绿色横向相间斑纹，部分品种带金边','无明显地上茎，具地下根状茎','总状花序，花小，常数朵簇生','白色至淡绿色','11-12月 / 极少开花','少见','叶片挺拔直立，线条刚硬简约，整体呈现一种刚毅偏现代的美感。','medium',3,6,'喜光也极耐阴，在散射光或全日照下皆可生长，长期处于阴暗处叶色会变淡。','rarely',15,30,'极其耐旱，必须遵循宁干勿湿原则，待盆土完全干透再浇水，冬季严格控水。','干透浇透','每15-20天1次','每10-15天1次','每15-20天1次','每30天1次或断水','忌积水、忌频繁浇水、忌浇入叶心导致腐烂','普通室温自来水','low','喜干燥环境，不耐高湿，空气湿度过大、不通风极易导致病害。',18,30,10,38,0,'客厅、书房、明亮窗边、卧室、玄关','喜温暖湿润，耐干旱，喜光又耐阴，对土壤要求不严，排水需良好。','喜温暖，不耐寒。越冬温度需要保持在10℃以上，低于5℃易发生冻害。','平衡20-20-20','none','对肥料需求极低，一般可在春季生长季施1-2次稀薄液肥或缓释肥即可。','春季','稀薄的复合肥或缓释肥颗粒','不以观花为主，无需促花肥',1,'忌施浓肥、生肥，严禁秋末和冬季施肥','生长基本停滞，叶片显得薄而无神','春季','剪除老叶、枯黄叶或发生病斑的叶片','从基部直接平整剪断','避免在越冬期或低温环境下修剪','{\"fall\": \"秋末逐渐减少浇水频率，增强光照，帮助其安全越冬。\", \"spring\": \"生长旺季，可逐步开始浇水，进行换盆或者分株繁殖。\", \"summer\": \"虽然耐热，但高温时需保持环境通风，切忌闷热积水，无需过多浇水。\", \"winter\": \"严格控水，保持盆土干燥，室温需维持在10℃以上，防止冻伤。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"叶片表面形成白色或黄色的硬壳蜡质小点\", \"treatment\": \"人工用刷子刷除，或用蚧必治喷洒\"}], \"diseases\": [{\"name\": \"软腐病\", \"cause\": \"土壤积水、湿度过高或环境高温闷热\", \"symptom\": \"叶片基部出现水渍状软化腐烂，并伴有恶臭\", \"treatment\": \"立即切除病部，用多菌灵涂抹伤口，并严格控水更换排水土壤\"}], \"prevention\": \"保持环境通风、干燥，坚坚决避免土壤长期潮湿或积水。\"}','微毒','汁液、叶片','含有皂苷成分，误食可能导致流涎、呕吐、腹泻以及口腔麻木','对猫狗及儿童有毒，虽然叶片质硬不易被误食，仍需注意放置于安全处。','{\"leggy\": \"长期放在过于阴暗的角落，导致新长出的叶片细长、柔弱、斑纹变淡。\", \"noBloom\": \"虎皮兰室内养护极难开花，需要植株完全成熟、光照和温差合适才偶尔开花。\", \"drooping\": \"叶片变软下垂多为根系腐烂或遭遇寒冻受冻所致。\", \"mainTaboo\": \"频繁浇水导致盆土长期潮湿、积水。\", \"beginnerTip\": \"像照顾普通植物一样频繁关切地给它浇水，结果几个星期内就导致它烂根死掉。\", \"yellowLeaves\": \"多数情况是浇水过多引发基部根系腐烂，导致上方叶片发黄萎蔫。\"}','叶形挺拔极具线条美，适合各种现代简约、北欧、甚至新中式家装风格。','强大的空气净化专家，可夜间吸收二氧化碳释放氧气，对甲醛、苯吸收能力极强。','无食用价值','在一些传统药方中可用于清热解毒（严禁私自尝试）。','寓意坚韧不拔、大吉大利，直立如剑的叶片被认为具有辟邪、挡煞、招财的风水作用。','客厅、书房、明亮窗边、卧室、玄关、办公室、酒店前台','排水良好的盆栽土','沙质土:腐叶土:珍珠岩 = 2:2:1，或多肉专用营养土','陶盆或塑料盆均可，透气较好的盆尤佳','口径15-25cm','每2-3年换盆一次',6.0,7.5,'easy','slow',120,1,0,0,1,'/images/plants/snake-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(4,'琴叶榕','琴叶橡皮树','Ficus lyrata','fiddle-leaf-fig','桑科','榕属','木本','多年生','观叶','非洲西部的热带雨林','琴叶榕是一种常绿乔木，因其叶片巨大、形状酷似提琴而得名。其叶片厚革质，深绿色富有光泽，茎干挺拔，极具现代时尚感，是近年来深受国内外室内设计师追捧的“网红”大型植物。','提琴状独特大叶，极具北欧极简风的网红树。','倒卵形，形似小提琴，边缘常有波浪状起伏','深绿色，背面脉络明显','直立木质化茎干，皮层较硬，高大挺拔','隐头花序（榕果状），在室内盆栽中极为罕见','绿褐色（隐于果内）','极为罕见','少见','整株呈树状，叶片巨大而密集地生长在挺拔的直立主干上，气质优雅而现代。','high',5,8,'喜充足的明亮散射光或柔和直射光。若光照不足易落叶，但盛夏需避免强光暴晒。','weekly',7,10,'土面下2-3厘米变干时再行浇透。遵循表土干透再浇透原则，冬季需严格控水。','见干见湿','每周1次','每周2次','每10天1次','每15-20天1次','忌盆底长期积水或托盘留有积水，会导致不可逆的烂根落叶','建议晾置过夜的温和自来水','high','原产热带雨林，喜较高的空气湿度。干燥季节需经常向叶片周围喷雾或使用加湿器。',18,30,12,35,0,'客厅、书房、明亮窗边、大堂、落地窗旁','喜温暖、湿润和阳光充足环境，不耐寒，忌积水，对环境变化较为敏感。','喜温暖舒适环境，非常不耐寒。冬季温度不可低于12℃，否则极易发生大量落叶或冻死。','平衡20-20-20','biweekly','春夏生长期每半月施一次稀薄的观叶类水溶肥，秋冬季则停止施肥。','春季和夏季','氮肥稍高或平衡型水溶性肥料','无需专门促花肥',1,'忌施浓肥，秋末降温后严禁施肥','新叶变小、变薄，生长缓慢，下部老叶易发黄易脱落','春季','剪除顶端优势以促进分枝（打顶），剪除枯黄或受损的老叶','在芽点上方1厘米处平剪。注意修剪时会流出白色乳汁，避免沾染皮肤','避免在冬季寒冷季节进行大面积重剪','{\"fall\": \"随着温度下降减少浇水，让其逐渐适应光照，停止施肥准备过冬。\", \"spring\": \"换盆与修剪打顶的最佳时期。随气温回升逐渐增加浇水，并开始恢复施肥。\", \"summer\": \"严防烈日暴晒以防叶片灼伤，需移至明亮散射光处，保持环境通风良好并多喷水。\", \"winter\": \"绝对防寒，室温不低于12℃。严格控制浇水，停止施肥，给予其全天候充足的室内光照。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"叶背有细微红点，伴有细丝网，导致叶面失绿发灰\", \"treatment\": \"用湿布擦拭叶片，或喷洒螨危等杀螨剂\"}], \"diseases\": [{\"name\": \"叶斑病\", \"cause\": \"主要是空气湿度大、盆土长期积水且环境通风不良引起的真菌感染\", \"symptom\": \"叶片上出现大面积褐色、黑色或红褐色斑点，并逐渐扩大导致整叶脱落\", \"treatment\": \"剪除病叶，喷洒多菌灵或代森锰锌溶液，并立即改善通风、控制浇水\"}], \"prevention\": \"保持环境通风是养好琴叶榕的关键，定期擦拭巨大叶片以清除灰尘，提升光合作用。\"}','微毒','茎叶内的白色乳汁','桑科植物特有的乳汁含有刺激性，接触皮肤易引发红肿或过敏，误食可导致消化道灼烧和不适','对猫狗及儿童有毒。由于其汁液具刺激性，修剪时应佩戴手套，并避免宠物抓咬叶片。','{\"leggy\": \"光照严重不足，导致主干细长，叶片与叶片之间的间距变得非常稀疏。\", \"noBloom\": \"室内作为观叶树种养护，基本不具备开花条件，无需关注其开花。\", \"drooping\": \"换环境产生的应激反应，或者由于浇水严重不足、气温骤降导致的叶片下垂、无力。\", \"mainTaboo\": \"高湿环境搭配密闭不通风，以及频繁挪动其养护位置。\", \"beginnerTip\": \"买回家后觉得好看频繁给它换地方摆放，且不注意客厅的通风，导致它几天内就开始疯狂掉叶子。\", \"yellowLeaves\": \"下部老叶发黄脱落多为正常新陈代谢或浇水过多导致的闷根；若新叶发黄多为缺光或缺肥。\"}','极具现代感和雕塑感的网红植物，能瞬间提升客厅、店铺等空间的北欧极简格调。','叶片巨大，能高效吸收空气中的有害微粒，净化甲醛等装修污染，并调节室内湿度。','无食用价值','无家庭药用价值','寓意聚财发福、吉祥如意、和睦平安，巨大叶片有纳气招财之风水寓意。','客厅、明亮窗边、落地窗旁、办公室、咖啡厅、展厅、大堂','排水良好的盆栽土','泥炭土:珍珠岩:腐叶土 = 3:1:1，要求优良的透气性与排水性','水泥盆、陶盆或质感较好的塑料盆','口径25-40cm','每2年左右换盆一次',6.0,7.0,'hard','moderate',300,1,0,0,1,'/images/plants/fiddle-leaf-fig.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(5,'白掌','白鹤芋、一帆风顺、和平百合','Spathiphyllum wallisii','peace-lily','天南星科','白鹤芋属','草本','多年生','观花','美洲热带地区','白掌是一种多年生常绿草本植物。叶片翠绿青翠，花茎挺拔高出叶面，佛焰苞洁白如雪，形状酷似扬帆起航的小船，因而民间常称其为“一帆风顺”。它不仅耐阴性极佳，还能很好地适应水培环境，是极为常见的室内花卉。','白花如帆，兼具观叶与花艺的净化好手。','长椭圆状披针形，具明显纵脉，边缘有波状皱褶','深绿色，富有光泽','无明显地上茎，叶片自基部丛生开来','佛焰苞呈苞片状，包裹着黄白色的肉穗花序，形似风帆','洁白色，后期会逐渐转为浅绿色','5-8月 / 条件适宜四季均可开花','少见结果','丛生状生长，翠绿挺拔的叶片间托起数朵洁白的花朵，整体风格清新、素雅。','medium',3,5,'喜半阴和散射光环境，畏惧强光暴晒，但长期过于阴暗会导致其无法开花。','frequent',3,5,'喜湿润环境，生长期应保持盆土微潮但不积水。一旦缺水叶片会快速下垂，及时补水可恢复。','见干见湿','每3-5天1次','每2-3天1次，可多喷水','每5-7天1次','每10-14天1次，保持微润即可','忌盆土长期积水导致根部腐烂，同时忌盆土彻底干透太久','温和的温室自来水','high','对空气湿度要求较高，喜湿润。天气干燥时，应常向叶面及周围地面喷水。',18,28,10,35,0,'客厅、书房、明亮窗边、办公桌、卫生间','喜温暖湿润、半阴环境，忌强光暴晒，怕干旱，稍耐寒，喜肥沃排水良好的壤土。','喜温暖环境。冬季气温低于10℃时容易发生冻害导致叶片萎蔫，夏天需注意降温通风。','平衡20-20-20','biweekly','生长期每两周施用一次稀薄的观叶液肥，在开花前可适当增施磷钾肥以促花。','春季和夏季','稀薄的氮磷钾复合液肥','高磷钾肥促进现蕾开花',1,'忌施浓肥或未腐熟的生肥，施肥时避免沾污叶片和花朵','叶片发黄变薄、生长停滞、长期无法抽出花茎','全年生长季均可','及时剪除植株底部的枯黄老叶和开花凋谢后的残花梗','从受损叶片或花梗的基部直接剪断','无特殊禁忌，修剪残花即可','{\"fall\": \"随着温度降低，逐步减少施肥并拉长浇水间隔，多让其接触温和的阳光。\", \"spring\": \"春季是换盆和分株的好时机，逐渐增加浇水量和施肥，给予适度的明亮散射光。\", \"summer\": \"高温高湿季节，需移到阴凉通风处，避免暴晒，增加向叶面喷水的频率以控温。\", \"winter\": \"防寒保暖，室温控在10℃以上，严格控制浇水，盆土不干不浇，停止施肥。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"叶背、花梗处出现细小害虫，叶片失绿并有黄斑\", \"treatment\": \"可用清水擦洗叶片，严重时喷洒啶虫脒或阿维菌素\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"盆土排水不畅，长期积水或施肥过浓烧根\", \"symptom\": \"叶片边缘枯黑并整体萎蔫下垂，根部变黑腐烂\", \"treatment\": \"脱盆剪除烂根，用多菌灵浸泡后更换疏松的新土重新栽种\"}], \"prevention\": \"保持环境通风，严禁盆土积水，定期清理残叶残花。\"}','微毒','汁液、叶片','含有草酸钙结晶，皮肤触碰汁液可能过敏，误食会引发消化道和口腔粘膜红肿、灼烧感','对猫狗及儿童有毒，需妥善放置，修剪后及时洗手，防止宠物啃食。','{\"leggy\": \"针对室内养护缺乏光照，导致叶柄抽得极长且变得脆弱易倒伏。\", \"noBloom\": \"长期放置在过于阴暗的角落，或者长期未施用磷钾肥导致营养不足。\", \"drooping\": \"最典型的是缺水，只要及时浇透水即可恢复；若是浇水后依然无法恢复，则是根系已经腐烂。\", \"mainTaboo\": \"烈日暴晒和低温冻害。\", \"beginnerTip\": \"一看到白掌叶子软倒就以为它快死了，其实往往只是缺水，及时浇一次透水它几个小时后就能挺立起来。\", \"yellowLeaves\": \"多数因浇水过多、土壤不透气闷根发黄；偶尔也有由于光照过强导致的叶片灼伤发黄。\"}','经典的室内赏花赏叶两相宜植物，线条柔和清雅，极具现代家居美感。','净化空气的明星，能有效过滤空气中的甲醛、苯、三氯乙烯及氨气。','无食用价值','无家庭药用价值','因花形似帆，寓意“一帆风顺”、事业顺遂、家庭和睦平顺。','客厅、书房、明亮窗边、办公桌、会议室、洗手间','排水良好的盆栽土','腐叶土:泥炭土:珍珠岩 = 2:2:1，要求富含有机质且疏松透气','陶盆、塑料盆或水培专用器皿','口径15-25cm','每年春季换盆一次',5.5,6.5,'easy','moderate',60,1,0,0,1,'/images/plants/peace-lily.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(6,'芦荟','库拉索芦荟、油葱、象鼻草','Aloe barbadensis miller','aloe-vera','阿福花科','芦荟属','肉质','多年生','多肉','地中海地区、非洲','芦荟是一种著名的多年生常绿肉质草本植物。叶片肥厚多汁，呈狭长披针形，边缘长有疏尖刺。它不仅外形独特，且生命力强健，极耐干旱，其叶片内部的凝胶广泛运用于美容和轻度烫伤护理，是非常实用的“生活型”植物。','肥厚多汁、全能耐旱的美容生活小助手。','狭长披针形，基部宽大，顶端渐尖，边缘有刺状小齿','浅绿色或翠绿色，幼苗期常带有白色斑点','无茎或茎极短，叶片呈莲座状簇生','总状花序，花葶高大抽出，花朵呈管状下垂','黄色、橙色或红色','冬季至春季 / 室内养护较难开花','少见','呈放射状莲座排列，叶片肥厚坚挺向外伸展，呈现出一种充满自然野趣的几何美感。','bright_direct',6,10,'非常喜光，在全日照或明亮的直射光环境下生长健壮，稍耐半阴，但长期缺光会徒长变软。','rarely',14,25,'极度耐旱，体内储水丰富。必须等盆土彻底干透后再浇水，春夏季多浇，秋冬季严格控水。','干透浇透','每10-15天1次','每7-10天1次','每15-20天1次','每30天1次或彻底断水','严忌频繁浇水和盆内积水，浇水时切勿将水灌入中心叶盘，极易导致烂心','室温自来水','low','喜干燥环境，不耐潮湿。家庭环境中无需特殊空气增湿，保持良好的通风即可。',15,35,5,40,0,'明亮窗边、阳台、南向卧室、书桌、厨房桌子','喜温暖、干燥和阳光充足环境，极耐干旱，怕积水，不耐寒，喜排水极其良好的沙质土。','喜温暖和高温气候，极其不耐寒。越冬温度不宜低于5℃，否则肥厚的叶片极易受冻溃烂。','平衡20-20-20','none','耐贫瘠，对肥料依赖极低。可在春季生长期施1-2次稀薄的有机肥或多肉缓释肥即可。','春季','低氮高磷钾的稀薄多肉专用肥或缓释肥颗粒','不以观花为主，无需促花肥',1,'忌施浓肥或直接施用生肥，防止烂根','生长基本停滞，叶片显得薄而无神','春夏季','剪除底部的干枯老叶、受损受冻的叶片，或掰除过多的侧芽','用消毒的锋利小刀从叶片基部紧贴茎干处切除','避免在冬季寒冷且伤口不易愈合的时期进行修剪','{\"fall\": \"秋末逐渐减少浇水频率，增强光照，帮助其安全越冬。\", \"spring\": \"生长的黄金期，可以将其搬至阳光充足处，并进行分株繁殖与换盆，适量浇水。\", \"summer\": \"虽然耐热，但高温时需保持环境通风，切忌闷热积水，无需过多浇水。\", \"winter\": \"严格控水，保持盆土干燥，室温需维持在5℃以上，防止冻伤。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"在叶片凹槽或基部聚集白色或黄色的硬壳蜡质小点\", \"treatment\": \"人工用刷子刷除，或用蚧必治喷洒\"}], \"diseases\": [{\"name\": \"黑斑病\", \"cause\": \"主要是多雨潮湿、环境不通风或者盆土长期积水感染真菌\", \"symptom\": \"叶片上出现圆形或不规则的黑褐色斑点，病斑凹陷\", \"treatment\": \"剪除病叶，喷洒多菌灵或百菌清，并移到通风、干燥、阳光充足处\"}], \"prevention\": \"控制浇水，多晒太阳，保持环境空气流通、干燥。\"}','微毒','汁液、叶片','含有芦荟素成分，大量误食会导致腹痛、腹泻、呕吐等胃肠刺激','对猫狗有毒，宠物误食可能引发严重的呕吐和腹泻，请避免宠物和儿童随意抓咬。','{\"leggy\": \"长期缺乏光照，叶片会变得细长、薄弱且无力向四周耷拉，失去挺拔感。\", \"noBloom\": \"室内光照、积温以及温差通常达不到芦荟开花的标准，养护数年的老株在阳光极好时才会开花。\", \"drooping\": \"叶片变软下垂多为根系腐烂或遭遇寒冻受冻所致。\", \"mainTaboo\": \"频繁浇水、盆土长期潮湿积水、环境阴暗不通风。\", \"beginnerTip\": \"像照顾普通植物一样频繁关切地给它浇水，结果几个星期内就导致它烂根死掉。\", \"yellowLeaves\": \"多数情况是土壤积水严重导致根部烂掉，叶片因而失去营养发黄萎蔫；长期缺光也会导致叶片发黄变软。\"}','株形简约、带有现代线条美，适合北欧风、现代风等现代多肉植物造景。','能在夜间吸收二氧化碳、释放氧气。对甲醛、二氧化碳具有很强的吸收能力。','部分品种（如库拉索芦荟）的内部透明凝胶可食用，但需科学去皮加工，不可盲目乱吃。','凝胶有极佳的消炎、杀菌、补水和促进轻度烫伤/蚊虫叮咬愈合的作用。','具有辟邪、挡煞、化解室内煞气的作用，同时也寓意着健康长寿与切断坏运气。','阳台、明亮窗边、书桌、厨房桌子、办公室、南向卧室','排水良好的盆栽土','沙质土:普通园土:珍珠岩 = 2:2:1，或多肉专用营养土','陶盆最佳，塑料盆需多带排水孔','口径10-20cm','每2-3年换盆一次',6.5,7.5,'easy','slow',50,1,1,0,1,'/images/plants/aloe-vera.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(7,'吊兰','挂兰、钓兰、折鹤兰、兰草','Chlorophytum comosum','spider-plant','天门冬科','吊兰属','草本','多年生','观叶','非洲南部','吊兰是一种极为经典的常绿多年生草本植物。其根茎短，根系肥大呈肉质。长条状叶片自基部丛生，最独特的特征是成熟时会从叶丛中抽长出柔软的匍匐茎，茎端倒挂着一丛丛精致的幼苗，形似飞鹤。极易养护，极为适合悬挂垂吊欣赏。','折鹤倒挂，生命力无限的室内吸毒气之王。','线形至披针形，细长如兰草，顶端渐尖','全绿，或叶缘有白色/黄色纵条纹（金边、银边吊兰）','地上茎不明显，但成熟后会伸出长而下垂的匍匐茎','小花簇生在下垂的匍匐茎上，花朵细小呈星状开裂','纯白色','5-8月 / 全年可开花','秋季（少见）','丛生叶片向四周自然弯曲下垂，长长的匍匐茎上悬挂着错落有致的小吊兰，非常飘逸灵动。','medium',4,6,'喜温暖湿润和明亮的散射光，较耐半阴。忌烈日暴晒，光照过强易导致叶尖枯焦。','weekly',5,7,'吊兰具有肥厚的肉质根，能储藏大量水分，因此较耐旱。生长期保持盆土湿润，切勿长期积水。','见干见湿','每周1-2次','每3-5天1次，视干燥度增加喷水','每5-7天1次','每10-14天1次，严格控水','盆土忌长期形成泥泞积水，否则会导致肉质根系腐烂','室温自来水即可','medium','喜湿润的空气环境。北方春季干燥或夏季高温时，需经常向叶面喷水以防叶尖干枯。',15,28,5,35,0,'客厅、书房、明亮窗边、高柜顶部、厨房、悬挂吊阳台','喜温暖湿润、半阴环境，适应性强，较耐旱，不耐寒，对土壤要求不严，根系极其发达。','喜温暖舒适，越冬温度需保持在5℃以上，气温低于5℃时生长停止，叶片容易发黄冻伤。','平衡20-20-20','biweekly','春夏生长期每半月施一次稀薄的复合肥或观叶无机液肥；金边品种注意不要施过量氮肥以防斑纹消失。','春季和夏季','稀薄的观叶专用平衡营养液','不以观花为主，一般不需要促花肥',1,'忌浓肥和生肥，秋冬低温季节严禁施肥','叶面颜色黯淡、斑纹模糊，匍匐茎减少且不长新小吊兰','春季','剪除枯焦的叶尖、发黄的老叶，以及修剪过密、过长的匍匐茎','用剪刀直接将黄叶基部剪除；干枯叶尖可顺着叶片形状斜剪掉；小吊兰可剪下直接进行繁殖','无特殊修剪禁忌，生命力极强，极耐修剪','{\"fall\": \"气温痕量降低后逐渐减少浇水。多让其接受柔和秋光，有助于根系强健、提高抗寒性。\", \"spring\": \"换盆、分株繁殖的黄金期。可将匍匐茎上的小吊兰剪下水培或土培，极易成活。增加浇水施肥。\", \"summer\": \"严禁烈日暴晒，需移向阴凉散射光处。注意多通风，高频率向周围空气喷雾降温。\", \"winter\": \"必须移入室内保暖防冻，控水停肥，尽量放置在室内阳光较好的窗台或架子上。\"}','{\"pests\": [{\"name\": \"粉虱/介壳虫\", \"symptom\": \"叶片背面或基部出现白色飞虫或蜡质小虫，导致叶面发黏、生长不良\", \"treatment\": \"用肥皂水刷洗、冲洗叶片，或使用蚧必治喷洒消灭\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"花盆透气性差，盆土长期积水，环境通风不良导致真菌滋生\", \"symptom\": \"整丛叶片从基部发黄萎蔫，根系呈黑色水渍状腐烂\", \"treatment\": \"脱盆修剪掉烂根和黄叶，用多菌灵消毒后换用新土重新栽植，并控制浇水\"}], \"prevention\": \"保持环境通风、烘干，严防盆土长时间处于过湿状态，定期清理黄老叶片。\"}','无毒','无','完全无毒，对人类及宠物均安全','对猫狗绝对安全。由于其下垂的叶片和幼苗酷似玩具，极易吸引猫咪抓咬，虽然无毒但会破坏株形，可挂在高处。','{\"leggy\": \"缺少光照，导致叶片长得又细又薄，色泽变淡且容易折断。\", \"noBloom\": \"光照极度缺乏或长期不换盆导致盆内肉质根全长满、土壤已无养分。\", \"drooping\": \"主要是肉质根遭受极度缺水引起的叶片干瘪无力垂软（及时补水可恢复）。\", \"mainTaboo\": \"长期烈日暴晒与盆土长期泥泞不透气。\", \"beginnerTip\": \"发现叶尖枯焦就拼命在盆里浇水，结果导致空气依然干燥但盆土却积水，最终直接把花养烂根了。\", \"yellowLeaves\": \"最常见的是“干尖”现象（仅叶片顶端枯焦），多由空气太干燥或烈日暴晒引起；若整片叶子发黄则多是积水烂根或过度缺肥。\"}','传统的室内悬挂垂吊名花，线条飘逸、动感十足，能打破室内生硬的建筑线条。','享有“绿色净化器”之美誉。对室内甲醛、一氧化碳、苯等有害气体的吸收率高达95%以上。','无食用价值','在传统中医中其根、全草有清热解毒、止咳化痰的功效（严禁私自调配使用）。','寓意守望幸福、坚韧不拔，有招财聚气、净化磁场之说。','客厅、书房、明亮窗边、高柜顶部、厨房、悬挂吊阳台、办公室','排水良好的盆栽土','园土:腐叶土:河沙 = 2:2:1，或者市售通用营养土，要求疏松透气','吊盆最为合适，塑料盆、陶盆均可','口径15-25cm（由于其长势快且根系发达，宜选稍深的花盆）','每年春季换盆一次',6.0,7.0,'easy','fast',40,1,0,1,1,'/images/plants/spider-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(8,'金钱树','雪铁芋、金币树、泽米叶天南星','Zamioculcas zamiifolia','zz-plant','天南星科','雪铁芋属','草本','多年生','观叶','非洲东部热带雨林','金钱树是一种极为独特的常绿草本植物，具肥大的地下块茎。其羽状复叶自块茎顶端抽生，小叶肉质肥厚、圆润浓绿，在叶轴上排列整齐，形似一串串挂着的铜钱，因而得名。它极其耐阴、耐旱，是室内高端商务与家居装饰的常客。','叶形似铜钱，耐阴耐旱的质感招财植物。','卵形或长卵形，厚革质且肉质化，边缘全缘','浓绿色，表面有强烈的蜡质光泽，油亮碧绿','地上无主茎，分枝为肥大的肉质叶轴；地下具粗壮的块茎','佛焰苞花序，从基部叶轴中抽出，形似小棒，在室内极罕见','黄绿色、黄白色','夏季至秋季 / 极少开花','少见','复叶挺拔直立，左右小叶整齐对生，如同拉链或排列的金币，整体株形优雅，富有雕塑感。','medium',3,6,'喜明亮的散射光，但也非常耐阴。极忌烈日暴晒，强光会导致叶片灼伤发黄。','rarely',15,25,'地下有肥大的块茎，能储藏大量水分，极耐干旱。浇水应坚持“宁干勿湿”，必须盆土完全干透再浇透，冬季更需严格控水。','干透浇透','每15天1次','每10-14天1次','每15-20天1次','每30天1次或断水','严忌高频率浇水和盆土长期潮湿，否则地下土块茎及根系会迅速腐烂','晾置过的室温自来水','medium','对空气湿度要求中等，喜略微湿润的环境，但由于叶片质厚，能耐受较干燥的北方室内环境。',18,32,10,35,0,'客厅、书房、办公室、前台、玄关、会议室','喜温暖、微干、半阴环境，极耐干旱，怕积水，忌寒冷，喜排水极佳、富含腐殖质的沙质壤土。','喜温暖及炎热环境，非常畏寒。冬季室温需保持在10℃以上，低于5℃极易导致严重的冻害烂根。','平衡20-20-20','monthly','生长期每逢每月施一次稀薄的复合液肥或在盆土表面撒入缓释肥颗粒即可，秋冬寒冷季节停肥。','春季和夏季','低氮、高磷钾的复合肥或多肉专用肥，促使复叶粗壮','不以观花为主，无需促花肥',1,'忌施浓肥、生肥，气温低于15℃时绝对不要施肥','新抽出的复叶细弱、叶色发淡发黄，生长极其缓慢','春季','剪除老化发黄的底层叶片、受损叶片或过密的弱势枝条','从受损或老化复叶的基部直接用利刀割除','避免在冬季低温及阴雨天气进行修剪，防伤口感染腐烂','{\"fall\": \"气温降至20℃以下后，拉长浇水间隔，停止施肥，增加其光照以充实组织健壮越冬。\", \"spring\": \"换盆好时机。随着块茎新芽抽出，逐渐恢复浇水与施肥，放置于明亮散射光处。\", \"summer\": \"盛夏注意遮阴防暴晒，加强环境通风，可以适当向其周围地面喷水降温，切忌土壤过湿。\", \"winter\": \"必须移至室内温暖处，严格控制浇水，保持盆土微干甚至干燥，全力防寒防冻。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"羽状小叶对生处或叶轴基部出现白色蜡质盾壳状害虫\", \"treatment\": \"用酒精棉球擦拭或用蚧必治喷洒\"}], \"diseases\": [{\"name\": \"块茎腐烂病\", \"cause\": \"土壤长期积水，不透气，或者使用了未腐熟的生肥感染细菌\", \"symptom\": \"地上复叶迅速发黄、变软、倒伏，地下块茎变软溃烂并有酸臭味\", \"treatment\": \"立即脱盆，挖出块茎并切除腐烂部分，用多菌灵浸泡后更换全沙质新土重新栽种\"}], \"prevention\": \"控制浇水是预防一切病害的核心；保持室内环境有良好的空气对流。\"}','有毒','汁液、全株','天南星科植物，汁液中含有植物草酸钙和毒性蛋白质，皮肤接触引发红肿刺痛，误食会导致口腔剧烈灼痛、肿胀及无法发声','对猫狗及儿童有毒，且毒性相对绿萝稍强。应放置于儿童与宠物不易接触到的高处或独立区域。','{\"leggy\": \"长期放置在阴暗角落，导致新抽出的叶轴极为细长瘦弱，且叶片间距拉大，失去挺拔美感。\", \"noBloom\": \"室内极难开花，一般无需追求开花，主要欣赏其常绿的厚革质复叶。\", \"drooping\": \"主要是块茎受损腐烂无法固定，或者是环境温度暴跌冻伤，导致复叶整体疲软倒伏。\", \"mainTaboo\": \"频繁浇水导致盆土长期处于湿漉漉的泥泞状态。\", \"beginnerTip\": \"因为它的名字叫“金钱树”就每天对它过度关切、频繁浇水，结果很快就把地下块茎泡烂导致死掉。\", \"yellowLeaves\": \"90%以上是由于浇水过多引起的闷根、烂根、导致叶片发黄；或者是遭遇了低温冻害、强光暴晒。\"}','叶片整齐硬朗，油亮闪耀，极具现代几何感。常用作开业乔迁、商务大堂或现代客厅的质感绿化。','叶面宽大且有厚蜡质，能吸附空气中的微小灰尘，净化室内甲醛等装修污染。','无食用价值','无家庭药用价值','名字极为吉利，寓意“招财进宝”、“荣华富贵”、“财源滚滚”，是居家和开业的风水佳品。','客厅、办公室、前台、玄关、会议室、大堂','排水良好的盆栽土','泥炭土:珍珠岩:粗沙 = 3:1:1，确保优异的透气排涝性','质感庄重的紫砂盆、陶盆或高端塑料盆','口径20-35cm','每2-3年春季换盆、换土一次',6.0,6.5,'easy','slow',150,1,0,0,1,'/images/plants/zz-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(9,'橡皮树','印度榕、印度橡胶树、黑金刚','Ficus elastica','rubber-plant','桑科','榕属','木本','多年生','观叶','印度、马来西亚等亚洲热带地区','橡皮树是一种常绿大乔木。盆栽时主干挺拔，其叶片肥厚宽大，呈长椭圆形，质地为厚革质。最为人熟知的品种“黑金刚”叶色深绿近乎墨黑，顶芽包裹在红色的托叶中，红黑相间，极具高冷、工业风的极简现代美感。','挺拔高冷，红芽黑叶的极简工业风网红树。','长椭圆形或卵状长圆形，厚革质，全缘，先端有小突尖','深绿色、墨绿色（黑金刚品种近乎黑亮），新顶芽呈鲜红色','直立木质化茎干，表皮平滑灰褐色，全株具丰富的白色乳汁','隐头花序，在室内盆栽中几乎不具备开花可能','绿褐色（隐于隐头花序内）','极为罕见','少见','单干直立或有少量分枝，大而厚重的叶片错落排列在挺拔的主干上，整体风格硬朗、沉稳且极具存在感。','high',5,8,'非常喜光。明亮的散射光或充足的直射光能让叶片颜色更深、更亮。虽耐半阴，但长期缺光会落叶。','weekly',7,10,'遵循“见干见湿”原则。在春夏季生长期需保持盆土湿润；秋冬季生长减缓，需等盆土干燥后再浇水。','见干见湿','每周1次','每周2次','每10天1次','每15-20天1次，严格控水','严忌花盆内长期积水，这会导致根系缺氧腐烂进而引起大规模落叶','晾置过的自来水','medium','对空气湿度适应性较强，喜略微潮湿，但也能耐受普通的室内干燥环境。',18,30,8,38,0,'客厅落地窗旁、大堂、明亮书房、玄关、明亮窗边','喜温暖湿润和阳光充足环境，忌积水，较耐旱，耐高温，喜肥沃、排水良好的酸性沙质土。','喜温暖、高温气候，抗热性极强。不耐严寒，冬季越冬温度建议保持在8℃以上，防止发生冻害。','平衡20-20-20','biweekly','生长期每两周施用一次稀薄的复合液肥或观叶类水溶肥，以氮磷钾平衡肥为优。冬季彻底断肥。','春季和夏季','稀薄的平衡型饼肥水或氮磷钾无机复合液肥','不以观花为主，无需促花肥',1,'忌浓肥，温度低于15℃或高于35℃时严禁施肥','新叶变小变薄，叶面失去光泽，主干瘦弱不粗壮','春季','剪除顶端以促分枝（打顶短截）、修剪过密枝条及底部的老黄叶','在侧芽点上方1厘米处平剪。修剪时会流出大量白色黏性乳汁，可涂抹草木灰或用纸巾擦干','避免在冬季寒冷期重剪。皮肤敏感者修剪时请佩戴手套','{\"fall\": \"秋末逐步拉长浇水间隔，停止施肥，尽量让其多见阳光，使主干木质化以增强抗寒力。\", \"spring\": \"换盆、修剪、扦插的最好时期。随着新顶芽萌动，增加浇水施肥，多晒温和太阳。\", \"summer\": \"耐热不需要遮阴，但如果烈日极度暴晒可稍作防护。注意保持环境极佳的通风，并多浇水。\", \"winter\": \"移入室内温暖向阳处。严格控水，盆土不干不浇。定期用湿抹布擦拭叶片，清理灰尘。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"叶片背面或茎秆节处出现硬壳小虫或细微红点，伴有失绿斑点\", \"treatment\": \"用刷子刷除，或喷洒杀扑磷、蚧必治或阿维菌素进行驱杀\"}], \"diseases\": [{\"name\": \"炭疽病\", \"cause\": \"主要是夏季高温、高湿且室内空气密闭不通风引发的真菌感染\", \"symptom\": \"叶片边缘或表面出现不规则的黑褐色斑点，后期病斑干枯穿孔\", \"treatment\": \"剪除病叶，喷洒多菌灵或百菌清溶液，并立即开窗通风、减少喷水\"}], \"prevention\": \"核心在于长期保持室内环境通风良好，定期用湿布擦洗巨大的叶面以保持卫生。\"}','微毒','茎叶内流出的白色乳汁','乳汁中含有橡胶烃、有机酸等成分，皮肤接触可能引发红肿、瘙痒或过敏反应；误食会导致消化道灼烧、呕吐和腹泻','对猫狗及儿童有毒。修剪或折断叶片时需特别注意，防止白色汁液滴落地板或被宠物、儿童误触误食。','{\"leggy\": \"光照太差，主干细长无力，叶片之间的距离被拉得极长，整株显得稀疏软弱。\", \"noBloom\": \"室内养护由于环境限制，完全不具备开花条件，属于正常现象。\", \"drooping\": \"新买回家不适应环境（应激反应），或者由于气温骤降、根系严重腐烂引发的叶片低垂无力。\", \"mainTaboo\": \"盆土长期积水不干以及长期处于完全阴暗的角落。\", \"beginnerTip\": \"不经常擦拭叶子，导致巨大的叶面上堆满灰尘，不仅难看还严重阻碍了橡皮树的光合作用，导致其生长停滞。\", \"yellowLeaves\": \"最主要原因是浇水过多闷根或者托盘长期积水；另外，长期缺乏阳光导致光合作用不足也会引发底层叶片发黄脱落。\"}','叶片肥大、光亮，黑金刚品种自带冷峻的工业质感，非常符合现代极简主义及北欧风的软装设计。','具有极强的吸附粉尘、烟尘能力，并能有效吸收空气中的甲醛、一氧化碳等有害气体。','无食用价值','无确切家庭药用价值','寓意稳重、诚实、吉祥如意，在风水上有“催吉生旺”、挡煞、聚财的刚强植物寓意。','客厅落地窗旁、办公室角落、玄关、咖啡厅、展厅、大堂','排水良好的盆栽土','腐叶土:园土:珍珠岩 = 2:2:1，确保土壤基础结构疏松透气','水泥盆、大号陶盆或简约风格塑料盆','口径20-35cm','每1-2年春季换盆一次',6.0,7.0,'easy','fast',250,1,0,0,1,'/images/plants/rubber-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(10,'波士顿蕨','高大肾蕨、波士顿肾蕨','Nephrolepis exaltata','boston-fern','肾蕨科','肾蕨属','草本','多年生','观叶','全球热带及亚热带近水湿地','波士顿蕨是肾蕨的一种极其受人喜爱的园艺变种。它不产生孢子，依靠分株繁殖。其叶片为羽状深裂，下垂生长。复叶繁茂细密、颜色鲜绿翠嫩，线条极为柔美，呈现出蓬松的爆炸状。因其极其耐阴、喜高湿，是悬吊、壁挂观赏的绝佳蕨类植物。','蓬松翠嫩、羽叶下垂的喜湿润空气净化器。','一回羽状复叶，细长向四周弯曲下垂，小叶呈长披针形，边缘有细钝齿','鲜绿色、翠绿色，质地鲜嫩柔和','无地上直立主茎，具匍匐茎，根系常伴有球状肉质块茎','蕨类植物，完全不抽花茎，不孕、不结实、无花','无','无','无','整株呈茂密的蓬松丛生状，无数羽状复叶呈优美的抛物线向外扩散下垂，显得生机勃勃、极为轻盈飘逸。','low',2,4,'高度耐阴，喜明亮的散射光或半阴环境。绝对不能承受强光或烈日暴晒，强光会导致叶片瞬焦发白。','frequent',2,4,'非常喜湿润。生长期需保持盆土彻底潮湿（但绝非泥泞积水），表土稍微有微干就要立即浇透水。','喜湿忌干','每2-3天1次','每1-2天1次，高频叶面及环境喷雾','每3-5天1次','每7-10天1次，视室温稍微控水','严忌盆土彻底干透，一次长时间的严重缺水会导致娇嫩叶片发生不可逆的干枯干死','晾置过的室温自来水或纯净水','high','对空气湿度要求极高，理想湿度在70%以上。环境干燥会导致叶边缘干枯脱落。需高频向叶面周围喷雾。',15,26,10,32,0,'洗手间、明亮厨房、客厅高架上、北向卧室、悬挂吊阳台','喜温暖阴湿环境，畏惧强光，怕干旱，不耐寒，喜疏松肥沃、排水优良的腐殖土。','喜温暖湿润，生长适温为15-26℃。不耐寒，冬季室内温度必须维持在10℃以上，防止大量落叶受冻。','平衡20-20-20','biweekly','春夏旺盛生长期每两周施用一次极其稀薄的液肥（浓度建议为普通植物的一半）。秋冬季全面停肥。','春季和夏季','稀薄的以氮钾为主的弱效液肥或观叶营养液','蕨类不应施用促花肥',1,'极忌浓肥、生肥，否则鲜嫩的根系会瞬间烧伤导致全株枯萎','新长出的羽叶颜色发白、发黄，整株缺乏生机，叶片蓬松度变差','春季','剪除底层干枯、发黄的老叶，以及修剪内部过密、阻碍通风的叶片','用剪刀深入植株基部，将黄干的叶柄直接剪断即可','无特殊禁忌，但修剪时动作要轻，避免扯伤、损伤周围鲜嫩的健康新芽','{\"fall\": \"随着天气转凉减缓浇水频率，但空气喷雾不能停，北方秋季干燥需特别关注空气湿度。\", \"spring\": \"换盆、分株繁殖的黄金期。将密集的植株切开分盆，增加浇水与稀薄肥水，移到半阴处。\", \"summer\": \"严防高温与暴晒。将其移到最阴凉通风的地方，每天早晚各喷雾一次，盆土确保高湿润。\", \"winter\": \"必须进屋保暖，温度控在10℃以上。虽然要适度控制浇水，但由于暖气房干燥，仍需高频喷雾或放置在加湿器旁。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"羽叶间出现极细的微小蜘蛛网，叶片开始干枯无神\", \"treatment\": \"由于蕨类叶片娇嫩易受药害，优先用清水高压淋洗擦拭，严重时喷洒极稀薄的阿维菌素\"}], \"diseases\": [{\"name\": \"叶枯病\", \"cause\": \"盆土排水不畅，长期泥泞积水，同时环境闷热不通风引发细菌感染\", \"symptom\": \"小羽片大面积变黑、脱落，基部茎干变黏软烂\", \"treatment\": \"剪掉全部受损叶片，脱盆剪除坏根，浸泡多菌灵后更换轻质透气新土，并开窗通风\"}], \"prevention\": \"核心在于营造“高空气湿度+良好空气对流”的协调环境，避免盆土死水积水。\"}','无毒','无','全株完全无毒，极其安全','对猫、狗及儿童绝对安全。由于其叶片下垂且一动即摇晃，非常受猫咪喜爱，可挂在高处防止被猫啃秃。','{\"leggy\": \"在完全无光的极端黑暗环境，新叶会开裂不全、长得过长且呈病态的苍白色。\", \"noBloom\": \"蕨类植物属于无花植物，终生不孕不抽花，完全属于正常生理特性。\", \"drooping\": \"主要是土壤干透缺水导致鲜嫩的羽叶脱水垂软，只要没干死，及时浸盆或浇透水能快速恢复挺拔。\", \"mainTaboo\": \"环境极度干燥以及遭遇烈日暴晒。\", \"beginnerTip\": \"把它放在阳光充足的阳台上养，且不知道往叶面喷水，结果几天内整盆细嫩的叶片就全部枯黄死掉。\", \"yellowLeaves\": \"最典型的原因是“空气湿度严重不足”导致叶缘发黄发干、小叶大面积脱落；其次是彻底缺水或烈日曝晒。\"}','蓬松茂密、翠绿灵动，能够营造浓郁的热带雨林及林下自然感。作为吊盆、壁挂植物效果惊艳。','能以惊人的效率常绿生长。对甲醛、二甲苯等装修毒气吸收率极高，并能像天然加湿器一样显著提升室内湿度。','无食用价值','无确切家庭药用价值','寓意常青、长寿、充满活力与蓬勃的生机。密集重叠的羽叶也有多子多福的风水意头。','洗手间、北向卧室、明亮厨房、客厅高柜上、咖啡厅吊顶、悬挂阳台、植物墙','排水良好的盆栽土','泥炭土:水苔:珍珠岩 = 2:2:1，或者全腐叶土配合珍珠岩，要求高度保水且排水优良','塑料吊盆最佳、透气性好的泥瓦盆、壁挂盆均可','口径15-25cm','每年春季结合分株换盆一次',5.5,6.5,'medium','fast',60,1,0,1,1,'/images/plants/boston-fern.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(11,'玉树','燕子掌、景天树、发财树','Crassula ovata','jade-plant','景天科','青锁龙属','肉质','多年生','观叶','南非','玉树是一种多年生常绿肉质灌木。茎干粗壮木质化，分枝多，形态古朴。其叶片肥厚肉质，卵圆形，翠绿油亮如碧玉，叶缘在阳光充足及温差大时会泛红。它极耐干旱，生命力长久，常作为树状多肉盆景栽培。','叶茂如玉，茎干古朴且极度耐旱的松柏姿态多肉。','卵圆形至匙形，肥厚肉质，表面光滑全缘','翠绿色、碧绿色，阳光充足时叶缘常带有一圈红边','主干粗壮，肉质化并随着年龄增长木质化，表皮灰绿色或浅褐色','繁密的小花呈伞房花序顶生，星状五裂','白色或淡粉红色','冬季至早春 / 室内老株在光照极佳时才开花','少见','株形丰满，枝叶紧凑，颇有老树古董盆景的苍劲风茂，整体感觉稳重、常青。','bright_direct',5,8,'非常喜光。明亮的直射光能让其株形紧凑、叶片肥厚油亮。虽能耐半阴，但长期缺光会徒长变软、叶片脱落。','rarely',10,20,'典型的多肉植物，体内蓄水能力极强。必须坚持“干透浇透”原则，宁干勿湿。夏季高温休眠期和冬季低温期需严格控水。','干透浇透','每10-15天1次','每15-20天1次','每10-15天1次','每30天1次或彻底断水','严忌盆土长期潮湿泥泞，绝对不能让底座托盘长期存有积水','普通室温自来水','low','喜干燥环境，不耐高湿。普通室内湿度即可，梅雨季节或闷热天气需严格保持空气对流。',15,30,5,35,1,'南向阳台、明亮窗边、客厅落地窗旁、书桌台面','喜温暖干燥和阳光充足环境，极耐干旱，忌积水潮湿，怕寒冷，喜疏松排水极佳的沙质土。','喜温暖干燥，极不耐寒。夏季高温超过35℃时可能短暂休眠需通风，冬季温度需保持在5℃以上防冻伤。','平衡20-20-20','monthly','对肥料需求不高。仅在春季和秋季生长期每月施一次极其稀薄的液肥或撒入几粒缓释肥颗粒即可。夏冬两季严禁施肥。','春季和秋季','低氮、高磷钾的稀薄多肉专用肥或复合有机肥','老株催花可于秋季增施1-2次极稀薄的磷钾肥',1,'忌浓肥、生肥，酷暑及寒冬期严禁施肥','叶片变薄软塌，整株生长完全停滞且显得无神','春季','剪除徒长枝、过密枝、交叉分枝以及发软萎缩的老叶','用消毒剪刀在分枝节点上方平剪，修剪后伤口需保持干燥','避免在夏季高温闷热或冬季受冻期间进行大面积重剪','{\"fall\": \"秋凉后迎来第二个生长期。恢复正常干透浇透，多晒太阳，使其叶缘出红边，组织更加紧实。\", \"spring\": \"黄金生长期。逐步增加浇水，给予全日照。可结合换盆进行修剪造型，剪下的枝条可轻松扦插。\", \"summer\": \"高温超过33℃时会进入半休眠。必须搬到阴凉通风处避免烈日暴晒，严格控水，严防烂根。\", \"winter\": \"移入室内温暖向向阳处。严格控制浇水或断水，盆土保持完全干燥有利于提高其抗寒防冻能力。\"}','{\"pests\": [{\"name\": \"粉觧\", \"symptom\": \"在叶片背面、嫩芽或枝条缝隙间聚集白色棉絮状或硬壳小虫\", \"treatment\": \"用酒精棉球逐个擦拭掐死，或喷洒蚧必治防治\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"盆土长期积水闷根，或夏季高温高湿且环境极不通风真菌滋生\", \"symptom\": \"茎干或分枝基部变黑变软、溃烂，叶片大量脱落\", \"treatment\": \"切除变黑腐烂的茎干至健康组织处，伤口涂抹多菌灵晾干，更换全颗粒沙土重新扦插\"}], \"prevention\": \"核心在于常年管住手、少浇水，并始终保持居家养护环境拥有良好的空气流通。\"}','微毒','全株汁液','汁液中含有一些刺激性多肉植物化学成分，皮肤接触可能引发红肿阻碍，误食会导致恶心、呕吐及腹泻','对猫狗及儿童有毒，猫狗误食可能引发严重的呕吐和心率不齐，需放置在宠物无法触及的稳固高处。','{\"leggy\": \"长期将其摆放在阴暗、照不到阳光的地方，导致茎干细长软弱、节间拉长、叶片变薄变稀且失去光泽。\", \"noBloom\": \"室内养护因为光照时长、红外线积温以及日夜温差不够，玉树极难开花，一般只作为观叶盆景观赏。\", \"drooping\": \"整体复叶及分枝发软下垂，是根系腐烂、严重缺水或遭遇大降温冻伤的表现。\", \"mainTaboo\": \"频繁浇水、托盘积水以及冬季遭遇5℃以下的低温暴击。\", \"beginnerTip\": \"一看到它长得像小树就每天给它倒水，结果不到一个星期主干基部就彻底泡烂腐烂死掉。\", \"yellowLeaves\": \"最普遍是浇水过多引起烂根闷根导致叶片发黄、一碰就掉；长期过度缺水也会导致老叶发黄萎缩。\"}','树冠挺拔丰满，叶片翠绿如玉，自带中式古典盆景及现代极简几何质感，极具长线观赏价值。','能在夜间吸收二氧化碳、释放氧气，有微弱的吸附室内浮尘能力。','无食用价值','无家庭药用价值','民间又称其为“万年青”，寓意富贵吉祥、财源广进、健康长寿。','客厅电视柜旁、书房桌子、明亮窗边、南向阳台、办公室前台','排水良好的盆栽土','多肉专用颗粒土:普通园土:珍珠岩 = 3:2:1，或用粗沙混合腐叶土','透气较好的陶盆、泥瓦盆或重质紫砂盆','口径15-25cm','每2-3年春季换盆一次',6.0,7.0,'easy','slow',150,1,1,0,0,'/images/plants/jade-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(12,'薰衣草','香草、灵香草、黄香草','Lavandula angustifolia','lavender','唇形科','薰衣草属','草本','多年生','观花','地中海沿岸、欧洲南部','薰衣草是一种多年生常绿亚灌木或草本植物。全株带有浓郁独特的清香。叶片细长狭窄，披着一层银灰色的柔毛。花序为穗状花序顶生，开花时呈现出大片梦幻的蓝紫色。它是世界著名的香草植物，广泛运用于提炼精油、安神和园林景观。','梦幻蓝紫、全株浓郁芬芳的喜阳光香草女王。','线形或披针状线形，全缘，边缘常向背面卷曲','灰绿色至银灰色（因表面覆有细柔毛）','直立，基部木质化，分枝多，钝四棱形，带有明显香气','轮伞花序在枝顶聚集成间断或密集的穗状花序，花冠管状二唇形','蓝紫色、紫色，部分品种为粉色或白色','6-8月','秋季','呈紧凑的丛生灌木状，花期时无数高挑的花穗挺立在银灰色叶丛之上，优雅浪漫，极具视觉与嗅觉吸引力。','bright_direct',6,12,'极端喜光植物。必须给予全日照和全天候明亮的直射阳光。光照不足会导致其无法开花、植株瘦弱干枯。','rarely',7,12,'极为耐旱，原产地中海。浇水严格遵循“宁干勿湿”和“不干不浇，浇则浇透”的原则。阴雨天和冬季需断水或严格控水。','干透浇透','每5-7天1次','每3-5天1次','每7-10天1次','每15-20天1次，保持土壤微干','严忌频繁给水导致盆土长期泥泞，浇水时严禁从顶端直接淋浇叶片和花簇，极易引发全株枯萎腐烂','普通室温自来水','low','极度喜干燥环境，抗旱能力强。非常害怕高空气湿度及多雨闷热，环境必须常年保持极佳的通风对流。',15,25,-10,32,1,'全日照阳台、南向露台、室外花园、阳光房、南向窗台外侧','喜阳光充足、凉爽干燥环境，极耐干旱，怕积水，怕高温闷热，喜排水极其优良、带微碱性的沙质壤土。','喜香草及干燥气候，较耐寒。但极度害怕夏季的高温高湿，连续闷热易枯死。','平衡20-20-20','none','极其耐贫瘠，对肥料极为敏感。仅在春季开始萌芽生长时施1-2次极其稀薄的磷钾复合肥即可，切勿多施，否则易只长叶不开花或烧死。','春季','极其稀薄的低氮高磷钾复合水溶肥','现蕾初期可喷洒一次极稀薄的磷酸二氢钾促进花穗饱满',1,'严忌施用浓肥、未腐熟的生肥及过量施用氮肥','除非土壤极端贫瘠，通常无明显缺肥表现，过肥反而导致其迅速死亡','秋季','花期结束后剪掉残花梗，以及修剪掉过密的交叉枝、底部干枯发黑的叶片','在花序下方2-3个节点处连同部分老枝剪掉。注意修剪时不可剪到完全木质化的基部，否则老枝很难再萌发新芽','避免在盛夏酷暑或冬季严寒期间进行重剪，修剪后伤口严禁淋水','{\"fall\": \"花后修剪的最佳时期。剪去残花，使其株形紧凑。随着气温下降拉长浇水间隔，多晒秋季太阳。\", \"spring\": \"生长的黄金爆发期，必须给予全天候无死角的直射光，结合生长适量浇水并施稀薄磷钾肥，准备开花。\", \"summer\": \"薰衣草的“生死劫”。高温闷热极易引发全株枯死。必须移到遮阴、凉爽且风口通风极好的地方，严格控水，避免雨淋。\", \"winter\": \"较耐寒，但盆栽仍建议移入冷凉室内向阳处（5-10℃为宜）越冬。严格控制浇水，停止一切肥水。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"叶片上有微小针尖样黄点，叶片逐渐失去银灰色光泽\", \"treatment\": \"加强通风，严重时喷洒稀释的联苯肼酯或阿维菌素进行防治\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"夏季高温高湿、盆土长期积水、环境密闭不通风或土壤带有真菌孢子\", \"symptom\": \"全株叶片迅速发黄变黑、垂软，根部及茎基部变黑坏死腐烂\", \"treatment\": \"极难挽救。一旦发现需立即拔除病株，周围土壤喷洒多菌灵或百菌清消毒，健康分枝尝试剪下扦插\"}], \"prevention\": \"制造一个“干燥、极度通风、多晒太阳”的环境是预防所有香草植物病害的万能钥匙。\"}','无毒','无','对人类完全无毒。其清香有极好的提神醒脑和安神睡眠作用','对猫狗有微弱风险。虽然并非剧毒，但猫狗大量误食其植物体可能因无法代谢其精油成分而引发肠胃不适或流涎。','{\"leggy\": \"在光照不足的室内，茎干会变得极度细长软弱，向一侧倒伏，叶片稀疏苍白，香气大幅变淡。\", \"noBloom\": \"99%是因为光照严重不足。薰衣草是全日照植物，在室内普通散射光下几乎100%无法开花。\", \"drooping\": \"主要是夏天闷热闷根导致根系丧失吸水功能，或者盆土彻底干透脱水，需及时排查。\", \"mainTaboo\": \"盛夏多雨季节淋雨、频繁浇水以及长期摆放在密闭不通风的室内角落。\", \"beginnerTip\": \"买回家后觉得好闻就把它放在不通风、没有直射光的卧室床头，结果不到一个星期植物就整株发黑枯死。\", \"yellowLeaves\": \"最主要是因为环境太闷热或者浇水太多闷根，导致底层叶片大量发黄焦黑；其次是长期放在室内缺乏光照导致植物衰弱发黄。\"}','经典的欧式花园香草，蓝紫色的花穗浪漫典雅，全株自带的高级香气具有极高的生活情调。','全株散发的挥发性薰衣草精油能够极好地净化室内异味，并有天然的驱蚊、杀菌作用。','花朵晾干后可以制作薰衣草香草茶、糕点点缀，但盆栽观赏期不建议随意大量食用。','其精油具有公认的安神镇静、缓解焦虑、帮助睡眠以及轻度抗菌消炎的功效。','寓意浪漫、等待爱情、心心相印，在风水上有纯洁磁场、舒缓家庭紧张关系、赶走污浊之气的效果。','全日照阳台、露台、南向阳光房、室外庭院花境、有强直射光的南向窗台','排水良好的盆栽土','粗沙/珍珠岩:普通园土:泥炭土 = 3:2:1，或大量加入蛭石、陶粒，必须保证极佳的排涝和透气性','透气和排水性绝佳的红陶盆、瓦盆或多孔控根盆','口径15-25cm','每1-2年春季换盆一次',7.0,8.0,'hard','moderate',60,0,1,0,0,'/images/plants/lavender.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(13,'罗勒','九层塔、金不换、圣约瑟夫草、兰香','Ocimum basilicum','basil','唇形科','罗勒属','草本','一年生','观叶','亚洲、非洲等热带地区','罗勒是一种著名的药食两用芳香草本植物。叶片对生，呈卵形，质地柔嫩，色泽鲜绿，全株散发出类似茴香、丁香和薄荷交织的强烈辛香气味。它是西餐（特别是意大利青酱）和三杯鸡等料理中不可或缺的顶级调味香草，同时也非常适合盆栽于厨房明亮处。','芬芳浓郁，随摘随吃的三杯鸡与意面经典意式香草。','卵形至卵状长圆形，全缘或有疏锯齿，叶面常有轻微的凸起波纹','鲜绿色、亮绿色（紫罗勒品种则为深紫色）','直立，钝四棱形，多分枝，新枝常带绿色或略带紫色，具有强烈的芳香气','总状花序顶生，轮伞花序通常有6朵花，呈层状排列（故名九层塔）','白色、淡粉红色或淡紫色','7-9月','秋季','呈茂密的分枝丛生小灌木状，绿叶繁茂，花期时顶端抽出一塔塔精巧的小花，整体洋溢着浓浓的田园烟火气与生机。','bright_direct',5,8,'非常喜光。明亮充足的阳光直射能让其叶片肥厚、分枝茂密、芳香油分泌更旺盛。在稍有散射光的窗边也能生长，但容易徒长且香气会变淡。','frequent',2,5,'罗勒叶片多而柔嫩，蒸发量大，不耐干旱。生长期需保持盆土湿润，表土变干就要立即浇透水。夏季高温时需大幅增加浇水频率，切勿让土壤彻底干透。','喜湿忌干','每2-4天1次','每1-2天1次（根据暴晒程度，需确保水能从盆底快速流出）','每3-5天1次（随降温逐渐减少）','每7-10天1次（北方有暖气房内需视干燥度而定，控水保暖）','严忌盆内长期存水造成死水闷根，同时切勿在正午烈日当头时用冷水直接淋浇盆土','普通的室温自来水即可','medium','对空气湿度要求中等，喜略微湿润、空气对流良好的环境，不耐极度干燥，更怕长期闷热高湿。',18,32,10,38,0,'朝南明亮厨房窗台、阳台、明亮窗边、露台、阳光房','喜温暖湿润、阳光充足环境，不耐寒，怕干旱，忌积水，喜疏松肥沃、排水通畅的酸性或中性沙质壤土。','极其喜温暖、耐高温，原产热带。生长适温为18-32℃。极度畏寒，秋末气温低于10℃时会停止生长，遭遇霜冻会瞬间整株枯萎冻死。','平衡20-20-20','biweekly','由于经常采摘叶片食用，对养分需求较大。生长期每两周施用一次稀薄的氮磷钾平衡有机肥或观叶类水溶肥。由于是食用植物，建议优先使用安全有机肥。','春季和夏季','富含氮素的稀薄蔬菜专用肥或发酵饼肥水，促进多长嫩叶','作为食用香草，通常不希望其开花，一旦发现花蕾应立即摘除（打顶），无需施用促花肥',1,'忌施未腐熟的生肥或过浓的化学肥料，采收叶片前一周内停止施肥','下部老叶发黄变薄、整株茎干细弱、叶片变小、风味香气变差','全年生长季（结合采收进行）','频繁进行“打顶摘心”，剪掉各分枝的顶端嫩芽，以及随时摘除刚冒出的花蕾','在主干或分枝的第2-3对叶片上方用指甲掐断或用剪刀剪断。频繁打顶能促使其腋芽爆发，让1株变10株，株形更爆盆','开花后植物会将养分全部集中用于结实，导致叶片老化变硬、失去风味，因此见花必剪是最大铁律','{\"fall\": \"秋末气温低于15℃时长势大幅减缓。需将其移入室内保暖。如果任其留在室外，遭遇第一场寒流就会彻底枯死。\", \"spring\": \"播种或买苗的最好时期。给予充足散射光并逐渐过渡到直射光，保持盆土湿润，开始频繁打顶促销分枝。\", \"summer\": \"罗勒的黄金爆发期。极其耐热，只要供水充足、通风良好，晒太阳越多长得越疯狂。可以高频采摘叶片做菜。\", \"winter\": \"一处暖气且阳光充足的室内，可严格控水停肥，作为多年生继续维持其生命。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"叶片上出现白色或黄色的弯曲线条，或叶背有微小红点\", \"treatment\": \"将受损严重的叶片直接摘除扔掉。可用稀释的印楝油（天然环保杀虫剂）或肥皂水喷洒驱杀\"}], \"diseases\": [{\"name\": \"粗倒病\", \"cause\": \"主要是播种过密、盆土长期潮湿、环境不通风或者空气湿度连续过高感染真菌\", \"symptom\": \"幼苗基部呈水渍状变软倒伏；或成株叶片背面出现灰色霉层，叶面产生黄斑\", \"treatment\": \"作为食用香草不建议盲目喷洒化学农药。应立即拔除病株，全盆彻底严格控水，并移到阳光暴晒、极度通风的地方\"}], \"prevention\": \"保持植株内部修剪合理通风、多晒太阳，每次浇水摸一下土，土干再浇，严防土壤稀烂。\"}','无毒','无','全株完全无毒，是世界著名的安全安全食用调味草本植物','对猫狗及儿童绝对安全。猫咪偶尔啃食罗勒叶不会造成任何毒性危害，但其浓烈的气味通常会让大多数猫狗主动避开。','{\"leggy\": \"放在光照不足的室内阴暗处，导致茎干变得又长又细、弱不禁风，且叶片之间的间距变得极宽，香气极度变淡。\", \"noBloom\": \"罗勒只要长到一定大小且光照充足就会非常容易开花，但由于开花会降低叶片风味，养殖者通常应主动阻止其开花。\", \"drooping\": \"叶片干瘪耷拉通常是由于极度干旱缺水引起的，只要及时浇透水，通常在半小时内就能神奇地恢复坚挺挺拔。\", \"mainTaboo\": \"任由其开花不修剪、秋冬天留在室外受冻以及盆土积水导致根部死掉。\", \"beginnerTip\": \"舍不得摘叶子吃，任由它往上长，结果它很快就开花结子，然后整株植物就老化、干枯、寿终正寝了。\", \"yellowLeaves\": \"最常见原因是土壤长期处于泥泞积水状态导致闷根发黄；其次是秋季降温受冻发黄，或者长期缺水引起底层老叶干黄。\"}','绿意盎然，丛生茂密，具有浓浓的北欧式或地中海式厨房田园风格。','全株散发的挥发性精油具有极佳的清新空气、消灭厨房异味以及驱赶蚊蝇的作用。','顶级西餐和亚洲料理调味香草。可制作经典的意式青酱（Pesto）、搭配玛格丽特披萨、意面、台湾三杯鸡或九层塔炒蛋。','在传统草药学中具有健胃消食、疏风解表、行气活血和轻度抗菌的功效。','在许多文化中被视为“神圣之草”，象征着好运、健康、财富和家庭和睦。','南向明亮厨房窗台、阳光阳台、露台边、办公室明亮窗边','排水良好的盆栽土','腐叶土:普通园土:粗沙/珍珠岩 = 3:2:1，可适量混入腐熟的鸡粪或蚯蚓粪作为基肥','普通塑料盆、红陶盆或树脂长条种菜盆均可','口径15-25cm（根据株型，罗勒根系生长较快，宜选稍大的盆）','一年生香草通常无需换盆，直接从小苗养到成熟采收即可',6.0,7.0,'easy','fast',50,1,1,1,0,'/images/plants/basil.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(14,'蝴蝶兰','蝶兰、台湾蝴蝶兰','Phalaenopsis spp.','orchid','兰科','蝴蝶兰属','草本','多年生','观花','亚洲热带及亚热带雨林','蝴蝶兰是一种多年生常绿附生草本兰花。其花茎长而弯曲，花朵盛开时形如成群飞舞的蝴蝶，姿态优美高雅，被誉为“洋兰皇后”。它没有传统的土壤根系，而是依靠肥厚的肉质气生根附生于树干或岩石上，吸收空气中的水分和养分，是年宵花卉的绝对明星。','洋兰皇后，花形似蝶、高贵典雅的附生花卉。','椭圆形、长圆形或倒卵状长圆形，质地肥厚革质，全缘','深绿色，部分品种叶背略带紫色或有斑纹','茎极短，常被叶鞘所包裹；具多数粗壮、扁平、灰绿色的肉质气生根','总状花序或圆锥花序自叶腋抽出，花瓣展开，侧瓣大，唇瓣三裂，形状极似蝴蝶','纯白、粉红、紫红、黄、交织斑纹等极多园艺色','春节前后（1-4月） / 控温良好可长达2-3个月','少见','几片肥厚的绿叶伏于基部，长长的花梗优美地向一侧低垂弯曲，一串如蝴蝶般精致的花朵依次排列绽放，风姿绰约，极具华丽感。','medium',3,5,'喜半阴的明亮散射光。非常畏惧强光暴晒，烈日会导致叶片瞬间灼伤变白变黑；但长期过于阴暗会导致其无法分化花芽和开花。','weekly',7,10,'蝴蝶兰常用苔藓或水苔栽培，这类基质保水力强。浇水需看基质和气生根的颜色：当水苔表面变干、暴露出的气生根由翠绿变白发灰时，即为浇水信号，需彻底浇透。冬季低温需严格控水。','见干见湿','每5-7天1次','每3-5天1次','每7-10天1次','每10-14天1次，保持基质微潮偏干即可','严忌普通盆栽土栽种、严忌水苔长期湿漉漉泥泞、严忌将水灌入叶心或长期滞留在花瓣上，极易引发烂心和掉花','晾置过夜的室温自来水或纯净水','high','原产热带雨林，对空气湿度要求很高，理想湿度为60%-80%。干燥季节需高频向叶片周围喷雾或使用加湿器。',18,28,15,32,0,'客厅茶几、玄关、书房明亮处、办公桌、无阳光直射的窗台内侧','喜温暖、高湿、半阴环境，忌烈日暴晒，极不耐寒，不耐干旱，严忌普通泥土栽种，喜透气极佳的附生基质。','喜温暖、多湿环境，极不耐寒。越冬温度必须在15℃以上，低于10℃会停止生长并易受冻引发落蕾、烂叶。','平衡20-20-20','biweekly','兰花喜薄肥。生长期每两周施用一次极其稀薄的液肥（浓度建议为普通植物的1/4），遵循“薄肥勤施”原则。花期、盛夏酷暑和冬日寒冷期必须完全停肥。','春季和秋季','极其稀薄的平衡型水溶肥，促长新叶和新根','秋末冬初花芽分化期，可连续施用2-3次高磷钾肥促进花葶抽出',1,'极忌浓肥、生肥，严禁直接将固体颗粒肥丢在水苔上','叶片薄弱发软、失去光泽，长期不抽新叶，花芽分化期无花葶抽出','春季','花朵完全凋谢后剪除残花梗、修剪空心发黑的腐烂老根、剪除干枯发黄的底层叶片','如果想让其年内再次开花，可从花梗基部往上数第3-4个节位上方平剪；若想让植株彻底休息，则从花梗基部直接全剪断。修剪老根时需使用酒精消毒过的剪刀','严禁在花蕾孕育期修剪，修剪完根系后2-3天内严禁大量浇水','{\"fall\": \"秋季是花芽分化的关键期。此时日夜温差若能达到10℃左右，最利于孕蕾。适度增加光照，施用高磷钾肥促花，控制浇水。\", \"spring\": \"春季是蝴蝶兰的花盛期与花后修剪期。花谢后及时剪掉花梗、换水苔。随气温回升，气生根开始抽新根，恢复正常浇水与极薄肥水。\", \"summer\": \"严防酷暑与暴晒。必须移至最阴凉、空气对流极好的散射光处，多向周围喷雾降温，水苔不干不浇，严防高温闷烂气生根。\", \"winter\": \"绝对防寒保暖。室温低于15℃需采取套袋等保温措施。控制浇水，水温需与室温一致，盆土保持微干，给予其充足的室内温和阳光。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"叶片背面、叶腋深处出现白色蜡质盾壳状害虫\", \"treatment\": \"用软毛刷或酒精棉球人工刷除，数量多时喷洒蚧必治或阿维菌素\"}], \"diseases\": [{\"name\": \"软腐病\", \"cause\": \"空气湿度过高、浇水灌入叶心无法蒸发、环境闷热且不通风导致细菌滋生\", \"symptom\": \"叶片上产生水渍状病斑，迅速蔓延软化腐烂，并伴有恶臭\", \"treatment\": \"立即用消过毒的刀片切除病变叶片，并在伤口处涂抹多菌灵粉末或草木灰，全盆断水，移到干燥通风处强力通风\"}], \"prevention\": \"核心在于营造“高空气湿度+强通风空气对流”的协调环境，浇水切勿淋心。\"}','无毒','无','全株完全无毒，极其安全','对猫狗及儿童绝对安全。虽然猫咪啃咬其花瓣不会中毒，但会彻底破坏昂贵的观赏价值，建议放置在宠物无法攀爬的茶几中央或高架上。','{\"leggy\": \"长期缺乏明亮散射光，导致叶片抽长、变薄、颜色变浅并丧失硬挺度，极难抽出花葶。\", \"noBloom\": \"90%是因为秋季花芽分化期时光照不足、养分不够（缺少磷钾肥），或者缺乏合理的日夜温差刺激。\", \"drooping\": \"叶片像垂头鲨一样发软低垂、起皱纹，主要由两种极端情况引起：一是长期不浇水导致基质彻底干透脱水，二是浇水太多导致气生根全部烂死。\", \"mainTaboo\": \"使用普通泥土栽种、积水闷根、低温冻害、烈日暴晒。\", \"beginnerTip\": \"买回家后像对待普通盆栽一样，把它连同塑料盆种进厚重的泥土里，并天天给它浇水，结果花没开完根就全烂了。\", \"yellowLeaves\": \"最常见是水苔长期过湿闷根导致根系腐烂，进而叶片发黄变软；或者是冬季气温太低发生冻害发黄，以及盛夏强光灼伤。\"}','公认的高端室内观赏花卉，花形华丽贵气，色彩缤纷，极具节日喜庆和高雅的艺术审美价值。','与其他CAM植物类似，能在夜间吸收二氧化碳，对室内的有害气体有微弱的过滤作用。','无食用价值','无家庭药用价值','寓意“鸿运当头”、“幸福美满”、“仕途顺畅”、“吉祥富贵”，是新春佳节、开业、乔迁的最佳风水迎祥花卉。','客厅茶几、大堂前台、会议室、玄关大位、高档会所','排水良好的盆栽土','优质水苔:树皮/松针:高岭土 = 3:2:1，或直接使用100%纯水苔包裹根系','底部和侧面多孔的透明塑料营养盆（便于观察根系健康与颜色）外加美观瓷盆','口径10-15cm（兰花喜紧凑环境，切忌用大盆）','每1-2年春季花谢后，更换一次老化腐烂的水苔基质',5.5,6.5,'hard','slow',50,1,0,1,0,'/images/plants/orchid.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(15,'竹芋','孔雀竹芋、飞羽竹芋、双线竹芋、青苹果竹芋','Calathea spp.','calathea','竹芋科','肖竹芋属','草本','多年生','观叶','巴西等南美洲热带雨林','竹芋（以孔雀竹芋为例）是一种著名的多年生常绿草本植物。其叶片宽大肥厚，最引人注目的是叶面上具有大自然造化般的奇特斑纹，如同孔雀开屏的尾羽，色彩交织，绚丽夺目。它具有独特的“睡眠运动”生理特性：白天叶片展开，夜晚叶片则会直立折叠合拢，是室内高端观叶植物的杰出代表。','叶纹如画，夜间叶片自动闭合的喜阴高湿雨林精灵。','卵状椭圆形或长圆形，全缘，叶面平展光滑，由长叶柄自基部抽出','叶面主色为翠绿或黄绿色，沿侧脉整齐排列着羽状排列的暗绿色斑块，叶背通常为高贵奢华的紫红色','地上无明显主茎，根茎短而肉质化，小叶丛生','穗状花序从叶丛基部抽出，小花通常被苞片包裹，室内盆栽极罕见开花','白色、淡紫色或黄色','冬季至春季 / 极少开花','无','呈紧凑、丰满的丛生状。白天整株叶片层叠舒展，露出斑斓的叶面；夜晚叶片全部挺拔直立包裹在一起，极其奇特有趣。','low',2,4,'高度耐阴。最喜柔和的明亮散射光或半阴环境。绝对不能承受哪怕是一小时的烈日直射，强光会瞬间将叶片晒焦。','frequent',3,5,'叶片巨大，水分蒸发较快，且其肉质根系不耐干旱。生长期必须保持盆土充沛湿润（但非大水淤积），只要表土干下去1厘米就必须立刻浇透水。','喜湿忌干','每3-5天1次','每2-3天1次，早晚高频喷雾','每4-6天1次','每8-12天1次，严格控水防冻闷根','严忌盆土干透开裂、严忌长期大水死水淤积烂根、严忌在阳光能直射到叶片时朝叶面喷水','建议使用纯净水、雨水，或自来水晾置至少48小时后使用','high','对空气湿度要求严苛，理想湿度需在70%以上。室内空气干燥是导致其叶缘焦枯的罪魁祸首。需每天向叶面及周围狂喷水雾或常开加湿器。',18,28,12,32,0,'客厅无直射光的北侧角落、书房阴凉处、洗手间、明亮北向卧室、无日照的玄关','喜温暖湿润、强半阴环境，极畏惧强光直射，极其不耐干旱，不耐寒，喜疏松肥沃、排水极佳的微酸性腐殖土。','喜温暖舒适，原产雨林底层。最适生长温度为18-28℃。不耐严寒，冬季越冬室温需维持在12℃以上，低于10℃极易冻伤落叶。','平衡20-20-20','biweekly','喜薄肥。春夏生长期每两周施用一次极其稀薄的观叶类复合液肥（浓度减半）。主要补充氮肥维持叶片。当气温高于32℃或低于15℃时，需完全停止施肥。','春季和秋季','稀薄的氮磷钾平衡有机肥或高氮观叶水溶肥','不以观花为主，无需促花肥',1,'极忌浓肥、生肥，严禁秋末降温后追肥，极易引发烧根萎蔫','新长出的叶片斑纹颜色暗淡、模糊、小叶柄细弱易倒伏','春季','随时剪除底部干枯、老化发黄的老叶，以及修剪焦边严重破坏美观的叶片','用剪刀顺着叶柄直达根茎基部平剪断。如果是局部小面积叶尖枯焦，可顺着叶片天然弧度斜剪掉焦边','无特殊修剪禁忌，修剪残老叶有利通风，但修剪时勿伤及中心刚抽出的螺丝卷状新叶芽','{\"fall\": \"秋季空气极其干燥，要重点保证空气湿度，喷雾不能停。秋末随气温下降拉长浇水间隔，停止施肥，让叶片组织充实。\", \"spring\": \"换盆、分株的黄金期。将密集的肉质根茎轻轻掰开分盆。随着新叶疯狂抽出，增加浇水与薄肥，保持强半阴。\", \"summer\": \"竹芋的危险期。高温易使其生长停滞。必须搬到家里最阴凉、北面最通风的地方，每天开加湿器或高频喷雾，绝不能断水。\", \"winter\": \"防寒第一要务！必须移入12℃以上的温暖房间。严格控制浇水，盆土不干不浇，防止低温加水湿引发烂根。暖气房内需远离暖气片。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"空气干燥时极易发生。叶背出现细密碎尘状红点，伴有小蛛网，叶片失绿并大面积卷曲干枯\", \"treatment\": \"用大量纯净水高压淋洗叶背，或喷洒联苯肼酯等专业杀螨剂\"}], \"diseases\": [{\"name\": \"叶枯病/烂根\", \"cause\": \"土壤长期积水不透气导致闷根烂根，或环境闷热不通风导致真菌感染\", \"symptom\": \"叶片边缘开始大面积发黑溃烂、并向内蔓延，整丛叶柄变软倒伏腐烂\", \"treatment\": \"剪掉所有受损叶片，脱盆修剪掉黑烂根系，用多菌灵浸泡后更换轻质新土，并控制浇水并改善通风\"}], \"prevention\": \"常年营造高空气湿度并严防盆土积水，保持室内优良的空气自然对流。\"}','无毒','无','全株完全无毒，极其安全','对猫、狗及儿童绝对安全。由于其叶片宽大肥美、夜晚会动，极易吸引猫咪抓挠玩耍，建议放在猫咪上不去的矮凳或架子上。','{\"leggy\": \"在完全没有光线的极端阴暗密闭处，新叶斑纹会大幅褪色变浅，叶柄变得细长瘦弱且容易倒伏。\", \"noBloom\": \"室内养护由于缺乏雨林底层微环境，几乎终生不会开花，这完全属于正常的生理现象，无需担忧。\", \"drooping\": \"如果白天叶片依然严重卷曲、低垂无力，通常是极度缺水脱水或者根系已经全部烂死、丧失吸水功能的红灯信号。\", \"mainTaboo\": \"烈日暴晒、空气极度干燥、自来水直接浇灌以及花盆积水。\", \"beginnerTip\": \"把它放在阳光直射的南阳台上，且嫌麻烦直接用刚放出来的自来水浇，不到三天整盆叶子就会全部焦枯卷死。\", \"yellowLeaves\": \"最典型的是叶子边缘“焦边、枯黄”，100%是空气湿度太低干燥所致；若整片叶子发黄萎蔫，则是浇水过多导致烂根闷根，或自来水太硬氟中毒。\"}','公认的室内高级观叶网红。叶纹精美如艺术画作，睡眠运动极其奇特。','叶片宽大，具有优秀的吸附空气浮尘、净化室内甲醛和二氧化碳的能力，其高蒸腾率能像天然加湿器一样改善空气湿度。','无食用价值','无家庭药用价值','寓意“绚丽多彩”、“转机”、“前程似锦”。由于其夜间合拢白天张开，有调和阴阳、聚气生旺的作用。','客厅北侧阴凉角、明亮书房、高档洗手间、北向卧室、办公室无直射光处','排水良好的盆栽土','泥炭土:腐叶土:珍珠岩 = 2:2:1，可适量混入少量粗沙或椰糠','透气性好且大小适中的陶盆、艺术塑料盆或浅口花盆','口径15-25cm','每年春季换盆、换土一次',5.5,6.5,'hard','moderate',60,1,0,1,1,'/images/plants/calathea.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(16,'天堂鸟','鹤望兰、鹤之王','Strelitzia reginae','bird-of-paradise','旅人蕉科','鹤望兰属','木本','多年生','观叶','非洲南部','天堂鸟是一种著名的常绿多年生草本植物（在室内常长成高大木本质感）。市场上作为大型客厅绿植的多为“尼古拉鹤望兰”（大天堂鸟），其叶片巨大如芭蕉，挺拔大气。它以极具热带雨林风情和现代极简质感而闻名，是室内大型植物的首选之一。','巨叶挺拔如蕉，充满北欧及热带雨林风情的高大家居网红。','长圆形至卵状披针形，极巨大，形似芭蕉叶，革质全缘，叶柄极长且粗壮','灰绿色、深绿色，表面带有一层淡淡的蜡质白霜','无明显的地上主茎，长长的叶柄自肉质化肥大的地下根茎中挺拔抽出','总花梗与叶等长，佛焰苞舟状，花被片狭长伸展，形似一只正欲展翅飞翔的五彩仙鹤（室内大天堂鸟极难开花）','大天堂鸟为黑白/蓝白色；小天堂鸟为极其鲜艳的橙黄色与天蓝色交织','10月-翌年3月 / 室内盆栽通常需养护数年且光照极佳、通风好才偶尔开花','少见','体型高大宏伟，巨大的叶片从中心向两侧扇形展开，线条刚健挺拔，极具视觉冲击力和热带奢华格调。','high',5,8,'非常喜光。最喜充足明亮的散射光和柔和的直射光。充足的阳光能让叶柄短壮、叶片肥厚不倒伏。虽较耐半阴，但长期昏暗叶柄会过度拔高且变得脆弱易折断。','weekly',7,10,'天堂鸟拥有极为粗壮肥大的肉质根，能储藏大量水分，因此具有一定耐旱性，但极其害怕土壤积水死水。浇水严格遵循“见干见湿”，等盆土表层往下4-5厘米彻底干透后再浇透。冬季低温期生长基本停滞，需严格控水，保持土壤偏干状态。','见干见湿','每周1次','每周1-2次','每10天1次','每15-20天1次，盆土干透再浇一点','严忌频繁给水导致盆土长期处于泥泞泥浆状态，这会导致粗壮的肉质根缺氧迅速彻底腐烂','晾置过的普通室温自来水','medium','对空气湿度要求中等，喜略微湿润，但由于叶片有厚革质且带白霜，能比竹芋更好地耐受北方普通的室内干燥环境。干燥季节可经常擦拭叶面或适当喷水。',18,30,8,35,0,'明亮客厅落地窗旁、大堂角落、沙发旁、书房大窗边、阳光房','喜温暖湿润、阳光充足环境，怕干旱，极忌积水闷根，不耐寒，喜深厚肥沃、排水极佳的疏松酸性或中性沙质壤土。','喜温暖湿润，生长适温为18-30℃。不耐严寒。冬季越冬室温需保持在8℃以上，低于5℃极易发生严重的冻害烂根和大面积落叶。','平衡20-20-20','biweekly','天堂鸟体型巨大，长势较快，属于喜肥植物。春夏秋生长期每两周施用一次稀薄的复合液肥或观叶类无机水溶肥。由于以观叶为主，可选择氮钾平衡的肥料。盛夏超过35℃或冬季低于15℃时必须全面停肥。','春季和夏季','稀薄的氮磷钾平衡水溶肥，或在盆土表面定期埋入长效复合缓释肥颗粒','针对小天堂鸟老株，在秋季促花期可连续喷施2次稀薄的磷酸二氢钾促进花芽萌发',1,'忌施未腐熟生肥或过浓的化学肥料，秋末降温后严禁施肥','新长出的叶片变小变薄、叶色发黄发淡、生长极慢且主叶柄无力软塌','春季','剪除底部干枯、老化发黄的老叶，随时修剪受损破裂严重的叶片，剪除发生黑斑的病叶','用锋利的快刀从发黄老叶的叶柄基部平整割断。由于其蕉叶巨大，天然风吹或干燥容易导致叶片沿侧脉发生开裂，如果不严重，无需理会，保持自然美即可','修剪大老叶时动作要轻，切勿伤及中心正中央刚挺拔抽出的锥形新叶主轴','{\"fall\": \"秋季空气转凉，逐步拉长浇水间隔，停止施肥。尽量让其多晒温和的秋季阳光，充实叶柄组织，提高冬季抗寒抗冻力。\", \"spring\": \"换盆、修剪的最好黄金期。随着气温回升新芽萌动，将其移到阳光充沛处，逐渐增加浇水与肥水，多晒温和阳光。\", \"summer\": \"耐热，在室内阳光下一般不需要特意遮阴，但如果放置在烈日直射的南阳台需适当防晒。核心是必须保持环境极佳的空气对流，严防湿热闷根。\", \"winter\": \"防寒重中之重。必须进屋保暖，室温控在8℃以上。严格控制浇水，盆土不干不浇。定期用湿布擦拭其巨大的叶面，清除灰尘，提升室内的观赏价值。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"在巨大叶片的背面、或者叶柄包裹的叶腋深处聚集白色蜡质硬壳小虫，吸食汁液\", \"treatment\": \"用酒精棉球逐个擦拭掐死，或喷洒杀扑磷、蚧必治稀释溶液\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"花盆过大且不透气，土壤排水差，频繁浇水导致盆土长期处于黏重积水死水状态感染真菌\", \"symptom\": \"叶片大面积发黄、干枯、主叶柄变软无力倒伏，拔出后发现肥大的肉质根变黑腐烂中空\", \"treatment\": \"立即脱盆，用利刀切除所有变黑腐烂的肉质根，伤口大量涂抹多菌灵粉末晾干两三天，更换全沙质透气新土和多孔新盆重新栽种，严格断水控水\"}], \"prevention\": \"核心在于控制浇水，常年坚持土不干透绝不浇水，并始终保持居家养护环境通风良好。\"}','微毒','全株汁液、种子','汁液中含有一定量的植物碱和刺激性成分，皮肤接触可能引发轻微过敏，误食可能导致口腔不适、恶心、呕吐和腹泻','对猫狗及儿童有毒。由于其叶片巨大且高大，猫狗不易大量误食，但仍需注意防止宠物抓咬长长的叶柄或啃食掉落的叶片。','{\"leggy\": \"长期摆放在缺乏阳光的完全阴暗角落，导致新抽出的叶柄为了找光而过度拔高、变得极度细长瘦弱，且巨大叶片容易因头重脚轻而折断、倒伏。\", \"noBloom\": \"市场上最常见的高大“大天堂鸟”在室内盆栽环境下由于空间和热带阳光积温限制，几乎99.9%一辈子都不会开花，主要作为大型观叶植物。只有矮小的小天堂鸟在温室或阳光极好的露台养护多年后才会开出开开花。\", \"drooping\": \"巨大的叶片向外翻、软塌下垂、失去挺拔感，多为根系腐烂无法输送水分，或者由于长期极度缺水、气温骤降冻伤所致。\", \"mainTaboo\": \"频繁浇水导致盆土长期死水、花盆托盘积水以及冬季遭遇5℃以下的低温暴击。\", \"beginnerTip\": \"以为它长得像芭蕉树就很喜欢水，每天有事没事就往盆里倒水，结果不到两个星期它强壮的肉质根就全部烂成臭泥，整株植物软塌死掉。\", \"yellowLeaves\": \"90%以上是由于频繁浇水、盆土积水导致地下肥大的肉质根受损腐烂，导致叶片发黄；或者是遭遇了冬季低温冻害发黄，以及长期不浇水导致的底层老叶干黄。\"}','体型高大挺拔，巨叶充满浓郁的南美热带雨林格调与奢华的北欧极简质感，是提升现代大客厅、商业软装空间档次的大型绿植。','巨幅叶片能如同天然吸尘器般高效吸附室内的漂浮粉尘，净化室内大量的甲醛、苯及二氧化碳，并具有优秀的湿度调节能力。','无食用价值','无家庭药用价值','名字带有著名的“鹤望兰”，寓意自由、幸福、长寿、大吉大利，在风水学上有强大的镇宅辟邪作用。','客厅电视柜旁、明亮大落地窗边、沙发拐角处、办公室老总位、高档店铺大堂、展厅','排水良好的盆栽土','腐叶土:泥炭土:园土:粗沙 = 2:2:2:1，由于其肉质根系极为粗壮发达，土壤必须混入足量沙质颗粒确保排水通畅，盆底需垫一层陶粒作为排水层','体型巨大，宜选用厚重大号的水泥盆、大号陶盆或高档北欧风塑料深盆以防头重脚轻倒伏','口径30-50cm（由于其根系呈爆炸式生长，必须选用大而深的花盆）','每1-2年春季换盆、换土一次',6.0,7.0,'easy','moderate',250,1,1,0,1,'/images/plants/bird-of-paradise.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(17,'佛珠','珍珠吊兰、绿之铃、情人泪','Curio rowleyanus','string-of-pearls','菊科','千里光属','肉质','多年生','观叶','非洲西部纳米比亚等干燥地区','佛珠是一种非常独特的多年生常绿多肉植物。其最显著的特征是细长柔弱的蔓生茎上，密生着一颗颗饱满圆润、形似珍珠或佛珠的肉质叶片。每颗“珍珠”上都有一条半透明的纵向条纹（称为“叶窗”），用以聚集光线。非常适合作为悬垂盆栽，如同一道绿色的珍珠瀑布。','圆润如珠，低垂如瀑的浪漫悬垂多肉。','球形、卵圆形，肉质肥厚，先端有微尖头，上有半透明纵向窗孔','翠绿色、深绿色，表面带有微量白粉，光照充足时圆珠显得通透油绿','细长匍匐或下垂的肉质茎，极柔嫩，接触土壤的节位易生出不定根','头状花序，长花梗自叶腋抽出，花朵呈筒状开裂，雄蕊伸出花冠外','白色或淡粉色，带有独特的肉桂般清香','12月至翌年1月 / 室内条件适宜才开花','少见','细长的茎秆上挂满密密麻麻的翠绿圆珠，从盆沿自然垂落漂逸，如同精致的珍珠项链，整体风格灵动、精致且极具多肉趣味。','medium',4,6,'喜温暖湿润和明亮的散射光，较耐半阴。夏季高温时极忌烈日曝晒，否则圆珠易被灼伤萎缩变白；冬季则需充足的全日照。','rarely',10,15,'肉质圆珠能储存大量水分，极为耐旱。浇水遵循“宁干勿湿”，必须等盆土彻底干透再浇透。可以通过观察圆珠状态来判断是否缺水：当圆珠开始起皱、发软、失去光泽时，即为浇水信号。夏季半休眠期和冬季低温期需严格控水。','干透浇透','每10天1次','每15-20天1次，傍晚微量给水','每10天1次','每30天1次或断水，保持土壤彻底干燥','严忌盆土长期处于黏重潮湿状态，浇水时切勿从顶部直接劈头盖脸淋浇，圆珠间积水在高温下极易引发全株黑腐','普通的室温自来水即可','low','作为多肉植物，它喜干燥的空气环境。但与其他沙漠多肉相比，它在生长期能耐受略微湿润的空气，极忌夏季高温闷热高湿。',15,25,5,32,1,'朝南或朝东窗边、高柜顶部、悬挂吊阳台、书架边缘','喜凉爽干燥、明亮散射光环境，耐干旱，怕积水，忌高温闷热，怕寒冷，喜疏松肥沃、排水极佳的沙质壤土。','喜凉爽舒适环境，生长适温为15-25℃。不耐极端高温，盛夏气温超过30℃时会进入半休眠；不耐严寒，冬季越冬室温需保持在5℃以上防冻伤。','平衡20-20-20','monthly','佛珠对肥料需求中等。仅在春季和秋季生长期，每月施用一次极其稀薄的观叶类复合液肥。多施磷钾肥能让圆珠更圆润坚挺，夏冬两季完全停肥。','春季和秋季','稀薄的高磷钾、低氮多肉专用肥或稀薄饼肥水','冬初现蕾时可喷施一次极稀薄的磷酸二氢钾促进开花',1,'严忌施用浓肥、生肥，严禁在盛夏酷暑和冬季寒冷期追肥','圆珠长得稀疏、个头变小、斑纹暗淡、长长势极其缓慢','春季','剪除干枯发黑的藤蔓、修剪过长或稀疏的枝条，以及掰除发生腐烂的圆珠','用消毒剪刀在分枝节位上方平剪。剪下的健康藤蔓可以直接平铺在微潮的土面上，极易生根繁殖成新植株','避免在夏季极端闷热或伤口不易愈合的阴雨天进行修剪','{\"fall\": \"秋凉后迎来第二个快速生长期。恢复正常浇水，逐步增加光照，让珠子充实、变圆，增强越冬抵抗力。\", \"spring\": \"生长的黄金期。给予充足的明亮散射光，看圆珠状态干透浇透，可配合薄肥，让其藤蔓快速抽长挂果。\", \"summer\": \"佛珠的“危险期”。超过30℃进入半休眠，极易发生“黑腐”。必须彻底移到阴凉、全天候强通风处，拉长浇水间隔，坚决全面断肥，严禁淋雨。\", \"winter\": \"必须进屋保暖，温度维持在5℃以上。给予其全天候充足的室内阳光直射。严格控制浇水，保持盆土偏干，完全停止施肥。\"}','{\"pests\": [{\"name\": \"蚜虫\", \"symptom\": \"春季嫩梢或冬春花梗上易聚集绿色、黑色小虫吸食汁液，圆珠萎缩\", \"treatment\": \"用清水冲洗，或喷洒吡虫啉、阿维菌素稀释溶液\"}], \"diseases\": [{\"name\": \"黑腐病\", \"cause\": \"夏季高温高湿、盆土长期潮湿、环境密闭不通风导致真菌爆发\", \"symptom\": \"肉质圆珠突然变黑、化水、像被煮熟一样脱落，藤蔓基部变黑软烂\", \"treatment\": \"极难救治。一旦发生需立即彻底剪除变黑坏死的部分，将健康的枝条剪下、用多菌灵消毒晾干后重新扦插\"}], \"prevention\": \"控制浇水、管住手是养好它的铁律。夏季保持极端通风，严禁高温期盆土潮湿。\"}','微毒','全株肉质汁液','属于菊科植物，汁液中含有一定量的生物碱，皮肤接触可能引发皮炎红肿，误食会导致流涎、呕吐、腹泻和肠胃痉挛','对猫狗及儿童有毒。由于其悬垂的圆珠极像好玩的玩具，极易吸引猫咪和儿童抓咬误食。必须将其悬挂在高处，严防猫咪触碰。','{\"leggy\": \"长期缺乏明亮散射光，导致藤蔓节间距拉得极长，圆珠与圆珠之间排列极其稀疏，且圆珠变小变尖，失去饱满的珍珠感。\", \"noBloom\": \"室内养护由于光照积温限制和没有冬春冷凉温差刺激，较难开花，一般只作为多肉观叶悬垂植物栽培。\", \"drooping\": \"佛珠天然就是下垂生长的。但如果整盆圆珠失去弹性和硬挺度，软绵绵地垂挂，通常是根系已经彻底黑腐腐烂的信号。\", \"mainTaboo\": \"频繁浇水导致盆土长期潮湿、夏季高温高湿且密闭通风不良、烈日曝晒。\", \"beginnerTip\": \"觉得它长得像珍珠很漂亮，每天都有事没事往圆珠上喷水，结果不到两个星期整盆珠子就全部黑腐化水死光了。\", \"yellowLeaves\": \"圆珠发黄、化水多为浇水过多导致的黑腐烂根；若圆珠干瘪、起皱且失去光泽，则是长期极度缺水或夏季烈日暴晒灼伤。\"}','叶形绝妙奇特，圆润如珠，低垂时如同一挂绿色的珍珠垂帘，极具文艺、清新和现代家居的灵动美感。','多肉类植物，净化化学毒气能力较弱，主要用于室内的趣味观赏和微弱的绿化造景。','无食用价值','无家庭药用价值','圆润的珠子寓意“圆圆满满”、“事事顺心”、“合家团圆”，在风水上有柔化室内刚硬线条的作用。','客厅高柜顶部、悬挂吊阳台、书架边缘、明亮窗台侧面、无强光直射的朝东窗边','排水良好的盆栽土','泥炭土:多肉颗粒土 = 1:1，确保高透气排涝性，盆底垫好防积水层','透气性极佳的浅口红陶盆、瓦盆或悬挂专用的带孔塑料吊盆','口径12-20cm（盆宜浅不宜深，防底层土壤存水）','每1-2年春季换盆一次',6.0,7.0,'medium','fast',100,1,0,0,0,'/images/plants/string-of-pearls.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(18,'心叶蔓绿绒','心叶藤、青苹果蔓绿绒、吊藤心叶绒','Philodendron hederaceum','philodendron','天南星科','喜林芋属','藤本','多年生','观叶','中美洲、加勒比海地区热带雨林','心叶蔓绿绒是一种非常著名且极易养护的常绿攀援藤本植物。其叶片呈完美的爱心形，质地肥厚革质，表面油亮光滑，极具丝绒般的光泽。它的生命力、耐阴性以及攀援能力都极强，既可以作为吊盆悬垂垂吊，也可以设立棕柱向上攀援生长，常与绿萝混淆，但比绿萝更具高级感。','完美心形绿叶，耐阴且充满浪漫爱意的高级垂吊藤本。','完美的卵心形，基部深深心形凹陷，先端渐尖，全缘厚革质','深绿色、浓绿色，表面有强烈的油亮光泽，新叶常带有一丝高级的红褐色','蔓性藤本茎，绿色，触感柔韧，节间距整齐，节位极易抽出长长的气生根','佛焰苞花序，在室内家庭盆栽环境下几乎100%不会开花','白绿色、乳白色','极为罕见','无','枝蔓飘逸柔美，爱心形的叶片整齐对生垂挂，如同由无数颗绿色爱心串联成的浪漫门帘，整体株形丰满、极富热带风情。','low',2,5,'极耐阴，最喜明亮的散射光或半阴环境。能在昏暗的室内角落长期存活。严禁烈日暴晒，强光会导致其叶片变白、灼伤干枯并失去蜡质光泽。','weekly',5,8,'遵循“见干见湿”原则。等盆土表面往下2-3厘米彻底变干后再行浇透水。它具有较强的耐旱性，偶尔忘记浇水不会致死，但严忌盆土长期处于泥泞积水状态。冬季需严格控水，保持土壤微潮偏干。','见干见湿','每5-7天1次','每3-5天1次，可配合高频叶面喷雾','每7-10天1次','每12-15天1次，土不干透不浇','严忌花盆底部托盘积水不退，这会导致其肉质化的不定根迅速窒息烂根导致全株自下而上发黄脱落','晾置过的普通室温自来水即可','medium','喜略微潮湿的空气环境，对室内湿度的适应性比竹芋更广。北方干燥季节经常向其叶面喷水，能让爱心叶片更加油亮闪耀。',16,30,10,35,0,'客厅无直射光角落、明亮书房、书架顶部、洗手间、卧室明亮窗边、办公室隔断隔板','喜温暖湿润、半阴环境，生命力强健，极耐阴，忌烈日暴晒，怕积水烂根，耐干旱能力强于绿萝。','喜温暖舒适的热带气候。生长适温为16-30℃。不耐严寒，冬季室内越冬温度需保持在10℃以上，低于8℃极易引发大量冻伤落叶。','平衡20-20-20','monthly','对肥料需求中等。在春、夏、秋三季生长旺季，每月施用一次稀薄的无机观叶复合肥或平衡液肥即可。主要补充氮钾肥以促进藤蔓抽长和叶片油亮。冬季寒冷期生长缓慢，需全面停肥。','春季和夏季','稀薄的氮磷钾平衡水溶肥或高氮观叶专用营养液','观叶藤本，完全无需施用促花肥',1,'忌施浓肥、生肥，气温低于15℃或高于35℃时绝对不要施肥','新长出的爱心叶片明显变小变薄、叶色发淡发黄，藤蔓节间距变得极短','春季','随时剪除过长细弱的藤蔓、修剪底层发黄老化的叶片，以及剪掉枯死的气生根','用消毒剪刀在分枝节点下方1厘米处直接剪断。剪下的健康藤蔓只要带有2个以上的节点，可以直接水培或直接插在微潮的营养土中，极易成活','无特殊修剪禁忌，生命力极强，极耐修剪和折腾','{\"fall\": \"秋末逐步拉长浇水间隔，停止施肥，尽量让其多见阳光，充实藤蔓组织，提高冬季抗寒抗冻力。\", \"spring\": \"换盆、修剪、扦插繁殖的绝佳好时机。随气温回升逐渐增加浇水施肥，移到有温和散射光的朝东、朝北窗边。\", \"summer\": \"严防烈日暴晒以防叶片灼伤。将其移到阴凉通风的地方，保持土壤湿润，早晚多向其四周喷雾降温，切忌土壤过湿闷根。\", \"winter\": \"必须进屋保暖防冻，室温维持在10℃以上。严格控制浇水，盆土不干不浇，保持偏干。暖气房内需远离暖气设备。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"空气极度干燥时易发生。叶背出现细密红点或茎秆上出现褐色蜡质小点，叶片失绿\", \"treatment\": \"用温水高压淋洗叶片表面，或喷洒阿维菌素、蚧必治等稀释药剂\"}], \"diseases\": [{\"name\": \"根腐病\", \"cause\": \"花盆透气性差，盆土长期积水闷根，环境长期处于密闭不通风状态导致真菌感染\", \"symptom\": \"叶片突然大面积发黄、萎蔫下垂，藤蔓基部变软发黑变黏，拔出后根系变黑腐烂中空\", \"treatment\": \"立即脱盆，剪除所有黑烂根系和黄叶，用多菌灵消毒后更换疏松透气的新土重新栽种，严格控制浇水，移到强通风处\"}], \"prevention\": \"核心在于坚决管住手、土干再浇水，并始终保持居家养护环境拥有良好的空气流通。\"}','有毒','全株茎叶、汁液','天南星科植物，全株汁液中含有大量的针状草酸钙结晶以及毒性蛋白。皮肤直接接触汁液可能引发红肿、瘙痒与刺痛；误食会导致口腔、咽喉剧烈灼痛、流涎、舌头肿胀以及吞咽困难','对猫狗及儿童有毒。由于其悬垂的爱心叶片极易吸引猫狗抓咬，必须放置或悬挂在儿童和宠物绝对触碰不到的高处。','{\"leggy\": \"长期将其摆放在极度缺乏光线的黑暗处，导致茎干变得细长瘦弱、新长出的爱心叶片变得极小且稀疏，失去油亮感。\", \"noBloom\": \"室内附生栽培条件下几乎100%不会开花，主要作为常绿高级观叶植物观赏，属于完全正常现象。\", \"drooping\": \"叶片干瘪起皱、软绵绵下垂，通常是由于长期极度缺水干旱引起的，及时浇一次透水能快速恢复；若浇水后依然无法恢复，则是根系已经彻底腐烂死掉。\", \"mainTaboo\": \"频繁浇水导致盆土泥泞、盛夏酷暑烈日曝晒，以及冬季遭遇8℃以下的低温打击。\", \"beginnerTip\": \"买回家后觉得它跟绿萝很像就疯狂给它大量倒水，结果不到两个星期它高级的爱心叶片就全部闷根发黄、藤蔓烂成了一地酸臭的黏泥。\", \"yellowLeaves\": \"最主要原因是浇水过多闷根或托盘长期积水，导致根系无法呼吸发黄；其次是冬季气温骤降受冻发黄，或者长期缺水引起的底层老叶干黄脱落。\"}','经典的爱心形叶片饱满深绿，自带优雅、浪漫的情调，比普通绿萝更具高级的软装高级感，常作为极简北欧风垂吊绿化。','能极高效率地吸收室内的甲醛、苯、三氯乙烯、一氧化碳等装修化学毒气，并有效清除异味。','无食用价值','无家庭药用价值','心形叶片寓意“心心相印”、“家庭和睦”、“充满爱意”、“浪漫平安”，在风水上有促进家人感情、招财化煞的温馨植物寓意。','客厅高柜顶部、明亮书房架子、无直射光的卧室角落、洗手间窗台、办公室隔断','排水良好的盆栽土','泥炭土:腐叶土:珍珠岩 = 2:2:1，或者直接使用排水通畅的高品质通用营养土，盆底需做好排水层','吊盆（悬挂专用盆）、简约高脚瓷盆，或者带有椰棕柱向上攀爬的立式深盆','口径15-25cm','每1-2年春季换盆、换土一次',5.5,6.5,'easy','fast',200,1,0,0,1,'/images/plants/philodendron.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(19,'镜面草','中国钱币草、翠屏草、镜面花','Pilea peperomioides','chinese-money-plant','荨麻科','冷水花属','草本','多年生','观叶','中国云南、四川等西南地区高山潮湿林下','镜面草是一种我国特有的多年生常绿肉质草本植物。因其肥厚的叶片呈完美的正圆形，中央有一黄色叶心，形似古代女子梳妆用的圆镜或圆滚滚的古代铜钱，因而得名。它茎干直立，叶柄长而放射状散开。近年来在欧美软装界风靡一时，被形象地称为“中国钱币草”，极具东方古典韵味与现代极简几何美感。','正圆如镜，在欧美风靡一时的中国古典招财网红草。','完美的正圆形、盾状着生，厚革质略带肉质，表面光滑全缘','翠绿色、浓绿色，表面油亮，中央叶柄连接处有一点精致的淡黄色或淡绿色圆心','直立主干，短粗肉质化，随着年龄增长基部会逐渐木质化并变成灰褐色','雌雄异株，聚伞花序长梗自叶腋抽出，小花极细小如碎米，室内盆栽偶尔开花','绿白色、带有一丝淡粉色','4-5月 / 室内盆栽偶尔开花','少见','一根精巧的主干上，伸出无数条纤长有弹性的叶柄，顶着一枚枚正圆形的翠绿绿叶向四周呈伞状散射分布，株形奇特，极具平衡雕塑感。','medium',4,6,'喜充足明亮的散射光或柔和的半阴环境。较耐阴，但长期缺乏光照会导致叶片变薄且失去正圆的坚挺度。极忌盛夏烈日暴晒，强光会瞬间将圆叶灼伤、枯焦变黄。','weekly',5,7,'镜面草略带肉质，具有一定蓄水能力，但它并不属于典型的干旱多肉，依然喜湿润土壤。浇水遵循“见干见湿”，等盆土表面1-2厘米变干后立刻浇透水。切勿让盆土彻底干透太久，否则圆叶会迅速疲软下垂。冬季需适度控水，保持盆土微潮偏干。','见干见湿','每4-6天1次','每3-5天1次，加强空气对流','每5-7天1次','每10-14天1次，严格遵循不干不浇','严忌花盆内长期死水积水，这会导致肉质主干的地下根系迅速缺氧窒息腐烂，引发下部圆叶疯狂发黄脱落成光杆','晾置过的普通室温自来水即可','medium','原产我国高山林下，喜略微湿润的空气环境。耐干燥能力中等。在春季和夏季炎热干燥期，可高频向叶片周围喷水增加湿度。',15,26,5,32,0,'客厅茶几、明亮书桌、朝东或朝北窗边、办公桌台面、北向卧室台面','喜温暖湿润、半阴环境，抗逆性强，较耐寒，忌烈日暴晒，怕盆土干透，喜疏松肥沃、排水极佳的微酸性沙质壤土。','喜温暖湿润、凉爽舒适的环境，生长适温为15-26℃。不耐极端高温，盛夏超过32℃时长势减缓需注意通风。具有一定耐寒力，冬季越冬温度保持在5℃以上即可安全防冻伤。','平衡20-20-20','biweekly','喜肥。在春季和秋季生长期，每两周施用一次稀薄的观叶类平衡液肥（浓度减半）。主要补充氮肥促进新圆叶抽长，但注意配比平衡，若单施氮肥易引发徒长导致圆叶变薄易碎、叶色变淡。盛夏酷暑和冬日寒冷期生长缓慢，需完全停肥。','春季和秋季','稀薄的氮磷钾平衡复合液肥或高品质观叶植物营养液','不以观花为主，完全无需施用催花肥',1,'忌施浓肥、生肥，严禁在正午炎热或土壤彻底干燥时直接施用无机原液','新长出的圆叶个头严重缩水变小、整株圆叶边缘向内卷曲、叶面失去亮绿色泽、生长停滞','春季','随时剪除底层老化变黄的圆老叶，以及掰除过于拥挤的小侧芽进行分株繁殖','用消过毒的锋利剪刀紧贴直立茎干，将变黄叶柄平整剪断即可。基部萌发的小侧芽（带有独立根系）可以用刀小心割下，直接上盆即成新一株镜面草','修剪底部老叶时动作要慢，绝对严禁折断或损伤直立木质化的主干顶芽中心','{\"fall\": \"秋凉后迎来第二个快速生长期。逐步增加温和的光照，拉长浇水间隔，停止施肥，让茎干充实健壮，准备过冬。\", \"spring\": \"镜面草的黄金爆发期与换盆繁殖期。随着大量新圆叶从顶部抽生，确保充足的明亮散射光，干透浇透并恢复施薄肥，让其快速爆盆。\", \"summer\": \"严防酷暑烈日。必须移到家里最阴凉、空气对流极好的强半阴处，保证水分充足，早晚向叶面周围喷雾，严禁闷热积水。\", \"winter\": \"必须移入温暖室内保暖，越冬温度控在5℃以上。给予其全天候明亮的室内阳光直射。严格控制浇水，盆土不干不浇，停止一切肥水。\"}','{\"pests\": [{\"name\": \"介壳虫\", \"symptom\": \"空气过于干燥密闭且不通风时发生。叶片背面或长叶柄上易出现盾壳状小虫，导致叶面失绿起皱纹\", \"treatment\": \"用酒精棉球逐个擦拭掐死，数量较多时使用蚧必治、阿维菌素喷洒防治\"}], \"diseases\": [{\"name\": \"烂根\", \"cause\": \"花盆长期积水死水、盆土黏重不透气，或者使用了未腐熟生肥烧根引发真菌感染\", \"symptom\": \"下部圆叶成批干黄、脱落，主干基部变黑变软软塌，整株失去支撑力倒伏\", \"treatment\": \"立即脱盆，用利刀切除所有黑烂根系和主干坏死部分。若顶部主干依然健康，可涂抹多菌灵晾干两天后重新扦插\"}], \"prevention\": \"核心在于管住手、严禁频繁高频率浇水导致盆土形成烂泥，并始终保持居家养护环境通风良好。\"}','无毒','无','全株完全无毒，极其安全','对猫、狗及儿童绝对安全。由于其长长的叶柄顶着圆盘极其好玩，经常被猫咪当作玩具抓挠，虽然误食无毒，但会破坏完美的几何造型，宜放在稳固的台面中央。','{\"leggy\": \"长期将其摆放在缺乏光线的客厅内侧或昏暗死角，导致叶柄为了找光而发生严重的无限制伸长、拔高（俗称长成高脚镜面草），叶柄变得又细又长又软，最终无法支撑、整盆彻底软瘫低垂在盆沿四周，圆叶也缩水变小、变薄，失去蜡质层的油亮感。\", \"noBloom\": \"室内养护虽然偶尔在春季抽出长梗开出碎米般的小花，但由于花朵极小无观赏性，开花还会大量消耗养分，通常可主动剪除花梗。\", \"drooping\": \"叶柄失去弹性和支撑力、向四周软塌耷拉，多为彻底缺水脱水的前兆（及时浇透水半天内可恢复挺拔）；若浇水后一整天依然瘫软发黑，则是由于频繁大水根系已经彻底溃烂死掉。\", \"mainTaboo\": \"盛夏烈日暴晒、频繁频繁大水导致托盘积水，以及长期处于空气密闭密不透风的死角。\", \"beginnerTip\": \"买回家后觉得它像古代铜钱很讨喜，就天天给它拼命浇水并晒太阳，结果不到一个星期，圆圆的叶子就全部晒焦、烂根掉光了。\", \"yellowLeaves\": \"最普遍是由于频繁倒水导致土壤闷根发黄脱落；若圆叶边缘干枯焦黑，则是烈日暴晒或空气极度干燥引起的灼伤；若由于长期缺水，整盆圆叶会发软下垂，及时浇水可恢复。\"}','完美的正圆形盾状绿叶向四周散射，线条极具现代极简几何美感与东方古典茶道韵味，是近年来风靡全球的质感桌面绿植明星。','叶面光滑油亮，能有效吸收室内的甲醛、二氧化碳及微小灰尘，对室内空气有微弱的净化与调湿作用。','无食用价值','无确切家庭药用价值','在欧美被称为“中国钱币草”，寓意“财源滚滚”、“招财进宝”、“团团圆圆”、“好运连连”，是现代家居极佳的极品风水招财植物。','客厅茶几、明亮窗边、办公桌台面、独立小书桌、咖啡厅木质茶几、电视柜一侧','排水良好的盆栽土','腐叶土:泥炭土:珍珠岩/粗沙 = 2:2:1，可适量埋入腐熟的有机饼肥或粪肥作为基肥，要求高保水、高透气','质感素雅的小号红陶盆、白瓷盆或极简水泥盆，能极好烘托其几何美感','口径12-18cm（它喜欢紧凑的根系环境，盆切忌过大过深）','每年春季换盆、换土一次',6.0,6.8,'easy','moderate',40,1,0,1,1,'/images/plants/chinese-money-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-23 10:18:50'),(20,'仙人掌','仙巴掌、霸王树、观音掌','Cactaceae spp.','cactus','仙人掌科','仙人掌属','肉质','多年生','多肉','美洲热带及亚热带干旱沙漠地区','仙人掌是仙人掌科常绿肉质植物的统称。为了适应极端干旱的沙漠环境，其叶片已完全退化为刺，而肥厚多汁、形似手掌或球状的茎干则代替叶片进行光合作用并储藏大量水分。它极为耐旱、耐热、喜阳光，是生命力顽强的“懒人植物”代表。','退叶成刺、极度耐旱的沙漠生命奇迹。','退化为针刺、硬刺或棉毛状刺座，无传统意义上的阔叶片','刺多为黄色、白色或褐色；其肉质茎为翠绿色、深绿色或灰绿色','茎极其肥厚肉质化，分节，呈掌状、球状、柱状或长圆形，表面多具一层蜡质硬皮','花单生于茎节上部的刺座上，辐状钟形，花瓣重叠，色彩极为艳丽','黄色、橙色、红色、粉色或白色','6-8月 / 室内盆栽需要充足光照养护多年方可开花','秋季','形态千奇百怪，线条刚硬、奇特，整体呈现出一种充满异域沙漠风情与极简主义的几何雕塑美感。','bright_direct',6,12,'极端喜光。全日照植物，必须给予全天候高强度的直射阳光。极其不耐阴，长期缺乏阳光会导致其严重畸形徒长、变软并最终衰亡。','rarely',20,40,'体内储水极其丰富，是顶级的耐旱植物。浇水必须坚持“干透浇透”、“宁干勿湿”的铁律。盆土必须完全干透、甚至干到土壤开裂时再稍微浇水。冬季低温期必须彻底断水。','干透浇透','每20-30天1次','每15-20天1次','每25-35天1次','整个冬季完全断水、保持土壤绝对干燥','严忌频繁浇水和盆土长期潮湿，浇水时严禁直接淋浇在肉质茎及刺座上，积水极易导致局部黑腐化水','普通的室温自来水即可','low','极度喜干燥环境，非常害怕高湿闷热。室内养护无需任何喷水，必须保持空气常年极佳的流动和对流。',20,38,5,45,0,'全日照阳台、南向明亮窗台、阳光房、露台、光照极好的办公室台面','喜阳光充足、温暖干燥环境，极耐干旱，怕积水，极怕寒冷闷湿，喜排水极佳、透气通畅的沙质土。','极度耐高温和酷暑。最适生长温度为20-38℃。不耐严寒，冬季越冬室温需保持在5℃以上，低于0℃肉质茎极易被彻底冻伤溃烂。','平衡20-20-20','none','极其耐贫瘠，对肥料依赖度极低。仅在春季生长季，可随浇水追施1-2次极其稀薄的多肉专用高磷钾肥即可，切勿多施。冬夏两季严禁施肥。','春季','极其稀薄的高磷钾、低氮型多肉无机液肥','不以观花为主，一般无需使用促花肥',1,'严忌施用浓肥、未腐熟生肥以及过量的氮肥','除非土壤彻底无养分多年，通常无明显缺肥表现，长势变慢属于其正常生理特性','春季','剪除老化发黄、变软或遭遇病虫害的茎节，以及掰除过于拥挤、阻碍主干发育的侧芽','修剪时必须佩戴厚橡胶手套以防被刺伤。用消毒过的锋利刀片从茎节连接的狭窄处切除，伤口需涂抹多菌灵粉末，并保持彻底干燥，一周内严禁淋水','避免在冬季严寒或阴雨连绵、空气湿度极大的恶劣天气进行修剪','{\"fall\": \"秋季天气转凉，逐步拉长浇水间隔。让其接受充足的温和秋光，使肉质茎表皮角质化，增强冬季抗寒抗冻能力。\", \"spring\": \"复苏和生长期。将其移到阳光最猛烈处，随着气温回升缓慢恢复浇水，可追施一次极其稀薄的液肥。\", \"summer\": \"极其耐热。在室内无需任何遮阴，晒得越多茎干越硬挺、刺座越健康。核心是必须保持全天候强开窗通风，严防闷热。\", \"winter\": \"防寒重点。必须移入室内温暖处。整个冬季完全断水、彻底断肥，让其进入强迫休眠，阳光越多越好。\"}','{\"pests\": [{\"name\": \"盾蚧/介壳虫\", \"symptom\": \"肉质茎表面、凹槽处易聚集白色蜡质硬壳小虫，严重时茎表面布满粉白色斑点，吸食汁液\", \"treatment\": \"人工用竹签或旧牙刷人工小心刷除掐死，或喷洒蚧必治、杀扑磷稀释溶液\"}], \"diseases\": [{\"name\": \"黑腐病/茎腐病\", \"cause\": \"土壤长期积水死水、频繁频繁给水、使用了生肥，或在高温高湿且环境闷热密闭下感染真菌\", \"symptom\": \"肉质茎基部或表面突然变黑、变软、化水，轻轻一按就流出酸臭的汁液，整株软倒\", \"treatment\": \"极难挽救。一旦发生，需用消毒利刀彻底切除变黑坏死的部分直至露出完全绿色的健康组织。伤口涂满多菌灵在阴凉干燥处彻底晾干一周，直至伤口形成干燥的皮层后，再插入全新的全沙质干燥土中重新分株扦插生根\"}], \"prevention\": \"核心在于常年管住手、少浇水，保持盆土彻底干燥、环境常年维持绝佳的空气流通。\"}','无毒','无','全株完全无毒。但其表面密布的坚硬植物针刺具有极强的机械性物理伤害，扎入皮肤会引发红肿、刺痛甚至发炎','对猫、狗及儿童有严重的物理伤害风险。虽然肉质无毒，但细小的钢刺极易扎伤儿童和宠物的皮肤、眼睛及口腔。必须摆放在高处或独立安全的防触碰区域。','{\"leggy\": \"长期摆放在阴暗角落，导致肉质茎为了找光而发生严重的畸形发育（尖头徒长）：原本应该圆胖的茎干变得像一根细长、苍白、软弱的豆芽菜，彻底失去观赏价值。\", \"noBloom\": \"室内养护由于缺乏红外线直射积温、光照时长严重严重不够，极难开花，需要常年放置在全日照露台养护多年才偶尔开花。\", \"drooping\": \"柱状或掌状肉质茎失去挺拔感、疲软下垂倒伏，多为基部已经彻底黑腐腐烂死掉，或遭遇了严重的低温冻害所致。\", \"mainTaboo\": \"频繁频繁浇水、盆土长期潮湿积水，以及长期摆放在完全阴暗密闭不通风的室内角落。\", \"beginnerTip\": \"以为它跟普通花草一样需要每天关切地浇水和喷水，结果买回家不到半个月，仙人掌就直接在盆里烂成了一滩臭水。\", \"yellowLeaves\": \"肉质茎发黄、变软、化水99%是因为浇水过多导致烂根闷根或黑腐；若肉质茎长期缺水，则会整体出现干瘪、起皱和变薄变小，及时补水可恢复。\"}','线条刚硬简练，几何感十足，自带高级的沙漠风情与工业极简主义格调，常用于现代冷淡风软装和多肉微景观造景。','与其他CAM植物一致，能在夜间吸收二氧化碳并释放氧气，对净化室内空气有微弱辅助作用。','部分品种（如食用仙人掌）的肉质茎和果实去刺后可食用，味道酸甜微酸，但普通观赏仙人掌禁止盲目食用。','在传统中医药学中，仙人掌肉质茎捣烂外敷可用于清热解毒、消肿止痛。','直立如剑、满身带刺的特征使其在风水学上具有极强的“辟邪、挡煞、防小人”作用，但也由于带刺，严禁摆放在卧室及客厅中央，宜放于阳台或玄关外侧挡煞。','全日照阳台、南向明亮窗台、阳光露台、写字楼高光落地窗旁','排水良好的盆栽土','粗沙/粗颗粒土:普通园土:腐叶土 = 4:2:1，或直接使用市售的仙人掌专用全颗粒沙质土，盆底需垫好防积水层','透气和排水性绝佳的红陶盆、瓦盆、紫砂盆或底部带有多孔的专用多肉盆','口径10-20cm（花盆宜小不宜大，盆大存水极易引发闷根烂干）','每2-3年春季换盆、换土一次',6.5,7.5,'easy','slow',150,1,1,0,0,'/images/plants/cactus.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-20 11:51:40','2026-05-24 16:00:14'),(21,'散尾葵','黄椰子、紫葵、黄常绿椰子','Dypsis lutescens','areca-palm','棕榈科','散尾葵属','木本','多年生','观叶','马达加斯加等热带岛屿雨林','散尾葵是一种常绿灌木或小乔木。其茎干丛生，金黄色或黄绿色，具明显的环纹。叶片羽状全裂，细长柔美，呈优美的弧形向外平展下垂。它具有浓郁的南国热带风光气息，株形高大飘逸，且具有极为出色的天然空气加湿和吸毒净化能力，是现代大客厅绿化的主力军。','羽叶飘逸、充满南国海岛风情的大型天然加湿器。','羽状全裂，裂片线状披针形，细长如剑，先端长渐尖，叶柄细长呈弧形下垂','鲜绿色、黄绿色，在阳光照射下常带有一层柔和的金黄色泽','茎干丛生，基部常分蘖大量新秆，秆身光滑黄绿色，布满黑色的细小斑点及环状节纹','圆锥花序生于叶鞘以下，分枝多，花极细小如碎金，室内盆栽极难开花','金黄色','5月 / 室内极罕见','秋季','整株体型高大、蓬松繁茂，无数细长如羽毛的绿叶层叠层叠向外展开下垂，姿态潇洒轻盈、极富动感与南国热带奢华质感。','medium',4,6,'最喜温暖湿润的明亮散射光或半阴环境。较耐阴，能适应室内普通客厅的光照。极忌盛夏强光直射暴晒，烈日会瞬间将柔嫩细长的羽叶全部晒焦、干枯变黄。','weekly',5,7,'散尾葵叶片繁密、蒸腾量大，属于喜湿润的植物，但它同时也具有木本质感，不能长期泡水。浇水必须坚持“见干见湿”原则，等盆土表面往下2-3厘米彻底变干后再行浇透水，切勿让土彻底干透，否则叶片会迅速焦枯变脆。冬季低温期必须严格控水。','见干见湿','每5-7天1次','每3-5天1次，早晚高频向叶面喷水','每7-10天1次','每12-15天1次，严格遵循不干透绝不浇水','严忌花盆托盘内长期存有死水积水，这会导致密集的根系缺氧引发全株大规模从下而上发黄干枯、落叶','散尾葵对自来水中的氯气和水质硬度非常敏感。长期直接用硬自来水浇会导致严重的黄化病和焦边。建议自来水至少晾置48小时，或偶尔加入极少量的硫酸亚铁以维持土壤酸性','high','原产热带海岛，对空气湿度要求极高，理想空气湿度在60%以上。室内环境过于干燥（特别是北方供暖期）会直接导致羽叶大面积干尖、枯焦。需高频向叶面周围喷雾或使用大型加湿器。',18,32,10,35,0,'客厅电视柜旁、沙发拐角处、落地窗一侧、明亮书房大窗边、商业大堂','喜温暖湿润、阳光充足或半阴环境，极怕烈日暴晒，极不耐寒，怕干旱，忌土壤积水死水，喜疏松肥沃、排水极佳的酸性腐殖土。','喜温暖多湿的热带气候，最适生长温度为18-32℃。非常不耐寒。冬季室内越冬温度必须维持在10℃以上，低于5℃极易发生不可逆的严重冻害。','平衡20-20-20','biweekly','散尾葵长势高大、体型肥硕，属于喜肥植物。在春、夏、秋三季生长旺季，每两周施用一次稀薄的复合液肥或观叶无机水溶肥。应重点补充微量元素，防止叶片发生缺素发黄。盛夏气温高于35℃或冬季低温期必须完全停肥。','春季和夏季','稀薄的氮磷钾平衡复合液肥，或定期在盆表面埋入观叶专用平衡缓释肥颗粒','观叶棕榈，无需催花肥',1,'严忌施用浓肥、未腐熟生肥，秋末降温后绝对严禁继续施用任何肥料','新长出的羽叶颜色发白、苍黄，整株细叶边缘大面积枯死、生长严重停滞','春季','随时剪除底部老化变黄的干枯羽叶、修剪受损破裂的细裂片，以及剪除发生黑斑的枯萎分枝','用消毒过的长柄大剪刀深入茎干基部，将变黄枯焦的整根叶柄一刀剪断。如果是局部小面积的叶尖枯焦，可顺着叶片剑形的弧度将枯焦部分斜剪掉，保持美观','剪除老叶时动作要轻，绝对严禁折断或损伤中心正中央刚矛状新叶轴','{\"fall\": \"秋季空气极其干燥，要重点保证空气湿度，喷雾频率不能低。秋末随降温逐步拉长浇水间隔，停止施肥，让茎干充实健壮，准备越冬。\", \"spring\": \"散尾葵的换盆与修剪造型黄金期。随着气温回升大量新芽从基部萌动，给予充足的明亮散射光，干透浇透并配合薄肥，让其快速抽长新秆。\", \"summer\": \"严防酷暑烈日暴晒。必须移到家里最明凉、全天候大开窗空气强流通的强半阴处，保持水分充足，早晚各进行一次大面积叶面喷雾降温，严禁闷热积水。\", \"winter\": \"防寒是生死存亡的关键！必须移入10℃以上的温暖房间。严格控制浇水，盆土不干透绝不浇水，防止低温水湿引发闷根。暖气房内需远离暖气片，必须高频开加湿器防干燥焦尖。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"在空气极度干燥闷热时极易爆发。叶背、细裂片缝隙间布满密集微小红点，导致叶片开始疯狂发灰、干枯并产生黏液\", \"treatment\": \"将整盆植物移到浴室用高压温水全面强力喷淋清洗叶背，或喷洒联苯肼酯药剂进行驱杀\"}], \"diseases\": [{\"name\": \"叶枯病\", \"cause\": \"主要是空气湿度严重不足干燥引起微小伤口，或者在高温期盆土长期死水积水且环境通风不良感染真菌\", \"symptom\": \"羽叶细裂片上出现大量圆形、黑褐色病斑，后期病斑连成一片导致整根叶柄焦枯、脱落\", \"treatment\": \"立即用消过毒的剪刀剪掉全部病变严重的叶柄。全盆严格控水，更换排水好的土壤，连续喷洒多菌灵并立即改善通风\"}], \"prevention\": \"高频率擦拭、喷洒叶面以常年维持高空气湿度，并严禁盆土积水，保持室内优良的开窗开门通风对流。\"}','无毒','无','全株完全无毒，极其安全','对猫、狗及儿童绝对安全。由于其叶片细长、飘逸的羽叶在风吹时会剧烈摇晃，极具动感，是猫咪无法抗拒的玩具。虽然猫啃咬无毒，但娇嫩的羽叶会被瞬间抓烂、咬秃严重破坏美观，建议放置在猫不易触及的沙发角落。','{\"leggy\": \"长期将其摆放在极度缺乏阳光的阴暗密闭处，导致长长的叶柄为了找光而发生严重的过度长长，使得羽叶之间间距极稀疏、软弱无力下垂，甚至主干发生倾斜易倒伏。\", \"noBloom\": \"室内观叶植物栽培由于空间和微环境局限，几乎100%终生不会开花，这完全属于正常的棕榈类生理特性，无需处理。\", \"drooping\": \"细长的复叶整体失去弹性、软绵绵向盆沿四周过度耷拉软塌，多为严重缺水脱水的前兆，或由于遭遇大降温受冻、根系已经全部烂死所致。\", \"mainTaboo\": \"盛夏酷暑烈日暴晒、空气极度极度干燥、自来水直接浇灌以及托盘死水积水。\", \"beginnerTip\": \"买回家后贪图好看直接塞在密不透风、没有一丝阳光的昏暗厕所或客厅死角里，并且不给叶子喷水，结果不出一两个星期，原本茂密的绿树就全部焦枯、黄叶烂根变成枯木。\", \"yellowLeaves\": \"最普遍、最头疼的是叶尖“干尖焦边”，100%是由于空气极度干燥或水质过硬盐碱化引发；若大面积整根叶柄发黄萎蔫，则是浇水频繁导致地下根系缺氧窒息腐烂，或者冬季遭遇了10℃以下的寒流冻伤。\"}','株型蓬松繁茂，长羽叶线条流畅柔美、潇洒轻盈，自带浓郁、奢华的南美海岛热带雨林格调，是填补大客厅、落地窗软装视觉空白的大型功勋绿植。','能以惊人的效率蒸腾水分，显著提升室内空气湿度；并能高效过滤空气中的甲醛、苯、三氯乙烯等新房装修化学毒气，吸毒和湿度调节净化能力极强。','无食用价值','无确切家庭药用价值','名字带有“散尾”与“葵”，寓意大吉大利、步步高升、一举夺魁、吉祥长寿，其向外辐射散开的密集绿叶在风水学上有招财纳气、驱除室内阴冷磁场的奇佳效果。','大客厅电视柜旁、明亮落地窗旁、沙发拐角处、写字楼老总位、酒店银行大堂、展厅','排水良好的盆栽土','腐叶土:泥炭土:珍珠岩 = 3:2:1，可适量加入少量发酵过的松树皮，必须保证土壤具有强保水力的同时兼具绝佳的排涝透气度，盆底需做好陶粒排水层','由于其株型高大、蓬松，必须选用厚重大号的优质水泥盆、大号陶盆以防头重脚轻歪倒','口径30-50cm（散尾葵根系呈密集丛生网状，需给予宽裕的根部空间）','每2年左右在春季换盆、换土一次',5.5,6.5,'medium','moderate',250,1,1,1,1,'/images/plants/areca-palm.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-21 11:02:45','2026-05-23 10:18:50'),(22,'春羽','春芋、羽裂喜林芋、裂叶喜林芋、小天使','Philodendron bipinnatifidum','selloum','天南星科','奇叶芋属','草本','多年生','观叶','巴西、巴拉圭等南美洲热带雨林','春羽是一种多年生常绿草本植物。随着年龄增长会形成粗壮挺拔的地上直立茎，茎上布满叶片脱落后留留下独特圆形“眼圈”疤痕（俗称“蛇皮身”或“龙鳞”）。其叶片巨大革质，呈极为震撼的羽状深裂，叶柄粗壮悠长。它对室内环境适应能力极强，以狂野、奔放、充满原始热带丛林风情而备受现代空间软装喜爱。','巨叶裂纹狂野，主干布满神神奇眼圈的雨林观叶霸王。','巨大卵状心脏形，呈极其明显的两回羽状深裂，裂片狭长且边缘常有波浪状起伏皱褶','浓绿色、墨绿色，表面具有坚硬的革质光泽，极油亮','直立粗壮的木质化肉质茎，随着生长会大量脱叶，在主干上留下一圈圈形似人类眼睛或龙鳞的奇特叶痕疤痕；气生根极发达如粗绳索','佛焰苞花序从叶腋抽出，佛焰苞通常为内白外绿，形似小船包裹肉穗花序，室内盆栽极罕见开花','乳白色、黄绿色','夏季 / 室内极罕见','少见','整株体型庞大开阔，粗壮的龙鳞主干上伸出无数长而粗横向散开的叶柄，支撑着巨大、开裂狂野的浓绿蕉叶，整体风格极其粗犷、奔放且极具热带原始生命力。','medium',4,6,'喜充足明亮的散射光或半阴环境。它非常耐阴，能在普通客厅昏暗的内侧角落长期健康存活。极忌盛夏烈日暴晒，强光直射会瞬间将巨大的叶片灼伤发白、烤焦焦黑并彻底失去油亮感。','weekly',5,8,'春羽体型巨大，粗壮的茎秆和根系能储藏大量水分，因此具有很强的耐旱能力，最怕土壤长期黏重泡水。浇水遵循“见干见湿”原则，等盆土表面往下3-4厘米彻底干透后再行浇透水。夏季生长期蒸发快可适当多浇；冬季低温期长势缓慢，必须严格控水偏干。','见干见湿','每5-7天1次','每3-5天1次，早晚喷雾降温','每7-10天1次','每12-15天1次，严格遵循不干透绝不浇水，保持盆土偏干','严忌花盆托盘内长期滞留死水积水，这会导致其粗壮的肉质地下根系迅速窒息腐烂，引发下部巨叶疯狂发黄溃烂','普通的室温自来水即可','high','喜略微潮湿的空气环境。虽然能耐受普通的室内干燥，但高空气湿度（50%-70%）能让其裂叶更大、蜡质层更厚。干燥季节可经常向叶面及周围地面喷雾或使用湿布擦拭巨叶。',16,30,8,35,0,'明亮客厅落地窗旁、大堂角落、沙发拐角处、书房大窗边、楼梯转角平台','喜温暖湿润、强散射光的半阴环境，极耐阴，生命力极其顽强，忌烈日暴晒，怕长期土壤积水闷根，较耐旱，喜疏松肥沃、排水极佳的酸性腐殖土。','喜温暖舒适、高湿的热带雨林气候，最适生长温度为16-30℃。具有较天南星科其他植物稍强的耐寒力。冬季室内越冬温度建议保持在8℃以上，低于5℃极易发生严重的冻害烂叶。','平衡20-20-20','monthly','春羽生命力旺盛、长势惊人，属于喜肥植物。在春、夏、秋三季生长旺季，每月施用一次观叶类水溶性复合肥颗粒即可。应多补充微量元素，氮肥可稍微偏高以促进巨叶生发。盛夏气温高于35℃或冬季低温期必须完全停肥防止烧根。','春季和夏季','稀薄的富含氮素的观叶类平衡水溶肥，或在盆表面定期埋入长效复合缓释肥颗粒','观叶绿植，完全无需催花肥',1,'忌施未腐熟生肥或过浓的化学肥料，气温低于15℃时严禁追肥','新长出的叶片不裂叶或裂纹严重变浅变少、个头明显缩水、叶色发淡发黄','春季','随时剪除底部老化变黄的干枯老叶、修剪受损开裂严重的残叶，以及修剪过长横出的粗糙气生根','用消毒过的锋利割刀从发黄老叶的粗壮叶柄基部紧贴主干平整割断。割断后主干上会留下一枚精美崭新的“眼睛叶痕”。粗大的气生根如果过多影响美观，可以适当剪短，但不可全部剃光','修剪底部老叶柄时，绝对严禁损伤或割伤位于主干正中央顶端刚抽出的尖锥形新叶芽','{\"fall\": \"秋季空气干燥，可多擦拭叶面保持光亮。秋末随降温逐步拉长浇水间隔，完全停止施肥，让茎干充实准备过冬。\", \"spring\": \"春羽换盆、修剪老叶、修剪造型的最好黄金期。随着气温回升，将其移到有温和散射光的明亮处，逐渐增加浇水施肥，促进新叶破土抽出。\", \"summer\": \"极其耐热。在室内无需特意遮阴，实用保持环境极佳的空气对流强通风。供水需充足，早晚向其周围喷雾或用湿布擦拭巨叶降温，切忌土壤过湿闷根。\", \"winter\": \"防寒防冻。必须进屋保暖，越冬温度控在8℃以上。严格控制浇水，盆土不干透绝不浇水。定期用湿抹布清除其巨叶上的灰尘，提升室内的观赏档次。\"}','{\"pests\": [{\"name\": \"红蜘蛛/红盾介壳虫\", \"symptom\": \"在室内空气极度极度干燥密闭时偶有发生。巨大叶背出现粉碎尘状红点，导致叶面开始失绿、发灰并起皱纹\", \"treatment\": \"用湿布蘸取稀释的肥皂水高频擦拭巨大叶面和叶背，或喷洒阿维菌素稀释溶液\"}], \"diseases\": [{\"name\": \"叶斑病/根腐病\", \"cause\": \"花盆透气性差，土壤长期黏重泥泞积水，加上室内环境长期空气闭塞不通风引发真菌感染\", \"symptom\": \"巨叶边缘产生大面积黑色水渍状腐烂斑块，主叶柄变软无力整体瘫软倒伏，拔出后根系发黑恶臭中空\", \"treatment\": \"立即用消过毒的快刀彻底切除变黑病变的叶柄。脱盆切除所有黑烂根系，伤口大量涂抹多菌灵粉末晾干两天，更换全沙质透气新土和多孔新盆重新栽种，严格断水并移到强通风口处\"}], \"prevention\": \"控制浇水、土不干透绝不频繁频繁浇水，常年保持居室养护环境拥有良好的开窗空气强通风。\"}','有毒','全株汁液、茎叶','天南星科植物，全株汁液中含有大量的针状草酸钙结晶以及毒性蛋白。皮肤接触汁液可能引发剧烈红肿、刺痛与过敏瘙痒；误食会导致口腔、咽喉剧烈灼痛、肿胀、流涎、声带麻痹以及胃肠道严重痉挛呕吐','对猫、狗及儿童有毒。由于其汁液毒性具有强刺激性，换盆或折断叶柄时请务必佩戴橡胶手套并及时洗手。必须摆放在儿童和宠物不易接触到的独立区域。','{\"leggy\": \"长期将其摆放在极度缺乏光线的完全阴暗死角，导致新抽出的粗大叶柄为了找光而发生严重的无限制伸长、拔高（高脚徒长），叶柄变得又细又长又软，导致无数重叠的圆叶和花朵毫无支撑力地向盆沿四周大面积软瘫、瘫倒在土表，原本金银色纵脉纹理完全褪色减淡，彻底失去精美挺拔的年宵花观赏价值。\", \"noBloom\": \"室内附生或盆栽栽培环境下由于空间和热带阳光积温高度受限，几乎100%一辈子都不会开花，主要作为常绿大型原始风观叶植物观赏，属于完全正常的生理现象。\", \"drooping\": \"横展的粗壮叶柄失去弹性和支撑力、软绵绵向盆沿四周瘫软瘫倒、耷拉。多为彻底缺水脱水的前兆（及时给水可恢复挺拔）；或者是由于频繁大水根系已经彻底溃烂死掉、丧失吸水和固定功能，需立刻检查主藤蔓基部是否变黑发黏。\", \"mainTaboo\": \"频繁频繁浇水导致盆土黏重死水、盛夏酷暑强光直射暴晒，以及冬季遭遇5℃以下的严寒打击。\", \"beginnerTip\": \"买回家后觉得它充满了热带生命力，每天都有事没事往盆里大量倒水，结果不到一个月它粗壮的龙鳞主干基部就全部闷根腐烂，整株瘫软成一地臭泥。\", \"yellowLeaves\": \"95%以上是由于频繁频繁倒水导致盆土形成死水泥泞、根系缺氧窒息黑腐发黄；其次是冬季气温骤降、遭遇8℃以下低温发生冻害发黄，以及盛夏酷暑烈日曝晒灼伤。\"}','蕉叶巨大、羽裂开裂狂野奔放，主干布满怪异、神奇的龙鳞“眼睛”疤痕，自带极其粗犷、奔放且极具热带原始生命力。','巨幅的皮革质叶面能如强力吸尘器般高效吸附室内的漂浮粉尘、化学微粒；并能极高效率地成批吸收室内的甲醛、苯、一氧化碳等装修有毒气体，其强大的蒸腾能力还能显著改善室内空气湿度。','无食用价值','无家庭药用价值','名字带有“春羽”（春风翠羽），主干布满“龙鳞大眼”，寓意“欣欣向荣”、“蒸蒸日上”、“长寿健康”、“大吉大利”，其横空出世的巨幅开裂绿叶在风水学上有强力镇宅辟邪、化解四方煞气、汇聚滚滚财气的刚强植物功用（因其带剧毒，在风水上宜摆放在客厅或玄关的远端角落，严禁摆放在靠近卧室、厨房或餐厅的位置）。','大客厅明亮落地窗旁、沙发一侧拐角凹陷处、写字楼前台大堂、商业高档餐厅拐角、展厅','排水良好的盆栽土','腐叶土:泥炭土:粗沙 = 2:2:1，可适量混入松针，确保具有优异的排涝透气度','厚大号的水泥盆、大号陶盆或高端深筒塑料深盆以防头重脚轻倒伏','口径25-45cm（春羽长势极快且肉质根系呈爆炸式生长，必须选用大而深的花盆）','每1-2年春季换盆、换土一次',5.5,6.5,'easy','fast',200,1,1,0,1,'/images/plants/selloum.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:02:45','2026-05-23 10:18:50'),(23,'铜钱草','香菇草、中华天胡荽、盾叶天胡荽','Hydrocotyle vulgaris','pennywort','五加科','天胡荽属','草本','多年生','观叶 / 水培','欧洲、北美及北非的湿地','铜钱草是一种多年生常绿匍匐草本植物。其最大的特点是叶片呈完美的正圆形，宛如一枚枚绿色的古代铜钱，又因形似小香菇而得名。它生命力极其极其极其顽强，极度喜水、喜阳光，既可土培也可半水半土或纯水培，是室内极为常见的爆盆小植物。','圆如铜钱，遇水即活、极易爆盆的喜光水生草本。','完美的正圆形、盾状着生，边缘有波状浅裂或钝锯齿，触感柔嫩变薄','鲜绿色、亮绿色，富有清新光泽','走茎（匍匐茎）极其发达，纤细、白色或绿白色，在节位上疯狂生根发芽向四周蔓延','伞形花序从小叶柄基部抽出，小花极其细小密集，呈碎米状簇生，基本无观赏价值','绿白色或淡黄色','5-8月（夏秋季） / 只要光照充足极其容易开花','秋季（少见）','呈密集的丛生和地毯式平铺状。无数高高低低的长叶柄顶着圆滚滚的绿色钱币错落层叠，洋溢着一种极为野蛮、清新且充满朝气的生命律动。','bright_direct',5,10,'非常喜光。明亮充足的直射阳光是其长势良好的核心动力。极度耐受全日照，阳光越猛，其叶柄越粗壮、圆叶越大越厚、株形越紧凑。虽稍耐半阴，但长期缺乏阳光会导致其严重畸形徒长、严重严重倒伏并枯萎。','frequent',1,3,'铜钱草属于半水生植物，可以说是“给点水就灿烂”，极度喜水、极度不耐旱。生长期花盆内必须常年保持湿漉漉甚至是保持一层浅水（半水半土养殖最佳）。一旦缺水，叶柄会在几个小时内全部软瘫倒伏，及时补水可奇迹般恢复。纯土培必须每天浇水，冬季低温期长势缓慢，需适当控水保持湿润即可。','喜湿忌干','每1-2天1次（保持盆土极度潮湿）','每天1-2次，或花盆内常年蓄水1-2厘米（严禁干旱）','每2-3天1次','每5-7天1次，视室内温度保持盆土潮湿偏温即可，防止彻底结冰','它是唯一的“不怕积水”的室内绿植，养殖它的唯一禁忌是“彻底缺水干旱”，一次长期的干旱会导致整盆圆叶和走茎彻底枯死','普通的室温自来水即可（水培建议晾置一天驱除氯气）','high','原产水生湿地，对空气湿度和盆土水分要求极高。非常喜湿润环境。在春夏季生长期和气候干燥期，需经常向叶面高频喷水以防干燥。',15,32,5,38,0,'南向明亮窗台、全日照阳台、露台水景旁、阳光房、阳光充足的办公桌大窗边','喜温暖潮湿、阳光充足环境，极度不耐干旱（给水即活），怕寒冷，对土壤要求极低，最喜半水半土（淤泥）环境。','喜温暖舒适、多湿气候，最适生长温度为15-32℃。抗热性强，盛夏只要不缺水可正常生长。不耐严寒，冬季越冬室温需保持在5℃以上，低于0℃地上部分极易被彻底冻伤枯萎溃烂，但地下根茎通常能耐受微霜冻。','平衡20-20-20','biweekly','铜钱草生命力强健、长势极其恐怖，属于极为喜肥的植物。在春、夏、秋三季生长旺季，每两周随浇水施用一次观叶类水溶性复合肥（或直接向盆内丢入十几粒平衡缓释肥颗粒）。由于它经常因为长得太密而被割茬，充足的肥水能让其几天内重新爆盆。冬季低温期必须停止施肥。','春季和夏季','稀薄的富含氮素的观叶类水溶肥或高氮液体复合营养液，促进圆叶疯狂发大','它开出的碎米小花会大量掠夺养分导致圆叶变小、株形散乱，因此完全不需要施用促花肥，见花苞应立即摘除或剃头',1,'忌施未腐熟生肥或浓度过高导致的烧根（表现为叶边缘发黑发焦）','新长出的圆叶明显缩水变小、叶色变得干发白、发黄，叶柄变得细长、软弱无力无法挺立','春夏季（全生长季均可进行大修剪）','随时剪除底层发黄老化的圆叶、随时修剪疯狂长出的细小花梗，以及在株形杂乱、叶片变小时进行彻底的“剃头”大修剪','铜钱草极为耐修剪，可以说是“剪不死的小强”。当发现整盆圆叶太密、发黄、长势不佳时，可以用大剪刀紧贴土面，将地上所有的叶柄全部一刀剪光（俗称剃头）。只要根茎健康，供足阳光和水，不到一个星期它就会重新长出一整盆崭新、油绿油绿的大铜钱。修剪下的花梗见一根剪一根，防其结实消耗养分','剃头大修剪后两三天内，严禁将未干枯的基部浸泡在过深的死水中，需给予充足的烈日暴晒以促进新芽生发','{\"fall\": \"秋季天气转干燥，注意给水不能断。秋末随降温长势减缓，可以逐渐将其移入室内阳光最强处，停止施肥。\", \"spring\": \"播种、分株、彻底剃头大修剪的最好黄金期。将其移到阳光最充足的室外或窗台，供足大量肥水，让其在几周内彻底爆发爆盆。\", \"summer\": \"铜钱草的黄金爆发期。极其耐热，只要供水供肥充足、晒太阳越多长得越疯狂、圆叶大如手掌。核心是必须每天检查盆内水位，严防正午彻底干旱脱水软瘫，无需遮阴。\", \"winter\": \"防寒。必须移入室内温暖处。虽然低温下地上圆叶会逐渐发黄变丑，但只要将其移到向阳窗台、保持土壤潮湿、温度在5℃以上，地下根茎就能安全过冬。若温度低于0℃，可将地上部分全部剪掉，保持盆土微潮偏干，春暖后会自动重新发芽。\"}','{\"pests\": [{\"name\": \"红蜘蛛/蜗牛/红线虫\", \"symptom\": \"水培容器底层偶尔产生细小红线虫，或圆叶被蜗牛、菜青虫咬出破洞缺口\", \"treatment\": \"水培有红线虫可彻底清洗容器并换纯净水；有虫咬直接人工抓除，或喷洒印楝油环保杀虫剂\"}], \"diseases\": [{\"name\": \"烂根/黄叶（多为干旱引发后遗症）\", \"cause\": \"它几乎不生病。所谓的烂根多是因为前期由于极度缺水导致部分根系干死，后期再次加水后，死根在死水中发生发酵腐烂引发恶臭\", \"symptom\": \"圆叶成批干黄、软瘫，水培水质变臭，走茎变黑软烂\", \"treatment\": \"立即倒掉臭水，将整盆植物连根拔出，用自来水强力冲洗干净，剪掉所有发黑腐烂的死根和地上黄叶。重新换干净的土或水，加入少许观叶营养液，移到强通风、多阳光处养护即可\"}], \"prevention\": \"核心在于常年保持水质清洁、供足高强度的直射阳光，坚决严防任何形式的缺水干旱。\"}','无毒','无','全株完全无毒，极其安全','对猫、狗及儿童绝对安全。由于其长得极像一盆好吃的野草，猫咪极其喜欢啃食其嫩圆叶或者用爪子打捞容器里的水玩。虽然误食无毒，但会被猫咪抓烂咬坏破坏完美的爆盆景观，可摆在猫猫不易折腾的明亮窗台外侧。','{\"leggy\": \"长期将其摆放在缺乏光线的客厅内侧或昏暗死角，导致新抽出的叶柄为了找光而发生极其严重的无限制伸长、拔高（俗称长成高脚鸡），叶柄变得又细又长又软，最终无法支撑、整盆彻底软瘫低垂在盆沿四周，圆叶也缩水变小、失去蜡质层，彻底失去美感。\", \"noBloom\": \"它只要长到一定大小且光照极其充足，就会疯狂开花（生发细小绿白花梗）。但养殖者通常极度反感它开花，因为开花会大量消耗养分导致圆叶迅速缩水、变小变脆、株形彻底乱掉。见花必剪、甚至直接剃头是养护的铁律。\", \"drooping\": \"整盆高高低低的圆叶和叶柄突然像断了电一样、软绵绵毫无支撑力地全部软瘫倒伏在地上。这100%是极端干旱脱水的红灯信号！只要它的根茎没被彻底晒死成干草，此时必须立刻将整盆植物浸泡在大水盆里（浸盆法）或在无孔盆里灌满自来水，在阴凉处放置3-4个小时，它就会神奇地重新满血复活、重新坚挺挺立起来。\", \"mainTaboo\": \"彻底缺水干旱（哪怕只有半天时间）、长期摆放在完全缺乏直射阳光的阴暗密闭角落。\", \"beginnerTip\": \"把它像普通天南星科植物（如绿萝、白掌）一样塞在没有阳光的客厅深处，并且用带底孔的普通花盆每隔几天才倒一次水，结果不到两个星期，它就因为极度缺光和干旱、彻底软瘫枯死成一盆干草。\", \"yellowLeaves\": \"90%以上是由于偶尔一次彻底缺水干旱、导致叶片脱水干枯发黄；其次是长期摆放在昏暗室内缺乏阳光引发的畸形发黄，或者生长期长期不给肥导致的营养不良性发黄。\"}','圆绿的钱币叶片玲珑可爱，高低错落、层叠爆盆，具有极高的小清新、文艺范与现代田园生活的盎然生机，是非常经典的桌面和窗台小绿植明星。','水生类植物，吸附微小灰尘能力强，对室内二氧化碳和有害化学气体有微弱的净化作用，其超高的水分蒸腾量能显著提升窗台周围的空气湿度。','无食用价值（虽属天胡荽属，但普通观赏铜钱草口感苦涩且可能带污染，严禁随意采摘食用）。','在传统中医药学中，同属植物全草有清热利湿、解毒消肿的微弱功效（请勿盲目自行尝试）。','名字极其极其吉利，正圆的绿叶形似古代铜钱，寓意“财源滚滚”、“招财进宝”、“富贵吉祥”、“团团圆圆”，是居家和办公桌上公认的强力招财风水佳品。','南向明亮窗台、全日照阳台、电脑桌窗边、阳光房、独立小书桌台面、露台鱼缸旁','排水良好的盆栽土','普通菜园土/塘泥/黑土 = 100%（它最喜黏重、肥沃、保水力极强的淤泥质土壤，严禁使用过于透气、完全不保水的沙质土、珍珠岩，否则极易脱水）','底部完全不带排水孔的无孔瓷盆、塑料碗盆、水仙盆或长条形不漏水种菜盆','口径15-30cm（宜选用宽口、浅底的容器，有利于走茎向四周疯狂蔓延扩展）','无需频繁换盆，但由于其走茎长满速度极快，每半年到一年建议进行一次分株或彻底“剃头”重新分盆',6.0,7.0,'easy','fast',30,1,1,1,0,'/images/plants/pennywort.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:02:45','2026-05-23 10:18:50'),(24,'幸福树','菜豆树、蛇仔树、大叶富贵树','Radermachera sinica','china-doll','紫葳科','菜豆树属','木本','多年生','观叶','中国南部及台湾、南亚等热带及亚热带低山林中','幸福树是一种常绿中乔木。盆栽时茎干挺拔直立，其最大特征是具有高品质的两回至三回羽状复叶。小叶对生，呈卵形或卵状披针形，叶片表面具有波浪状的起伏凹凸皱褶，浓绿油亮，在明亮光线下犹如涂了一层厚厚的蜡质，极具华丽质感。它长势旺盛、冠幅丰满，是居家客厅和办公空间非常受欢迎的中大型常青树树种。','叶面凹凸油亮，树冠丰满常青且极富存在感的中大型中式/现代客厅网红树。','卵形至卵状披针形，先端长渐尖，全缘，叶面具有极为明显的波浪状隆起凹凸纹理皱褶','深绿色、浓绿色，表面油亮闪耀，具有极其强烈的高级蜡质光泽','主干挺拔直立，老茎表皮呈灰褐色，平滑或有细小纵裂，分枝能力强，木质化程度高','顶生圆锥花序，花冠钟状漏斗形，形似大喇叭，花大且带有淡淡的清香（室内中大型中小型盆栽极罕见开花）','乳白色、淡黄色','5-9月（夏秋季） / 室内盆栽通常需养护多年且光照极佳、通风好才偶尔开花','10-12月（长条状蒴果，形似菜豆，故名菜豆树）','整株呈标准的小树状，主干挺拔，上部枝叶繁茂、冠幅横展丰满，无数油亮起伏的羽状浓绿蕉叶错落排列，整体风格沉稳、常青且极具优雅的质感存在感。','high',5,8,'非常喜光。最喜充足明亮的散射光和温和的直射阳光。充足的光照能让其叶片更加紧凑、凹凸纹理更深更亮。虽较耐半阴，能适应普通客厅，但如果长期缺乏光照或摆放在密闭阴暗死角，会导致其新叶变薄发软，并引发大规模疯狂脱落叶片成光杆。','weekly',7,10,'幸福树属于木本植物，根系对水分较为敏感，最怕土壤长期处于湿漉漉的烂泥状态。浇水严格遵循“见干见湿”原则。必须等花盆表层往下3-4厘米彻底变干、摸起来没有一丝潮气后再行浇透水。春夏季生长期长势旺盛、蒸发快，可适当缩短间隔；秋冬季长势减缓，必须严格控水偏干，等土干透了再浇一点水。纯土培严忌托盘留有积水。','见干见湿','每周1次','每周2次（高温高蒸发期，需配合叶面大面积喷雾降温）','每10天1次（随着秋末降温逐渐延长浇水时间）','每15-20天1次，严格遵循土不干透绝不频繁频繁倒水，保持土壤微干防冻伤闷根','严忌频繁高频率频繁浇水导致盆土长期处于黏重潮湿状态，这会导致其木质化根系迅速窒息腐烂，表现为地上叶片不发黄就直接疯狂大面积脱落','普通的室温自来水即可（建议晾置一天以使水温与室内气温一致，防止冷水惊根）','medium','喜略微湿润的空气环境，对普通室内干燥有一定抗性。但在夏季酷暑炎热期或冬季北方暖气房干燥期，过低的空气湿度会导致叶尖干枯卷曲。需定期用大型喷雾器向叶面及周围喷雾以调湿。',18,30,8,35,0,'客厅落地窗旁、大堂角落、沙发旁、书房大窗边、落地大阳台内侧','喜温暖湿润、阳光充足或明亮散射光环境，较耐高温，忌长期土壤积水死水，怕干旱，不耐寒，喜疏松肥沃、排水极佳的酸性或中性沙质壤土。','喜温暖湿润，生长适温为18-30℃。较耐高温。不耐严寒，冬季越冬温度建议保持在8℃以上，低于5℃极易发生严重的冻害烂根，导致整株冷冻坏死、叶片落光。','平衡20-20-20','monthly','幸福树体型较大、枝叶繁茂，在春、夏、秋三季生长旺季对养分有一定需求。可每月施用一次稀薄的无机观叶复合液肥，或在每季度开春时，在盆土表面定期埋入20-30粒长效平衡缓释肥颗粒即可。它对肥料浓度较为敏感，盛夏高温（超过35℃）或冬季低温期必须完全完全停肥防止烧根。','春季和秋季','稀薄的氮磷钾平衡复合水溶肥，或高观叶专用营养液，促进新羽状复叶不断生发','室内主要是观叶，无需单独施用促花肥',1,'极忌浓肥、未腐熟生肥，严禁将原液直接大量浇灌在靠近主干的根基部','新长出的复叶颜色发白苍淡、凹凸不平的波浪纹理变浅变平、生长极其缓慢、下部叶片老掉','春季','剪除老黄叶、修剪徒长无力的细枝、修剪阻碍内部通风的内膛交叉密枝，以及进行“打顶短截”控制树高和塑形','用消毒过的专业木本大修枝剪进行修剪。剪除黄老叶时从叶柄基部剪断；控制树高时，在主干或分枝所需的侧芽点上方1厘米处平剪，修剪完后伤口几天内切勿淋水。合理的剪除内侧密枝能大幅改善通风，防止夏季闷热落叶','严忌在冬季极度寒冷和夏季极端高温闷热期进行大面积大刀阔斧的重剪，防止伤口感染坏死','{\"fall\": \"秋季天气转凉干燥，逐步拉长浇水间隔，完全停止追施任何肥水。尽量让其多晒温和的秋季阳光，促使主干和枝条木质化，提高冬季抗寒抗冻抗灾能力。\", \"spring\": \"换盆、松土、大修剪造型的最好黄金期。随着新复叶从各个分枝顶部破土萌动，增加浇水施肥，移到家里光线最好的大窗边，让其树冠丰满常青。\", \"summer\": \"严防湿热闷根和烈日暴晒。必须移到家里最明凉、全天候大开窗开门、空气强对流通风的强散射光处。供水需严格看土，土不干透绝不频繁频繁倒水，早晚可向叶面大面积喷雾降温。\", \"winter\": \"防寒防冻是生死存亡的第一要务！必须进屋保暖，越冬温度控在8℃以上（12℃以上最佳）。严格控制浇水，盆土不干透绝不频繁频繁浇水，防止低温水湿加重冻害烂根。暖气房内需远离暖气片防止烤焦，定期用大型喷雾器清洗叶面灰尘保持油亮美感。\"}','{\"pests\": [{\"name\": \"介壳虫/红蜘蛛/蚜虫\", \"symptom\": \"在空气过于干燥密闭且不通风时发生。油亮的复叶背面、或主干嫩梢处聚集白色棉絮状或褐色盾壳状小虫，叶面变黏、失绿起皱纹\", \"treatment\": \"用刷子刷除，或喷洒蚧必治、阿维菌素或吡虫啉稀释药剂进行杀灭\"}], \"diseases\": [{\"name\": \"叶枯病/叶斑病/闷根落叶\", \"cause\": \"花盆透气性差，频繁浇水导致土壤长期处于黏重死水积水状态导致闷根烂根，或者环境密闭不通风导致真菌（主要是叶点霉属）爆发\", \"symptom\": \"叶片表面产生不规则黑褐色斑点，或者没有任何征兆、绿莹莹的叶子开始疯狂大面积脱落，几天内落成光杆树\", \"treatment\": \"极难挽救。一旦发现大规模掉绿叶，必须立刻脱盆检查根系，将黑烂死根全切除，用多菌灵大面积浸泡消毒，更换全沙质透气新土重新上盆。严格断水控水，彻底移到强风口处，连续喷洒多菌灵或代森锰锌溶液\"}], \"prevention\": \"核心在于“管住手、少浇水，多开窗、强通风”。保持环境常年拥有绝佳的空气自然流通对流。\"}','无毒','无','全株完全无毒。全株无毒且没有任何刺激性乳汁或毒性碱，是非常安全的家庭观赏树木','对猫、狗及儿童绝对安全。由于其叶片细密且高大挺拔，猫狗一般只能啃咬到掉落的枯叶，完全不会造成任何毒性伤害，但仍需防止宠物抓挠木质化主干抓坏树皮。','{\"leggy\": \"长期将其摆放在缺乏阳光的客厅死角或完全密闭无风的卧室，导致新抽出的分枝为了找光而发生严重的过度长长、拔高（高脚徒长），叶片之间的距离被拉得极长，整株显得稀疏软弱无力、失去挺拔质感。\", \"noBloom\": \"室内大型盆栽由于受到花盆空间限制、光照积温不够，几乎99.9%终生不会开花，这完全属于正常的紫葳科乔木类生理特性，无需处理，主要欣赏其油亮常青的复叶结构。\", \"drooping\": \"油亮挺拔的叶片整体失去弹性、软绵绵无精打采地下垂耷拉，多为盆土严重缺水脱水的前兆，或由于频繁浇水根系已经全烂死、遭遇了寒流严寒受冻所致。\", \"mainTaboo\": \"频繁频繁大水浇灌导致土壤泥泞、托盘长期存有死水、环境常年密闭完全不通风、冬季遭遇5℃以下的低温暴击。\", \"beginnerTip\": \"买回家后觉得树大很需要水，每天回家都往大盆里灌几碗水，并且把大窗户常年关得死死的，结果不到两个星期，原本茂密浓绿的大树就直接把叶子全部掉精光、变成了一根光秃秃的死枯木。\", \"yellowLeaves\": \"最普遍、最让人头疼的是“不发黄就直接疯狂掉叶子”，100%是由于频繁浇水盆土积水闷根烂根、或者环境密闭完全不通风引发的红灯信号；若叶边缘焦黑卷曲，则是空气太干燥或烈日暴晒引起的灼伤。\"}','树干挺拔，树冠丰满常青，羽状复叶细密整齐，最独特的波浪凹凸纹理具有极其强烈、高贵奢华的华丽蜡质油亮光泽，自带中式稳重和现代北欧风的软装高级感，极具空间存在感。','净化空气的高手。由于体型大且叶片繁密，能如同大面积吸尘器般高效吸附室内的漂浮粉尘、化学微粒；并能极高效率地吸收室内的甲醛、苯、二氧化碳等装修有毒气体，其强大的蒸腾能力还能显著改善室内温湿度。','无食用价值','无家庭药用价值','名字带有“幸福”与“菜豆（多子多福）”，寓意“合家欢乐”、“幸福美满”、“富贵长寿”、“吉祥平安”，在风水学上有强大的镇宅辟邪、凝聚家宅朝气、赶走家庭紧张阴冷磁场的强力风水效果。','客厅明亮落地窗旁、沙发拐角凹陷处、电视柜一侧、写字楼老总位、高档写字楼大堂、乔迁新居送礼','排水良好的盆栽土','腐叶土:泥炭土:园土:珍珠岩/粗沙 = 3:2:3:2，由于其根系发达且害怕积水，土壤必须混入足量沙质或颗粒介质，盆底必须垫厚度足够的陶粒或碎石作为排水层','体型高大，必须选用厚重大号、质感庄重的紫砂盆、大型花岗岩或水泥盆、北欧风简约深大塑料盆（防止头重脚轻歪倒）','口径30-50cm（视树木规格而定，必须给予根系宽裕的呼吸排涝空间）','每2年左右在春季换盆、换土一次（大型大树盆栽可以仅进行表面松土和更换表层肥土）',6.0,7.0,'medium','moderate',250,1,1,1,1,'/images/plants/china-doll.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:02:45','2026-05-23 10:18:51'),(25,'网纹草','费道尼亚、白网纹草、红网纹草','Fittonia albivenis','nerve-plant','爵床科','网纹草属','草本','多年生','观叶 / 水培 / 多肉','秘鲁及南美洲亚马逊河流域热带雨林底层','网纹草是一种多年生常绿匍匐草本植物。其最大特征是矮小玲珑，肥厚的叶片呈卵状椭圆形，全缘。最为人瞩目的是其叶面上密布着如同网眼般极其精细、规整的白色或红色、粉色的植物脉络纹理（网纹），色彩对比极高。它极其耐阴、极度喜高湿，生命力娇嫩，是现代微景观生态瓶、桌面和办公室极其受欢迎的小精巧盆栽。','网纹精美如织，矮小玲珑且极度喜湿润空气的生态瓶精灵。','卵状椭圆形，全缘，平展柔嫩，对生在匍匐的短侧枝上','主叶色为浅绿、深绿或暗绿色，其上密布着极其精细、对比强烈的白色、鲜红色或粉红色网眼状叶脉纹理','茎平卧或匍匐生长，短小肉质化，钝四棱形，绿色或略带紫色，表面密被一层微小的细茸毛，节位极易生根','穗状花序顶生，苞片密集重叠，小花呈细长管状漏斗形，在室内盆栽环境下偶尔开花，无观赏性','黄色或淡黄色','9-11月（秋季） / 室内条件适宜才开花','少见','整株呈低矮、平卧铺地丛生状。精美奇特的色彩脉络交织，如同一张厚厚平铺着的刺绣地毯，整体风格精巧、别致、极具大自然的几何造化趣味。','low',2,4,'高度耐阴。最喜温暖阴湿环境，最适合明亮的散射光或半阴处。能在无光照的室内普通台面长期存活。绝对不能承受强光或烈日曝晒，强光会导致其娇嫩的圆叶瞬间干枯焦白、叶脉纹理褪色卷曲。','frequent',2,4,'网纹草属于典型的“水娃娃”，对水分十分依赖且极度不耐旱。生长期必须保持盆土充沛湿润。只要表土稍微干下去1厘米就必须立刻、彻底地浇透水。由于其叶片娇嫩且蒸发极快，一旦缺水，整株在几个小时内就会像中暑一样彻底软瘫低垂在盆沿，及时补水可快速恢复。冬季低温期由于其畏寒，需适度延长间隔保持土壤微潮偏干，防止湿冷闷根烂掉。','见干见湿 / 喜湿忌干','每2-3天1次（保持盆土潮湿润泽）','每1-2天1次（高温干燥期，除大水量浇透外必须早晚高频向叶面周围喷洒雾气，或在盆底垫一托盘湿湿的沙砾调湿）','每3-5天1次','每7-10天1次，严格遵循土不干不浇，并且必须用晾置到与室温完全一致的温水浇灌，严防冷水激根冻死','严忌盆土彻底干透变成硬块、严忌托盘长期死水泡盆引发地下根系窒息黑腐发臭，浇水时严禁在正午强光下朝叶面直接淋水','晾置过的普通温和自来水或纯净水','high','原产亚马逊雨林底层底层，对空气湿度要求达到恐怖的“强迫症”级别，理想湿度需在70%-80%以上。室内哪怕只有一两天的极度干燥，都会导致其嫩叶边缘迅速干焦、甚至整株叶片发脆脱落。非常喜湿润环境。需常开加湿器、或放置在玻璃生态瓶、雨林缸中养护最佳。',16,26,12,32,0,'客厅高湿生态瓶中、北向明亮窗台内侧、高湿洗手间、小书桌一角、办公室无光办公桌台面','喜温暖多湿、强阴蔽半阴环境，极度不耐干旱（一缺水就软瘫），极怕烈日暴晒，极不耐寒冷，喜疏松肥沃、高度保水且排水极佳的微酸性腐殖土。','喜凉爽舒适、高湿的热带底层微环境，生长适温为16-26℃。非常不耐高温，盛夏超过32℃时长势严重减缓需极度注意强通风降温。极度不耐严寒，属于热带娇气绿植，冬季室内越冬室温必须死守在12℃以上，低于10℃会发生严重的不可逆冻害，导致整株发黑软烂死亡。','平衡20-20-20','biweekly','网纹草矮小，喜薄肥。在春季和秋季生长期，每两周施用一次极其稀薄的观叶类无机平衡液肥（浓度建议降为普通植物的一半甚至1/4），遵循“薄肥勤施”原则。多施钾肥能让其网状脉络色彩更加对比鲜明。盛夏酷暑（超过30℃）或冬季寒冷期（低于15℃）必须完全完全停止施肥。','春季和秋季','极其稀薄的低氮高钾型复合有机液肥，或高品质水溶性植物平衡营养液','不以观花为主，花大消耗营养，完全无需施用促花肥，见花序应立刻剪掉',1,'极忌浓肥、生肥，严禁直接将固体复合肥颗粒撒在紧靠其娇嫩茎叶的土表面，极易引发大面积烧伤萎缩','新长出的叶片个头变小、精美的网状脉络色彩对比变差、叶片失去坚挺厚实感','春季（生长季均可进行摘心修剪）','频繁进行“打顶摘心”控制主蔓生长、剪除底部老化干黄的老叶，以及随时剪除刚抽出没有观赏性的绿色穗状花序','用消毒的小剪刀在分枝的第2-3对叶片上方，直接将顶芽剪断（摘心）。频繁的摘心能强力刺激其基部和腋芽爆发，促使其株形向四周横向横展、长得矮胖密集更容易爆盆。修剪下的健康走茎只要带有2对叶子，直接插在潮湿的水苔或土中，在高温高湿下两三天就能生根成为一株新小苗','避免在冬季极端寒冷、或伤口极易发生霉烂软化的连续阴雨天进行修剪','{\"fall\": \"秋季天气转极度干燥，是发生“焦边”的高危期。必须高频向其周围喷雾或放置在加湿器风口。秋末随气温下降严格拉长浇水间隔，完全停止任何施肥，多见温和秋光，充实茎干硬度准备过冬。\", \"spring\": \"网纹草播种、换盆、打顶分株的最好黄金期。随着大量精美的网纹新叶从各个节位抽出，将其移到有温和散射光的半阴明亮处，干透浇透并恢复施薄肥，常往周围喷雾调湿。\", \"summer\": \"网纹草的危险期！极度害怕高温高湿加不通风。必须彻底移到家里最阴凉、北面空气强对流通风的强半阴角落。供水需高频，土变干就要浇透，必须每天高频开大型喷雾器、或直接扣一个透明塑料杯在盆上进行物理锁水控温降温，坚决断肥，严防黑腐。\", \"winter\": \"防寒是生死存亡的第一要务！它是极度怕冷的“小公主”。必须立刻移入12℃以上的温暖房间（最好有暖气或套透明塑料袋保温）。严格控制浇水，盆土不干透绝不频繁频繁浇水，盆土保持偏干。暖气房内需远离暖气出风口以防烤干，必须高频进行空气细雾喷雾防干燥焦枯。\"}','{\"pests\": [{\"name\": \"红蜘蛛/粉虱\", \"symptom\": \"空气过于干燥闷热时爆发。叶背、短柄处聚集密集微小红点或白粉状飞虫，网纹褪色且叶片成批起皱缩水卷曲\", \"treatment\": \"将整盆小植物直接扣在水龙头下用温和弱水流全面彻底强力冲洗干净，或喷洒极其稀薄的印楝油、阿维菌素药剂\"}], \"diseases\": [{\"name\": \"黑腐病/根腐病/猝倒病\", \"cause\": \"花盆过大或土壤黏重，长期积水死水，或者在夏季高温期环境处于完全密闭不通风的死角感染真菌\", \"symptom\": \"匍匐的肉质茎突然变黑、软化、像被开水烫过一样发生软烂脱落，叶片大面积黑化水渍状坏死\", \"treatment\": \"极难挽救。一旦发现，需立刻将所有发生黑烂坏死的分枝切除扔掉。将顶端尚未感染的健康走茎剪下，用多菌灵稀释液大面积消毒晾干，在全新干净的微潮水苔或全颗粒沙土中进行强力强通风扦插生根。旧土旧盆必须彻底销毁\"}], \"prevention\": \"核心在于“保持高空气湿度”的同时“必须配合空气的极佳通风对流”，严禁盆土闷热死水积水。\"}','无毒','无','全株完全无毒。属于完全无毒的家庭绿色草本植物，无任何化学毒素或刺激乳汁','对猫、狗及儿童绝对安全。被ASPCA（美国动物保护协会）认证的对宠物100%绝对绝对安全的无毒绿色植物。即使猫咪好奇踩烂、啃咬一两片叶子，也完全不用担心任何中毒危害，是宠物友好的顶级小绿植代表。','{\"leggy\": \"长期将其摆放在缺乏光线的极端阴暗、或者阻隔一切散射光的死角里，导致匍匐茎为了找光而发生严重的向上垂直过度长长、拔高，叶片与叶片之间的距离被拉得极宽极其稀疏，原本矮胖爆盆的株形变得零落软弱，精美的网纹对比度也变得暗淡模糊，彻底失去观赏档次。\", \"noBloom\": \"它只要在秋季时光照合适、温湿度稳定，就会很容易在枝顶抽出一根长长的绿色“麦穗状”绿色花序、绽放黄色小漏斗花。但因为花极其微小无观赏美感、开花还会疯狂掠夺全株养分导致其引以为傲的网纹色彩变浅、叶子变小，因此一旦发现必须毫不犹豫地立刻剪掉花序。\", \"drooping\": \"整盆低矮、精美的圆叶和叶柄突然像被晒化了一样、软绵绵毫无支撑力地全部四脚朝天软瘫瘫倒、耷拉在盆沿。这100%是由于土壤彻底干透、脱水引起的中暑信号！只要根系没被彻底烘干死，此时必须立刻用晾置的自来水将盆土浇透，并在其上扣一个透明塑料杯锁水，放置在阴凉处，不到两三个小时它就会像变魔术一样重新满血复活、重新挺拔坚挺挺立起来。但若浇水后一整天依然软瘫腐烂，则是根系已经彻底黑腐烂死。\", \"mainTaboo\": \"空气极度极度干燥（供暖干燥）、彻底严重严重缺水、烈日直射暴晒，以及冬季遭遇10℃以下的寒流暴击。\", \"beginnerTip\": \"买回家后觉得它跟多肉很像，就把它随手丢在阳光充足、空气干燥的南阳台上，并且每隔一个多星期才浇一次水，结果不到三天，它娇嫩精美的叶子就全被暴晒烤焦、彻底软瘫枯死成一地死草屑。\", \"yellowLeaves\": \"最普遍、最常见的是“软瘫和焦边”：若叶边缘干枯焦黑变脆脱落，100%是由于空气湿度太低、极度极度干燥引起；若整片小叶发黄变软并伴有黑化水，则是频繁浇水盆土积水闷根烂根、或者遭遇了低于10℃的严重受冻冻伤。\"}','矮小紧凑，叶面密布的精美红白网纹如同微缩版的叶脉精细刺绣艺术品，色泽艳丽、精巧绝伦，自带高级的桌面田园风情与精致的高级精致生活质感，是构建微型苔藓玻璃生态瓶、热带雨林缸底层景观的核心功勋明星。','草本微型植物，吸收化学毒气总量较弱，主要用于室内的微型观赏和极佳的桌面湿度调节辅助，其极高的蒸腾效率能微弱改善小办公桌周围的局部空气湿度。','无食用价值','无家庭药用价值','精美交织的红色白色网纹寓意“网罗财源”、“心细如发”、“合家团圆”、“大吉大利”，在风水学上有强大的促进家庭感情、柔化生硬书桌棱角、兴旺独立办公桌小财气的精致风水作用。','桌面苔藓微景观生态瓶中、雨林缸植物底层、独立小书桌台面、朝北无强光办公室台面、高湿洗手间窗台内侧','排水良好的盆栽土','腐叶土:泥炭土:珍珠岩 = 3:2:1，可适量混入少量泥炭藓（水苔碎屑）或蛭石以增强土壤的保水性，必须保证高度疏松透气，盆底需垫好陶粒排水层','质感素雅精致的小号红陶盆、浅口矮胖陶瓷盆、不漏水的玻璃小生态瓶或多孔控根小塑料盆','口径8-15cm（它是典型的低矮铺地植物，根系极浅，花盆宜浅不宜深，严忌用大深盆）','每年春季结合修剪分株进行换盆、换土一次（由于其匍匐生长极快，长满即需分盆）',5.5,6.5,'medium','fast',15,1,0,1,1,'/images/plants/nerve-plant.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:02:45','2026-05-23 10:18:51'),(26,'袖珍椰子','矮生椰子、袖珍椰子葵、幸福椰子','Chamaedorea elegans','parlor-palm','棕榈科','袖珍椰子属','木本','多年生','观叶 / 水培','墨西哥和中美洲热带雨林底层','袖珍椰子是一种高效耐阴的常绿小灌木。它形似高大棕榈树的微缩版，主干直立，不分枝。羽状全裂的叶片翠绿柔美，向四周舒展。因其株型小巧玲珑，具有浓郁的热带椰林风情，且极易养护，是办公室桌面、书房小空间绿化的绝佳选择。','微缩版热带椰子树，耐阴小巧的桌面棕榈。','羽状全裂，裂片披针形，细长如剑，先端渐尖，叶柄稍弯曲向外舒展','深绿色、亮绿色，富有清新蜡质光泽','主干直立丛生，细长如竹，绿色，表面具不明显的环状节纹，不分枝','肉穗花序自叶轴基部抽出，分支多，花极细小如金色小圆球，呈小珠状整齐排列','鲜黄色、金黄色','春季（3-5月） / 只要散射光充足，在室内极易开花','夏秋季（橙红色至黑色小浆果）','直立的小竹竿顶着一丛丛优美下垂的羽状绿叶，错落有致，虽矮小却极具热带雨林挺拔挺秀的优雅姿态。','low',2,4,'高度耐阴。最喜温暖阴湿的明亮散射光或半阴环境。能在缺乏直射光的昏暗室内长期健康生长。极忌烈日暴晒，强光直射会瞬间导致鲜嫩的羽叶发白、灼伤枯焦。','weekly',5,7,'遵循“见干见湿”原则。等盆土表面往下2-3厘米彻底变干、摸起来没有一丝潮气后再行浇透水。它虽然喜湿润，但其细小的根系非常害怕长期泡水，冬季低温期需严格控水，保持盆土微潮偏干。','见干见湿','每5-7天1次','每3-5天1次（高温蒸发快，配合早晚叶面喷雾）','每7-10天1次','每12-15天1次，严格遵循土不干透绝不频繁浇水','严忌频繁给水导致盆土长期积水泥泞，这会导致其根系迅速窒息黑腐，引发羽叶成批枯黄脱落','普通的室温自来水即可','high','原产热带雨林底层，对空气湿度要求较高。喜湿润环境。室内干燥（特别是冬季北方暖气房）极易导致叶尖枯焦，需高频向叶面周围喷洒细雾调湿。',18,30,10,35,0,'办公桌台面、明亮书桌一角、洗手间窗台、客厅无直射光茶几、北向卧室台面','喜温暖湿润、强半阴环境，极耐阴，忌烈日暴晒，怕干旱，忌积水，喜疏松肥沃、排水极佳的微酸性沙质壤土。','喜温暖舒适、多湿气候。最适生长温度为18-30℃。较耐高温。不耐严寒，冬季越冬温度需死守在10℃以上，低于5℃极易受冻冻伤导致落叶干枯。','平衡20-20-20','monthly','袖珍椰子长势缓慢，对肥料需求不高。在春、夏、秋三季生长旺季，每月随浇水施用一次稀薄的观叶平衡类液肥（浓度减半），或每半年在盆面撒入十几粒缓释肥颗粒即可。盛夏酷暑（超过35℃）或冬季低温期必须完全停肥。','春季和秋季','稀薄的富含氮钾的观叶类平衡水溶肥，促进新羽叶萌发生长','它开出的珠状小黄花会消耗部分养分，但不属于主要开花植物，无需施用促花肥，若觉得杂乱可直接剪掉花序',1,'极忌施浓肥、生肥，严禁降温后继续追肥','新长出的羽叶变得细小变薄、叶色呈现无光的苍黄色、生长完全停止','春季','随时剪除底层老化发黄的干枯老叶、剪除受损开裂的残叶，以及剪掉开花凋谢后的残花梗','用消过毒的细尖修枝剪深入主干基部，将变黄的老叶柄平整剪断即可。若局部小面积叶尖枯焦，可顺着羽裂片形状剪除焦尖','严忌损伤或割伤位于每一根竹状茎杆最顶端的中心直立新芽轴，主干顶端一旦受损，该主干将彻底停止生长','{\"fall\": \"秋季空气转极度干燥，需高频进行叶面空气喷雾。秋末随降温逐步拉长浇水间隔，完全停止施肥，让植株组织充实准备过冬。\", \"spring\": \"换盆、修剪、恢复长势的黄金期。将其移到有温和散射光的明亮桌面，逐渐增加浇水施肥，常往其周围喷水防干燥。\", \"summer\": \"耐热，但在室内高温期需移到阴凉、空气对流极佳的通风处，供水充足，表土干了就浇透，早晚喷雾降温，严忌湿热闷根。\", \"winter\": \"防寒第一要务！必须移入10℃以上的温暖房间。严格控制浇水，盆土不干透绝不频繁频繁倒水，保持偏干防冻伤闷根。暖气房内需远离暖气出风口。\"}','{\"pests\": [{\"name\": \"红蜘蛛/介壳虫\", \"symptom\": \"在空气过于干燥密闭时发生。细小羽叶背面聚集密集微小红点，导致叶面发灰起皱、大面积干枯\", \"treatment\": \"将整盆植物移到浴室用高压水流彻底冲洗叶片背面，或喷洒阿维菌素、联苯肼酯药剂\"}], \"diseases\": [{\"name\": \"叶枯病/烂根\", \"cause\": \"花盆透气差，土壤长期死水积水，或者在高温期环境长期闭塞不通风感染真菌\", \"symptom\": \"羽叶尖端开始大面积变黑变干并向内蔓延，主干基部变软发黑，拔出后根系黑腐中空\", \"treatment\": \"剪掉所有受损严重的叶柄。脱盆切除黑烂根系，用多菌灵消毒后更换疏松透气新土重新栽种，严格断水控水，移到强通风口处\"}], \"prevention\": \"核心在于通过高频给其周围喷雾常年“保持高空气湿度”，同时“坚决管住手、土不干透不频繁频繁倒水”。\"}','无毒','无','全株完全无毒。属于完全无毒的家庭观赏小棕榈，没有任何化学毒素或刺激乳汁','对猫、狗及儿童绝对安全。被权威机构认证的对宠物100%绝对绝对安全的无毒绿色植物。即使猫咪好奇抓咬其羽叶，也完全不会造成任何中毒危害，是顶级的宠物友好小绿植。','{\"leggy\": \"长期将其摆放在完全缺乏光线的昏暗死角，导致其主干和叶柄为了找光而发生严重的过度拔高，使得叶片之间间距变宽、软弱无力下垂，失去挺拔秀丽的质感。\", \"noBloom\": \"它只要在散射光充足、环境温湿度稳定的办公桌上，在春季极易抽出一串串密密麻麻的“小金球”肉穗花序，属于极易开花的室内绿植。\", \"drooping\": \"挺拔的羽状复叶整体失去弹性、软绵绵向四周瘫软耷拉，多为彻底缺水脱水的前兆（及时补水可恢复），或由于频繁浇水根系已经全烂死、丧失吸水固定功能。\", \"mainTaboo\": \"盛夏酷暑烈日暴晒、空气极度极度干燥、托盘内长期有死水积水。\", \"beginnerTip\": \"觉得它很有热带海岛风情，就直接把它丢在阳光猛烈的露台上，结果不到两天娇嫩细小的羽叶就全部被烈日暴晒烤黑枯死。\", \"yellowLeaves\": \"最普通、最普遍的是叶尖“干尖枯焦”，100%是由于空气湿度太低、极度极度干燥引起；若整根羽叶大面积发黄萎蔫，则是浇水频繁导致烂根闷根，或者冬季遭遇了10℃以下的寒流冻伤。\"}','株型小巧玲珑、挺秀典雅，羽状复叶错落舒展，自带高级、清新的热带椰林风情与现代办公室生活的精致调性，是极具普及度的桌面绿植明星。','享有著名的“空气高效净化器”美誉。能高效吸收、过滤空气中的甲醛、苯、三氯乙烯等装修化学毒气，对吸烟产生的尼古丁气体也有优秀的净化吸收能力。','无食用价值','无家庭药用价值','寓意“大吉大利”、“生意兴隆”、“平安吉祥”、“幸福美满”，其挺拔细长的常青羽叶在风水学上有柔化硬实桌面线条、汇聚办公桌朝气和财气的佳美风水作用。','办公室办公桌台面、明亮书桌一角、无直射光客厅茶几、洗手间窗台、独立小花架上','排水良好的盆栽土','腐叶土:泥炭土:珍珠岩/粗沙 = 3:2:1，可混入适量椰糠，要求具有良好保水力的同时兼具优异的排涝度，盆底垫陶粒','质感精美的小号红陶盆、白瓷盆、水培玻璃瓶或多孔控根小塑料盆','口径10-18cm（它喜欢根系稍微紧凑的环境，严忌大盆深盆养小花）','每2-3年春季换盆、换土一次（因其长势较慢，无需频繁折腾）',5.5,6.5,'easy','slow',100,1,0,1,1,'/images/plants/parlor-palm.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:03:27','2026-05-23 10:18:51'),(27,'豆瓣绿','青叶碧玉、豆瓣菜（误称）、椒草、翡翠椒草','Peperomia obtusifolia','peperomia','胡椒科','草胡椒属','肉质','多年生','观叶 / 水培 / 多肉','美洲热带及亚热带雨林底层','豆瓣绿是一种多年生常绿肉质草本植物。其最大特征是叶片肥厚多汁、形似宽卵圆形，表面极其平滑、浓绿油亮，呈现出如同高档翡翠或碧玉般的华丽质感。它茎干矮小短粗，生命力极其顽强，对光照和水分有很强的忍耐力，极其耐阴，是室内桌面和电脑旁普及率最高的懒人小绿植之一。','叶厚如玉，浓绿油亮且生命力顽强的无忧电脑旁小碧玉。','倒卵形或长卵圆形，先端圆钝，全缘，质地极厚革质且高度肉质化，表面平展光滑','深绿色、浓绿色，油亮闪耀，具有极其强烈的高级蜡质层和如碧玉般的光泽','茎短粗，肉质化，平卧或直立生长，多分枝，表面光滑绿色，节间距整齐','穗状花序顶生或与叶对生，形似一根根绿色或黄绿色的细长“小尾巴”或小老鼠尾巴，无传统花瓣，观赏价值低','黄绿色、浅绿色','2-4月及9-10月（春秋季开花） / 只要长势成熟在室内极其容易开花','少见（浆果）','整株体型低矮、繁茂紧凑。圆润肥厚的浓绿叶片在短粗的肉质茎上错落排列，显得极为肥美、憨态可掬且充满清新的生机。','medium',3,6,'喜充足明亮的散射光或半阴环境。它非常耐阴，能在办公桌微弱光线下长期健康存活。极忌盛夏烈日暴晒，强光直射会瞬间将肥厚的肉质叶片晒焦发黄、产生灼伤黑斑并失去碧玉光泽。冬季需多见温和阳光。','rarely',7,14,'豆瓣绿属于多肉质植物，叶片和茎干内储藏有大量水分，具有极其强悍的耐旱能力，最怕土壤长期黏重泥泞。浇水严格遵循“干透浇透”、“宁干勿湿”原则。必须等盆土表层往下3-4厘米彻底变干、摸起来没有一丝潮气后再行浇透水。冬季低温期必须严格控水，等土彻底干透后再微量给水。','干透浇透','每7-10天1次','每5-7天1次（高温期需看土干燥度，选择清晨或傍晚浇，切忌托盘存积水）','每7-10天1次（秋末随降温大幅拉长间隔）','每15-20天1次，严格保持土壤偏干以抗寒防冻烂','严忌高频率频繁倒水导致土壤长期积水潮湿，这会导致其短粗的肉质地下根系迅速缺氧窒息腐烂，表现为肥厚叶片无缘无故疯狂脱落','普通的室温自来水即可','medium','对空气湿度适应性极广。虽然原产雨林，但由于其叶片具有肥厚的肉质储水层，因此能极好地适应干燥的北方供暖室内和空调房环境。普通室内湿度即可，无需刻意高频喷水。',15,28,10,35,0,'电脑桌前、办公桌台面、明亮书桌、客厅茶几边缘、无直射光的窗台内侧、小电视柜一侧','喜温暖湿润、半阴环境，极耐阴，生命力极其顽强抗折腾，极耐旱（宁干勿湿），怕积水闷根，喜疏松肥沃、排水极佳的沙质营养土。','喜温暖舒适、微湿的环境，生长适温为15-28℃。不耐极端高温，盛夏超过33℃时长势停止需加强通风。不耐严寒，冬季室内越冬室温需维持在10℃以上，低于5℃肥厚的叶片和茎干极易彻底发生冻害变黑腐烂。','平衡20-20-20','monthly','对肥料需求较低。在春季和秋季生长期，每月随浇水追施一次极其稀薄的无机观叶复合平衡液肥颗粒即可（浓度减半）。主要补充氮肥维持叶片油绿，切勿施浓肥。盛夏酷暑和冬日寒冷期必须完全停肥。','春季和秋季','稀薄的富含氮素的观叶类水溶液肥或通用品质营养液','它开出的鼠尾状花序无观赏美感且严重抢夺全株叶片养分，无需施用促花肥，见花序应直接掐断',1,'极忌浓肥、生肥，严禁直接把原液大量浇灌在靠近肉质根基部防止发生局部烧灼','新长出的碧玉叶片个头变小变薄、叶色失去蜡质光泽变得干发苍白、生长极慢','春季（生长季均可进行修剪）','随时剪除底部老化发黄的厚老叶、随时修剪细长如尾巴的花序，以及在株形过度徒长长高时进行“打顶摘心”','豆瓣绿极为耐修剪且极易繁殖。用消毒小剪刀在所需的节位上方0.5厘米处平剪。为了促使其横向矮胖分枝、长得更爆盆，可在主蔓长高到15厘米时将顶芽剪掉（打顶）。剪下的健康肥厚分枝只要带有一对小叶，插在微潮的沙土或清水中，不到一个星期就能迅速生根成为一株新小苗，甚至一片肥厚的叶片（带完整叶柄）直接叶插在土里也能生根','修剪后两三天内伤口未干涸前，严禁往伤口及叶片上大量喷水，防止发生切口软化霉烂','{\"fall\": \"秋季天气转凉，长势恢复，可以适当多见温和阳光。秋末降温后严格拉长浇水间隔，完全停止任何施肥，充实茎干和肥厚叶片，准备过冬。\", \"spring\": \"豆瓣绿播种、换盆、分株打顶的黄金期。随着大量新碧玉叶片从茎节抽出，确保充足的明亮散射光，干透浇透并恢复施薄肥，常保持环境空气流通。\", \"summer\": \"严防湿热闷根和烈日暴晒。必须移到家里最阴凉、强通风对流的强半阴处。供水需严格控量，坚决看到土干透再浇，严禁托盘存积水。早晚可以向其周围喷雾，坚决断肥，严防黑腐。\", \"winter\": \"防寒防冻！它肥厚的叶片极度怕冻。必须立刻移入10℃以上的温暖房间（最好有暖气房内向阳窗台）。严格控制浇水，盆土不干透绝不频繁浇水，盆土保持偏干。暖气房内需远离散热器，定期用湿布轻轻擦拭圆叶尘埃保持其碧绿油亮。\"}','{\"pests\": [{\"name\": \"介壳虫/红蜘蛛\", \"symptom\": \"在空气过于干燥密闭且不通风时偶有发生。肥厚叶片背面或叶腋深处聚集白色粉状小虫，吸食汁液导致起皱\", \"treatment\": \"用酒精棉球人工逐个擦拭掐死，数量多时喷洒蚧必治稀释药剂\"}], \"diseases\": [{\"name\": \"根腐病/黑腐病\", \"cause\": \"花盆透气差或盆大，频繁浇水土壤长期死水积水闷根，或在夏季高温高湿且密闭不通风下感染真菌\", \"symptom\": \"肥厚的肉质叶片突然大面积无故发黑、脱落，肉质短茎变软腐烂发黏，整株松散倒伏\", \"treatment\": \"立即脱盆，用利刀切除所有发黑坏死的肉质根和主茎。若顶端茎叶依然健康绿色，涂多菌灵晾干伤口两三天后，插在全新的干净干燥全颗粒沙土中重新扦插生根。旧土扔掉\"}], \"prevention\": \"核心在于“管住手、少浇水，多开窗、强通风”。盆土宁可干到起皱也严禁长期处于湿漉漉的烂泥状态。\"}','无毒','无','全株完全无毒。属于100%绝对无毒的家庭常绿肉质植物，无任何化学毒素，其肥厚汁液安全无害','对猫、狗及儿童绝对安全。被ASPCA（美国动物保护协会）官方认证的对猫狗完全无毒的友好植物。由于其圆润、绿油油、触感好，猫咪极其喜欢啃咬其肥厚的肉质叶片。虽然误食安全无毒，但会咬坏叶片破坏碧玉美感，可摆在稳固的台面中央。','{\"leggy\": \"长期将其摆放在缺乏光线的电脑桌死角或昏暗无光的内侧台面，导致肉质茎为了找光而发生严重的过度长长（长成高脚碧玉），茎干细长无力并发生倾斜倒伏，叶片之间的距离拉得极宽极其稀疏，原本肥厚圆润的叶片也缩水变小、变薄，失去蜡质层的油亮翡翠感，彻底沦为杂草模样。\", \"noBloom\": \"它在春秋季时光照合适极其容易在枝顶抽出一根根细长、弯曲的绿色“小尾巴”穗状花序。但由于花序无任何传统花瓣之美，还会极其严重地掠夺全株圆叶的营养，导致叶片长不大、变薄变平。一旦发现这种小尾巴，必须立刻、无情地全部掐掉。\", \"drooping\": \"肥厚油亮的圆叶和分枝整体失去弹性和支撑力、垂头丧气地瘫软低垂在盆沿。这多为土壤彻底干透、干旱脱水引起的信号（及时浇透水半天内可恢复挺拔）；若浇水后一整天依然瘫软发黑，则是由于频繁大水根系已经彻底溃烂死掉。\", \"mainTaboo\": \"频繁频繁大水浇灌、托盘存积水、盛夏酷暑强光直射暴晒，以及冬季遭遇5℃以下的低温打击。\", \"beginnerTip\": \"把它当成普通的喜水绿植（如水培绿萝或白掌）一样，天天回家都关切地给它盆里灌满水，结果不到两个星期，它肥厚的碧玉叶子就全部掉成了一个秃光杆死树。\", \"yellowLeaves\": \"95%以上是由于频繁倒水、盆土积水积水导致地下根系黑腐窒息，引发叶片发黄或绿莹莹就疯狂脱落；其次是冬季气温受冻发黄，或者长期极度缺水引起底层老叶干黄萎缩。\"}','小巧玲珑、株形紧凑繁茂，圆润肥厚的叶片具有极其强烈、高贵奢华的翡翠蜡质油亮光泽，自带日式极简与清新懒人的精致生活格调，是放置在电脑旁、办公桌台面的完美质感桌面绿植明星。','净化空气的无忧小助手。能有效吸附电脑周围的浮尘、吸收微量的化学有害气体，其碧绿的颜色能够极好地调节长时间看电脑产生的视觉疲劳，被称为“防辐射、养眼碧玉”。','无食用价值','无家庭药用价值','名字带有“碧玉”与“青叶”，寓意“吉祥如意”、“阖家平安”、“翡翠常青”、“步步高升”，其圆润肥厚、常青闪耀的绿叶在风水学上有柔化电脑桌周围刚硬电子设备、汇聚桌面小财气和文昌运的奇效作用。','电脑办公桌前、明亮小书桌台面、无强光客厅茶几边缘、独立小电视柜一侧、高湿洗手间明亮内窗台','排水良好的盆栽土','泥炭土:腐叶土:珍珠岩/粗沙 = 2:2:1，或者直接使用市售的多肉营养土混合少许通用土，必须保证土壤疏松透气排涝，盆底垫陶粒','精美小巧的马卡龙色塑料盆、简约小红陶盆、白瓷盆或水培专用带孔小容器','口径10-15cm（它是低矮小草本，根系极短浅，花盆宜小宜浅，盆大极易存水引发黑腐）','每1-2年春季换盆换土一次（可以结合修剪剪枝扦插进行）',6.0,7.0,'easy','moderate',25,1,0,1,1,'/images/plants/peperomia.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:03:27','2026-05-23 10:18:51'),(28,'花叶万年青','黛粉叶、哑巴甘蔗、大王黛粉叶','Dieffenbachia seguine','dumb-cane','天南星科','花叶万年青属 (黛粉叶属)','草本','多年生','观叶','南美洲巴西等热带雨林底层','花叶万年青是一种常绿多年生灌木状草本植物。其主干粗壮直立。最引人注目的是其巨大的长椭圆形叶片，叶面绿白相间，密布着不规则的乳白色、淡黄色斑块与斑点，色彩明亮夺目。它极耐阴、长势丰满，是非常经典的室内大型观叶植物，但因全株具有较强毒性，养护需特别注意安全。','巨叶色彩白绿斑斓、极耐阴的华丽雨林观叶霸王。','大长椭圆形或长圆状披针形，先端长渐尖，全缘厚革质，长叶柄基部扩大成鞘状包裹主干','主叶色为亮绿色或深绿色，其中央或全叶面密布着不规则的乳白色、粉绿色或淡黄色的斑块、点阵，色彩斑斓华丽','主干粗壮挺拔，肉质化，随着年龄增长基部木质化，灰绿色，具明显的竹子般的叶柄脱落环状环纹，内含剧毒白色乳汁','佛焰苞花序从叶腋抽出，长圆形，形似扁小船包裹着长穗状的肉穗花序，在室内普通家庭盆栽环境下极罕见开花','绿白色、淡黄色','夏季（5-7月） / 室内极罕见','秋季（少见小红浆果）','粗壮直立的主干上，向四周错落伸出长长的粗大叶柄，托举着巨幅、色彩极为明亮斑斓的斑马状大叶，整株冠幅饱满丰满，充满浓郁的亚马逊热带雨林狂野格调。','medium',4,6,'喜充足明亮的散射光或柔和的半阴环境。它高度耐阴，能在普通客厅昏暗的角落长期健康存活。绝对铁律：极忌盛夏酷暑烈日暴晒！强光直射会瞬间将巨幅的斑斓大叶成片灼伤发白、烤焦干枯焦黑。若光照极度缺乏，叶面华丽的乳白斑块会褪色变绿减淡。','weekly',5,8,'花叶万年青巨叶蒸腾量大，喜湿润，但由于其主干粗壮肉质、根系害怕长期泡水。浇水严格遵循“见干见湿”原则。必须等盆土表层往下3-4厘米彻底变干、摸起来没有一丝潮气后再行浇透水。纯土培严忌托盘内积水不退。冬季低温期生长完全停止，必须严格控水保持土壤偏干，否则极易湿冷冻伤烂根。','见干见湿','每5-7天1次','每3-5天1次（高温生长期，除大量浇透水外必须早晚高频向叶面周围喷雾降温防干燥）','每7-10天1次（随着秋末降温逐渐延长浇水时间）','每12-15天1次，严格遵循土不干透绝不频繁倒水，保持土壤微干以防冻伤闷根','严忌高频率频繁倒水导致土壤长期处于死水积水状态，这会导致其粗壮的肉质地下主根系迅速缺氧窒息腐烂，地上巨叶会无缘无故大面积发黄溃烂下垂','普通的室温自来水即可（建议晾置一天驱除氯气且使水温与气温一致，严防冰冷自来水刺激肉质根）','high','原产南美暴雨雨林底层，对空气湿度要求较高。喜空气湿润环境。在春夏季生长期、空调房或北方冬季供暖期，空气过于干燥会导致大叶边缘发生干焦卷曲。需定期用大型喷雾器向其巨叶表面和周围高频喷雾调湿。',18,30,12,35,0,'宽敞客厅落地窗旁、大玄关一侧、写字楼明亮拐角、沙发旁、书房大花架上','喜温暖湿润、强散射光的半阴环境，极耐阴，长势极快，生命力强健，忌烈日暴晒，怕长期土壤积水死水闷根，极怕寒冷，喜疏松肥沃、排水极佳的酸性腐殖土。','喜温暖舒适、高湿的热带气候，最适生长温度为18-30℃。较抗酷暑。极度不耐严寒！冬季室内越冬室温必须死守在12℃以上（15℃以上最佳），低于10℃会发生极其严重且不可逆的冻害，导致巨叶疯狂变黑软烂、全株木质化主干溃烂坏死。','平衡20-20-20','monthly','花叶万年青体型巨大、长势迅速，属于极为喜肥的植物。在春、夏、秋三季生长旺季，每月施用一次稀薄的观叶类平衡水溶复合肥颗粒即可（浓度减半）。应适当补充钾肥，能让叶面斑斓的乳白图腾色彩对比更加明亮华丽。盛夏酷暑（超过35℃）或冬季低温期必须完全完全停止施肥防止烧根。','春季和秋季','稀薄的富含钾素的观叶类水溶复合肥或高品质液体通用营养液','主要是观叶植物，开花无观赏性且消耗巨量营养，无需施用促花肥',1,'极忌施浓肥、生肥，施肥时严禁将原液直接大量浇灌在木质化根基部，防止灼伤','新长出的椭圆大叶个头严重缩水变小、叶面的乳白花纹斑块褪色缩小变绿、下部老叶疯狂发黄','春季','随时剪除底层老化变黄的干枯大老叶、修剪受损破裂严重的残叶，以及在主干过高过度拔高时进行“短截砍头”重剪更新','特别安全警告：它属于强毒性植物。修剪时必须、绝对佩戴防渗透橡胶手套与防护眼镜！用消毒过的锋利大割刀从老化叶柄基部平整割断。如果主干长得太高导致下部光秃，可在春季用锯子从所需的直立干高度（通常离地15-20厘米处）一刀横向锯断（砍头）。切口处涂抹多菌灵保持彻底干燥。锯断的顶端健康主干可以晾干伤口后插入沙土中，极易重新扦插成活，而留下的老主干基部会重新爆发长出多头华丽的新嫩芽。修剪完后必须立刻大量用肥皂水洗手，并将工具彻底洗净，严防毒素残留','严忌裸手直接修剪碰触其伤口流出的白色乳汁！敏感者皮肤接触会红肿过敏，严禁冬季低温受冻期重剪','{\"fall\": \"秋季天气转凉干燥，长势恢复，可以适当多见温和阳光促进斑纹明亮。秋末降温后严格拉长浇水间隔，完全停止任何施肥，充实粗壮主干，准备过冬。\", \"spring\": \"花叶万年青换盆、分株繁殖与砍头更新的最好黄金期。随着大量斑斓的新椭圆大叶从主干顶部疯狂萌发，确保充足的明亮散射光，干透浇透并恢复施薄肥，常擦拭叶面调湿。\", \"summer\": \"严防酷暑湿热闷根和烈日暴晒。必须移到家里最阴凉、大开窗开门空气强对流通风的强半阴处。供水看土，看到土表面干下去几厘米再浇透，严禁托盘存积水。早晚可以向其巨叶大面积喷雾降温，坚决断肥，严防黑腐。\", \"winter\": \"防寒防冻是生死存亡的核心第一要务！它是极端怕冷的“天南星小霸王”。必须立刻移入12℃以上的温暖房间（15℃以上最佳）。严格控制浇水，盆土不干透绝不频繁浇水，保持盆土高度偏干。暖气房内需远离暖气出风口以防烤干，定期用温水抹布轻轻擦拭斑斓巨叶上的尘埃，提升极佳的室内热带观赏美感。\"}','{\"pests\": [{\"name\": \"红蜘蛛/红盾介壳虫\", \"symptom\": \"在室内空气极度极度干燥密闭且不通风时发生。巨幅叶背聚集密集微小红点，导致斑斓大叶开始大面积失绿、发灰、起皱纹并卷曲\", \"treatment\": \"戴手套，用温水湿布蘸取稀释的肥皂水全面、高频强力擦洗巨幅叶面和叶背，或者喷洒阿维菌素、杀扑磷稀释溶液\"}], \"diseases\": [{\"name\": \"烂根/软腐病/炭疽病\", \"cause\": \"花盆过大，土壤排水极差，频繁频繁给水土壤长期处于死水积水状态导致闷根烂根，或者在高温期环境长期处于空气密闭不通风引发真菌细菌爆发\", \"symptom\": \"巨大的长叶表面产生大量黑色水渍状病斑并软化溃烂，粗壮的主干基部变黑变软软塌发黏、流出酸臭恶臭汁液，整株彻底软倒倒伏\", \"treatment\": \"极难挽救。一旦发生，必须立刻用消过毒的快刀彻底切除变黑病变的主干和烂根。若顶端主干叶片依然绿色健康，可切下涂抹多菌灵在干燥阴凉处裸根晾干三四天，直至切口完全结痂形成硬皮后，再在全新的全颗粒沙质干燥土中重新扦插生根。旧土旧盆彻底扔掉\"}], \"prevention\": \"核心在于控制浇水，管住手、土不干透绝不频繁浇水，并始终保持居家养护环境拥有良好的大开窗空气强通风。\"}','有毒','全株各部位，特别是木质化茎干和叶柄内流出的白色乳汁','天南星科剧毒观叶绿植代表。其英文俗名被称为“哑巴甘蔗”（Dumb cane）。全株乳汁中含有的大量草酸钙针晶、毒性皂苷及某些罕见的蛋白酶毒素。皮肤直接触碰白色乳汁会引发剧烈的皮肤红肿、奇痒、刺痛与水疱；一旦误食，毒素会强烈灼伤并麻痹口腔、舌头和咽喉粘膜，导致其迅速极度肿胀，引发声带无法发声（变成哑巴）、流涎不止、呼吸极度困难，大量误食严重时可窒息致死','对猫、狗及儿童有严重的强剧毒高风险！由于其叶片色彩白绿斑斓极其好看，长长的粗叶柄易被儿童和宠物抓咬误食。修剪时流出的乳汁更属于高危化学品。必须绝对、必须将其摆放在儿童和宠物绝对、永远无法触及的稳固独立区域，或者家有婴幼儿和啃咬控宠物的家庭严禁养殖此植物！修剪时必须严密佩戴全套手套护目镜。','{\"leggy\": \"长期将其摆放在缺乏阳光的客厅死角或完全没有对流通风的昏暗走廊，导致粗壮的主干和长叶柄为了找光而发生严重的过度长长、拔高（高脚徒长），叶柄变得细长、软弱无力向外大幅折断垂软，且巨大的叶片会缩水变小，引以为傲的乳白斑纹完全褪色减淡变成普通的苍绿色，彻底失去华丽的观赏美感。\", \"noBloom\": \"室内附生或盆栽栽培环境下由于空间和热带阳光积温高度受限，几乎99.9%一辈子都不会抽佛焰苞开花，这完全属于正常的植物生理特性，无需处理，主要欣赏其斑斓如画的巨幅开裂大椭圆叶片。\", \"drooping\": \"巨幅的椭圆大叶整体失去弹性、软绵绵顺着主干向下耷拉软塌瘫软。多为彻底严重缺水脱水的前兆（及时给水可恢复挺拔）；或者是由于频繁大水根系已经彻底溃烂死掉、丧失吸水和固定功能，需立刻排查茎干基部是否发黑发软。\", \"mainTaboo\": \"裸手直接修剪导致乳汁中毒、频繁频繁大水浇灌导致土壤黏重死水、盛夏酷暑烈日直接直射曝晒，以及冬季遭遇10℃以下的寒流摧毁。\", \"beginnerTip\": \"买回家后觉得它白绿色的叶子太华丽太好看了，就直接裸手去掰它的叶柄来插花，结果乳汁沾到皮肤上导致两只手瞬间剧烈奇痒红肿、起了满手水疱、甚至揉眼睛导致眼睛险些红肿失明，并且由于天天给它大盆浇水，不到两个星期大树就彻底闷根烂成了臭泥。\", \"yellowLeaves\": \"90%以上是由于频繁频繁倒水导致土壤长期泥泞积水死水、根系缺氧窒息黑腐发黄；其次是冬季室内气温骤降受冻、遭遇10℃以下严寒发生严重的冷冻发黄软烂，或者盛夏酷暑烈日直接暴晒灼伤引起的黑斑。\"}','体型宏伟挺拔，大橢圆形叶面上密布的乳白、淡黄花纹斑块斑纹极其鲜艳华丽，对比度极高，如同一幅充满浓郁印第安图腾与热带雨林奔放风情的大型天然油画，是提升现代奢华大客厅、高端写字楼和商业会所空间高贵格调的顶级观叶功勋绿植。','净化空气的卓越功勋霸王。由于体型高大且巨幅叶片表面积惊人，能如同高效空气滤网般强力吸附室内的漂浮灰尘、PM2.5颗粒；并能极高效率地成批吸收室内的甲醛、苯、三氯乙烯、二甲苯等新房装修高浓度化学毒气，吸毒和湿度调节净化能力极强。','具有极强剧毒，严禁任何形式的任何嘴部接触或食用！','无确切且安全的家庭药用价值（因毒性过强，严禁私自调配外敷）','名字带有“万年青”，寓意“健康长寿”、“基业长青”、“阖家平安”、“吉祥如意”，虽然全株有毒，但其向外横展、巨幅斑斓的绿叶在风水学上有强大的镇宅辟邪、化解明堂煞气、汇聚四方财气的刚强植物风水功用（因其带剧毒，在风水上宜摆放在客厅或玄关的远端角落，严禁摆放在靠近卧室、厨房或餐厅的位置）。','宽敞大客厅落地窗旁、大写字楼大堂前台拐角、沙发一侧视觉空白处、老总办公室 corner、高档会所过道、展厅','排水良好的盆栽土','腐叶土:泥炭土:园土:珍珠岩/粗沙 = 3:2:3:2，由于其害怕积水烂根，土壤必须混入足量粗颗粒或沙质介质，盆底必须垫足量陶粒作为排涝防淤层','由于其体型高大宏伟且冠幅横展，必须选用厚重大号、稳重不易倒的经典水泥盆、大号陶盆或高端深筒塑料深盆','口径25-45cm（视植株规格大小选择，必须给予粗壮肉质根宽裕的呼吸防涝空间）','每1-2年春季换盆换土一次（其长势极快，根系很快会顶满全盆）',6.0,7.0,'medium','fast',200,1,1,0,1,'/images/plants/dumb-cane.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:03:27','2026-05-23 10:18:51'),(29,'酒瓶兰','象腿树、蓬莱木','Beaucarnea recurvata','ponytail-palm','天门冬科','酒瓶兰属','肉质','多年生','观叶 / 多肉','墨西哥干热干旱地区','酒瓶兰是一种多年生常绿肉质小乔木。其最大的特征是基部茎干极为肥大肿胀，状似一个巨大的红酒瓶或大象的腿，用以储存大量水分。顶端丛生着细长如线、优美弯曲下垂的绿叶，形似一条条绿色的飘带。它极耐干旱、耐阴，株形奇特，极具热带沙漠风情与现代雕塑美感。','基部大如酒瓶，顶叶细长飘逸的强力耐旱懒人树。','线形，细长如丝带，革质坚韧，全缘，顶端渐尖，向四周自然弯曲下垂','深绿色、亮绿色，表面光滑无毛','直立主干，基部极其肥大肿胀，皮层粗糙呈龟裂状，灰褐色，极像象腿或酒瓶，内含大量储水组织','圆锥花序自叶丛顶端抽出，分枝极多，小花极其细小，室内盆栽极罕见开花','乳白色或淡黄色','夏季（6-8月） / 室内盆栽通常需全日照养护数十年方可偶尔开花','少见','巨大的大象腿茎干直立，顶端爆发出无数条细长如发丝的绿叶飘逸垂挂，刚柔并济，整体株形奇特古朴，充满极简现代感与雕塑质感。','bright_direct',5,10,'极其喜光。最喜充足明亮的直射阳光，耐全日照。光照充足能让其基部更加肥大肥硕、叶片紧凑坚挺。虽极耐半阴，在室内普通客厅能长期存活，但长期缺乏光照会导致叶片变软变细、基部生长停滞。','rarely',15,30,'酒瓶兰基部肥大，能储藏恐怖的水分，耐旱能力高居室内绿植前列。浇水遵循“宁干勿湿”、“干透浇透”原则。必须等盆土完全彻底干透、甚至干到土壤开裂时再稍微浇透水。春夏季生长期随温度升高可正常浇水，秋冬季及低温期必须严格控水偏干，甚至彻底断水。','干透浇透','每15-20天1次','每10-15天1次（高温蒸发期，表土干透再浇，切勿让托盘存有积水）','每20-25天1次（秋末随降温大幅拉长间隔）','每30-40天1次或彻底断水，保持土壤绝对干燥有利于提高抗寒防冻能力','严忌高频率频繁倒水导致盆土长期积水死水泥泞，这会导致其木质化的肥大基部及根系迅速黑腐溃烂，整株彻底死亡','普通的室温自来水即可','low','极喜干燥环境，不耐高湿。对普通室内干燥、空调房有极强的抗性。无需任何形式的叶面喷水，保持居家常年良好的空气对流即可。',18,32,5,38,0,'客厅大落地窗旁、阳光阳台一侧、玄关大位、沙发旁明亮处、光照极好的独立书房、办公室前台一侧','喜阳光充足、温暖干燥环境，极耐干旱，怕积水闷根，喜肥沃、排水极佳的沙质壤土。','喜温暖干燥，极其耐高温与暴晒。最适生长温度为18-32℃。具有较强的耐寒力，冬季室内越冬温度只要保持在5℃以上即可安全防冻伤。','平衡20-20-20','none','酒瓶兰长势缓慢，极耐贫瘠，对肥料依赖度极低。可在春季和秋季生长季，随浇水追施1-2次极其稀薄的无机观叶复合平衡肥（或撒入十几粒缓释肥颗粒）即可。盛夏酷暑和冬日寒冷期严禁施肥。','春季和秋季','极其稀薄的高磷钾、低氮型多肉专用肥或复合平衡液肥','主要是观叶植物，完全无需单独施用促花肥',1,'极忌浓肥、生肥，严禁直接把无机复合原液大量倾倒在靠近其肥大基部的土壤中防止灼伤','长期不给肥基本无明显表现，过肥反而极易引发烂根黑腐、导致叶片迅速干枯掉落','春季','随时剪除底部老化变黄的干枯线老叶、剪除受损严重或折断的羽状绿带，以及剪掉发黑的坏死气生根','用消毒剪刀紧贴直立主干基部，将变黄的叶片平整剪断即可。如果是局部小面积的叶尖枯焦，可顺着叶子线条用剪刀修剪掉焦尖，保持自然美感','绝对严禁切断或割伤位于主干顶端中心爆发喷泉状叶丛的生长点（叶心顶芽），顶芽一旦被彻底割死，全株将无法向上继续生长','{\"fall\": \"秋季空气转凉，逐步拉长浇水间隔。尽量让其多晒温和的秋季直射光，充实茎干和基部组织硬度，提高抗寒抗冻抗御灾害力。\", \"spring\": \"酒瓶兰换盆造型的黄金期。随着气温回升，将其移到光照最强烈的明亮位置，适量恢复浇水，可追施一次极其稀薄的缓释肥。\", \"summer\": \"极其耐热耐暴晒。在室内无需任何特意遮阴，晒太阳越多基部酒瓶越厚实挺拔。核心是必须保持全天候强开窗通风，严防闷热死水积水。\", \"winter\": \"防寒。必须移入室内保暖（5℃以上）。整个冬季严格控制浇水或彻底断水，停止一切肥水，保持盆土完全干燥，全天候多晒室内阳光。\"}','{\"pests\": [{\"name\": \"介壳虫/红蜘蛛\", \"symptom\": \"在室内空气过于干燥密闭且完全不通风时发生。线形叶片对生丛深处、或凹槽间出现白色棉絮状或硬壳小虫，吸食汁液\", \"treatment\": \"用酒精棉球小心逐个擦拭掐死，数量多时喷洒蚧必治、杀扑磷稀释溶液\"}], \"diseases\": [{\"name\": \"基部黑腐病/根腐病\", \"cause\": \"花盆透气太差、频繁大水浇灌导致盆土长期处于湿漉漉的泥泞积水状态导致闷根腐烂真菌滋生\", \"symptom\": \"肥大的酒瓶基部突然变黑变软，轻轻一按就下陷、并流出带有酸臭味的褐色黏液，整株叶丛开始疯狂枯萎\", \"treatment\": \"极难救治。一旦发生基部深度软化变黑，多全株报废。若病发初期，可脱盆切除所有变黑腐烂的部分，涂抹多菌灵粉末裸根晾干一周，重新在全颗粒干燥沙土中尝试插盆栽培\"}], \"prevention\": \"控制浇水是预防一切多肉木本病害的万能钥匙。常年保持养护环境拥有良好的空气流通对流。\"}','无毒','无','全株完全无毒。属于100%绝对无毒的家庭常绿观赏植物，无任何化学毒素，全株汁液安全无害','对猫、狗及儿童绝对安全。被ASPCA（美国动物保护协会）官方认证的对宠物完全无毒友好的顶级植物。由于其顶端下垂的长叶片极像逗猫棒在晃动，猫咪极度喜欢抓挠啃咬其线形叶。虽然误食安全无毒，但会咬坏叶片破坏美感，宜放在稳固稳重的矮凳上。','{\"leggy\": \"长期将其摆放在缺乏光线的客厅死角或昏暗的内侧台面，导致顶部的线片为了找光而发生严重的无限制伸长、拔高（俗称高脚徒长），叶片变得细长、软弱无力无法挺立下垂，酒瓶状基部也会瘦弱干瘪变细，彻底失去蜡质层的雕塑挺拔感。\", \"noBloom\": \"室内观叶栽培由于空间受限、光照积温、红外线强度严重不够，几乎99.9%一辈子都不会开花，属于完全正常的生理现象，主要作为古朴多肉盆景观赏。\", \"drooping\": \"顶部爆发的喷泉状叶丛整体失去弹性和支撑力、垂头丧气地瘫软低垂。多为基部已经彻底黑腐软烂失去固定，或遭遇了大降温受冻受灾、根系全烂死所致。\", \"mainTaboo\": \"频繁频繁大水浇灌、托盘内存积水、冬季遭遇3℃以下的极端低温重创。\", \"beginnerTip\": \"觉得它形似一棵小树就每天回家都关切地给它盆里灌满大杯水，结果不到两个星期，它最核心、最名贵的酒瓶状肥大基部就全部黑腐化成了臭稀泥。\", \"yellowLeaves\": \"最普通、最普遍的是由于频繁倒水盆土长期积水导致根系缺氧黑腐引发叶片大面积发黄；或者是遭遇了5℃以下的严寒受冻，以及长期极度缺水引起的底层老叶干黄脱落。\"}','基部肥大粗犷如象腿酒瓶，顶叶细长飘逸如绿色喷泉，刚硬坚挺与柔美浪漫在主干上交织碰撞，极具高级的工业冷淡风、极简主义与北欧现代生活的现代雕塑格调。','净化空气的持久小助手。由于长势慢、呼吸速率平稳，能稳定地吸附室内的浮尘、过滤吸收微量的甲醛和有害化学气体，具有极高的常青观赏与长线美化性能。','无食用价值','无家庭药用价值','名字极其带有“酒瓶”（谐音久平，长久平安）与“蓬莱”，寓意“富贵吉祥”、“财源广进”、“健康长寿”、“大吉大利”，其刚毅古朴、常青闪耀的奇特株形在风水学上有镇宅辟邪、化解客厅硬角煞气、凝聚家宅坚毅朝气的奇强风水植物功用。','大客厅落地窗旁、大玄关一侧大位、明亮书房窗边、沙发拐角一侧、写字楼老总位、高档店铺前台一侧','排水良好的盆栽土','腐叶土:粗沙/多肉颗粒土:园土 = 2:2:1，或大量加入蛭石、珍珠岩，必须保证优异的排涝和透气性，盆底垫好防积水陶粒排水层','透气和排水性好的大号红陶盆、重质中式深紫砂盆或质感高级的简约塑料控根盆（需有一定重量防止头重脚轻倒伏）','口径20-35cm（根据基部酒瓶大小选择，不宜选用过大过深的盆防存水闷根）','每2-3年春季换盆、换土一次（因长势缓慢，无需频繁换盆）',6.0,7.5,'easy','slow',150,1,1,1,1,'/images/plants/ponytail-palm.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:03:27','2026-05-23 10:18:51'),(30,'合果芋','箭叶芋、紫梗芋、五指合果芋','Syngonium podophyllum','arrowhead','天南星科','合果芋属','藤本','多年生','观叶 / 水培','中美洲及南美洲热带雨林底层','合果芋是一种多年生常绿常青蔓生草本植物。其最大的特征是叶形具有奇妙的“变态发育”过程：幼年期叶片呈精巧的箭头形（三角形或戟形），成熟后会逐渐分裂成羽状三裂或五裂的多指形。它具有极强的耐阴性、极高地空气净化与极易水培的优良特性。近年来其粉色（粉佳人）、花叶等园艺品种风靡一时，是极具文艺清新调性的室内观叶植物。','叶形如箭斑斓、极耐阴且生命力野蛮的雨林小水培明星。','幼叶呈标准的三角形或心状箭形，基部深深凹陷；随着植株成熟，叶片会逐步分裂变成三裂或掌状五裂的盾形，全缘，叶柄长而绿色','翠绿色、黄绿色，沿主脉两侧常分布着大面积银白色或乳白色、粉红色的华丽云雾状网纹斑块（根据园艺品种而异）','茎蔓性、肉质化，幼时直立丛生，后逐渐抽长演变成长长的匍匐攀援藤蔓，节位极易生根并抽出长长的白色气生根','佛焰苞花序自叶腋抽出，外面呈浅绿色或乳白色，包裹着棒状的肉穗花序，在室内普通家庭盆栽环境下几乎100%不会开花','白绿色、淡黄色','夏季（5-7月） / 室内家庭盆栽极其罕见开花','无','幼苗期株形低矮丰满，繁密精美的心状箭叶向四周散射；随着藤蔓抽长，枝蔓开始自然下垂轻盈低垂，呈现出一种充满自然野趣与热带柔美浪漫的飘逸线条。','low',2,5,'高度耐阴。最喜明亮舒适的散射光或半阴环境。能在缺乏直射光的昏暗室内角落或洗手间长期健康健康生存。绝对铁律：严禁盛夏烈日暴晒！强光直射会瞬间将娇嫩斑斓的箭叶大面积烤焦、干枯发白变黄。长期在绝对黑暗处养护，叶面的粉色或银白斑纹会褪色变绿减淡。','frequent',3,5,'合果芋属于“喜水派”，叶片多而薄、水分蒸腾速率极快，不耐干旱。生长期必须保持盆土充沛湿润。遵循“见干见湿”原则，只要表土表面1-2厘米一变干就必须立刻、彻底地浇透水。偶尔一次忘记浇水导致其软瘫低垂，及时浇水能快速恢复。水培则需每5-7天换干净清水一次。冬季低温期必须适度延长浇水时间偏干，防止冷湿闷根冻坏。','见干见湿 / 喜湿忌干','每3-5天1次（生长期保持土壤温润）','每2-3天1次（高温干燥期，除大水量浇透外必须早晚高频向叶面周围喷洒雾气，或在盆底垫托盘存少许水）','每4-6天1次','每8-12天1次，严格遵循不干不浇，并确保用晾置过的温自来水浇灌','严忌盆土彻底干透开裂变成硬块、严忌花盆内长期大水死水泡盆引发闷根导致叶片泛黄大面积脱落','普通的室温自来水即可（水培建议使用纯净水或晾置过的自来水）','high','原产热带雨林，喜高湿度的空气环境。喜环境湿润。在春夏季生长期和北方供暖干燥季节，需经常向叶面高频喷雾，或直接将其放置在加湿器风口，能让箭叶色彩更加粉嫩油亮。',16,28,10,35,0,'洗手间窗台内侧、明亮厨房、北向书桌一角、客厅无阳光直射茶几、书架边缘垂吊、无光的办公桌台面','喜温暖湿润、半阴环境，极耐阴，生命力极其极其旺盛、抗逆性极强，怕干旱，不耐寒，对土壤要求不严，极喜半水半土及纯水培环境。','喜温暖舒适、多湿的热带底层气候，生长适温为16-28℃。耐热性强，盛夏只要不缺水可正常疯长。不耐严寒，冬季室内越冬室温需维持在10℃以上，低于8℃极易引发严重的冷冻冻伤导致整盆叶片发黑软烂溃烂。','平衡20-20-20','biweekly','合果芋生命力野蛮、长势极其恐怖，属于较为喜肥的植物。在春、夏、秋三季生长旺季，每两周随浇水追施一次观叶类水溶复合液肥（浓度减半）。粉色或花叶品种应适当增施磷钾肥、减少氮肥比例，否则氮肥过多会导致其引以为傲的粉红色彩褪色、变成普通的杂绿色。盛夏酷暑（超过35℃）或冬季低温期必须完全停肥。','春季和秋季','稀薄的低氮高钾型观叶植物专用肥或复合平衡型液体营养液','观叶藤本，完全无需单独施用任何催花肥',1,'极忌浓肥、生肥，严禁将未稀释的肥料原液直接浇灌在靠近其娇嫩基部的土表面','新长出的箭叶个头明显变小变薄、叶面斑纹云雾色彩变得暗淡模糊、叶柄细弱严重易软瘫下垂','春夏季（全生长季均可进行修剪）','随时剪除底部老化变黄的厚老叶、修剪过长或零乱的攀援藤蔓，以及在株形过度徒长长高时进行“打顶摘心”控制长势','合果芋极耐修剪且极易扦插繁殖。用消毒小剪刀在分枝所需的节位下方1厘米处直接剪断。为了促使其矮胖成丛爆盆，可频繁将长长的藤蔓嫩尖掐断（摘心）。修剪下的任何一段健康长藤蔓只要带有2个以上的节点（哪怕没有叶片），将其平铺或插在微潮的营养土或清水中，在高温高湿下三四天就能迅速生根发芽成为一株崭新的小绿苗','修剪或折断其汁液时必须注意，不可让其毒性乳汁接触到暴露的皮肤伤口或眼睛','{\"fall\": \"秋季空气转凉极度干燥，是发生“干尖焦边”的高危期，必须高频进行叶面空气喷雾。秋末随降温大幅拉长浇水间隔，完全停止一切施肥，充实茎干硬度，准备过冬。\", \"spring\": \"合果芋换盆、松土与剪枝扦插繁殖的最好黄金期。随着大量精美斑斓的新箭叶从各个基部抽出，确保充足的散射光，干透浇透并恢复施稀薄肥，高频往其周围喷雾调湿。\", \"summer\": \"极其耐热，是它的疯狂疯长期。在室内无需遮阴但必须保持环境极佳的开窗强空气流通，严防湿热闷根。供水需高频充分，表土干了就浇透，早晚高频喷雾，坚决断肥防止黑腐。\", \"winter\": \"防寒第一要务！它很怕冷。必须立刻移入10℃以上的温暖室内（最好在暖气房向阳处）。严格控制浇水，盆土不干透绝不频繁浇水，盆土保持高度偏干防冻伤闷根。暖气房内需远离暖气出风口。\"}','{\"pests\": [{\"name\": \"红蜘蛛/红盾介壳虫\", \"symptom\": \"在空气过于干燥密闭且完全不通风时发生。精美箭叶背聚集密集微小红点，导致叶面大面积发灰、斑纹褪色起皱并卷曲\", \"treatment\": \"将整盆植物移到浴室用高压温水全面强力冲洗叶片背面，或喷洒阿维菌素、联苯肼酯药剂\"}], \"diseases\": [{\"name\": \"根腐病/叶斑病\", \"cause\": \"花盆透气太差或黏重，频繁高频频繁倒水导致土壤长期处于死水积水状态导致闷根烂根，或者在高温期环境处于空气密闭不通风下感染真菌\", \"symptom\": \"箭叶边缘突然大面积变黑、产生水渍状化水溃烂，藤蔓基部变黑软烂发黏，整盆叶柄大面积脱落倾倒发臭\", \"treatment\": \"立即脱盆，用利刀切除所有发黑腐烂的根系和软烂藤蔓。若顶端主蔓依然健康绿色，涂抹多菌灵晾干伤口两天后，在全新的微潮水苔或全颗粒沙质干燥土中重新扦插生根。旧土旧盆扔掉\"}], \"prevention\": \"核心在于“通过高频给其周围喷雾常年保持高空气湿度”，同时“坚决管住手、看到土彻底干透后再行浇透水”，强通风。\"}','有毒','全株茎叶、汁液','天南星科植物，其茎叶折断后流出的透明汁液或白色乳汁中含有大量的针状草酸钙结晶以及刺激性蛋白酶。皮肤直接接触汁液可能引发剧烈红肿、过敏瘙痒与刺痛；一旦误食，毒素会强烈灼伤并麻痹口腔和咽喉粘膜，导致其迅速肿胀、流涎不止、无法发声并伴有胃肠道严重痉挛呕吐','对猫、狗及儿童有严重的强毒性风险！由于其叶片色彩斑斓、形状似好玩的箭头，长长的长叶柄极易吸引儿童抓挠或宠物猫咪玩耍啃咬。必须绝对将其摆放在儿童和宠物绝对无法触及的高处，或者采用悬挂吊盆养护，严防宠物误食中毒。','{\"leggy\": \"长期将其摆放在缺乏阳光的暗淡角落或完全不通风的密闭死角，导致蔓性茎为了找光而发生严重的过度长长、拔高（俗称长成细长妖精），藤蔓又细又长又软，节间距极宽极其稀疏，原本饱满爆盆的箭叶也缩水变小、变薄，引以为傲的粉红或银白云雾纹理完全褪色减淡变成普通的苍绿色，彻底失去华丽的文艺观赏美感。\", \"noBloom\": \"室内附生或水培栽培环境下由于缺乏雨林底层特有的红外线直射积温，几乎100%一辈子都不会抽佛焰苞开花，主要作为常绿高级多彩观叶植物观赏，属于完全正常的生理特性，无需处理。\", \"drooping\": \"柔嫩的箭叶和叶柄整体失去弹性、软绵绵毫无支撑力地向盆沿四周瘫软瘫倒、耷拉。多为彻底严重缺水脱水的前兆（及时给水可快速恢复挺拔）；或者是由于频繁大水根系已经彻底溃烂死掉、丧失吸水和固定功能，需立刻检查主藤蔓基部是否变黑发黏。\", \"mainTaboo\": \"裸手直接修剪导致乳汁中毒、频繁频繁大水浇灌、盛夏酷暑强光直射暴晒，以及冬季遭遇8℃以下的低温摧毁。\", \"beginnerTip\": \"买回家后觉得粉色（粉佳人品种）太梦幻太文艺了，天天都有事没事往大盆里频繁倒水，结果不到两个星期它高级的梦幻粉色叶子就全部闷根发黄、藤蔓烂成了一地酸臭的黏泥。\", \"yellowLeaves\": \"90%以上是由于频繁频繁大水浇灌导致土壤长期处于死水泥泞积水状态、地下根系窒息黑腐发黄；其次是冬季气温骤降受冻、遭遇10℃以下严寒发生严重的冷冻发黄软烂，或者盛夏酷暑烈日直接暴晒灼伤引起的焦黑黑斑。\"}','叶形精美多变（从箭形发展到掌状分裂），叶面上布满银白或粉红、浅绿交织的华丽云雾网纹斑块，色泽极其粉嫩清新、对比斑斓，自带浓浓的北欧小文艺、ins风和田园生活的精致格调，是放置在桌面、书架和水培造景的完美小功勋绿植明星。','净化空气的高能卓越功勋。由于蒸腾效率极高且长势繁茂，能如同高效空气滤网般强力吸附室内的漂浮灰尘、PM2.5微粒；并能极高效率地成批吸收、过滤室内的甲醛、氨气、苯及二氧化碳等新房装修化学毒气，调节空气湿度净化能力极强。','具有较强毒性，严禁任何形式的任何嘴部接触或食用！','无家庭药用价值','名字带有“合果”（谐音和睦、百年好合）与“芋”（谐音富裕），寓意“阖家欢乐”、“百年好合”、“前程似锦”、“吉祥如意”，虽然全株有毒，但其向外舒展、错落有致的斑斓箭叶在风水学上有强大的促进家庭感情、柔化生硬电脑桌棱角、兴旺窗台温馨朝气的极佳风水作用。','办公室办公桌台面、明亮小书桌台面、洗手间内侧窗台、书架顶部边缘垂吊、客厅茶几边缘无直射光处、北向卧室内侧台面','排水良好的盆栽土','腐叶土:泥炭土:珍珠岩/粗沙 = 3:2:1，或者直接购买疏松透气的高品质通用营养土，盆底做好排水层','吊盆（悬挂专用盆）、简约清新的小号陶瓷盆、玻璃水培瓶或长条种菜盆','口径12-20cm（它根系生长快，容器不宜过小过深）','每年春季结合修剪分株进行换盆、换土一次（因抽蔓分蘖速度快）',5.5,6.5,'easy','fast',40,1,0,0,1,'/images/plants/arrowhead.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:03:27','2026-05-23 10:18:51'),(31,'绿宝石','绿宝石喜林芋、长心叶蔓绿绒、大叶蔓绿绒','Scindapsus pictus','satin-pothos','天南星科','喜林芋属','藤本','多年生','观叶','哥伦比亚及南美洲热带雨林中','绿宝石是一种多年生大型常绿攀援藤本植物。其茎干粗壮，气生根发达。最大的特征是具有极其巨大的、呈完美锐尖箭形或长心形的叶片，表面平滑无毛，深绿色，在明亮光线下散射出如同高品质祖母绿或绿宝石般的高贵奢华光泽。它长势旺盛，通常设立棕柱让其向上攀爬攀援，体型高大宏伟，是室内非常受欢迎的高端热带观叶树种。','大叶箭形如翠玉，主干挺拔粗壮、充满南美奢华热带风情的高大网红树。','巨大的长心形或锐尖箭形，先端长渐尖，基部呈深耳状凹陷全缘，厚革质，长叶柄粗壮略带紫红色','深绿色、浓绿色，油亮闪耀，表面具有极其强烈的高级蜡质层和如绿宝石般深邃的光泽，新芽和叶柄常带有一丝高贵冷艳的红褐色','主茎粗壮挺拔，肉质化并逐渐木质化，绿色或紫褐色，分枝节间距整齐，节位极易生出如粗绳索般的发达灰褐色气生根','佛焰苞花序自叶腋抽出，佛焰苞通常为外深红内乳白，形似厚小船包裹肉穗花序，在室内普通家庭盆栽环境下极罕见开花','紫红色、乳白色','夏季（5-7月） / 室内盆栽通常需养护多年且阳光充足才偶尔开花','少见','主干依靠椰棕柱直立向上木质化生长，向四周错落伸出粗长的紫红色叶柄，托举着巨幅、坚挺油亮的祖母绿大箭叶，整体风格极其硬朗、挺拔且极具热带原始雨林奢华的存在感。','medium',4,6,'最喜充足明亮的散射光或半阴环境。它非常耐阴，能在普通客厅昏暗的 corners 长期健康存活。绝对铁律：极忌盛夏酷暑烈日暴晒！强光直射会瞬间将巨大的叶片大面积灼伤发白、烤焦焦黑并彻底失去绿宝石油亮感。冬季需多见温和阳光。','weekly',5,8,'绿宝石体型巨大，粗壮的茎干和根系能储藏大量水分，具有较强的耐旱能力，最怕土壤长期处于湿漉漉的死水泥泞状态。浇水严格遵循“见干见湿”原则。必须等盆土表层往下3-4厘米彻底变干、摸起来没有一丝潮气后再行浇透水。秋冬季降温后长势减缓，必须严格控水偏干，等土干透了再浇一点水，防止低温湿热闷根烂掉。','见干见湿','每5-7天1次','每3-5天1次（高温生长期，除大量浇透水外必须早晚高频向叶面周围喷雾降温防干燥）','每7-10天1次（随着秋末降温逐渐延长浇水时间）','每12-15天1次，严格遵循土不干透绝不频繁倒水，保持土壤微干以防冻伤闷根','严忌高频率频繁倒水导致土壤长期处于死水积水状态，这会导致其粗壮的肉质地下主根系迅速缺氧窒息腐烂，地上巨叶会无缘无故大面积发黄溃烂下垂脱落','普通的室温自来水即可','high','原产南美多雨热带丛林，对空气湿度要求较高。喜空气湿润环境。在春夏季生长期和冬季北方暖气房干燥期，过低的空气湿度会导致叶尖发生干焦卷曲。需定期用大型喷雾器向其巨叶表面和周围高频喷雾，或用湿布擦拭巨叶调湿。',18,30,10,35,0,'明亮客厅落地窗旁、大堂角落、沙发拐角处、书房大窗边、落地大阳台内侧、写字楼明亮过道旁','喜温暖湿润、强散射光的半阴环境，极耐阴，长势极快，生命力强健抗病，忌烈日暴晒，怕长期土壤积水死水闷根，极怕寒冷，喜疏松肥沃、富含腐殖质、排水极佳的酸性壤土。','喜温暖舒适、高湿的热带气候，最适生长温度为18-30℃。较抗酷暑。不耐严寒！冬季室内越冬室温建议死守在10℃以上，低于8℃极易发生严重的冻害烂根，导致地上巨幅大叶疯狂变黑软烂、全株崩溃脱落。','平衡20-20-20','monthly','绿宝石生命力旺盛、体型肥硕，在春、夏、秋三季生长旺季对养分有一定需求。可每月施用一次稀薄的无机观叶复合液肥，或在开春时，在盆土表面定期埋入20-30粒长效平衡缓释肥颗粒即可。主要补充氮钾肥促进大箭叶油绿。盛夏高温（超过35℃）或冬季低温期必须完全停止施肥防止烧根。','春季和秋季','稀薄的富含氮素的观叶类平衡复合肥或液体通用营养液','观叶绿植，完全无需单独施用促花肥',1,'极忌浓肥、生肥，严禁将未稀释的肥料原液直接大量浇灌在靠近其根基部防止发生局部烧灼','新长出的箭形大叶个头严重缩水变小、叶色发淡发白失去绿宝石的祖母绿蜡质光泽、长势极其缓慢','春季','随时剪除底部老化变黄的干枯大老叶、修剪受损开裂严重的残叶，以及修剪过长横出的粗糙气生根','用消毒过的锋利大割刀从发黄老叶的粗壮叶柄基部紧贴主干平整割断。粗大的气生根如果过多引向零乱，可以用剪刀适当剪短，但不可全部剃光。若植株长得太高超过室内空间，可以在春季从所需的直立高度处一刀拦腰截断（砍头更新），切口涂多菌灵防黑腐，截下的顶端健康主干晾干后可重新扦插生根','修剪底部老叶柄或折断茎干时动作要慢，特别警告：切勿让其白色或透明乳汁沾染到暴露的皮肤伤口或眼睛中','{\"fall\": \"秋季天气转凉干燥，长势恢复，可以适当多见温和阳光促进叶面光泽。秋末降温后严格拉长浇水间隔，完全停止任何施肥，充实粗壮主干，准备过冬。\", \"spring\": \"换盆、修剪老叶与砍头更新的最好黄金期。随着大量新祖母绿大箭叶从主干顶部疯狂爆发萌发，确保充足的明亮散射光，干透浇透并恢复施薄肥，常擦拭叶面调湿。\", \"summer\": \"严防酷暑湿热闷根和烈日暴晒。必须移到家里最阴凉、大开窗开门空气强对流通风的强半阴处。供水看土，看到土表面干下去几厘米再浇透，严禁托盘存积水。早晚可以向其巨叶大面积喷雾降温，坚决断肥，严防黑腐。\", \"winter\": \"防寒防冻是生死存亡的核心第一要务！必须立刻移入10℃以上的温暖房间（最好有暖气房内向阳窗台）。严格控制浇水，盆土不干透绝不频繁浇水，盆土保持高度偏干。暖气房内需远离暖气出风口以防烤干，定期用温水抹布轻轻擦拭巨幅箭叶上的尘埃，保持其亮绿油美感。\"}','{\"pests\": [{\"name\": \"红蜘蛛/红盾介壳虫\", \"symptom\": \"在室内空气极度极度干燥密闭且不通风时发生。巨幅叶背聚集密集微小红点，导致大箭叶开始大面积失绿、发灰并起皱纹\", \"treatment\": \"用温水湿布全面、高频强力擦洗巨幅叶面和叶背，或者喷洒阿维菌素稀释溶液\"}], \"diseases\": [{\"name\": \"根腐病/叶斑病\", \"cause\": \"花盆透气太差或盆大，频繁大水浇灌导致土壤长期处于死水积水状态导致闷根烂根，或者在高温期环境长期处于空气密闭不通风引发真菌爆发\", \"symptom\": \"巨大的长叶表面产生大量黑色水渍状病斑并软化溃烂，粗壮的主干基部变黑变软软塌发黏，拔出后根系发黑恶臭中空\", \"treatment\": \"立即脱盆，用利刀切除所有发黑腐烂的根系和主干坏死部分。若顶端主干叶片依然绿色健康，可切下涂抹多菌灵在干燥阴凉处裸根晾干两三天，直至切口完全结痂形成硬皮后，再在全新的全颗粒沙质干燥土中重新扦插生根。旧土旧盆彻底扔掉\"}], \"prevention\": \"核心在于控制浇水，管住手、土不干透绝不频繁浇水，并始终保持居家养护环境拥有良好的开窗空气强通风。\"}','有毒','全株各部位茎叶流出的白色或透明汁液','天南星科植物，全株汁液中含有大量的针状草酸钙结晶以及强刺激性化学有毒蛋白酶。皮肤直接触碰汁液会引发剧烈的皮肤红肿、奇痒、刺痛与过敏红斑；一旦误食，毒素会强烈灼伤并麻痹口腔、舌头和咽喉粘膜，导致其迅速极度肿胀，引发声带麻痹无法发声、流涎不止、严重呕吐以及胃肠道剧烈痉挛','对猫、狗及儿童有严重的强毒性高风险！由于其巨幅的大箭叶极其挺拔好玩，长长的粗叶柄易被儿童和宠物抓咬误食。修剪时流出的汁液更属于高危过敏源。必须绝对将其摆放在儿童和宠物绝对无法触及的稳固独立区域。修剪操作时需严格佩戴防渗透橡胶手套。','{\"leggy\": \"长期将其摆放在缺乏阳光的客厅死角或完全没有对流通风的昏暗走廊，导致粗壮的主干和长叶柄为了找光而发生严重的过度长长、拔高（高脚徒长），叶柄变得细长、软弱无力向外大幅下垂，且巨大的叶片会缩水变小，引以为傲的绿宝石蜡质油亮光泽完全褪色减淡变成普通的苍绿色，彻底失去华丽的奢华观赏美感。\", \"noBloom\": \"室内附生或立式栽培环境下由于空间和热带阳光积温高度受限，几乎99.9%一辈子都不会开花，这完全属于正常的喜林芋属生理特性，无需处理，主要欣赏其祖母绿常青的大箭叶结构。\", \"drooping\": \"巨幅的锐尖大叶整体失去弹性、软绵绵顺着棕柱向下耷拉软塌瘫软。多为彻底严重缺水脱水的前兆（及时给水可恢复挺拔）；或者是由于频繁大水根系已经彻底溃烂死掉、丧失吸水和固定功能，需立刻检查直立主茎基部是否变黑变软。\", \"mainTaboo\": \"裸手直接修剪导致乳汁中毒、频繁频繁大水浇灌导致土壤黏重死水、盛夏酷暑烈日直接直射曝晒，以及冬季遭遇5℃以下的严寒打击。\", \"beginnerTip\": \"买回家后觉得它充满了南美热带雨林的风情，每天回家都往大盆里频繁倒水，结果不到两个星期它强壮的主干根基就全部闷根黑腐，整株巨树连同椰棕柱一块瘫软砸在了地上、变成了一地软烂的臭泥。\", \"yellowLeaves\": \"90%以上是由于频繁频繁倒水导致土壤长期泥泞积水死水、根系缺氧窒息黑腐发黄；其次是冬季室内气温骤降受冻、遭遇8℃以下严寒发生严重的冷冻发黄软烂，或者盛夏酷暑烈日直接暴晒灼伤引起的黑斑。\"}','体型高大挺拔，巨幅的尖锐箭形大叶油亮闪耀，散射出极其强烈、高贵奢华的祖母绿蜡质光泽，自带浓郁的南美热带雨林与现代极简软装的高级奢华格调，是填补大客厅、办公室大空间软装空白的顶级功勋观叶植物。','净化空气的高能卓越功勋霸王。由于体型高大且巨幅叶片表面积惊人，能如同高效空气滤网般强力吸附室内的漂浮灰尘、吸附微小化学颗粒；并能极高效率地成批吸收室内的甲醛、苯、三氯乙烯、二氧化碳等装修高浓度化学毒气，吸毒和湿度调节净化能力极强。','具有较强毒性，严禁任何形式的任何嘴部接触或食用！','无家庭药用价值','名字带有“绿宝石”，寓意“富贵吉祥”、“基业长青”、“阖家平安”、“财源广进”，在风水学上有强大的镇宅辟邪、化解四方煞气、凝聚滚滚财气的刚强植物风水效果（因其带毒，在风水上宜摆放在大厅的远端角落，严禁靠近床头或餐桌）。','大客厅落地窗旁、大写字楼大堂前台角落、沙发一侧视觉空白处、写字楼老总位、高档会所过道、展厅','排水良好的盆栽土','腐叶土:泥炭土:园土:珍珠岩/粗沙 = 3:2:2:2，由于其根系发达且害怕积水闷根，土壤必须混入足量粗颗粒或沙质介质，盆底必须垫足量陶粒作为防淤防涝层','由于其体型高大宏伟且横展较宽，必须选用厚大号、稳重不易倒的经典水泥盆、大号陶盆或高端深筒塑料深盆以防头重脚轻歪倒','口径25-45cm（视树木规格大小选择，必须给予粗壮肉质根宽裕的呼吸排涝防淤空间）','每1-2年春季换盆换土一次（其肉质根系长满速度极快）',6.0,7.0,'easy','fast',200,1,1,0,1,'/images/plants/satin-pothos.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:04:17','2026-05-23 10:18:51'),(32,'白雪公主','白雪公主万年青、粗肋草','Aglaonema commutatum','chinese-evergreen','天南星科','粗肋草属','草本','多年生','观叶 / 水培','亚洲热带地区（园艺培育品种）','白雪公主是万年青家族中极其华丽的一种多年生常绿草本植物 [cite: 1]。其最大的特点是叶片上密布着大面积乳白色至白绿色的斑块，仅在边缘和中脉留有翠绿线条，仿佛披了一层白雪，因而得名 [cite: 1]。它极为耐阴，株形紧凑，色彩明亮，能为阴暗的室内角落带来一抹清新的亮色 [cite: 1]。','叶面覆雪斑斓，清秀耐阴的室内百合质感绿植 [cite: 1]。','披针形至长椭圆形，先端渐尖，全缘革质，长叶柄基部具鞘包裹茎干 [cite: 1]','乳白色、白绿色为主，夹杂着不规则的翠绿色斑点，叶缘和中脉为深绿色 [cite: 1]','直立，肉质，多分枝，随着生长基部会稍微木质化，灰绿色 [cite: 1]','佛焰苞花序自叶腋抽出，苞片绿色或黄绿色，包裹着棒状的肉穗花序，无明显观赏价值 [cite: 1]','黄白色、绿白色 [cite: 1]','4-6月（春夏季） / 室内盆栽偶尔开花 [cite: 1]','少见 [cite: 1]','呈紧凑、丰满的丛生状。长长的叶柄托举着白绿交织、色彩明亮的披针形大叶向四周自然平展，显得极为清秀、优雅且富有现代北欧格调 [cite: 1]。','low',2,5,'高度耐阴 [cite: 1]。最喜温暖明亮的散射光或半阴环境 [cite: 1]。极忌盛夏烈日暴晒，强光直射会瞬间将娇嫩的白斑大叶成片灼伤、烤焦焦黑 [cite: 1]。若长期处于绝对黑暗处，叶面银白色的斑块会逐渐变淡变绿 [cite: 1]。','weekly',5,8,'遵循“见干见湿”原则 [cite: 1]。等盆土表面往下2-3厘米彻底变干后再行浇透水 [cite: 1]。它具有一定耐旱性，偶尔忘记浇水不会致死，但最怕土壤长期处于死水积水状态 [cite: 1]。冬季低温期生长缓慢，必须严格控水偏干 [cite: 1]。','见干见湿 [cite: 1]','每5-7天1次 [cite: 1]','每3-5天1次（根据干燥情况，可配合高频叶面喷雾） [cite: 1]','每7-10天1次 [cite: 1]','每12-15天1次，严格遵循土不干透绝不频繁倒水 [cite: 1]','严忌花盆底部托盘积水不退，这会导致其肉质根系迅速窒息腐烂，表现为大叶片疯狂发黄脱落 [cite: 1]','普通的室温自来水即可 [cite: 1]','high','喜略微湿润的空气环境 [cite: 1]。对普通室内干燥有一定抗性，但在夏季酷暑期或冬季北方暖气房内，过低的湿度会导致叶尖干枯卷曲 [cite: 1]。可定期向叶面及周围喷雾调湿 [cite: 1]。',16,28,10,35,0,'客厅茶几边缘、明亮书桌、洗手间窗台、无直射光的卧室角落、办公室隔断隔板、办公桌台面 [cite: 1]','喜温暖湿润、半阴环境，极耐阴，生命力强健，忌烈日暴晒，怕长期土壤积水闷根，喜疏松肥沃、排水极佳的微酸性腐殖土 [cite: 1]。','喜温暖舒适、多湿的气候，不耐寒 [cite: 1]。生长适温为16-28℃ [cite: 1]。冬季室内越冬温度建议保持在10℃以上，低于8℃极易发生严重的冷冻冻伤导致叶片萎蔫变黑软烂 [cite: 1]。','平衡20-20-20','monthly','喜薄肥 [cite: 1]。在春、夏、秋三季生长旺季，每月施用一次稀薄的观叶类平衡液肥颗粒即可 [cite: 1]。适当补充钾肥，能让其白绿斑纹对比更加闪耀华丽 [cite: 1]。盛夏酷暑（超过35℃）或冬季低温期必须完全完全停肥 [cite: 1]。','春季和秋季 [cite: 1]','稀薄的富含钾素的观叶类平衡复合肥或水溶性通用营养液 [cite: 1]','主要是观叶植物，开花无观赏性，完全无需施用促花肥 [cite: 1]',1,'极忌浓肥、生肥，严禁直接将固体复合肥颗粒大量堆积在根颈基部 [cite: 1]','新长出的椭圆大叶个头严重缩水变小、叶面的乳白花纹斑块褪色缩小变绿、下部老叶疯狂发黄 [cite: 1]','春季 [cite: 1]','随时剪除底部老化变黄的枯老叶、修剪受损破裂的残叶，以及剪除没有观赏性的绿色穗状花序 [cite: 1]','用消毒剪刀紧贴直立茎干基部，将变黄的叶柄平整剪断即可 [cite: 1]。剪下的健康带顶芽茎段可以在春季进行扦插繁殖 [cite: 1]','修剪或折断其茎叶时需特别注意，不可裸手直接大面积触碰其伤口流出的白色乳汁 [cite: 1]','{\"fall\": \"秋季长势恢复，可以适当多见温和阳光促进斑纹明亮 [cite: 1]。秋末降温后严格拉长浇水间隔，完全停止任何施肥，准备过冬 [cite: 1]。\", \"spring\": \"换盆、松土与剪枝扦插繁殖的最好黄金期 [cite: 1]。随气温回升逐渐增加浇水施肥，移到有温和散射光的半阴明亮处 [cite: 1]。\", \"summer\": \"严防酷暑闷根和烈日暴晒 [cite: 1]。必须移到家里最阴凉、空气强对流通风的强半阴处 [cite: 1]。供水需看土，坚决断肥，严防黑腐 [cite: 1]。\", \"winter\": \"防寒防冻是生死存亡的核心第一要务 [cite: 1]。必须立刻移入10℃以上的温暖房间 [cite: 1]。严格控制浇水，保持盆土偏干，暖气房内需远离暖气片 [cite: 1]。\"}','{\"pests\": [{\"name\": \"红蜘蛛/介壳虫\", \"symptom\": \"空气极度干燥时易发生 [cite: 1]。大叶背面聚集密集微小红点，导致叶面大面积发灰、斑纹褪色起皱并卷曲 [cite: 1]\", \"treatment\": \"用温水湿布全面强力擦洗大叶面和叶背，或者喷洒阿维菌素稀释溶液 [cite: 1]\"}], \"diseases\": [{\"name\": \"根腐病/叶斑病\", \"cause\": \"花盆透气性差，频繁浇水导致土壤长期处于死水积水状态导致闷根烂根 [cite: 1]\", \"symptom\": \"大叶片表面产生黑色水渍状病斑并软化溃烂，茎干基部变黑变软软塌发黏 [cite: 1]\", \"treatment\": \"立即脱盆，剪除所有黑烂根系和黄叶，用多菌灵消毒后更换疏松透气的新土重新栽种，严格控制浇水，移到强通风处 [cite: 1]\"}], \"prevention\": \"核心在于控制浇水，管住手、土不干透绝不频繁浇水，并始终保持居家养护环境拥有良好的空气强通风 [cite: 1]。\"}','有毒 [cite: 1]','全株各部位，特别是茎叶、汁液 [cite: 1]','天南星科植物，全株汁液中含有大量的针状草酸钙结晶以及毒性蛋白 [cite: 1]。皮肤直接触碰白色乳汁会引发剧烈的皮肤红肿、奇痒与刺痛；一旦误食，毒素会强烈灼伤并麻痹口腔、舌头和咽喉粘膜，导致其迅速极度肿胀，引发声带无法发声、流涎不止、严重呕吐 [cite: 1]','对猫、狗及儿童有严重的强毒性风险 [cite: 1]！由于其叶片色彩白绿斑斓极其好看，长长的叶柄易被儿童和宠物抓咬误食 [cite: 1]。必须绝对将其摆放在儿童和宠物绝对无法触及的高处，严防宠物误食中毒 [cite: 1]。','{\"leggy\": \"长期将其摆放在缺乏阳光的客厅死角或完全没有对流通风的昏暗走廊，导致新抽出的分枝为了找光而发生严重的过度长长、拔高（高脚徒长），叶柄变得细长、软弱无力 [cite: 1]。\", \"noBloom\": \"室内附生或盆栽栽培环境下由于空间和热带阳光积温高度受限，几乎99.9%一辈子都不会抽佛焰苞开花，这完全属于正常的植物生理特性，无需处理 [cite: 1]。\", \"drooping\": \"柔嫩的大叶和叶柄整体失去弹性、软绵绵毫无支撑力地向盆沿四周瘫软瘫倒、耷拉 [cite: 1]。多为彻底严重缺水脱水的前兆（及时给水可快速恢复挺拔）；或者是由于频繁大水根系已经彻底溃烂死掉 [cite: 1]。\", \"mainTaboo\": \"裸手直接修剪导致乳汁中毒、频繁大水浇灌、盛夏酷暑强光直射暴晒，以及冬季遭遇8℃以下的低温摧毁 [cite: 1]。\", \"beginnerTip\": \"买回家后觉得它太华丽太好看了，天天都有事没事往大盆里频繁倒水，结果不到两个星期它高级的白绿相间叶子就全部闷根发黄、烂成了一地黏泥 [cite: 1]。\", \"yellowLeaves\": \"90%以上是由于频繁频繁大水浇灌导致土壤长期泥泞积水死水、根系缺氧窒息黑腐发黄；其次是冬季气温骤降受冻发生严重的冷冻发黄软烂 [cite: 1]。\"}','叶形精美，叶面上密布的乳白、白绿花纹斑块斑纹极其鲜艳华丽，对比度极高，色彩白绿斑斓如同一幅充满热带奔放风情的小型天然油画，是提升现代客厅、书房高贵格调的顶级观叶小明星 [cite: 1]。','净化空气的高能功勋 [cite: 1]。能高效吸收、过滤空气中的甲醛、苯、三氯乙烯等新房装修化学毒气，吸毒和湿度调节功能极强 [cite: 1]。','具有较强毒性，严禁任何形式的任何嘴部接触或食用 [cite: 1]！','无家庭药用价值 [cite: 1]','名字带有“白雪公主”，寓意“纯洁无瑕”、“高贵典雅”、“健康长寿”、“阖家平安”，在风水学上有强大的镇宅辟邪、凝聚室内祥和朝气的极佳风水作用 [cite: 1]。','办公室办公桌台面、明亮小书桌台面、客厅茶几边缘无直射光处、北向卧室内侧台面 [cite: 1]','排水良好的盆栽土 [cite: 1]','腐叶土:泥炭土:珍珠岩/粗沙 = 3:2:1，或者直接使用市售的优质通用营养土，盆底做好排水层 [cite: 1]','质感清新的北欧风塑料盆、小号红陶盆或简约白瓷盆 [cite: 1]','口径15-22cm（它根系生长温和，不宜选用过大过深的盆防存水闷根） [cite: 1]','每1-2年春季换盆、换土一次 [cite: 1]',5.5,6.5,'easy','moderate',50,1,0,0,1,'/images/plants/chinese-evergreen.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:04:17','2026-05-23 10:18:51'),(33,'龙血树','巴西铁、不老松、龙须树','Dracaena marginata','dragon-tree','天门冬科','龙血树属','木本','多年生','观叶','非洲及亚洲热带地区 [cite: 1]','龙血树是一种多年生常绿大型木本植物 [cite: 1]。主干挺拔粗壮，常呈古朴的木桩状 [cite: 1]。其最引人注目的是在树干顶端丛生开来的剑形长叶，质地坚韧，革质油亮，部分品种带有金黄色纵条纹（金心、金边巴西铁） [cite: 1]。它生长极为缓慢，寿命极长，生命力极其顽强，具有极高的高端家居及商务软装观赏价值 [cite: 1]。','茎干古朴如桩，长叶剑形丛生挺拔的大型长寿树 [cite: 1]。','宽线形至长披针形，形似长剑，先端渐尖，全缘厚革质，无柄或具鞘基抱茎 [cite: 1]','深绿色、鲜绿色，部分品种中央具一条金黄色宽纵带（金心）或边缘带黄边 [cite: 1]','地上主干粗壮挺拔，木质化程度极高，表皮灰褐色或浅褐色，具明显的年轮状环纹 [cite: 1]','圆锥花序自叶丛中央顶生抽出，花朵细小，呈密集小球状排列，入夜后会散发出极其浓郁甚至呛人的奇香 [cite: 1]','黄白色、淡绿色 [cite: 1]','冬季至早春（12月-翌年2月） / 室内盆栽养护多年且光照温度合适才偶尔开花 [cite: 1]','秋季（少见橙红色浆果） [cite: 1]','粗壮古朴的木桩主干上，爆发出几簇坚挺硬朗的剑形大长叶向四周自然辐射散开，线条苍劲有力，整体呈现出一种现代极简、大气且带有东方长青长寿的雕塑美感 [cite: 1]。','medium',4,7,'喜充足明亮的散射光或柔和的直射阳光 [cite: 1]。非常喜光，也极耐半阴，在室内普通客厅能长期健康存活 [cite: 1]。盛夏正午需避免强光直射暴晒，防止叶片被灼伤变黄干枯 [cite: 1]。若长期处于极端阴暗处，叶面的金色斑纹会褪色变绿减淡 [cite: 1]。','rarely',10,20,'木质化主干和发达的根系具有极强的储水和耐旱能力，浇水必须严格遵循“宁干勿湿”、“干透浇透”原则 [cite: 1]。必须等花盆表层往下3-4厘米彻底干透、变干发白后再行浇透水 [cite: 1]。夏季生长期蒸发快可正常给水，秋冬季及低温期必须严格控水偏干，等土彻底干透后再微量给水 [cite: 1]。','干透浇透 [cite: 1]','每10-15天1次 [cite: 1]','每7-10天1次（根据干燥情况，看到土干透再浇，切勿托盘存积水） [cite: 1]','每12-15天1次 [cite: 1]','每20-30天1次或彻底断水，保持土壤微干状态有利于提高其抗寒防冻能力 [cite: 1]','严忌高频率频繁频繁倒水导致土壤长期处于死水泥泞状态，这会导致其木质化的地下根系迅速窒息黑腐腐烂，表现为地上坚挺的剑叶开始毫无征兆地疯狂脱落 [cite: 1]','普通的室温自来水即可 [cite: 1]','medium','对空气湿度要求中等，对家庭室内普通的干燥有很强的抗性 [cite: 1]。在夏季酷暑期或北方供暖干燥季节，空气过于干燥可能导致剑叶尖端出现微小的干尖，可偶尔用温水擦拭叶面或适当喷雾调湿 [cite: 1]。',18,30,10,35,0,'客厅落地窗旁、大堂角落、玄关大位、沙发旁明亮处、写字楼过道、老总办公室 corner [cite: 1]','喜温暖、微干、阳光充足的环境，较耐高温，极耐半阴，生命力极其极长，极忌土壤长期死水积水闷根，怕寒冷，喜疏松肥沃、排水优良的酸性或中性沙质壤土 [cite: 1]。','喜温暖舒适、微干的环境，生长适温为18-30℃ [cite: 1]。极其耐受高温 [cite: 1]。不耐严寒，冬季越冬室温需维持在10℃以上，低于5℃木质化的主干和根系极易发生严重的冷冻烂根，导致整株冷冻受灾坏死 [cite: 1]。','平衡20-20-20','monthly','龙血树生长极其缓慢，对肥料依赖度较低 [cite: 1]。仅在春、夏、秋三季生长旺季，每月随浇水追施一次稀薄的观叶复合平衡肥（或在盆表面埋入20-30粒长效平衡缓释肥颗粒即可） [cite: 1]。金色品种切勿多施单一氮肥以防条纹消失 [cite: 1]。盛夏酷暑或冬季低温期全面停肥 [cite: 1]。','春季和秋季 [cite: 1]','稀薄的低氮高钾型观叶水溶复合肥或高品质液体通用营养液 [cite: 1]','不需要单独施用任何催花肥，其花香过浓甚至呛人，室内现蕾时若不习惯可直接剪掉花序 [cite: 1]',1,'极忌浓肥、生肥，严禁秋末降温后追肥防止发生烧根萎蔫 [cite: 1]','长期不给肥基本无明显表现，过肥反而极易引发烂根闷根导致叶片迅速发黄 [cite: 1]','春季 [cite: 1]','随时剪除底部老化变黄的干枯大长叶、修剪受损破裂或干尖严重的叶片，以及在树干过高或长势杂乱时进行“截干锯断” [cite: 1]','用消毒过的专业木本大修枝剪或锯子进行修剪 [cite: 1]。剪除发黄老叶时，顺着茎干从叶柄基部剥除或用剪刀平整剪断 [cite: 1]。如果是局部叶尖枯焦，可顺着剑叶剑形弧度将焦尖斜剪掉 [cite: 1]。若主干过高，可在春季用锯子一刀横向锯断（截干），切口涂抹多菌灵保持彻底干燥 [cite: 1]。锯下的茎干晾干伤口后可在湿沙中重新扦插生根，而留下的老木桩上会重新爆发出多个华丽的绿色新芽簇 [cite: 1]。','大修剪截干后一两周内，伤口彻底干涸前，切口及顶部叶丛严禁大量淋水淋雨，防止发生局部黑腐 [cite: 1]','{\"fall\": \"秋季空气转干燥，逐步拉长浇水间隔，完全停止任何施肥 [cite: 1]。尽量让其多晒温和的秋季直射光，促使分枝木质化，提高冬季抗寒抗冻力 [cite: 1]。\", \"spring\": \"换盆、松土、锯干造型与扦插更新的最好黄金期 [cite: 1]。随着新芽从粗壮主干顶部萌生，逐渐增加浇水施肥，多晒温和的春季阳光 [cite: 1]。\", \"summer\": \"极其耐热 [cite: 1]。在室内无需特意遮阴，但如果放置在烈日直射的阳台需适当防晒 [cite: 1]。核心是必须保持环境极佳的空气开窗通风，严防高温高湿闷根烂根 [cite: 1]。\", \"winter\": \"防寒防冻是生死存亡的核心第一要务 [cite: 1]！必须立刻移入10℃以上的温暖室内（最好在暖气房向阳处） [cite: 1]。严格控制浇水，盆土不干透绝不频繁浇水 [cite: 1]。定期用大型湿布擦拭其坚挺的剑叶清除灰尘，提升极佳的现代商务观赏美感 [cite: 1]。\"}','{\"pests\": [{\"name\": \"介壳虫/红蜘蛛\", \"symptom\": \"在空气过于干燥密闭且完全不通风时发生 [cite: 1]。丛生剑叶基部包裹的叶腋深处、或表面出现白色棉絮状或褐色盾壳状小虫，吸食汁液导致叶片失绿起皱 [cite: 1]\", \"treatment\": \"用酒精棉球逐个擦拭掐死，数量多时喷洒蚧必治、杀扑磷稀释溶液 [cite: 1]\"}], \"diseases\": [{\"name\": \"烂根病/炭疽病\", \"cause\": \"花盆过大或土壤黏重，频繁浇水导致土壤长期处于黏重死水积水状态导致闷根烂根 [cite: 1]\", \"symptom\": \"坚挺的剑叶无缘无故开始疯狂大面积脱落，或者叶面产生不规则黑褐色斑点并凹陷溃烂，主干基部拔出后发现肉质主根变黑中空发臭 [cite: 1]\", \"treatment\": \"立即脱盆，用利刀切除所有发黑腐烂的黑根，伤口大量涂抹多菌灵粉末晾干两三天，更换全沙质透气新土重新栽种，严格断水控水，移到强通风口处 [cite: 1]\"}], \"prevention\": \"核心在于控制浇水，常年坚持土不干透绝不频繁给水，并始终保持居家养护环境拥有良好的大开窗空气强通风 [cite: 1]。\"}','微毒 [cite: 1]','全株汁液、茎叶 [cite: 1]','含有皂苷等弱毒性化学成分 [cite: 1]。人类皮肤接触一般无明显过敏反应，但误食会导致口腔不适、恶心、呕吐、流涎不止和腹泻 [cite: 1]','对猫狗有毒 [cite: 1]！猫狗对其极为敏感，误食可能引发严重的呕吐（常常带血）、流涎、瞳孔放大以及极度抑郁，需将其摆放在宠物无法攀爬破坏的重质大盆内 [cite: 1]。','{\"leggy\": \"长期将其摆放在缺乏阳光的客厅死角或完全没有对流通风的昏暗走廊，导致新抽出的分枝和剑叶为了找光而发生严重的过度长长、拔高（高脚徒长），叶片变得细长、软弱无力无法挺立，且原本金黄色的条纹会彻底褪色减淡变成杂绿色，彻底失去华丽的观赏美感 [cite: 1]。\", \"noBloom\": \"室内大型盆栽由于受到花盆空间限制、光照时长严重不够，几乎99.9%一辈子都不会开花，属于完全正常的棕榈/百合树乔木类生理特性，无需处理，主要欣赏其常绿直立的复叶结构 [cite: 1]。\", \"drooping\": \"丛生的剑叶整体失去弹性和支撑力、垂头丧气地瘫软低垂、失去挺拔质感 [cite: 1]。多为基部已经彻底黑腐软烂失去固定，或遭遇了大降温受冻、根系已经全部烂死所致 [cite: 1]。\", \"mainTaboo\": \"频繁大水浇灌导致土壤泥泞、托盘长期存有死水、冬季遭遇5℃以下的低温暴击 [cite: 1]。\", \"beginnerTip\": \"以为树大很需要水，每天回家都往大盆里灌几大碗水，并且把窗户常年关得死死的，结果不到两个星期，原本茂密浓绿的大树就直接把叶子全部掉精光、变成了一根光秃秃的死木桩 [cite: 1]。\", \"yellowLeaves\": \"90%以上是由于频繁频繁倒水导致土壤长期泥泞积水死水、根系缺氧窒息黑腐发黄，表现为剑叶不发黄就直接疯狂掉落；其次是冬季气温骤降受冻发生严重的冻害发黄 [cite: 1]。\"}','主干挺拔直立、古朴如桩，顶部丛生的剑形长叶错落排列，线条刚劲沉稳，自带经典的东方长青不老松韵味与极简现代软装的雕塑高级感，极具长线观赏价值与宏伟的空间存在感 [cite: 1]。','净化空气的卓越功勋树 [cite: 1]。由于体型高大且剑叶繁密，能如同高效空气滤网般强力吸附室内的漂浮灰尘、吸附微小化学颗粒；并能极高效率地成批吸收室内的甲醛、苯、三氯乙烯、二甲苯等新房装修化学毒气，吸毒和湿度调节净化能力极强 [cite: 1]。','无食用价值 [cite: 1]','在传统中医药学中，部分同属植物的木质部提取物可用于止血、活血散瘀（即名贵中药“血竭”，普通盆栽禁止随意折损调配） [cite: 1]。','名字带有“龙血”与“不老松”，寓意“健康长寿”、“基业长青”、“富贵吉祥”、“阖家平安”、“长命百岁”，在风水学上有强大的镇宅辟邪、凝聚家宅坚毅刚强朝气、赶走家庭阴冷磁场的强力风水效果 [cite: 1]。','大客厅电视柜旁、明亮落地窗旁、沙发拐角一侧、写字楼老总位、高档写字楼大堂、乔迁新居送礼 [cite: 1]','排水良好的盆栽土 [cite: 1]','腐叶土:园土:珍珠岩/粗沙 = 3:3:2，由于其害怕积水烂根，土壤必须混入足量沙质颗粒介质，盆底必须垫一层陶粒作为排涝排水层 [cite: 1]','由于其株型高大挺拔且木桩厚重，必须选用厚重大号、质感庄重的水泥盆、大号陶盆或高端深筒北欧风塑料深盆以防倒伏 [cite: 1]','口径25-45cm（根据树木木桩规格大小选择，必须给予根系宽裕的呼吸排涝空间） [cite: 1]','每2-3年春季换盆换土一次（大型大树盆栽可以仅进行更换表层肥土） [cite: 1]',6.0,7.0,'easy','slow',200,1,1,0,1,'/images/plants/dragon-tree.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:04:17','2026-05-23 10:18:51'),(34,'仙客来','兔耳花、萝卜海棠、一品冠、篝火花','Cyclamen persicum','cyclamen','报春花科','仙客来属','草本','多年生','观花 / 多肉','地中海沿岸、中东多石山地','仙客来是一种著名的多年生常绿（夏季休眠）肉质块茎草本花卉 [cite: 1]。其地下具肥大的扁球形球茎 [cite: 1]。叶片自基部丛生，呈精美的心形，叶面密布着华丽的银白色斑纹 [cite: 1]。最奇特的是其花朵：花瓣完全向上反卷翻折，形状酷似一只只竖着耳朵、正欲跳跃的可爱小白兔，极其玲珑精巧，是冬春季室内高档年宵盆花的绝对主力 [cite: 1]。','花瓣反卷如兔耳，冬春季艳丽非凡的高档年宵花卉 [cite: 1]。','完美的卵心形或肾心形，边缘有细钝锯齿，质地厚革质肉质化，叶柄长而紫红色 [cite: 1]','深绿色，叶面上沿着主脉两侧密布着精美规整的银白色或乳白色云雾状、放射状脉络条纹（银脉），叶背多为高贵奢华的紫红色 [cite: 1]','地上无直立主茎；地下具有肥大、扁球形、肉质化的块茎，灰褐色，内含大量储水储藏组织 [cite: 1]','长花梗自块茎顶端抽出，单生顶端，花蕾期低垂，盛开时花冠五裂，花瓣完全向上180度反卷翻折，形似兔耳或篝火 [cite: 1]','鲜红、粉红、纯白、紫红、雪青及各种带边、复色 [cite: 1]','12月至翌年5月（长达数月，横跨元旦、春节） [cite: 1]','5-6月（蒴果，球形，成熟后花梗会像弹簧一样螺旋卷曲将果实送至土面） [cite: 1]','低矮、紧凑的丛生状。下面是密密麻麻、布满银色图腾的浓绿心叶层叠平铺；其上挺拔抽出一串串娇艳欲滴、形似小兔的花朵点缀簇生，整体风格精巧、华丽且充满强烈的节日喜庆氛围 [cite: 1]。','high',5,8,'非常喜光 [cite: 1]。最喜充足明亮的散射光和温和的冬春直射阳光 [cite: 1]。充足的光照是其花色艳丽、长花梗短壮不倒伏的核心核心条件 [cite: 1]。盛夏休眠期则需彻底遮阴防烈日曝晒 [cite: 1]。若冬春季长期缺乏光照，会导致其花蕾大量枯萎、落蕾并停止开花 [cite: 1]。','weekly',4,7,'仙客来对水分极其敏感，既喜湿润又极度怕涝，最怕盆土长期泥泞或彻底干透 [cite: 1]。生长期浇水严格遵循“见干见湿”原则 [cite: 1]。等盆土表面1-2厘米彻底变干、长叶柄摸起来稍微有些发软、失去弹力时立刻浇透水 [cite: 1]。最佳浇水方法是“浸盆法”（将花盆下部1/3浸入大水盆中5-10分钟，让水自下而上吸干），能完美防止水分接触块茎和叶心 [cite: 1]。盛夏进入休眠期后，必须严格控水保持几乎完全干燥 [cite: 1]。','见干见湿 [cite: 1]','每4-6天1次（开花盛期供水需充足） [cite: 1]','每15-20天1次或断水（高温休眠期，仅在傍晚土完全干干透时在盆边微量润湿，严禁大水闷烂块茎） [cite: 1]','每5-7天1次（秋凉块茎苏醒萌发新芽后逐渐恢复浇水） [cite: 1]','每5-7天1次（北方暖气房内蒸发快，严格看叶柄软硬度给水，严防冷水惊根） [cite: 1]','严忌频繁倒水导致土壤积水、严忌将水直接从顶部劈头盖脸淋浇到肥大的块茎顶端或灌入密集的叶心里，这在几个小时内就会引发毁灭性的块茎软腐烂心 [cite: 1]','晾置过的普通温和自来水（水温必须与室内气温完全一致，严防冰冷水刺激） [cite: 1]','medium','喜略微湿润的空气环境，环境空气湿度保持在50%-60%之间最佳 [cite: 1]。极忌密闭不通风的湿热环境 [cite: 1]。在冬春季暖气房内，过低的空气湿度会导致花瓣提早凋谢、叶缘焦枯 [cite: 1]。',12,20,5,30,1,'客厅茶几中央、南向明亮窗台内侧、阳光书桌前、南向卧室桌面上、阳光房独立花架 [cite: 1]','喜凉爽干燥、阳光充足的环境，冬春生发开花，盛夏酷暑高温休眠，极度怕涝怕闷，怕极度干旱，喜疏松肥沃、排水极佳、富含腐殖质的微酸性沙质营养土 [cite: 1]。','喜凉爽、畏温暖、极其害怕炎热，具有特异的冬长夏休眠生理特性 [cite: 1]。最适开花温度为12-20℃ [cite: 1]。当气温超过28℃时，叶片开始发黄并逐渐进入夏季强迫休眠；不耐极寒，冬季越冬室温需维持在5-10℃以上，防冻伤导致整盆瘫软 [cite: 1]。','平衡20-20-20','biweekly','仙客来花期长、花量极大，属于极度喜肥的花卉 [cite: 1]。在秋季新叶萌发至春季开花盛期，每两周随浇水（或通过浸盆液）追施一次极其稀薄的无机复合液肥 [cite: 1]。前期多施平衡肥，现蕾初期后必须完全改用高磷钾肥（如磷酸二氢钾，浓度建议减半），以促进长花梗抽出和花色艳丽 [cite: 1]。氮肥过量会导致只长长密叶、花梗抽不出且叶片极易腐烂 [cite: 1]。盛夏酷暑休眠期绝对绝对严禁施肥 [cite: 1]。','秋季（孕蕾期）和冬季（开花期） [cite: 1]','稀薄的低氮高磷钾型花卉专用无机水溶肥，促使源源不断的花苞从基部抽出 [cite: 1]','高磷钾专用肥（如花多多2号或磷酸二氢钾稀释液）通过浸盆施用，强力促花 [cite: 1]',1,'严忌施用浓肥、未腐熟生肥，严禁在5月中旬后至9月休眠期间追施任何肥水 [cite: 1]','花蕾大面积发黄枯萎、长花梗软塌无力倒伏无法挺立、后续花苞干瘪停止抽出、老叶边缘疯狂变黄脱落 [cite: 1]','全年生长花期均可进行微修剪 [cite: 1]',NULL,'特别经典技巧：仙客来摘除残花和黄叶严禁用剪刀剪断 [cite: 1]！因为剪刀留下的中空叶柄残端在密集潮湿的叶心里极易积水溃烂、引发毁灭性的软腐病 [cite: 1]。正确做法是：用手捏住受损长花梗或老叶柄的中上部，轻轻顺时针拧转一圈，然后用力向斜上方顺势一拔，就可以完整、干净地将整根花梗从块茎根基处“连根拔除”，不留任何残留腐烂源 [cite: 1]。','严禁使用带有铁锈或不干净的剪刀去剪除密集叶心深处的组织，修剪后伤口一天内切勿喷雾 [cite: 1]','{\"fall\": \"秋季（9月）是球茎苏醒复苏换盆期 [cite: 1]。随着气温跌破24℃，块茎顶端会重新冒出精致的绿色新芽轴 [cite: 1]。此时立刻脱盆进行换盆换土，块茎必须裸露1/3在土表 [cite: 1]。逐渐恢复正常干透浇透，开始追施观叶平衡薄肥，常让其多晒温和秋光，促进花芽分化 [cite: 1]。\", \"spring\": \"春季是仙客来的开花爆盆高峰期与末期 [cite: 1]。4月份后随着气温回升，花朵逐步凋谢，老叶开始发黄，此时需逐步减少浇水量、停止施肥，开始准备迎接夏季休眠 [cite: 1]。\", \"summer\": \"仙客来的“生死劫” [cite: 1]。5月下旬叶片全枯黄后，将地上枯叶完整拔除 [cite: 1]。将装有肉质球茎的花盆彻底移到家里最阴凉、完全无直射光、全天候大开窗空气强通风的冷凉处 [cite: 1]。彻底全面断肥，严格断水，保持盆土几乎完全干燥，仅在土彻底干成硬块时在盆边微量润湿，严防高温闷湿导致球茎彻底软烂化水 [cite: 1]。\", \"winter\": \"仙客来的黄金爆发盛花期 [cite: 1]！必须立刻移入温暖室内阳光最强烈的南向窗台、阳台 [cite: 1]。保持室温在12-18℃之间最佳（温度过高如超过22℃会导致花期大幅缩短、植株长势散乱倒伏） [cite: 1]。每两周通过浸盆施一次稀薄的高磷钾肥，看到长叶柄稍软立刻用浸盆法浇透水，让其源源不断吐出华丽的兔耳花 [cite: 1]。\"}','{\"pests\": [{\"name\": \"根结线虫/蚜虫/红蜘蛛\", \"symptom\": \"在空气过于干燥密闭且完全不通风时发生 [cite: 1]。叶背、花梗根基处聚集绿色、黑色小虫吸食汁液，导致花蕾枯萎萎缩或叶片畸形起皱纹 [cite: 1]\", \"treatment\": \"人工用棉签沾取稀释肥皂水刷除飞虫，数量多时喷洒阿维菌素或啶虫脒稀释药剂防治 [cite: 1]\"}], \"diseases\": [{\"name\": \"球茎软腐病/灰霉病\", \"cause\": \"花盆透气差或盆大，频繁浇水土壤长期处于死水积水状态导致闷根，或者由于浇水时直接淋浇叶心、水液滞留在块茎顶端，在密闭不通风的高温/温热下引发毁灭性细菌感染 [cite: 1]\", \"symptom\": \"密集油亮的心叶、长叶柄和花梗突然大面积变黑变软、像被开水烫过一样发生软烂脱落发黏，地下扁球茎彻底变软并流出带有极度酸臭恶臭的黏液 [cite: 1]\", \"treatment\": \"极难挽救，属于植物界的“癌症” [cite: 1]。一旦发现块茎变软酸臭，整盆连同土壤必须彻底扔掉销毁，不可回收 [cite: 1]。若病发初期，可完整拔除受损部分，用多菌灵原粉大面积涂抹伤口保持绝对干燥，全盆断水，移到强风口处 [cite: 1]\"}], \"prevention\": \"核心在于“坚决采用浸盆法浇水、严禁水淋叶心块茎”的同时“必须常年配合极佳的空气强开窗通风”，保持盆土干透浇透 [cite: 1]。\"}','有毒 [cite: 1]','全株各部位，特别是地下的肉质扁球茎、汁液 [cite: 1]','属于带有块茎毒性的花卉代表 [cite: 1]。其肉质块茎中含有大量的仙客来毒苷等强刺激性三萜皂苷化学成分 [cite: 1]。皮肤直接碰触其割断的汁液可能引发剧烈红肿、皮炎与过敏刺痛；一旦误食地下的“萝卜”球茎，会强烈刺激消化道，导致剧烈的呕吐、流涎不止、严重腹泻、肠胃痉挛，大量误食严重时可能引发全身抽搐、呼吸麻痹受阻中毒 [cite: 1]','对猫、狗及儿童有严重的剧毒高风险 [cite: 1]！由于其花朵神似好玩的小兔子、色彩极其鲜艳华丽，地下的扁块茎极像大萝卜，极易吸引儿童抓挠或宠物猫咪、狗狗玩耍、掘土啃咬 [cite: 1]。必须绝对、必须将其摆放在儿童和宠物绝对、永远无法触及的稳固独立茶几中央或高窗台上，严禁宠物和儿童触碰误食 [cite: 1]！','{\"leggy\": \"长期将其摆放在缺乏直射阳光的电脑桌死角或完全没有对流通风的昏暗走廊，导致新抽出的长叶柄和花梗为了找光而发生严重的过度长长、拔高（高脚徒长），叶柄和花梗变得又细又长又软，导致无数重叠的圆叶和花朵毫无支撑力地向盆沿四周大面积软瘫、瘫倒在土表，原本金银色纵脉纹理完全褪色减淡，彻底失去精美挺拔的年宵花观赏价值 [cite: 1]。\", \"noBloom\": \"90%是因为冬春盛花期时光照严重不足（长期放在昏暗客厅内侧）、或者生长期长期舍不得给肥（特别是缺乏磷钾肥导致没有营养孕蕾），以及施用了过量单一氮肥导致只疯狂长绿叶而完全不现蕾 [cite: 1]。\", \"drooping\": \"整盆高低错落、精美如兔耳的花朵和长心叶突然像断了电一样、软绵绵毫无支撑力地全部整齐地软瘫瘫倒、耷拉在花盆沿四周 [cite: 1]。这多为两种极端红灯信号：一是由于土壤彻底干透、干旱脱水引起的中暑软瘫（通过浸盆法补水后两三个小时能神奇地重新100%坚挺挺立起来）；二是由于频繁大水或浇水淋心，导致地下扁块茎已经彻底软腐黑腐烂死、丧失固定和功能，需立刻检查块茎硬度 [cite: 1]。\", \"mainTaboo\": \"劈头盖脸从顶部淋水到叶心和块茎上、频繁频繁大水浇灌导致土壤泥泞、盛夏酷暑闷热期花盆淋雨积水、冬季遭遇3℃以下的严重受冻 [cite: 1]。\", \"beginnerTip\": \"买回家后觉得它白绿色的斑纹和红花太漂亮了，像对待普通盆栽一样，每天都从顶部对准花朵和叶心拼命频繁倒大杯自来水，结果不到一个星期，它肥硕的“大萝卜”块茎就直接在盆里全部闷根软烂、化成了一滩奇臭无比的黏泥 [cite: 1]。\", \"yellowLeaves\": \"95%以上是由于频繁频繁大水浇灌、浇水淋心导致地下肉质扁球茎黑腐窒息软腐发黄；或者是夏季酷暑室内温度超过28℃时植物开始的生理性自下而上正常发黄准备休眠，以及长期不浇水引起的长长叶柄因脱水而发黄变脆 [cite: 1]。\"}','心形叶面上布满复杂的银色几何图腾与脉络，其上挺拔抽出的成串花朵花瓣完全向上180度反卷、精美神似成群竖着长耳朵飞跃的红色小兔子，色彩极其娇艳华丽，具有极高的欧式复古调性、现代艺术审美与强烈的冬春佳节阖家喜庆存在感，是不可多得的桌面盆花之王 [cite: 1]。','草本开花植物，吸收化学毒气总量较弱，其叶片表面覆有细柔毛，能微弱地吸附一些空气中的微小浮尘、PM2.5颗粒，并有优秀的节日居家微量湿度调节辅助 [cite: 1]。','全株具有强烈的球茎剧毒，严禁任何形式的任何嘴部接触或食用 [cite: 1]！','具有较强毒性，严禁盲目作为任何家庭药用（误用易中毒） [cite: 1]。','名字带有著名的“仙客来”，中文寓意极其极其吉利，象征着“仙客翩然而至”、“贵人提携”、“好运连连”、“大吉大利”、“喜迎贵宾”、“阖家欢乐” [cite: 1]。在风水学上有极为强力的开运招财、凝聚家庭温馨和睦朝气、赶走屋室阴冷低迷磁场的顶级风水迎祥效果 [cite: 1]。','客厅大茶几中央、南向明亮窗台内侧、阳光充足的办公桌前台、电脑桌窗边、独立小书桌台面、南向阳光房花架 [cite: 1]','排水良好的盆栽土 [cite: 1]','优质泥炭土:腐叶土:珍珠岩 = 3:2:1，或者直接购买疏松透气的高品质草本花卉专用营养土，必须混入少量骨粉作为长效基肥，盆底垫厚层陶粒作为排涝防淤层 [cite: 1]','透气和排水性绝佳的矮胖红陶盆、瓦盆或底部带有多孔排水道的高品质控根塑料盆 [cite: 1]','口径12-18cm（它根系集中在块茎周围，盆切忌过大过深，大深盆存水极易引发烂根黑腐） [cite: 1]','每年秋季（9月）块茎复苏开始萌发新芽前，换盆换土一次（上盆时必须注意：肥大的块茎顶端1/3至1/2必须完全裸露暴露在土表面以外，严禁全埋入土中，防止烂心） [cite: 1]',5.5,6.5,'hard','moderate',30,1,0,0,0,'/images/plants/cyclamen.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:04:17','2026-05-23 10:18:51'),(35,'倒挂金钟','灯笼花、吊钟海棠、吊钟花','Fuchsia spp.','fuchsia','柳叶菜科','倒挂金钟属','草本','多年生','观花','中南美洲及新西兰','倒挂金钟是一种多年生常绿半灌木或草本花卉。其最引人瞩目的特征是花朵自叶腋间垂吊而下，萼片向外反卷，花冠管状，形似一盏盏精巧高挂的宫灯或倒扣的铃铛。它花色艳丽多变，花期漫长，是室内和阳台悬挂观赏的顶级高档盆花之一，但在盛夏高温期极其娇气，有“夏必死”之称。','花如精巧宫灯倒挂，冷凉季节艳压群芳的悬垂花卉。','卵形至卵状披针形，边缘具细锯齿，对生或三叶轮生，柔嫩带有微柔毛','鲜绿色、暗绿色，部分品种新叶的叶脉或叶柄略带紫红色','分枝多，柔弱而稍下垂，新枝肉质带红色，老枝逐渐木质化呈灰褐色','花单生于茎枝上部的叶腋，具长梗而下垂；花萼筒钟状，裂片开张反卷；花瓣瓣片叠生，形似精美裙摆','红、粉、白、紫、蓝及各类双色复色，色彩搭配极其华丽','4-12月（春季至初冬） / 盛夏气温过高时会短暂停止开花并休眠','秋季（少见浆果）','呈丛生、横展或自然悬垂状。繁茂的绿叶间垂吊着成百上千盏色彩斑斓的“小灯笼”，随风摇曳，姿态极其曼妙、玲珑且富有戏剧性的动感美。','medium',4,6,'喜凉爽半阴环境。春、秋、冬三季需要充足的散射光或温和的早晚直射光。盛夏休眠期极度畏惧烈日暴晒，必须进行强力遮阴，否则叶片和花蕾会瞬间被灼伤、烤焦枯萎。','frequent',3,5,'倒挂金钟叶片多且娇嫩，开花量大，在春秋生长期对水分需求较高，需保持盆土湿润。遵循“见干见湿”原则，表土干下去1-2厘米即需立刻浇透水。盛夏进入高温半休眠期后，必须严格控水保持微干；冬季低温期也需适度控水。','见干见湿','每3-4天1次（保持土壤充沛湿润，满足开花需要）','每7-10天1次（高温休眠期严格控水，必须在傍晚土干透时沿盆边微量润湿，严禁大水）','每4-5天1次（秋凉苏醒后逐渐恢复正常浇水）','每10-14天1次，严格遵循不干不浇，避免湿冷导致肉质根系腐烂','严忌盆土长期潮湿泥泞或死水积水，盛夏酷暑休眠期绝不能频繁大水，浇水时避免将水液长期滞留在密集叶心里','普通的室温自来水即可（需提前晾置，使水温与室内气温完全一致）','medium','对空气湿度要求较高，理想湿度在50%-60%之间。极忌夏季高温高湿的“桑拿天”。在春秋生长期，环境干燥时可常向花盆周围喷雾以增加湿度。',15,25,5,30,1,'朝东或朝北的明亮窗台、封闭但通风极佳的阳台、客厅落地窗旁散射光处、独立花架顶部','喜凉爽湿润、半阴环境，既怕强光暴晒，又怕长期密闭闷热；怕干旱，极忌土壤积水闷根，喜疏松肥沃、排水通畅的微酸性腐殖土。','极喜凉爽，最畏酷暑闷热。生长与开花最适温度为15-25℃。当夏季气温超过30℃时生长停滞，超过35℃时若不通风极易大面积落叶、黑腐死亡；冬季越冬室温需保持在5℃以上防冻伤。','平衡20-20-20','biweekly','花期长、花量极大，属于极度喜肥的花卉。在春季和秋季生长期，每两周随浇水追施一次极其稀薄的无机花卉专用液肥。前期多施平衡肥促进分枝，现蕾后必须改用高磷钾肥。当夏季气温超过30℃或冬季气温低于10℃时，必须绝对全面停止施肥。','春季（盛花期）和秋季（孕蕾期）','稀薄的低氮高磷钾型花卉专用无机水溶肥，促使源源不断的花苞自枝条顶端抽出','高磷钾专用肥（如磷酸二氢钾稀释液）进行叶面喷施或灌根，强力催花促色',1,'严忌施用浓肥、生肥，严禁在盛夏高温休眠期和冬日严寒期进行任何追肥','长长的花梗无力低垂、花蕾大量发黄枯萎落蕾、后续花苞稀少不抽出、老叶边缘发黄脱落','秋季（休眠期结束或花后）','随时清除花谢后的残花残梗、剪除底部老化发黄的老叶，以及在春秋生长期频繁进行“打顶摘心”','倒挂金钟极为需要通过修剪来控制株形和增加花量。当幼苗长到10-15厘米高时，将枝条顶端的嫩尖掐断（打顶），促使其萌发多个侧枝；当侧枝长出3-4对叶片时，再次进行二次打顶。频繁打顶能使株形呈现丰满的球状。花期结束后，可对所有枝条进行“短截”重剪，剪去老枝的1/3至1/2。修剪下的健康嫩枝可轻松用于扦插繁殖','严忌在盛夏高温休眠期或冬季极端寒冷期进行大面积大刀阔斧的重剪，修剪后伤口严禁大量喷水','{\"fall\": \"秋季（9-10月）是苏醒恢复与第二轮花期。随着气温回落，将其脱盆换土，修剪去老弱枝。逐渐恢复正常浇水与极稀薄的复合磷钾肥，多晒秋季阳光促进孕蕾开花。\", \"spring\": \"倒挂金钟的开花大爆发爆发期。确保充足的明亮散射光或柔和早晚光照，供水需充沛，每两周追施一次薄肥。当发现新枝条过长时可适度打顶，保证灯笼源源不断挂满枝头。\", \"summer\": \"倒挂金钟的“生死浩劫”。超过30℃进入半休眠，极易黑腐坏死。必须将其移到家里最阴凉、完全无阳光直射、全天候大开窗空气强对流通风的强风口处。全面断肥，严格控水偏干，严禁雨淋，坚决防湿热闷根。\", \"winter\": \"防寒保暖。必须移入室内温暖向阳的窗台或封闭阳台（5-10℃以上最佳）。严格控制浇水，盆土不干透绝不频繁频繁倒水，完全停止一切肥水，让其在充足的室内直射光下安全越冬。\"}','{\"pests\": [{\"name\": \"白粉虱/红蜘蛛/蚜虫\", \"symptom\": \"最容易高发。娇嫩叶片背面、嫩梢花梗处聚集细小飞虫或白色粉状小虫，吸食汁液导致整盆叶片失绿、起皱干枯卷曲\", \"treatment\": \"将整盆植物移到浴室用弱温水流全面冲洗干净，数量多时喷洒吡虫啉、联苯肼酯或啶虫脒稀释药剂\"}], \"diseases\": [{\"name\": \"根腐病/灰霉病/灰腐黑腐\", \"cause\": \"主要是夏季高温高湿、环境处于完全密闭不通风的死角，或者频繁给水导致盆土长期处于黏重泥泞积水状态导致闷根感染真菌\", \"symptom\": \"繁密嫩绿的叶片和分枝突然大面积变黑变软，像被开水烫过一样发生软烂脱落，拔出后地下根系黑腐恶臭中空\", \"treatment\": \"极难挽救。一旦发生大面积黑腐变软多报废。若发病初期，立刻用消过毒的剪刀切除所有病变黑烂的枝叶。脱盆修剪掉黑烂根系，多菌灵消毒后更换全新全颗粒透气新土重新栽种，严格断水并改善通风\"}], \"prevention\": \"核心在于营造“凉爽干燥、极佳的空气对流强通风”的环境，春秋保持干透浇透，盛夏严格控水。\"}','无毒','无','全株完全无毒。属于完全无毒的家庭高档赏花盆卉，无任何化学毒素或刺激乳汁','对猫、狗及儿童绝对安全。被权威机构官方认证的宠物友好型草本花卉。即使猫咪因其花朵摇晃而好奇抓咬啃食，也完全不用担心任何中毒危害。但因其枝叶和花梗极其娇嫩易折断，宜放置在宠物不易折腾的窗台高处保护造型。','{\"leggy\": \"长期将其摆放在缺乏光线的客厅 corners 或完全不通风的内侧台面，导致新抽出的分枝为了找光而发生严重的过度长长、拔高（高脚徒长），枝条变得又细又长又软，导致无数繁密的小灯笼花和圆叶毫无支撑力地向四周大面积软瘫、瘫倒下垂，彻底失去爆盆美感。\", \"noBloom\": \"90%是因为生长期光照严重不足（长期放置在昏暗室内内侧）、或者施用了过量单一氮肥导致枝叶疯狂徒长却完全不分化花芽，以及缺乏合理的打顶摘心修剪，导致枝条单一不萌发开花侧枝。\", \"drooping\": \"高挂的宫灯花朵和娇嫩的绿叶突然像中暑一样、软绵绵毫无支撑力地全部整齐地软瘫瘫倒、耷拉。这多为两种极端信号：一是由于土壤彻底干透、干旱脱水引起的信号（及时浇透水两三个小时能神奇地重新恢复挺拔坚挺）；二是由于盛夏闷热频繁给水，导致地下根系已经全黑腐烂死、丧失固定和吸水功能。\", \"mainTaboo\": \"盛夏酷暑闷热高湿且密闭不通风、频繁大水导致托盘死水积水、酷暑盛夏烈日直接直射暴晒。\", \"beginnerTip\": \"在7、8月份酷暑天看到它有些黄叶软弱，就以为它极度缺水，天天往盆里疯狂大量频繁倒水，结果不到三天它柔嫩的根和主干基部就彻底闷根黑腐、化成了一地黑灰色的烂黏泥（俗称夏必死）。\", \"yellowLeaves\": \"95%以上是由于频繁频繁大水、盆土积水闷根，或夏季环境温度超过32℃且密闭不通风导致根系窒息腐烂发黄；其次是冬季气温骤降受冻发黄，或者长期极度缺水引起的长长叶柄枯黄变脆脱落。\"}','花朵玲珑奇特，花瓣反卷、瓣片叠生神似成群翩翩起舞、精巧高挂的彩色热带小仙女或中国古典宫灯，华丽非凡，色彩对比度极高，具有极高的英式复古庭院调性与现代精致生活的浪漫格调，是不可多得的阳台窗台悬挂花卉明星。','草本开花植物，吸收化学毒气总量较弱，主要用于室内的华丽观赏和佳节、春日家庭氛围的微量美化与湿度调节辅助。','无食用价值','无确切家庭药用价值','名字带有著名的“金钟”与“灯笼花”，寓意“大吉大利”、“喜气洋洋”、“鸿运当头”、“前程似锦”、“阖家平安”。在风水学上有极为强力的开运招财、柔化阳台刚硬栏杆线条、凝聚家庭温馨快乐朝气的极佳风水植物效果。','朝东或朝北明亮窗台内侧、封闭但强通风的阳台内侧、独立高脚花架顶部、无强光直射的阳光房侧面','排水良好的盆栽土','优质泥炭土:腐叶土:珍珠岩 = 3:2:1，或者直接购买疏松透气的高品质草本花卉专用营养土，盆底垫厚层陶粒作为防淤排水层','透气和排水性绝佳的泥瓦盆、红陶盆，或者适合悬挂垂吊的轻质多孔塑料吊盆','口径15-22cm（它根系较为娇嫩，花盆忌过大过深，大深盆存水极易引发黑腐烂根）','每年春季（花后）或秋季（苏醒后）换盆、换土一次',5.5,6.5,'hard','fast',60,1,1,1,0,'/images/plants/fuchsia.jpg',NULL,NULL,NULL,NULL,NULL,NULL,0,0,'2026-05-21 11:04:17','2026-05-23 10:18:51'),(36,'马醉木','日本马醉木、珍珠花','Pieris japonica','pieris-japonica','杜鹃花科','马醉木属','木本','多年生','观叶 / 观花','日本、中国东部','马醉木是一种常绿灌木，在鲜切花软装界以\"水养鲜切枝条\"而极度风靡。其叶片革质倒卵状披针形，新叶鲜红夺目，后转为翠绿。春季能开出成串形似风铃的吊钟状小白花。它姿态飘逸、寿命长，极具日式东方禅意美学。','飘逸灵动、自带日式高雅禅意的水培网红树','倒卵状披针形，革质表面光滑，边缘有细密锯齿','新叶常呈艳丽的红褐色或粉红色，成熟后演变为明亮油绿的翠绿色','树冠多分枝，枝条纤细而自然向外平展下垂，木质化程度高','总状花序或圆锥花序顶生，小花管状钟形，如同密集成串的倒挂小风铃','纯白色、淡粉红色','3-5月','8-10月','枝叶错落低垂，线条极其流畅轻盈，不论作为鲜切枝水养还是整株盆栽，都自带一种高雅的高级侘寂美感。','medium',4,8,'喜明亮充足的散射光，极耐半阴。多晒温和的阳光能让其新叶的红色更加鲜艳华丽；盛夏正午阳光直射暴晒需适当遮阴。','weekly',6,10,'土培遵循见干见湿，表土彻底干燥再浇透；若是鲜切水养枝条，需要每4-6天换干净清水一次。','见干见湿 / 水养定期换水','每周1次','每5-7天1次','每周1次','每15-20天1次，严格保持土壤偏干防湿冷烂根','土培严忌频繁浇水，水养切枝严忌水质变黄变发臭不更换','普通的室温自来水','medium','对空气湿度要求中等，耐受干燥能力强，但在极度干燥或暖气房内需偶尔叶面喷水防止发干。',15,28,-5,35,1,'客厅大落地窗旁、茶几中央水养、书房窗边、玄关大位','喜冷凉、强散射光的半阴环境，极耐寒，极忌积水闷根，喜肥沃排水绝佳的微酸性沙质土。','喜冷凉、湿润、空气对流的环境，较耐寒。极害怕盛夏酷暑多雨闷热的死水桑拿天气。','高磷钾肥','none','盆栽对肥料依赖度较低。可在春秋生长季每月追施一次极其稀薄的喜酸性肥即可。水养切枝完全无需任何施肥。','春季和秋季','稀薄的富含铁素的喜酸性复合液肥','冬末现蕾初期可连续喷施两次极稀薄的磷酸二氢钾促进花铃饱满',1,'严忌施用浓肥、未腐熟生肥，盛夏气温超过32℃严禁追肥','长期缺肥新叶红色斑块变浅，叶色呈现苍黄黄化病症状','春季','剪除开花过后的残花梗、修剪过密阻碍内部通风的内膛交叉密枝','用消毒的专业木本修枝剪在侧芽点上方平剪','修剪时流出的汁液有剧毒，修剪后严禁立刻叶面喷水','{\"fall\": \"秋凉后迎来新一轮新叶萌动。恢复正常见干见湿，多晒温和秋光。\", \"spring\": \"马醉木花期与新叶萌发期。给予全天候充足的明亮散射光，土培保持温润。\", \"summer\": \"马醉木的生死劫。极度怕闷热。必须彻底搬到阴凉、强风口的半阴处，严格控水，坚决断肥。\", \"winter\": \"较耐寒，在冷凉室内能很好过冬。严格控制浇水，盆土不干透绝不频繁倒水，完全断肥。\"}','{\"pests\": [{\"name\": \"军配虫/网蝽\", \"symptom\": \"叶片背面聚集白色、黑色带有网纹的小虫，叶面产生密集的失绿白斑\", \"treatment\": \"加强环境空气流通，数量多时喷洒吡虫啉或啶虫脒稀释溶液\"}], \"diseases\": [{\"name\": \"煤污病/叶斑病\", \"cause\": \"环境太长期处于空气密闭、密不透风状态\", \"symptom\": \"叶面表层产生大量一层黑色粉末状霉层，严重阻碍光合作用导致成批落叶\", \"treatment\": \"立即剪掉受损叶片，移到强风口处，喷洒多菌灵或代森锰锌溶液\"}], \"prevention\": \"核心在于营造常年冷凉、极度通风空气强对流的环境，定期擦拭清理叶片。\"}','剧毒','全株各部位，特别是茎叶内的马醉木毒素汁液','全株含有马醉木毒素等强力神经毒素。误食会迅速引发呼吸困难、流涎不止、恶心呕吐、心率暴跌，严重时可致死','对猫狗及儿童有极其严重的强剧毒高风险！家有婴幼儿或啃咬控猫狗的家庭禁止养殖或购买此切花！','{\"leggy\": \"长期将其摆放在极度缺乏阳光的暗淡角落，新抽出的枝条细长无力并发生发生倒伏，失去挺拔美感。\", \"noBloom\": \"室内养护缺乏充足的温和直射光和明显的冬春冷凉温差刺激，导致花芽无法顺利分化分化萌发花序。\", \"drooping\": \"柔美的复叶整体失去弹性、软绵绵顺着分枝向下耷拉。多为彻底严重缺水脱水引起的信号或根系已烂死。\", \"mainTaboo\": \"盛夏酷暑闷热高湿且空气死气密闭不通风、自来水硬化盐碱化、宠物儿童抓咬误食。\", \"beginnerTip\": \"买回家后觉得好闻、好看就随手塞在没有阳光、常年关窗的死角空调房里，结果很快叶片落光变成枯木桩。\", \"yellowLeaves\": \"最普遍、最常见的是由于频繁倒水盆土长期积水闷根发黄；其次是切枝水养时由于水质变臭细菌堵塞吸水孔导致叶尖快速焦枯脱落。\"}','树干挺拔枝条轻盈，红黑绿三色交织对生排列，线条带有浓郁的东方侘寂美学与高雅的日式极简格调。','全株具有较强的吸附粉尘烟尘能力，水养切枝由于蒸腾大，对局部案头的空气湿度有极佳的调湿改善作用。','具有强烈的化学剧毒，严禁任何形式的任何嘴部接触或食用！','无家庭药用价值','寓意清高常青、镇宅辟邪、平心静气。其高雅飘逸的株形在风水学上有强大的净化明堂低迷磁场的效果。','客厅电视柜旁、落地大窗旁、沙发拐角视觉空白、侘寂风西餐茶几中央、高档会所书桌','排水良好的盆栽土','优质腐叶土:泥炭土:珍珠岩 = 3:2:2，盆底需垫好排水层','中式复古重质紫砂盆、简约塑料控根盆，或高透明的长款玻璃花瓶','口径20-30cm','每2年春季花谢后换盆换土一次',5.0,6.0,'hard','slow',200,1,1,0,0,'/images/plants/pieris-japonica.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(37,'油画婚礼紫露草','婚礼紫露草、彩叶吊竹梅','Tradescantia fluminensis Quadricolor','tradescantia-quadricolor','鸭跖草科','紫露草属','草本','多年生','观叶 / 悬垂','南美洲','油画婚礼紫露草是一种多年生常绿匍匐草本植物。其最大特征是叶片上交织着如同油画大笔触般的绝美条纹：粉红、乳白、浅绿、深绿四色相间，叶背为深紫红色。其枝蔓自然下垂生长，色彩极其梦幻、华丽。','粉白绿紫四色交织，如梦似幻的油画色彩爆盆小仙女','卵体椭圆形，全缘略带肉质，平展柔嫩','叶面上交织着粗细不一的乳白色、梦幻粉色、浅绿色条纹，叶背为深紫红色','茎匍匐或自然下垂生长，短小肉质化，节位极易生出气生根','小花三瓣呈三角形，丛生在枝条顶端，小巧玲珑精致','纯白色或淡粉红色','5-8月','少见','呈密集的丛生和垂吊状。无数色彩斑斓的梦幻彩叶错落层叠从盆沿垂挂漂逸，整体洋溢着一种法式轻奢与生机。','high',4,8,'非常喜光。最喜明亮充足的散射光或温和的日照直射。充足的光照是维持其叶面梦幻粉色不褪色的核心条件。','weekly',4,7,'等盆土表面往下2-3厘米彻底变干后再行浇透。冬季严格控水。','见干见湿','每4-6天1次','每3-5天1次','每5-7天1次','每10-14天1次，严格遵循不干不浇，防止湿冷闷根烂黑','严忌盆内长期存有死水积水，更忌在正午阳光暴晒时用冰冷冷水直接淋浇','普通的室温自来水即可','medium','对空气湿度要求中等，喜略微湿润的空气环境。干燥季节可向周围喷雾增加湿度。',15,28,10,35,0,'悬挂吊阳台、客厅高柜顶部、明亮书架边缘、朝东明亮窗台','喜温暖湿润、阳光充足环境，生命力一强健，怕干旱，忌土壤积水闷根，喜疏松肥沃的腐殖土。','喜温暖湿润，生长适温为15-28℃。不耐严寒，冬季室内越冬室温需维持在10℃以上。','高磷钾肥','biweekly','在春季和秋季生长期，每两周随浇水追施一次稀薄的花卉类水溶复合肥。盛夏和寒冬停肥。','春季和秋季','稀薄的低氮高磷钾多肉肥或花卉类专用营养液','不以观花为主，其碎小百花现蕾后随打顶摘除即可',1,'极忌施浓肥、生肥，严禁氮肥过量导致严重的返绿现象','新长出的彩叶变小变薄、叶色完全发淡失去油画色彩','春夏季','频繁进行打顶摘心控制主藤蔓长势，以及随时剪除过度返绿的分枝','在分枝所需的节位上方0.5厘米处平剪。可频繁将攀援蔓顶芽嫩尖掐断（打顶），剪下枝条可轻松扦插','避免在冬季极端寒冷、或切口极易发生霉烂软化的连续阴雨天气进行修剪','{\"fall\": \"秋季空气转凉，长势恢复，可以适当多见温和秋光促进粉色花纹对比度。逐渐减少给水。\", \"spring\": \"婚礼紫露草展叶的最好黄金期。确保充足的强散射光，干透浇透并恢复施薄肥。\", \"summer\": \"严防酷暑强光直射暴晒。必须移到心里最阴凉、空气通风的明亮散射光角落。坚决断肥。\", \"winter\": \"防寒防冻。必须立刻移入10度以上的温暖房间。严格控制浇水，盆土保持偏干状态。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"在空气过于干燥密闭且完全不通风时发生。叶片背面聚集密集微小红点，导致叶面干枯\", \"treatment\": \"用温水高压全面彻底冲洗叶片背面，或者喷洒阿维菌素药剂\"}], \"diseases\": [{\"name\": \"烂根病/黑腐病\", \"cause\": \"花盆透气性差或土壤黏重，频繁倒水导致盆土长期处于死水积水状态闷根\", \"symptom\": \"肉质匍匐茎突然变黑、溃烂，色彩缤纷的大面积叶片水渍状发黑坏死\", \"treatment\": \"立即脱盆，用利刀切除所有发黑坏死和软烂的主干。分枝晾干后用多菌灵消毒重新扦插\"}], \"prevention\": \"核心在于通过管住手、少浇水，多开窗、强通风。保持环境常年拥有绝佳的空气自然对流。\"}','微毒','全株汁液','折断后流出的肉质汁液中含有一定量的植物酸，敏感人群接触皮肤可能引发红肿瘙痒与皮炎过敏','对猫狗有微弱毒性，其悬垂的华丽彩叶极易吸引宠物玩耍啃咬，强烈建议采用吊盆高处悬挂养护。','{\"leggy\": \"长期将其摆放在完全缺乏直射阳光的阴暗死角，导致匍匐茎徒长，原本密集的粉色油画大叶完全褪色缩小，失去爆盆美感。\", \"noBloom\": \"它只要在冬春生长期内光照极其充足就会在枝顶抽出一朵朵小花，由于开花无观赏美感还会极度功能性夺取营养，通常应主动掐掉。\", \"drooping\": \"肥厚的彩叶和肉质茎整体失去弹性、软绵绵毫无支撑力地向花盆外翻瘫软。多为土壤干透极端缺水引起的脱水信号。\", \"mainTaboo\": \"氮肥过多导致完全返绿、频繁大水导致闷根、盛夏酷晒，以及冬季遭遇10度以下的低温摧毁。\", \"beginnerTip\": \"买回家后觉得它太梦幻太文艺了，天天频繁倒水，结果不到两个星期藤蔓全烂成了一地黏泥。\", \"yellowLeaves\": \"95%以上是由于频繁大水浇灌导致土壤长期泥泞积水闷根黑腐发黄；或者是由于长期缺乏阳光引起的植株严重返绿变弱发黄。\"}','粉白绿紫四色在单片圆叶上大笔触交织，梦幻迷离，作为悬垂吊盆效果极其爆棚惊艳。','草本微型悬垂植物，能微弱地吸附室内空气中的微小浮尘，对净化空气有微弱辅助作用。','无食用价值','无确切家庭药用价值','寓意美满圆满、百年好合、温馨充满爱意。有促进家人感情和睦、柔化屋室生硬建筑线条的效果。','悬挂吊阳台外侧、明亮客厅高柜边缘、书架顶部隔断、有温和散射光的朝东窗台','排水良好的盆栽土','优质泥炭土:腐叶土:珍珠岩 = 2:2:1，盆底垫好陶粒作为防排涝层','塑料吊盆最佳、简约白瓷盆','口径12-20cm','每年春季结合修剪打顶扦跨进行换盆换土一次',6.0,7.0,'easy','fast',30,1,1,0,1,'/images/plants/tradescantia-quadricolor.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(38,'琴叶喜林芋','琴叶蔓绿绒、小提琴蔓绿绒、龙鳞喜林芋','Philodendron panduriforme','philodendron-panduriforme','天南星科','喜林芋属','藤本','多年生','观叶','南美洲亚马逊河流域','琴叶喜林芋是一种多年生大型常绿攀援藤本观叶植物。其最独特的标志是巨大的大叶片形状极其酷似小提琴，叶面厚革质全缘，浓绿且散发出强烈的如翠玉或祖母绿般的高贵蜡质油亮光泽。','大叶提琴造型独特，挺拔油亮的高端热带雨林大木柱','呈极其明显的提琴状深凹陷（小提琴形），先端渐尖基部呈大耳状张开','浓绿色、墨绿色，表面光滑厚革质，在明亮光线下折射出亮绿蜡质层光泽','主干粗壮挺拔肉质化，多分枝，节位常长出长而粗糙的气生根','佛焰苞花序，在室内家庭盆栽普通养护环境下几乎100%终生不孕不会开花','绿白色','夏季','少见','主干依靠椰棕柱直立向上生长，长长的粗叶柄向外错落散开，托举着小提琴大叶向四周自然平展，具有现代软装的空间雕塑存在感。','medium',4,6,'最喜明亮充足的散射光或半阴舒适环境。极其耐阴。极忌盛夏酷暑强直射光暴晒。','weekly',5,8,'等盆土表层往下3-4厘米彻底变干后再行浇透水。冬季必须严格控水偏干。','见干见湿','每5-7天1次','每3-5天1次，大水量浇透并配合早晚叶面喷雾','每7-10天1次','每12-15天1次，严格坚持不干不浇','严忌花盆底部托盘长期处于积水状态，防地下肉质主根系缺氧窒息引发巨幅大叶发黄溃烂','普通的室温自来水即可','high','原产雨林，对空气湿度要求较高。喜空气湿润环境。',18,30,10,35,0,'客厅落地大窗旁、大沙发拐角空白、商务前台大堂、明亮大书房一侧','喜温暖湿润、强明亮散射光的半阴环境，极耐阴，生命力强健，怕长期土壤死水积水闷根，喜酸性营养土。','喜温暖舒适、多湿的热带雨林微气候，最适生长温度为18-30℃。不耐严寒。','平衡20-20-20','monthly','在春、夏、秋三季生长旺季，每月随浇水追施一次稀薄的无机观叶复合液肥即可。','春季和秋季','稀薄的富含氮素的观叶类平衡水溶肥','观叶藤本，完全无需施用任何促花肥',1,'极忌浓肥、生肥，严禁直接将未稀释的原肥原液大量浇灌在靠近须根基部','新长出的提琴叶个头严重缩水变小、叶面的特殊凹陷弧度变平','春季','随时剪除底部老化变黄的干枯大老叶、修剪受损破裂的残叶','用消毒过的锋利大割刀从老化叶柄基部平整割断。长势过高时，可在春季进行短截砍头，促使发分枝','剪叶流出白色或透明剧毒乳汁，换盆修剪需佩戴防渗透手套','{\"fall\": \"秋季空气干燥可多用抹布擦洗叶面。秋末降温后严格拉长浇水间隔，完全停止一切追肥，准备过冬。\", \"spring\": \"换盆修剪的黄金期。随着新提琴大叶源源不断萌发抽出，确保充足的明亮散射光，干透浇透并配合薄肥。\", \"summer\": \"严防湿热闷根与强烈烈日暴晒。必须彻底搬到心里最阴凉、强通风对流的大开窗半阴处。早晚多对叶面喷雾。\", \"winter\": \"防寒是第一要务。必须立刻进屋保暖，温度维持在10度以上。严格控制浇水，暖气房内需远离烤炉设备。\"}','{\"pests\": [{\"name\": \"红蜘蛛\", \"symptom\": \"空气极度极度干燥密闭且不通风时发生。提琴叶背面聚集密集碎尘状红点，导致叶片失绿\", \"treatment\": \"用温水高压全面彻底冲洗巨大叶片背面，或者喷洒阿维菌素稀释溶液进行驱杀\"}], \"diseases\": [{\"name\": \"烂根病/叶斑病\", \"cause\": \"花盆透气太差或盆大，频繁大水倒水土壤长期死水积水导致闷根\", \"symptom\": \"巨大的提琴大叶无故大量发黄溃烂，主干基部拔出后变黑发黏并伴有恶臭\", \"treatment\": \"立即脱盆，用利刀切除所有发黑腐烂的黑主根。切口涂抹多菌灵原粉彻底晾干重栽\"}], \"prevention\": \"控制浇水、土不干透不频繁倒水，始终保持阳光对流。\"}','有毒','全株各部位茎叶、长柄内流出的白色或透明汁液','全株汁液中含有大量的针状草酸钙结晶以及强刺激性有毒蛋白酶。皮肤直接触碰汁液会引发皮肤奇痒、红肿与刺痛','对猫、狗及儿童有严重的强毒性高风险！长长的紫红叶柄易被儿童或宠物玩耍啃咬。必须绝对将其摆放在儿童和宠物无法触及的安全处。','{\"leggy\": \"长期将其摆放在缺乏阳光的内侧走廊或昏暗死角，导致主干和长柄为了找光而发生细长。斑纹完全变浅。\", \"noBloom\": \"室内附生立式栽培环境下由于空间和热带阳光积温高度受限，几乎100%一辈子都不会开花，主要作为常绿高级提琴观叶大树观赏。\", \"drooping\": \"巨幅的大提琴叶整体失去弹性、软绵绵顺着主干向下低垂耷拉。多为土壤彻底干透脱水引起的信号。\", \"mainTaboo\": \"裸手直接修剪接触乳汁、频繁频繁倒水大水、盛夏烈日暴晒，以及冬季遭遇5度以下的冰冷严寒重创。\", \"beginnerTip\": \"每天回家都往大盆里频繁倒大杯水，并且把窗户长年关得死死的，结果不到两个星期主干和根就全黑腐烂了。\", \"yellowLeaves\": \"90%以上是由于频繁大水倒水导致土壤长期积水死水闷根烂根；或者是遭遇了严重的冬季寒流受冻冻伤。\"}','叶形精美绝伦（形似小提琴），色泽深邃油亮、蜡质光泽强烈，自带高冷、奢华与现代生活的空间存在感。','巨幅的皮革质大叶片能高效吸附室内的漂浮微粒、粉尘；并能高效率地吸收室内的甲醛、苯等化学毒气。','具有较强剧毒，严禁任何形式的任何嘴部接触或食用！','无家庭药用价值','寓意基业长青、招财进宝、平平安富贵。在风水学上有强大的镇宅辟邪、化解硬实拐角煞气效果。','客厅明亮大落地窗旁、大沙发拐角一侧空白大位、商务前台大堂、写字楼老总位、高档展厅','排水良好的盆栽土','优质腐叶土:泥炭土:园土:珍珠岩 = 3:2:2:2，盆底必须垫好陶粒作为防淤排水层','由于高大且带有木质质感，必须选用稳重厚大号的水泥盆、手工大陶盆或高档塑料深盆','口径25-45cm','每1-2年春季换盆、换土一次',5.5,6.5,'easy','fast',200,1,1,0,1,'/images/plants/philodendron-panduriforme.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(39,'青叶冷水花','花叶冷水花、白雪草、铝叶草','Pilea cadierei','pilea-cadierei','荨麻科','冷水花属','草本','多年生','观叶','中国中南部、越南','青叶冷水花是一种多年生常绿草本植物。其最大特征是具有极其精致的对生卵状椭圆形叶片，翠绿的叶面上沿着凸起的叶脉整齐地分布着大面积乳白色至银白色的斑块，仿佛涂了一层液态铝，色彩对比度极高。','银绿相间、金属质感浓郁的耐阴小草本','卵状长椭圆形，全缘，表面光滑带有轻微波状凹凸','主叶色为亮绿色或深绿色，叶肉部分凸起并密布着如银霜般的乳白色条状斑块','茎直立或基部匍匐，肉质多汁，浅绿色，分枝多','聚伞花序，小花极细小如碎米，室内盆栽极少开花','黄白色','5-6月','少见','整株体型低矮、繁密紧凑。一片片带有金属光泽的银绿对生叶片整齐排列在肉质茎上，别致小巧。','medium',3,6,'最喜温暖明亮的散射光或半阴环境，极耐阴。忌烈日暴晒，强光极易烧伤叶面。','frequent',3,5,'属于喜湿润的植物，不耐干旱。生长期保持盆土充沛湿润，表土微干就要立即浇透水。','见干见湿 / 喜湿忌干','每3-5天1次','每2-3天1次，配合频繁周围喷雾','每4-6天1次','每10-12天1次，严格遵循不干不浇','严忌花盆长期形成死水积水导致烂根，更忌土壤彻底干透变成硬块','普通的室温自来水即可','high','喜湿润的空气环境。在干燥季节或供暖期，需高频向花盆周围喷雾以防叶尖枯焦。',15,28,8,35,0,'朝东窗台内侧、小书桌、明亮洗手间、客厅茶几边缘','喜温暖湿润、强半阴环境，怕干旱，忌盆土积水，喜疏松保水营养土。','喜温暖舒适，生长适温为15-28℃。不耐寒，冬季越冬温度需保持在8℃以上。','平衡20-20-20','monthly','在春秋生长期每月随浇水追施一次稀薄的观叶平衡肥即可。','春季和秋季','稀薄的富含钾素的无机观叶专用液肥','主要是观叶，无需促花肥，见花序可摘除',1,'忌施浓肥、生肥，避免原液直接大量沾染侧枝','新叶个头变小、银色斑块范围大幅缩水或褪色变绿','春季','随时剪除底部老化变黄的枯老叶，在长势过高时进行打顶摘心','用小剪刀在所需的叶节上方平剪。可在主蔓长高到15厘米时进行打顶，刺激腋芽爆发','避免在冬季严寒或伤口不易愈合的阴雨天气重剪','{\"fall\": \"秋末随降温逐步拉长浇水间隔，完全停止施肥，多见温和阳光促使茎干充实。\", \"spring\": \"换盆与打顶扦插的黄金期。逐渐增加浇水，保持空气湿度与明亮散射光，开始恢复施薄肥。\", \"summer\": \"高温期需移到阴凉、强通风对流的半阴角落，供水需高频充分，严防热闷，全面断肥。\", \"winter\": \"绝对防寒保暖，室温控在8度以上，严格控制浇水，盆土不干不浇，供暖房注意防干燥。\"}','{\"pests\": [{\"name\": \"蚜虫/红蜘蛛\", \"symptom\": \"嫩梢或叶背聚集密集微小飞虫或红点，导致叶面起皱变形\", \"treatment\": \"用温和弱水流全面强力冲洗干净，数量多时喷洒吡虫啉防治\"}], \"diseases\": [{\"name\": \"烂根病\", \"cause\": \"花盆透气差，频繁大水导致土壤长期处于死水积水状态闷根\", \"symptom\": \"下部叶片成批干黄脱落，肉质茎基部变黑软烂软塌\", \"treatment\": \"脱盆剪除烂根，用多菌灵消毒后换用透气新土，严格断水控水\"}], \"prevention\": \"核心在于管住手、土不干透不频繁倒水，保持养护环境拥有良好的空气流通。\"}','无毒','无','全株完全无毒。属于100%绝对无毒的家庭常绿肉质植物，汁液安全无害','对猫、狗及儿童绝对安全。由于叶片精美，虽然无毒环境但会破坏造型，宜放在稳固台面。','{\"leggy\": \"长期将其摆放在严重缺乏散射光的阴暗死角，导致茎轴拔高且叶片间距极稀疏变薄。\", \"noBloom\": \"室内养护属于正常现象，主要作为常绿观叶小盆栽栽培，无专门开花追求。\", \"drooping\": \"叶片干瘪耷拉通常是土壤干透彻底缺水引起的，及时浇透水半天内可恢复坚挺。\", \"mainTaboo\": \"彻底干旱缺水、花盆托盘长期积水，以及盛夏酷暑烈日曝晒。\", \"beginnerTip\": \"把它随手丢在阳光充足、空气干燥的阳台上，结果不到三天娇嫩的叶片就全部被晒焦枯死。\", \"yellowLeaves\": \"频繁大量倒水导致盆土积水闷根发黄，或者遭遇了严重的冬季低温冻害。\"}','叶面的银绿条纹极具液态金属质感，株形矮小紧凑，常用作精致的桌面案头绿化。','吸附灰尘能力优秀，能吸附室内的有害化学微粒，对调节空气湿度有一定辅助作用。','无食用价值','无确切家庭药用价值','寓意事事顺心、大吉大利。在风水上有柔化生硬书桌棱角、聚气生旺的效果。','办公室台面、独立小书桌、客厅茶几边缘、明亮洗手间窗台内侧','排水良好的盆栽土','泥炭土:腐叶土:珍珠岩 = 2:2:1，保水兼具排涝性','精致小巧的红陶盆、白瓷盆','口径10-15cm（根系短浅，不宜用深大盆）','每年春季换盆、换土一次',6.0,7.0,'easy','moderate',25,1,0,1,1,'/images/plants/pilea-cadierei.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(40,'鸟巢蕨','巢蕨、山苏花、雀巢蕨','Asplenium nidus','asplenium-nidus','铁角蕨科','铁角蕨属','草本','多年生','观叶','热带亚洲、非洲及澳洲','鸟巢蕨是一种多年生大型常绿附生草本蕨类植物。其最大的特征是无数片阔披针形、鲜绿油亮的大叶片呈辐射状自短小的根状茎中心向外环状生发，中心深深凹陷，形状极其酷似一个架在树干上的巨大鸟巢。','环抱如巢，翠绿光滑且极度耐阴的热带雨林林下附生蕨','阔披针形，革质表面光滑，全缘呈华丽的轻微波状起伏，叶柄极短','鲜绿色、亮绿色，中脉在叶背强烈凸起并常呈黑端绿色','地上茎不明显；直立根状茎短而粗壮，密被黑褐色鳞片，形成环状巢心','蕨类植物，终生不抽花茎，完全不发育花卉、无花','无','无','无（靠成熟叶背产生的条状线形孢子囊群进行繁殖）','无数巨大的翠绿叶自中心基部呈完美的抛物线向外辐射舒展，具有独特的几何对称美感。','low',2,4,'高度耐阴。最喜温暖阴湿的明亮散射光或半阴环境。能在缺乏直射阳光的昏暗室内长期健康存活。极忌阳光暴晒。','frequent',3,5,'鸟巢蕨属于\"喜水派\"，大叶片水分蒸发快且不耐干旱。生长期必须保持盆土彻底湿润。','见干见湿 / 喜湿忌干','每3-5天1次','每2-3天1次，高温干燥期除浇透外必须向叶面及中心的巢心周围喷洒雾气增湿','每4-6天1次','每8-12天1次，严格遵循不干不浇，防止冷湿闷根冻坏','严忌盆土彻底干透变成硬块、更忌花盆托盘内长期死水积水，冬季严忌大水灌入中心叶心防黑腐','普通的室温自来水即可','high','原产密林深处附生环境，对空气湿度要求很高。空气太干燥会导致叶边缘发生干焦卷曲。',16,26,10,32,0,'北侧客厅角落、高湿明亮的洗手间窗台内侧、明亮厨房、北向书桌一角','喜温暖阴湿、强半阴环境，极畏强光直射，极其不耐干旱，怕积水闷根，喜透气性好、排水优良的微酸性土。','喜温暖舒适、高湿的雨林环境，生长适温为16-26℃。非常不耐寒。','平衡20-20-20','biweekly','在春季和秋季生长期，每两周随浇水追施一次极其稀薄的观叶类水溶无机平衡液肥。','春季和秋季','极其稀薄的花卉观叶类平衡水溶肥','蕨类属于无花植物，完全无需使用任何促花肥',1,'极忌浓肥、生肥，严禁直接将无机复合肥颗粒丢入中心包裹的巢心内，防止烧黑腐烂心','新长出的辐射大叶个头明显变小变薄、叶色失去亮绿色泽变得暗淡发黄','春季','随时剪除底层老化变黄的陈旧老叶、随时修剪受损破裂严重的残叶','用消毒剪刀在所需的叶片最基部，贴近短根状茎平整剪断','严忌损伤或剪断位于最中心巢心中央刚长出的娇嫩新叶芽，顶芽一旦受损该巢将彻底报废','{\"fall\": \"秋季空气转极度干燥，是发生焦边的高危期。必须高频向其周围喷雾。秋末随气温下降严格拉长浇水时间。\", \"spring\": \"换盆换土与恢复长势的黄金期。新叶从中心巢底疯狂抽出，开始恢复施稀薄肥，常往周围喷雾。\", \"summer\": \"极度害怕高温高湿加不通风。必须彻底移到强半阴角落。必须每天早晚对全株大面积喷雾降温，断肥。\", \"winter\": \"防寒防冻是生死存亡的第一要务！必须立刻移入10度以上的温暖房间。严格控制浇水，保持偏干。\"}','{\"pests\": [{\"name\": \"红蜘蛛/介壳虫\", \"symptom\": \"在空气过于干燥密闭且完全不通风时发生。阔披针形大叶背出现细密红点或飞虫\", \"treatment\": \"用温水高压全面彻底冲洗叶片背面，数量多时喷洒阿维菌素稀释药剂防治\"}], \"diseases\": [{\"name\": \"线虫病/烂根心腐\", \"cause\": \"花盆过大，土壤长期死水积水闷根，或在夏季高温高湿期浇水直接灌入中心巢底且通风差\", \"symptom\": \"叶片内部产生褐色大面积坏死条斑，或者中心巢底变黑、发黏软烂发生大面积塌陷坏死\", \"treatment\": \"剪掉受损严重的叶柄。脱盆用利刀切除坏死根系，多菌灵消毒后更换干净新土，断水改善强通风\"}], \"prevention\": \"常年营造高空气湿度并严防盆土长期处于积水死水状态，保持室内优良的对流通风。\"}','无毒','无','全株完全无毒。属于完全无毒的家庭绿色草本蕨类，无任何化学毒素','对猫、狗及儿童绝对安全。被官方认证的对猫狗完全无毒的友好植物。由于其环抱的鸟巢结构极其好玩，猫咪极其喜欢钻入其巢中睡觉。','{\"leggy\": \"长期将其摆放在缺乏阳光的客厅死角，导致新叶为了找光而细长无力并向盆沿下垂倒伏，叶色变淡。\", \"noBloom\": \"蕨类植物属于孢子无花植物，终生不抽花序不孕，这完全属于正常的蕨类特性。\", \"drooping\": \"呈放射状平展的阔大叶整体失去弹性、软绵绵毫无支撑力地顺着盆沿向下瘫软。多为干旱脱水或已烂根。\", \"mainTaboo\": \"频繁频繁大水浇灌导致土壤泥泞、盛夏酷暑冬季强光直射暴晒、冬季低温期大水灌入叶心导致冷湿闷根烂心。\", \"beginnerTip\": \"买回家后觉得它长得像一个大鸟巢很新奇，天天往它的中心巢心里频繁灌水，结果很快烂成了发黑酸臭的黏泥。\", \"yellowLeaves\": \"90%以上是由于频繁大水倒水导致土壤长期处于死水积水状态导致闷根发黄；其次是冬季气温受冻发黄。\"}','翠绿光滑的大蕉叶呈抛物线向四周自然舒展，层叠丛生出完美的圆形深巢结构，线条极其优雅大气。','由于体型高大且巨幅叶片表面积惊人，能高效率地成批吸收室内的甲醛、二氧化碳。','无食用价值','在传统中医药学中，同属植物全草有清热解毒、强壮筋骨的微弱功效。','名字带有著名的鸟巢，寓意吉祥如意、阖家平安、筑巢引凤。有极佳的聚气生旺风水迎祥效果。','客厅北侧阴凉角、明亮大书房一侧、高湿明亮洗手间窗台、独立高脚花架顶部','排水良好的盆栽土','优质泥炭土:发酵松树皮:珍珠岩 = 2:2:1，必须保证高度疏松透气保水，盆底垫陶粒','透气性优良的浅口矮胖红陶盆、树脂吊盆','口径15-25cm（其根系集中在基部，不宜选用大深盆）','每1-2年春季换盆换土一次',5.5,6.5,'easy','moderate',60,1,0,1,1,'/images/plants/asplenium-nidus.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(41,'黑叶观音莲','黑叶芋、观音莲、非洲面具','Alocasia amazonica','alocasia-amazonica','天南星科','海芋属','草本','多年生','观叶','亚洲热带地区','黑叶观音莲是一种多年生常绿草本植物。其最引人注目的是其叶片形状：呈华丽的箭形或盾状心形。叶面为极为深邃、泛着金属光泽的墨绿色，而叶脉则呈对比强烈的银白色，边缘带有优美的波状起伏。','墨黑箭叶交织银白脉络，极具现代冷艳感的高端魔幻绿植','箭形或盾状心形，叶缘呈波状起伏，叶面厚革质','极为深邃的墨绿色，泛着金属光泽，叶脉呈对比强烈的银白色','地下有肉质块茎，地上茎短缩，粗壮的叶柄自基部直立抽出','佛焰苞花序，室内盆栽环境下极少开花','白绿色','少见','少见','墨黑箭叶交织银白脉络，整体呈紧凑的莲座状丛生，极具现代冷艳魔幻气质。','medium',3,5,'最喜温暖明亮的散射光或半阴舒适环境。极忌盛夏烈日暴晒，强光直射会瞬间将肥厚墨黑的叶面灼伤并烤焦枯萎。','weekly',5,8,'遵循\"见干见湿\"原则。等盆土表层往下2-3厘米彻底变干后再行浇透水。','见干见湿','每5-7天1次','每3-5天1次，配合早晚叶面喷雾增湿','每7-10天1次','每12-15天1次，严格遵循不干不浇，防止湿冷闷根烂茎','严忌花盆底部托盘长期积水，更忌冬季大水灌入叶心导致黑腐烂心','普通的室温自来水即可','high','对空气湿度要求严苛，理想湿度在65%以上。',18,30,12,32,0,'客厅明亮散射光角落、书房窗台内侧、高湿洗手间、办公室桌面','喜温暖高湿、明亮散射光的半阴环境，极畏强光直射，不耐干旱，怕积水闷根，喜疏松透气微酸性土。','喜温暖舒适、高湿的热带环境，非常不耐寒。冬季室内越冬室温需维持在12℃以上。','平衡20-20-20','monthly','在春季和秋季生长期，每月随浇水追施一次稀薄的观叶无机平衡液肥即可。','春季和秋季','稀薄的观叶类平衡水溶肥','观叶植物，无需施用促花肥',1,'极忌浓肥、生肥，严禁将肥料直接撒在叶柄基部的块茎上','新叶变小变薄、银白叶脉变淡、叶色失去深邃墨绿光泽','春季','随时剪除底部老化变黄的枯老叶、修剪受损破裂的残叶','用消毒剪刀从老化叶柄基部平整剪断','修剪时汁液有刺激性，需佩戴手套操作，修剪后避免立即叶面喷水','{\"fall\": \"秋凉后恢复正常浇水施肥。秋末随降温逐步拉长浇水间隔，完全停止追肥。\", \"spring\": \"展叶黄金期。新叶从基部陆续萌发，确保充足明亮散射光，干透浇透并恢复施薄肥。\", \"summer\": \"严防湿热闷根与烈日暴晒。必须移到强半阴、强通风的阴凉处。高温期早晚喷雾降温，断肥。\", \"winter\": \"防寒是第一要务！室温必须维持在12度以上。严格控水，盆土不干不浇，保持偏干。\"}','{\"pests\": [{\"name\": \"红蜘蛛/蚜虫\", \"symptom\": \"空气干燥密闭不通风时，叶背聚集微小红点或小飞虫\", \"treatment\": \"用温水高压冲洗叶片背面，或喷洒阿维菌素、吡虫啉防治\"}], \"diseases\": [{\"name\": \"软腐病/叶斑病\", \"cause\": \"土壤长期死水积水，或浇水灌入叶心且通风差\", \"symptom\": \"叶柄基部或叶片出现水渍状软腐坏死，伴有恶臭\", \"treatment\": \"立即脱盆切除腐烂部分，多菌灵消毒后换新土重栽，严格控水改善通风\"}], \"prevention\": \"保持常年高湿度和优良通风，管住手少浇水，定期擦拭叶面。\"}','有毒','全株各部位，特别是茎叶内的汁液','全株汁液含有大量草酸钙结晶。误食会引发口腔、咽喉剧烈疼痛肿胀，皮肤接触汁液会红肿瘙痒','对猫、狗及儿童有严重毒性！必须绝对摆放在儿童和宠物无法触及的安全处。','{\"leggy\": \"长期缺乏散射光，导致叶柄细长、叶片变小、银白脉纹变淡。\", \"noBloom\": \"室内环境下极少开花，主要作为观叶植物栽培，属正常现象。\", \"drooping\": \"叶片整体下垂失去弹性，多为土壤干透缺水或根系已烂。\", \"mainTaboo\": \"裸手接触汁液、频繁大水、盛夏烈日暴晒、冬季低温冻害。\", \"beginnerTip\": \"买回家天天浇水且放在阴暗角落，结果很快块茎腐烂、叶片全倒。\", \"yellowLeaves\": \"90%以上是频繁大水导致土壤积水闷根；或冬季低温冻害所致。\"}','墨黑箭叶交织银白脉络，极具现代冷艳感，是高端魔幻绿植的代表。','大型叶片能有效吸附室内浮尘，对甲醛等有害气体有一定的吸收能力。','具有较强剧毒，严禁任何形式的食用！','无家庭药用价值','寓意平安吉祥、驱邪避煞。在风水上有化解阴气、镇宅守财的效果。','客厅明亮角落、书房窗台内侧、高湿洗手间、办公室桌面、高档展厅','排水良好的盆栽土','优质泥炭土:腐叶土:珍珠岩 = 2:2:1，必须保证高度疏松透气','透气性好的红陶盆、简约白瓷盆或深色水泥盆','口径15-25cm','每1-2年春季换盆换土一次',5.5,6.5,'medium','slow',50,1,0,0,1,'/images/plants/alocasia-amazonica.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(42,'金钻蔓绿绒','金钻、大叶蔓绿绒、绿帝王','Philodendron Imperial Green','philodendron-imperial-green','天南星科','喜林芋属','草本','多年生','观叶','南美洲热带雨林','金钻蔓绿绒是一种多年生常绿草本观叶植物。其最大特征是地上无明显主茎，粗壮的复叶长柄自基部紧凑抽生。叶片巨大，呈优美的宽长心形，叶面浓绿深邃，散射出如同涂了一层厚重亮漆般的高贵奢华质感。','叶片肥硕如漆，硬朗挺拔且抗逆性极强的大器镇宅绿植','宽长心形，叶面厚革质，全缘，叶尖渐尖','浓绿深邃，散射出如同涂了一层厚重亮漆般的高贵奢华质感','地上无明显主茎，粗壮的复叶长柄自基部紧凑抽生','佛焰苞花序，在室内家庭盆栽环境下几乎不会开花','少见','少见','少见','叶片肥硕如漆，硬朗挺拔，整体呈紧凑的丛生灌木状，具有强烈的现代空间存在感。','medium',4,6,'最喜明亮充足的散射光或半阴舒适环境。能在普通客厅昏暗的角落长期存活。极忌盛夏酷暑烈日暴晒。','weekly',5,8,'浇水严格遵循\"见干见湿\"原则。必须等盆土表层往下3-4厘米彻底变干后再行浇透水。','见干见湿','每5-7天1次','每3-5天1次，大水量浇透并配合早晚叶面喷雾','每7-10天1次','每12-15天1次，严格坚持不干不浇','严忌花盆底部托盘长期积水，防地下肉质根缺氧窒息烂根','普通的室温自来水即可','high','喜空气湿润环境。在春夏季生长黄金期和冬季北方暖气房干燥期，需定期喷雾。',18,30,10,35,0,'客厅落地大窗旁、大沙发拐角空白、商务前台大堂、明亮大书房一侧','喜温暖湿润、强明亮散射光的半阴环境，极耐阴，生命力强健，怕长期土壤积水闷根，喜疏松肥沃微酸性土。','喜温暖舒适、多湿的热带雨林气候，最适生长温度为18-30℃。较抗酷暑。不耐严寒。','平衡20-20-20','monthly','在春、夏、秋三季生长旺季，每月随浇水追施一次稀薄的无机观叶复合液肥。','春季和秋季','稀薄的富含氮素的观叶类平衡水溶肥','观叶植物，完全无需施用任何促花肥',1,'极忌浓肥、生肥，严禁直接将未稀释的原肥原液大量浇灌在靠近须根基部','新长出的叶片个头严重缩水变小、叶面失去油亮光泽变得暗淡','春季','随时剪除底部老化变黄的枯老叶、修剪受损破裂的残叶','用消毒过的锋利剪刀从老化叶柄基部平整割断','剪叶流出的汁液有一定刺激性，换盆修剪需佩戴手套','{\"fall\": \"秋凉后恢复正常养护。秋末随降温严格拉长浇水间隔，完全停止追肥，准备过冬。\", \"spring\": \"换盆修剪的黄金期。新叶源源不断萌发，确保充足的明亮散射光，干透浇透并配合薄肥。\", \"summer\": \"严防湿热闷根与烈日暴晒。必须搬到阴凉、强通风的半阴处。早晚多对叶面喷雾，断肥。\", \"winter\": \"防寒是第一要务。室温维持在10度以上。严格控水，暖气房内需远离热源设备。\"}','{\"pests\": [{\"name\": \"红蜘蛛/介壳虫\", \"symptom\": \"空气干燥密闭不通风时，叶背聚集微小红点或白色介壳\", \"treatment\": \"用温水高压冲洗叶片背面，或喷洒阿维菌素防治\"}], \"diseases\": [{\"name\": \"叶斑病/烂根病\", \"cause\": \"花盆透气差，频繁大水导致土壤长期积水闷根\", \"symptom\": \"叶片出现大面积褐斑或水渍状溃烂，根系变黑发黏\", \"treatment\": \"立即脱盆，切除腐烂根系，多菌灵消毒后换新土重栽，严格控水\"}], \"prevention\": \"管住手少浇水，土不干透不倒水，保持阳光对流通风。\"}','有毒','全株各部位茎叶、叶柄内流出的汁液','全株汁液含有草酸钙结晶及刺激性蛋白酶。皮肤接触汁液会引发红肿瘙痒','对猫、狗及儿童有较强毒性！必须绝对摆放在儿童和宠物无法触及的安全处。','{\"leggy\": \"长期缺乏散射光，导致叶柄细长拔高、叶片变薄变小失去油亮光泽。\", \"noBloom\": \"室内环境下几乎不会开花，主要作为常绿观叶植物栽培，属正常现象。\", \"drooping\": \"大叶整体下垂失去弹性，多为土壤彻底干透缺水或根系已烂。\", \"mainTaboo\": \"频繁大水、盛夏烈日暴晒、冬季低温冻害。\", \"beginnerTip\": \"天天往大盆里频繁倒大杯水，结果不到两个星期根系全黑腐烂了。\", \"yellowLeaves\": \"90%以上是频繁大水倒水导致土壤积水闷根；或冬季低温冻伤。\"}','叶片肥硕如漆，硬朗挺拔，自带高冷与现代奢华的空间存在感。','大型厚革质叶片能高效吸附室内浮尘、甲醛、苯等有害气体。','具有较强毒性，严禁任何形式的食用！','无家庭药用价值','寓意基业长青、招财进宝。在风水学上有强大的镇宅辟邪、化解煞气效果。','客厅明亮大落地窗旁、大沙发拐角、商务前台大堂、写字楼办公室、高档展厅','排水良好的盆栽土','优质腐叶土:泥炭土:珍珠岩 = 3:2:2，盆底必须垫好陶粒作为防淤排水层','稳重大号的水泥盆、手工大陶盆或高档塑料深盆','口径20-35cm','每1-2年春季换盆、换土一次',5.5,6.5,'easy','fast',200,1,1,0,1,'/images/plants/philodendron-imperial-green.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(43,'千手观音海芋','千手观音、滴水观音小型种、小海芋','Alocasia cucullata','alocasia-cucullata','天南星科','海芋属','草本','多年生','观叶','中国中南部、中南半岛','千手观音海芋是一种多年生常绿草本植物，为滴水观音的同属小型精巧变种。其最大的标志是其叶片较小而密集：呈精致完美的肥厚倒卵状心形。由于它长势快、分蘖多，无数叶片错落层叠如千手舒展。','叶形如心，叶丛层叠密集如千手舒展的灵动吐水神草','精致完美的肥厚倒卵状心形，叶面光滑有光泽','鲜绿色、亮绿色，叶脉清晰，叶面光滑有蜡质光泽','地下有肉质块茎，地上茎短缩，分蘖力极强，密集丛生','佛焰苞花序，室内盆栽环境下偶尔可见','白绿色','夏季','少见','无数叶片错落层叠如千手舒展，整体呈密集的莲座状丛生，灵动飘逸。','medium',4,6,'喜充足明亮的散射光和柔和的半阴环境。极其耐阴。绝对铁律：严禁盛夏烈日直接直射曝晒！','weekly',4,7,'千手观音海芋属于\"喜水派\"，对水分依赖度高。生长期必须保持盆土充沛湿润。','见干见湿 / 喜水派','每4-6天1次','每2-3天1次，高温干燥期配合频繁叶面喷雾','每5-7天1次','每10-15天1次，严格遵循不干不浇','严忌花盆底部托盘长期积水，冬季严忌大水灌入叶心导致黑腐','普通的室温自来水即可','high','对空气湿度要求较高。当室内环境空气极其潮湿且土壤水分充足时，叶尖会通过吐水孔排出多余水分形成\"滴水\"奇观。',18,32,10,35,0,'客厅明亮散射光角落、书房窗台内侧、高湿洗手间、明亮玄关','喜温暖高湿、明亮散射光的半阴环境，极耐阴，生命力极其旺盛，怕积水闷根，喜疏松肥沃微酸性土。','喜温暖舒适、高湿的热带近水微环境，最适生长温度为18-32℃。长势极其野蛮迅速。非常不耐严寒。','平衡20-20-20','monthly','千手观音生命力极其野蛮、长势恐怖迅速，属于极度喜肥的植物。在生长旺季每月追肥一次。','春季和秋季','稀薄的富含氮素的观叶类平衡水溶肥','以观叶为主，无需施用促花肥',1,'极忌浓肥、生肥，严禁将肥料直接撒在叶柄基部的块茎上','新叶变小变薄、叶色变淡失去亮绿光泽','春季','随时剪除底部老化变黄的枯老叶、修剪受损破裂的残叶','用消毒剪刀从老化叶柄基部贴近块茎处平整剪断','汁液有一定刺激性，需佩戴手套操作','{\"fall\": \"秋凉后恢复正常浇水施肥。秋末随降温逐步拉长浇水间隔，完全停止追肥。\", \"spring\": \"展叶黄金期。新叶从基部大量萌发，确保充足明亮散射光，干透浇透并恢复施薄肥。\", \"summer\": \"严防湿热闷根与烈日暴晒。必须移到强半阴、强通风处。高温期早晚喷雾降温，断肥。\", \"winter\": \"防寒是第一要务！室温必须维持在10度以上。严格控水，盆土不干不浇。\"}','{\"pests\": [{\"name\": \"红蜘蛛/蚜虫\", \"symptom\": \"空气干燥密闭不通风时，叶背聚集微小红点或小飞虫\", \"treatment\": \"用温水高压冲洗叶片背面，或喷洒阿维菌素、吡虫啉防治\"}], \"diseases\": [{\"name\": \"软腐病/叶斑病\", \"cause\": \"土壤长期积水，或浇水灌入叶心且通风差\", \"symptom\": \"叶柄基部或叶片出现水渍状软腐坏死，伴有恶臭\", \"treatment\": \"立即脱盆切除腐烂部分，多菌灵消毒后换新土重栽，严格控水改善通风\"}], \"prevention\": \"保持常年高湿度和优良通风，管住手少浇水，定期擦拭叶面。\"}','有毒','全株各部位，特别是茎叶和块茎内的汁液','全株汁液含有草酸钙结晶。误食会引发口腔咽喉疼痛肿胀，皮肤接触汁液会红肿瘙痒','对猫、狗及儿童有较强毒性！必须摆放在儿童和宠物无法触及的安全处。','{\"leggy\": \"长期缺乏散射光，导致叶柄细长、叶片变小变薄。\", \"noBloom\": \"室内环境下偶尔可见佛焰苞花序，主要作为观叶植物栽培。\", \"drooping\": \"叶片整体下垂失去弹性，多为土壤干透缺水或根系已烂。\", \"mainTaboo\": \"裸手接触汁液、频繁大水、盛夏烈日暴晒、冬季低温冻害。\", \"beginnerTip\": \"天天浇水且放在阴暗角落，结果很快块茎腐烂、叶片全倒。\", \"yellowLeaves\": \"90%以上是频繁大水导致土壤积水闷根；或冬季低温冻害所致。\"}','叶形如心，叶丛层叠密集如千手舒展，灵动飘逸，极具东方禅意美感。','大型叶片能有效吸附室内浮尘，对甲醛等有害气体有一定的吸收能力。','具有较强毒性，严禁任何形式的食用！','无家庭药用价值','寓意千手护佑、平安吉祥。在风水上有化解煞气、镇宅保平安的效果。','客厅明亮角落、书房窗台内侧、高湿洗手间、明亮玄关、办公室桌面','排水良好的盆栽土','优质腐叶土:泥炭土:珍珠岩 = 3:2:2，盆底垫好陶粒排水层','透气性好的红陶盆、简约白瓷盆','口径15-25cm','每1-2年春季换盆换土一次',5.5,6.5,'easy','fast',150,1,1,0,1,'/images/plants/alocasia-cucullata.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(44,'彩叶芋','五彩芋、花叶芋、天使翅膀','Caladium bicolor','caladium-bicolor','天南星科','五彩芋属','草本','多年生','观叶','南美洲亚马逊河流域热带雨林','彩叶芋是一种多年生肉质块茎草本植物。其最大特征是叶片薄如蝉翼、形似巨大的爱心或天使的翅膀。叶面上交织着纯白、娇粉、鲜红、碧绿等大自然涂抹出的绝美条纹与半透明斑块。','叶薄如蝉翼、白粉红交织如天使翅膀的华丽彩色艺术品','薄如蝉翼，形似巨大的爱心或天使翅膀，叶面光滑','叶面上交织着纯白、娇粉、鲜红、碧绿等绝美条纹与半透明斑块','地下有肉质块茎，地上茎短缩，粗壮的叶柄自基部直立抽出','肉穗花序，室内盆栽环境下极少开花，开花无观赏价值','白绿色','少见','少见','叶薄如蝉翼、白粉红交织如天使翅膀，整体呈紧凑的莲座状丛生，华丽梦幻。','high',5,8,'喜充足明亮的明亮散射光。充足的明亮散射光是维持其叶面华丽粉红、纯白色彩对比的核心核心动力。','frequent',2,4,'彩叶芋是著名的\"水娃娃\"，叶片极薄且对水分依赖度达到恐怖级别，不耐任何形式的干旱。','见干见湿 / 喜水派','每3-5天1次','每2-3天1次，高温干燥期配合频繁叶面喷雾','每4-6天1次','休眠期完全断水，保持块茎干燥','严忌任何形式的干旱，叶片极薄极易脱水枯萎；更忌花盆底部托盘长期积水','普通的室温自来水即可','high','对空气湿度要求极高，理想湿度在65%-80%之间。',20,32,15,35,0,'客厅明亮散射光角落、书房窗台内侧、高湿洗手间、明亮玄关','极喜高温高湿、明亮散射光环境，不耐干旱，怕积水闷根，喜疏松肥沃微酸性土。具有冬眠特性。','极喜高温舒适、高湿的热带环境，生长适温为20-32℃。极其耐热。具有冬眠特性。','高磷钾肥','biweekly','在春季萌芽至秋初生长期，每两周随浇水追施一次观叶类花卉复合液肥。','春季和秋季','稀薄的观叶类花卉复合液肥','以观叶为主，无需施用促花肥',1,'极忌浓肥、生肥，休眠期严禁施肥','新叶变小变薄、叶面的粉红白色斑纹变淡缩小','春季','随时剪除底部老化变黄的枯老叶、修剪受损破裂的残叶','用消毒剪刀从老化叶柄基部贴近块茎处平整剪断','叶片极薄易碎，操作时需极其轻柔','{\"fall\": \"秋凉后叶片逐渐枯黄，是自然进入休眠的信号。逐步减少浇水和施肥，直至完全停止。\", \"spring\": \"萌芽展叶黄金期。块茎萌发后确保充足明亮散射光，保持盆土湿润并开始施薄肥。\", \"summer\": \"高温高湿是其最佳生长期。必须保持充足水分和空气湿度，避免烈日暴晒，薄肥勤施。\", \"winter\": \"休眠期。将块茎留在干燥盆土中或挖出存放在干燥温暖处，完全断水断肥，室温保持15度以上。\"}','{\"pests\": [{\"name\": \"蚜虫/红蜘蛛\", \"symptom\": \"嫩叶或叶背聚集密集微小飞虫或红点\", \"treatment\": \"用温水高压冲洗，或喷洒吡虫啉、阿维菌素防治\"}], \"diseases\": [{\"name\": \"软腐病/块茎腐烂\", \"cause\": \"土壤长期积水，或休眠期盆土过湿导致块茎腐烂\", \"symptom\": \"叶柄基部出现水渍状软腐，块茎变软发臭\", \"treatment\": \"挖出块茎，切除腐烂部分，涂抹多菌灵晾干后重新种植\"}], \"prevention\": \"生长期保持高湿度和优良通风，休眠期保持块茎干燥。\"}','有毒','全株各部位，特别是块茎和叶柄内的汁液','全株汁液含有草酸钙结晶。误食会引发口腔咽喉疼痛肿胀，皮肤接触汁液会红肿瘙痒','对猫、狗及儿童有较强毒性！必须摆放在儿童和宠物无法触及的安全处。','{\"leggy\": \"长期缺乏散射光，导致叶柄细长、叶片变小、色彩变淡。\", \"noBloom\": \"室内环境下极少开花，主要作为观叶植物栽培，属正常现象。\", \"drooping\": \"叶片整体下垂失去弹性，多为土壤干透缺水所致，及时浇透可恢复。\", \"mainTaboo\": \"生长期干旱、休眠期盆土过湿、盛夏烈日暴晒、冬季低温冻害。\", \"beginnerTip\": \"买回家后不知道它有冬眠特性，冬天看到叶片枯黄就以为死了直接扔掉。\", \"yellowLeaves\": \"生长期频繁大水导致积水闷根，或秋季自然枯黄进入休眠。\"}','叶薄如蝉翼，白粉红交织如天使翅膀，是自然界最华丽的彩色艺术品之一。','大型薄质叶片能吸附室内浮尘，对调节空气湿度有一定辅助作用。','具有较强毒性，严禁任何形式的食用！','无家庭药用价值','寓意五彩缤纷、生活多彩多姿。在风水上有增添居室活力、招财纳福的效果。','客厅明亮角落、书房窗台内侧、高湿洗手间、明亮玄关、高档展厅','排水良好的盆栽土','优质泥炭土:腐叶土:珍珠岩 = 2:2:1，保证疏松透气保水','透气性好的红陶盆、简约白瓷盆或彩色塑料盆','口径15-25cm','每年春季萌芽前换盆换土一次',5.5,6.5,'hard','fast',40,1,0,0,1,'/images/plants/caladium-bicolor.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(45,'常春藤','洋常春藤、英国常春藤、爬墙虎','Hedera helix','hedera-helix','五加科','常春藤属','藤本','多年生','观叶 / 悬垂 / 攀援','欧洲、亚洲和北非','常春藤是一种经典的多年生常绿攀援藤本观叶植物。其最具特征的是精美的对生叶片呈独特的全缘或3-5裂的枫叶状，质地坚硬，厚革质。它生命力极其顽强、极度耐寒、抗逆性极强。','枫叶状彩叶向四周弯曲悬垂，抗寒且吸毒净化全能的垂吊功勋绿植','全缘或3-5裂的枫叶状，质地坚硬，厚革质','深绿色，部分品种叶缘带白色或金色镶边','茎细长柔软，匍匐或攀援生长，节位极易生出气生根','伞形花序，小花极细小，室内盆栽环境下极少开花','黄绿色','少见','少见','枫叶状彩叶向四周弯曲悬垂，整体呈密集的垂吊或攀援状，抗寒且生命力极强。','medium',4,6,'喜充足明亮的散射光，但也非常耐阴。较耐太阳直射，但盛夏正午阳光直射暴晒需适当遮阴。','weekly',5,8,'常春藤革质的叶片蒸腾较慢，具有较强的抗旱能力，最怕土壤长期处于湿漉漉的死水泥泞状态。','见干见湿','每5-7天1次','每3-5天1次，配合叶面喷雾','每5-7天1次','每10-15天1次，严格遵循不干不浇','严忌土壤长期处于湿漉漉的死水泥泞状态，更忌盆底托盘长期积水','普通的室温自来水即可','medium','对空气湿度要求中等，喜略微湿润、空气对流良好的环境。',15,25,-5,30,0,'悬挂吊阳台、客厅高柜顶部、明亮书架边缘、朝北或朝东窗台','喜冷凉、微干燥气候，极耐寒，抗逆性极强。喜明亮散射光，也极耐阴。怕高温闷热。','喜冷凉、微干燥气候，最适生长温度为15-25℃。抗寒耐寒能力极强。','平衡20-20-20','monthly','常春藤对肥料需求不高。仅在春季和秋季生长季，每月追施一次稀薄的无机观叶复合平衡肥。','春季和秋季','稀薄的无机观叶复合平衡肥','以观叶为主，无需施用促花肥',1,'极忌浓肥、生肥，严禁氮肥过量导致徒长','新叶变小变薄、叶色变淡失去油亮光泽','春夏季','频繁进行打顶摘心控制主藤蔓长势，剪除过度徒长和返绿的分枝','在分枝所需的节位上方0.5厘米处平剪。剪下枝条可轻松扦插繁殖','避免在冬季极端寒冷天气进行重剪','{\"fall\": \"秋季空气转凉，长势恢复。逐渐增加光照，适当施薄肥促进枝叶充实。\", \"spring\": \"展叶与扦插的黄金期。确保充足的明亮散射光，干透浇透并恢复施薄肥。\", \"summer\": \"严防酷暑高温闷热。必须移到阴凉、空气通风的半阴处。高温期断肥，保持水分充足。\", \"winter\": \"极耐寒，在冷凉室内能很好过冬。严格控制浇水，保持偏干，完全断肥。\"}','{\"pests\": [{\"name\": \"蚜虫/红蜘蛛/介壳虫\", \"symptom\": \"嫩梢或叶背聚集密集微小飞虫或红点\", \"treatment\": \"用温水高压冲洗，或喷洒吡虫啉、阿维菌素防治\"}], \"diseases\": [{\"name\": \"叶斑病/根腐病\", \"cause\": \"土壤长期积水或环境湿热不通风\", \"symptom\": \"叶片出现褐色斑点或大面积坏死，根系变黑腐烂\", \"treatment\": \"剪除受损叶片，改善通风，严重时脱盆修剪烂根换新土\"}], \"prevention\": \"保持环境凉爽通风，管住手少浇水，定期擦拭叶面。\"}','有毒','全株汁液，特别是叶片和茎','全株含有常春藤皂苷。误食会引发恶心呕吐、腹痛腹泻，皮肤接触汁液可能引发皮炎','对猫、狗有较强毒性！悬垂的叶片极易吸引宠物玩耍啃咬，建议采用吊盆高处悬挂养护。','{\"leggy\": \"长期缺乏散射光，导致藤蔓细长、叶片间距拉大、色彩变淡。\", \"noBloom\": \"室内环境下极少开花，主要作为观叶植物栽培，属正常现象。\", \"drooping\": \"叶片整体下垂失去弹性，多为土壤干透缺水或高温闷热所致。\", \"mainTaboo\": \"频繁大水、盛夏高温闷热不通风、冬季暖气房过度干燥。\", \"beginnerTip\": \"买回家后放在高温闷热的封闭阳台上，结果很快叶片大量枯黄脱落。\", \"yellowLeaves\": \"频繁大水导致土壤积水闷根；或夏季高温闷热所致。\"}','枫叶状彩叶向四周弯曲悬垂，色彩丰富，是经典的垂吊攀援观叶植物。','被NASA认证的优秀空气净化植物，能高效吸收甲醛、苯、二甲苯等有害气体。','具有毒性，严禁食用！','在传统草药学中有祛风利湿、活血消肿的功效，但家庭不建议自行使用。','寓意青春常在、永不放弃。在风水上有化解煞气、守护家宅平安的效果。','悬挂吊阳台外侧、客厅高柜边缘、书架顶部隔断、朝北或朝东窗台','排水良好的盆栽土','优质泥炭土:腐叶土:珍珠岩 = 2:2:1，保证疏松透气排水','塑料吊盆、简约白瓷盆、红陶盆','口径12-20cm','每年春季结合修剪换盆换土一次',6.0,7.0,'easy','fast',150,1,1,0,1,'/images/plants/hedera-helix.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(46,'九里香','千里香、七里香、月橘','Murraya exotica','murraya-exotica','芸香科','九里香属','木本','多年生','观花 / 观叶 / 闻香','中国南部、南亚及东南亚热带地区','九里香是一种常绿灌木或小乔木。其最大的特征是每逢夏秋花期，枝头会绽放出成簇精巧的纯白色小花，并散发出极为浓郁、穿透力极强的独特清香，因\"花香能飘九里\"而得名。','白花如玉，香飘九里，自带古典文人风骨的常青小树盆景','奇数羽状复叶，小叶互生，卵形或卵状披针形，革质光滑','浓绿色、深绿色，表面光滑油亮，新叶嫩绿','树干灰白色，木质坚硬，分枝多而密，树形紧凑','聚伞花序顶生或腋生，小花五瓣呈星形，花瓣洁白如玉','纯白色','4-9月','9-12月','枝叶繁密紧凑，白花如玉点缀其间，整体呈优雅的灌木或小乔木状，自带古典文人风骨。','bright_direct',5,8,'非常喜光。属于全日照植物，最喜充足明亮的直射阳光。阳光越充沛，其株形越紧凑、叶片越油亮、花香越浓郁。','weekly',5,8,'九里香属于木本植物，主干储水能力强，具有一定耐旱性，根系最怕长期泡水。','见干见湿','每5-7天1次','每3-5天1次，高温期配合叶面喷雾','每5-7天1次','每10-15天1次，严格遵循不干不浇','严忌花盆底部托盘长期积水，更忌土壤长期处于泥泞状态','普通的室温自来水即可','medium','对空气湿度要求中等，喜微润环境。对室内干燥有较强的抗性。',18,32,5,38,0,'朝南大阳台、客厅落地大窗旁、庭院露台、书房窗台','全日照植物，喜充足阳光，喜温暖耐高温，不耐严寒。喜疏松肥沃排水良好的微酸性土。花香浓郁。','喜温暖、耐高温酷暑，生长适温为18-32℃。不耐受严寒，冬季室温建议保持在5℃以上。','平衡20-20-20','monthly','九里香花期长、开花勤，属于较为喜肥的植物。在生长旺季每月追施一次观叶观花类水溶复合肥。','春季和秋季','稀薄的富含磷钾的观花类水溶复合肥','花期前追施磷酸二氢钾促进花量和花香浓度',1,'极忌浓肥、生肥，花期避免施高氮肥导致落花','新叶变小变薄、叶色变淡、开花量明显减少','春季','剪除开花过后的残花梗、修剪过密的内膛交叉密枝、塑造树形','用消毒的专业木本修枝剪在侧芽点上方平剪。春季可进行短截造型修剪','花期避免重剪影响观赏，冬季低温期避免修剪','{\"fall\": \"花量逐渐减少，秋花仍可观赏。逐渐减少浇水和施肥，多见温和秋光。\", \"spring\": \"展叶与花芽萌发的黄金期。确保全日照充足阳光，干透浇透并恢复施薄肥。修剪整形。\", \"summer\": \"盛花期。保持充足水分和阳光，花后及时剪残花。高温期早晚可喷雾降温。\", \"winter\": \"防寒是第一要务！室温必须维持在5度以上。严格控水，保持偏干，完全断肥。\"}','{\"pests\": [{\"name\": \"蚜虫/红蜘蛛\", \"symptom\": \"嫩梢聚集密集微小绿色或黑色小虫，叶背出现红点\", \"treatment\": \"用温水冲洗，或喷洒吡虫啉、阿维菌素防治\"}], \"diseases\": [{\"name\": \"煤污病/叶斑病\", \"cause\": \"蚜虫分泌蜜露诱发，或环境长期密闭不通风\", \"symptom\": \"叶面表层产生黑色粉末状霉层，阻碍光合作用\", \"treatment\": \"先治蚜虫，再喷洒多菌灵清除煤污层\"}], \"prevention\": \"保持全日照和优良通风，定期检查嫩梢和叶背。\"}','无毒','无','全株无毒，花朵和叶片安全无害','对猫、狗及儿童安全无毒。但其枝条有小刺，幼童玩耍时需注意。','{\"leggy\": \"长期缺乏直射阳光，导致枝条细长、叶片稀疏、树形松散。\", \"noBloom\": \"缺乏充足的直射阳光是不开花的最主要原因。必须放在朝南全日照处。\", \"drooping\": \"叶片整体下垂失去弹性，多为土壤干透缺水或根系已烂。\", \"mainTaboo\": \"长期缺乏阳光、频繁大水、冬季低温冻害。\", \"beginnerTip\": \"买回家后放在阴暗角落，结果不开花、叶片大量脱落变成光杆。\", \"yellowLeaves\": \"频繁大水导致土壤积水闷根；或冬季低温冻害；或长期缺乏阳光。\"}','白花如玉，香飘九里，枝叶繁密油亮，自带古典文人风骨，是优秀的盆景素材。','常绿叶片能吸附室内浮尘，花香有清新空气、提神醒脑的作用。','花朵可提取香精，部分地区用花朵制作花茶，但不建议自行采食。','在传统中医药学中，根、叶有行气止痛、活血散瘀的功效。','寓意香远益清、高洁脱俗。在风水上有招财纳福、净化家宅气场的效果。','朝南大阳台、客厅落地大窗旁、庭院露台、书房窗台、高档茶室','排水良好的盆栽土','优质腐叶土:泥炭土:珍珠岩 = 3:2:2，盆底垫好陶粒排水层','紫砂盆、手工陶盆、水泥盆，适合盆景造型','口径20-35cm','每2年春季花谢后换盆换土一次',5.5,6.5,'easy','slow',150,1,1,1,1,'/images/plants/murraya-exotica.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-25 11:33:01','2026-05-25 17:11:12'),(47,'向日葵','朝阳花、太阳花、葵花','Helianthus annuus','helianthus-annuus','菊科','向日葵属','草本','一年生','观花','北美洲','向日葵是一种著名的药食赏多用一年生草本花卉。其最标志性的特征是巨大的头状花序随太阳转动，金黄色的舌状花瓣围成一圈，绚丽夺目。','金黄夺目、追随阳光的阳光活力代言人','广卵形至心脏形，边缘具粗锯齿，两面被粗糙刚毛','鲜绿色、深绿色，触感粗糙','茎直立粗壮，中心具髓，表皮密被粗硬刚毛','头状花序单生于茎顶，周围为金黄色舌状花，中央为管状花','金黄色、橙黄色','7-9月（夏季）','8-10月（瘦果，即葵花籽）','挺拔直立的主干顶着硕大的金黄色花盘，线条刚健挺拔，具有极强烈的田园阳光气息','bright_direct',6,12,'极端喜光。全日照植物，最喜全天候强高强度的直射阳光。极其不耐阴。','frequent',1,3,'向日葵长势极快，叶片宽大，在盛夏生长期蒸腾量极其惊人。必须保持盆土湿润。','见干见湿 / 喜湿忌干','每2-3天1次','每天1-2次（盛夏暴晒期需早晚浇透）','每3-5天1次','一年生草本，冬季已枯死，无需浇水','严忌正午烈日当头时用冰冷冷水直接浇灌，更忌花盆长期积水','普通室温自来水即可','medium','对空气湿度要求中等，严忌花盆长期积水闷根。',15,35,10,40,0,'全日照阳台、阳光充足的露台、南向窗台外侧、室外庭院','喜温暖干燥、阳光充足环境，长势迅速，极喜肥水，喜深厚肥沃排水极佳的沙质壤土','喜温暖、耐高温酷暑，生长适温为15-35℃。极不耐寒。','高磷钾肥','biweekly','从小苗期每两周追施一次稀薄复合液肥。现蕾初期改用高磷钾肥。','春季和夏季','富含氮磷钾平衡的复合水溶肥，促进株形粗壮','高磷钾专用肥进行频繁灌根，强力促花',0,'极忌浓肥生肥，严禁单一过量施用氮肥导致茎干细长易倒伏','生长缓慢、茎干细弱、花盘发育不全、底层叶片焦黄','夏季','剪除底层老化黄叶、修剪花谢后残花盘','单头品种无需打顶；多头品种可在小苗6-8片真叶时摘心促分枝','单头大花品种严禁打顶','{\"fall\": \"花后结果期。逐渐控制浇水，停止施肥。等待花盘变黄背面变褐时可采收葵花籽。\", \"spring\": \"播种与小苗快速生长期。给予全天候充足直射阳光，保持盆土微潮，每周追施稀薄平衡肥。\", \"summer\": \"盛花爆发期。极耐热，必须全日照暴晒，供水充沛，现蕾期高频施磷钾肥促花。\", \"winter\": \"一年生草本，入冬后自然枯死，清理盆土，留种等明年春季重新播种。\"}','{\"pests\": [{\"name\": \"蚜虫/潜叶蝇\", \"symptom\": \"叶面白色隧道线条，或嫩梢聚集绿色小虫\", \"treatment\": \"摘除虫害叶片，喷洒吡虫啉\"}], \"diseases\": [{\"name\": \"菌核病/白粉病\", \"symptom\": \"茎基部水渍状病斑变软烂，或叶面白色粉末状霉层\", \"treatment\": \"剪掉病叶，严格控水，移到强晒通风处，喷洒多菌灵\"}], \"prevention\": \"常年给予全天候阳光暴晒，严防长期淋雨，保持排水绝佳\"}','无毒','无','全株完全无毒，属于100%安全的药食赏全能植物','对猫狗及儿童绝对安全，被ASPCA官方认证的对猫狗完全无毒友好花卉','{\"leggy\": \"长期缺乏阳光导致茎干畸形发育又细又长，极易折断倒伏。\", \"noBloom\": \"99%是因为阳光严重不足，室内阴暗散射光下几乎无法开花。\", \"drooping\": \"多为表土干透缺水脱水引起，及时给水半天内可恢复。\", \"mainTaboo\": \"长期缺乏直射阳光、频繁大水导致泥泞、夏季长期淋雨积水。\", \"beginnerTip\": \"养在没有阳光的客厅内侧，不到一个月就徒长死掉，完全开不了花。\", \"yellowLeaves\": \"90%以上是土壤积水导致根系缺氧黑腐发黄，或严重干旱引起老叶干黄。\"}','花盘硕大，金黄闪耀，具有极高的田园风情与浓烈的生命朝气','能高效利用阳光进行高强度光合作用，微弱改善周围二氧化碳浓度','世界著名油料与坚果作物，成熟种子炒熟后可作休闲零食','花盘、茎髓有清热利尿、平肝降压的微弱功效','寓意朝气蓬勃、欣欣向荣、步步高升、光明前程，有汇聚正能量磁场的极佳效果','全日照向阳阳台、室外露台、南向窗台外侧、庭院阳光房','排水良好的盆栽土','普通菜园土:腐叶土:粗沙 = 4:3:3，混入足量缓释颗粒肥','稍大深筒的多孔塑料盆或陶盆','口径20-35cm','一年生植物无需换盆',6.0,7.5,'easy','fast',60,0,1,1,0,'/images/plants/sunflower.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-27 16:29:24','2026-05-27 17:01:07'),(48,'薄荷','留兰香、香草、卜荷、番荷菜','Mentha canadensis','mentha-canadensis','唇形科','薄荷属','草本','多年生','观叶 / 药食两用','北温带地区','薄荷是一种极受欢迎的多年生芳香草本植物。用手轻揉能散发出极其清凉、提神醒脑的独特薄荷醇香气。','清香提神，遇水即活的居家调味芳香草本','卵形或长圆状披针形，边缘具整齐锐锯齿，表面叶脉凹陷','鲜绿色、碧绿色，质地柔嫩，背面有微小腺点','直立或匍匐，钝四棱形，绿色或带紫红色，具地下根状茎','轮伞花序生于叶腋，花冠小，管状漏斗形','淡紫色、淡红色或纯白色','7-9月（夏季）','10-11月（小坚果）','密集丛生和地毯式蔓延状，繁密清秀绿叶层叠爆盆，散发缕缕清凉之气','bright_direct',5,8,'非常喜光。明亮充足的阳光直射能让叶片肥厚、茎干粗壮、香气油分泌更旺盛。','frequent',2,4,'薄荷属于喝水狂魔，不耐任何干旱。生长期必须保持盆土充沛湿润。','见干见湿 / 喜湿忌干','每2-4天1次','每1-2天1次（需彻底浇透，严禁正午浇水）','每3-5天1次','每10-14天1次，保持微润偏干防冻伤','严忌盆土彻底干透变成硬块，更忌托盘长期积水导致根黑腐','普通室温自来水即可','medium','对空气湿度要求中等。喜略微湿润、空气流动良好的环境。',15,32,-5,38,0,'朝南厨房窗台、全日照阳台、电脑桌窗边、阳光房','喜温暖湿润阳光充足环境，生命力极强，怕极度干旱，怕积水烂根','喜温暖、耐高温。生长适温为15-32℃。抗寒耐寒力极强。','平衡20-20-20','biweekly','春、夏、秋三季生长旺季每两周追施一次稀薄液肥。','春季和夏季','稀薄的富含氮素蔬菜专用有机液肥，促进多长脆嫩绿叶','不以观花为主，见花序必剪',1,'极忌浓肥生肥，严禁采摘食用前一周内施用任何无机化肥','下部老叶发黄变薄脱落、茎干细弱软瘫、香气大幅变淡','全年生长季（结合采收进行）','频繁打顶摘心，剪掉各分枝顶端嫩芽，摘除花蕾花序','用消毒小剪刀在叶片上方0.5cm处剪断顶芽，频繁打顶促腋芽爆发实现爆盆','开花后全株养分集中结实，叶片失去香气，见花序必剪是铁律','{\"fall\": \"秋凉后长势减缓。秋末随降温拉长浇水间隔，完全停肥，使地下根茎充实。\", \"spring\": \"换盆与打顶分株黄金期。移到阳光最充沛位置，干透浇透恢复施肥，开始频繁采摘顶芽。\", \"summer\": \"长势黄金期。极耐热，供水充足多晒直射光长得越疯狂。严防热闷，多开窗通风。\", \"winter\": \"较耐寒。地上部分逐渐枯萎，保持土壤微润、0℃以上地下根系可安全过冬。\"}','{\"pests\": [{\"name\": \"红蜘蛛/菜青虫\", \"symptom\": \"叶面针尖样黄点，或叶片被咬出破洞\", \"treatment\": \"摘除受损叶片，用稀释印楝油或清水高压淋洗\"}], \"diseases\": [{\"name\": \"锈病/白粉病\", \"symptom\": \"叶片背面黄褐色小疱斑，或叶面覆盖白粉\", \"treatment\": \"严禁大量喷药，剃头大修剪，严格控水，移到烈日强风口处强力通风\"}], \"prevention\": \"通过频繁打顶保持通风，多晒阳光，严防盆土长期积水\"}','无毒','无','全株完全无毒，世界公认的安全食用级芳香调味植物','对猫狗有微弱风险，浓烈薄荷醇成分通常让猫狗主动避开，大量误食可能引发微弱肠胃刺激','{\"leggy\": \"长期缺乏直射阳光导致茎干畸形拔高，枝条细长软弱，香气变淡。\", \"noBloom\": \"盛夏光照充足极易开花，但开花会降低风味，养殖者通常见花必掐。\", \"drooping\": \"100%是极端缺水脱水信号，及时浇透水半小时内可恢复挺立。\", \"mainTaboo\": \"任由开花不修剪、完全缺乏直射阳光、频繁大水导致泥泞。\", \"beginnerTip\": \"常年放在没有阳光的卧室床头，不到两星期就徒长干枯成死干草。\", \"yellowLeaves\": \"90%以上是频繁浇水导致土壤积水闷根黑腐，或严重干旱引起老叶干黄。\"}','绿意盎然丛生茂密，随手一碰便散发强烈清爽醇香，自带厨房田园风格与盎然生机','全株挥发性薄荷精油能净化室内异味、烟雾微粒，具有天然微弱驱赶蚊蝇作用','世界经典烹饪芳香调味香草，可制作薄荷莫吉托、薄荷茶、糕点点缀等','干燥全草具有疏散风热、清利头目、利咽透疹和疏肝行气的功效','寓意坚韧不拔、充满希望、健康平安，有清新室内磁场、凝聚朝气的作用','朝南厨房窗台、明亮窗边、全日照阳台、阳光房','排水良好的盆栽土','普通腐叶土:菜园土:珍珠岩 = 3:4:3，可适量埋入发酵鸡粪作基肥','普通塑料盆、红陶盆或长条形树脂种菜盆','口径15-25cm（走茎蔓延快，宜选宽口浅盆）','每年春季结合分株换盆换土一次',6.0,7.5,'easy','fast',40,1,1,0,0,'/images/plants/mint.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-27 16:29:24','2026-05-27 17:03:26'),(49,'无尽夏','绣球花（品种）、八仙花、紫阳花','Hydrangea macrophylla Endless Summer','hydrangea-macrophylla-endless-summer','绣球花科','绣球属','木本','多年生','观花','日本','无尽夏是绣球花中最具传奇色彩的殿堂级品种。能在新枝和老枝上同时孕蕾，开花源源不断。具有神奇的随土壤酸碱度自动变色特性（酸蓝碱粉）。','新老枝开花不断，能随土壤酸碱度自动魔幻变色的顶级观花网红','宽卵形或椭圆形，边缘密布粗尖锯齿，表面具清晰网状脉络','鲜绿色、亮绿色，新叶鲜嫩','分枝能力极强，呈灌木状，新枝肉质浅绿色，老枝木质化灰褐色','巨大头状聚伞花序顶生，无数小不孕花呈完美圆球状重叠簇生','酸性土呈天蓝色；碱性土呈粉红色（中性土呈蓝粉交织紫罗兰）','5-10月（整个夏秋季，长达数月）','少见结果','饱满圆润的丛生小灌木状，繁密大叶上托举数个硕大五彩斑斓的巨型绣球花球','medium',4,6,'喜半阴舒适环境，最喜充足明亮的散射光或早晚温和直射光。非常害怕盛夏正午烈日暴晒。','frequent',2,4,'无尽夏是花卉界著名的水老虎，极度不耐受任何形式的干旱脱水。生长期必须保持盆土充沛湿润。','喜湿忌干','每2-3天1次（保持盆土潮湿）','每天1-2次（高温蒸腾极快，早晚配合喷细雾）','每3-5天1次','每10-14天1次，保持土壤偏润防根系干死','严忌盆土彻底干透，更忌花盆托盘长期积水导致须根黑腐','普通室温自来水（若想调蓝需配合硫酸铝溶液酸化水质）','high','对空气湿度要求较高，喜湿润。过低的空气湿度会导致花球提早凋谢。',15,26,5,32,1,'朝东或朝北大落地窗旁、半阴阳台内侧、露台遮阴处、阳光房北侧','喜半阴凉爽多湿环境，长势迅速蓬松，极度怕烈日暴晒，极度不耐干旱','喜温暖、凉爽舒适的半阴凉环境，生长适温为15-26℃。非常害怕高温酷暑。','高磷钾肥','biweekly','每两周追施一次稀薄复合花卉液肥。盛夏酷暑或冬季低温必须停肥。','春季和秋季','稀薄氮磷钾平衡水溶复合肥，或开春时埋入有机配方肥作基肥','高磷钾专用肥进行浸盆或灌根，源源不断促花',1,'极忌浓肥生肥，严禁土壤干旱或烈日暴晒下倒化学液体原液','花球枯萎落蕾、花梗变细倒伏、后续花苞干瘪、叶片泛黄','秋季（花后修剪）','剪除底层黄叶、清除残花球、秋末重剪细弱枝','第一波花球凋谢后，在残花梗下方第2-3个饱满侧芽上方1cm处平剪，刺激腋芽爆发再开第二波花','无尽夏比普通绣球极其耐修剪，春末可对受冻死枯枝进行清理短截','{\"fall\": \"开花高峰尾期。及时剪残花球，秋末逐步拉长浇水间隔，完全停肥，枝条充实进入冬眠。\", \"spring\": \"换盆松土与萌发黄金期。给予明亮散射光，保证水分充足并恢复施平衡肥，孕蕾期改高磷钾肥催花。\", \"summer\": \"盛花爆发期与生死关。极怕热怕强光，必须移到最阴凉强通风的半阴处，每天早晚各浇一次水，完全断肥。\", \"winter\": \"地上部分枯萎冬眠。移入冷凉室内（5℃以上），严格控水每10-14天给少许水，完全断肥。\"}','{\"pests\": [{\"name\": \"红蜘蛛/蚜虫/盲蝽蟓\", \"symptom\": \"大叶背面聚集密集碎尘状红点\", \"treatment\": \"搬到浴室用高压水流冲洗叶片背面，或喷洒联苯肼酯\"}], \"diseases\": [{\"name\": \"白粉病/灰霉病/根腐病\", \"symptom\": \"叶面覆满白粉脱落，或花球变黑软烂发黏霉烂\", \"treatment\": \"剪掉病变花球和黄叶，脱盆修剪黑烂须根，多菌灵消毒后换新土\"}], \"prevention\": \"营造高散射光+强开窗空气对流环境，开花期水分给足，严忌土壤闷热积水\"}','微毒','全株汁液、茎叶、花朵','含有八仙花苷等弱毒性氰苷成分，误食会导致口腔不适、恶心呕吐、腹泻','对猫狗及儿童有毒！花球巨大色彩魔幻极易吸引儿童抓挠，必须摆放在无法触及处','{\"leggy\": \"长期缺乏散射光导致枝条徒长，花球头重脚轻整盆坍软。\", \"noBloom\": \"90%是光照严重不足，或生长期过量施用单一氮肥导致只长叶不孕蕾。\", \"drooping\": \"100%是土壤彻底干透干旱脱水引起，立刻大水浇透或浸盆法，阴凉处几小时可恢复。\", \"mainTaboo\": \"严重缺水干旱、盛夏强光直射暴晒、频繁大水积水、冬季0℃以下严寒。\", \"beginnerTip\": \"夏天看到叶子软就劈头盖脸频繁灌水，不到两天大花球全部霉烂黑腐。\", \"yellowLeaves\": \"90%以上是频繁大水导致土壤积水闷根烂根，或盛夏烈日直射灼伤。\"}','花球硕大华丽，色彩魔幻多变（天蓝粉红娇紫交织），具有极高的法式奢华格调与浪漫视觉存在感','叶片面积宽广能有效吸附漂浮灰尘，极高蒸腾效率能像天然加湿器改善空气湿度','具有较强弱毒性，严禁任何形式的食用！','无家庭药用价值','名字寓意无尽夏（希望无限、百年好合），花聚成球寓意阖家团圆、幸福美满，有催旺人缘的风水效果','客厅北侧或东侧明亮落地窗旁、半阴通风大阳台、露台遮阴处、阳光房强散射光处','排水良好的盆栽土','优质泥炭土:腐叶土:珍珠岩 = 3:3:2，混入少量骨粉作基肥','大号多孔排水通道的控根塑料盆或美观大号陶盆','口径25-40cm（根系爆炸式生长，小盆极易缺水萎蔫）','每年春季新芽萌发前必须换盆换土',5.2,7.0,'medium','fast',100,1,1,0,1,'/images/plants/hydrangea-endless-summer.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-27 16:29:24','2026-05-27 17:04:54'),(50,'多肉吉娃娃','吉娃莲、杨贵妃多肉','Echeveria chihuahuensis','echeveria-chihuahuensis','景天科','拟石莲花属','肉质','多年生','多肉','墨西哥','多肉吉娃娃是一种多年生常绿小型肉质植物。肥厚多肉的叶片呈标准的莲座状螺旋排列。叶面披有一层白霜，叶尖端有一抹极其鲜艳的深红色小红尖。','叶覆白霜，叶尖一抹惊艳小红尖的经典莲座多肉小硬汉','卵长匙形，顶端急尖具坚硬小突尖，全缘肥厚肉质化，呈莲座状重叠包裹','浅蓝绿色，表面覆厚厚白粉霜，阳光充足时叶尖叶缘泛鲜红色','地上茎极短或无茎，老株基部缓慢木质化产生老桩形态','蝎尾状聚伞花序自叶腋间抽出，花茎长弯曲，小花钟状五裂倒挂','橙黄色、外红内黄','4-6月（春夏季）','少见','肥厚肉质叶片天衣无缝组合成永不凋谢的灰蓝色玉石莲花，叶尖鲜红点缀，精巧几何对称美感','bright_direct',5,10,'非常喜光。全日照植物，最喜全天候明亮高强度的直射阳光。盛夏正午超过35℃需适当遮阴。','rarely',10,20,'肥厚多汁的肉质叶片能储藏大量水分，抗旱能力极强。严格遵循宁干勿湿、干透浇透原则。','干透浇透','每10-15天1次','每20-30天1次（高温半休眠严格控水，仅傍晚沿盆沿微量给水）','每10-15天1次','每30-40天1次或彻底断水，保持土壤绝对干燥提高抗寒能力','严忌频繁浇水导致土壤积水，更忌水灌入中心莲座叶盘，高温下会导致全株黑腐化水','普通室温自来水即可','low','极度喜干燥、空气流动极佳的环境。非常害怕高湿闷热。绝对严禁向叶面直接喷水。',15,28,5,35,1,'电脑办公桌、明亮书桌台面、客厅茶几一侧、南向窗台内侧','喜温暖微干阳光充足环境，极度耐旱（宁干勿湿），怕积水，忌高温闷热','喜温暖舒适、微干的环境。生长适温为15-28℃。不耐严寒，冬季室温需维持在5℃以上。','平衡20-20-20','none','生长极其缓慢，对肥料依赖度几乎为零。仅在春季追施1次极稀薄的多肉专用肥。','春季','极其稀薄的高磷钾低氮型多肉专用液体营养液','主要是观叶多肉，花梗抽出消耗营养，建议现蕾时直接剪断',1,'极忌浓肥生肥，严禁氮肥过量导致莲座变薄变软瘫软','长期不给肥无不良表现，长势慢属于正常生理特性','春季','用镊子剥除基部老化干枯老叶，侧芽过多时分株掰除','基部侧芽长到母株1/3大小时，用小刀小心割下带根侧芽，涂抹多菌灵晾干三天后独立上盆','大修剪分株后伤口未干结前，严禁直接淋水或大量喷雾','{\"fall\": \"秋凉后迎来第二个长势爆发期。日夜大温差刺激下小红尖极其艳丽。恢复正常干透浇透，秋末停肥。\", \"spring\": \"换盆松土与侧芽分株黄金期。确保充足全日照，干透浇透配合极稀薄肥水，让小红尖色泽艳丽。\", \"summer\": \"危险期！超过33℃进入半休眠。必须移到最阴凉强通风处，严格控水，完全断肥，严防高温黑腐化水。\", \"winter\": \"防寒。移入温暖房间（5℃以上），全天候明亮室内阳光直射，严格控水偏干，完全停肥。\"}','{\"pests\": [{\"name\": \"介壳虫/根粉蚧\", \"symptom\": \"叶片凹槽节缝处或根系上聚集白色棉絮状硬壳小虫\", \"treatment\": \"用酒精棉球逐个擦拭，数量多时用蚧必治稀释溶液浇灌\"}], \"diseases\": [{\"name\": \"黑腐病/根腐病\", \"symptom\": \"肉质叶从基部变黑化水，像被开水煮熟一样发黏大面积瘫软脱落\", \"treatment\": \"脱盆用利刀切除所有发黑部分，涂抹多菌灵，裸根晾干一周后插全颗粒干燥沙土重新扦插\"}], \"prevention\": \"常年控制浇水，管住手，看到土彻底干透甚至盆土开裂时再浇水，保持环境通风\"}','无毒','无','全株完全无毒，属于100%安全的家庭常绿肉质植物','对猫狗及儿童绝对安全，被ASPCA官方认证对宠物完全无毒友好，是宠物友好桌案绿植首选','{\"leggy\": \"长期缺乏阳光导致中心新叶严重徒长拔高，叶片间距拉宽，俗称摊大饼。\", \"noBloom\": \"春夏季极易从中心抽出花序，但开花消耗营养导致叶片变薄，通常建议见梗就剪。\", \"drooping\": \"多为土壤彻底干透缺水引起（及时浇透一两天可恢复），或根系已溃烂需排查基部。\", \"mainTaboo\": \"频繁大水导致泥泞、托盘积水、水灌入中心莲座盘、冬季3℃以下低温。\", \"beginnerTip\": \"随手丢在南阳台上，不到三天娇嫩叶片就全被暴晒烤焦枯死。\", \"yellowLeaves\": \"95%以上是频繁大水导致土壤积水闷根烂根，引发厚叶自下而上变黑化水。\"}','肉质叶坚挺呈莲座状星芒放射，白色横纹理规整鲜艳，红绿对比极高，自带高级工业冷淡风与极简主义','CAM呼吸机制夜间吸收二氧化碳释放氧气，精巧造型可调节视觉疲劳','无食用价值','无家庭药用价值','中文名带有吉娃娃，有镇宅辟邪、凝聚朝气、保佑吉祥的极佳效果','电脑办公桌前、明亮书桌台面、客厅茶几、南向阳台、南向卧室窗台','排水良好的盆栽土','多肉颗粒土（火山石/麦饭石/赤玉土）:泥炭土 = 6:4，盆底垫厚层陶粒','小巧精美浅口红陶盆、手工粗陶盆或多肉控根小塑料盆','口径8-12cm（花盆宜小宜浅，盆大存水极易黑腐）','每2-3年春季换盆换土一次',6.5,7.5,'easy','slow',15,1,1,1,1,'/images/plants/echeveria-chihuahuensis.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-27 16:29:24','2026-05-27 17:06:24'),(51,'文心兰','吉祥兰、跳舞兰、金蝶兰','Oncidium flexuosum','oncidium-flexuosum','兰科','文心兰属','草本','多年生','观花','美洲热带地区','文心兰是一种多年生常绿附生草本兰花。花瓣唇瓣特别放大肥硕，形似穿着华丽亮黄色大摆蓬蓬裙、正欲翩翩起舞的跳舞女郎。开花时带有独特的巧克力奇香。','花形似翩翩起舞的黄裙女郎，散发甜蜜巧克力奇香的高档附生兰花','长披针形或椭圆形，全缘，质地厚革质肉质化，自假鳞茎顶端抽出','鲜绿色、黄绿色，表面光滑无毛，带清新光泽','地上无明显主茎，基部具肥大扁球形绿色肉质假鳞茎，气生根洁白密集','复总状花序自假鳞茎基部叶腋抽出，长而细弱下垂，唇瓣呈扇形横向放大酷似舞女裙摆','亮黄色、金黄色，花心常带红褐色斑点','10月至翌年2月（秋冬季，花期可持续1-2个月）','少见','肥硕绿色小肉球撑起挺拔绿叶，上方高挑抽出柔美长花枝，悬挂着成百上千位正欲起舞的金裙舞女','medium',3,5,'喜半阴舒适环境，最喜充足明亮的散射光。非常畏惧强直射光暴晒。','weekly',5,8,'通常采用纯水苔附生栽培。等水苔表面彻底干下去、气生根由翠绿变白时用温水彻底浇透。','见干见湿 / 宁干勿湿','每5-7天1次（根据水苔干燥度彻底浇透）','每3-5天1次（高温蒸发极快，加强通风严防死水热闷根）','每5-7天1次（秋末孕蕾期水分给足）','每10-14天1次，保持水苔微润偏干，防湿冷冻伤','严忌普通黏重泥土栽种，严忌水苔长期湿漉漉泡盆，严忌水灌入假鳞茎叶心里','晾置过夜与室温一致的温和自来水或纯净水','high','原产热带雨林树干上，对空气湿度要求很高，理想湿度在65%以上。',15,25,10,32,0,'客厅大茶几中央、玄关大位、明亮书房无直射光案头、阳光房半阴内侧','喜温暖高湿度半阴附生环境，忌烈日暴晒，极不耐寒，怕土壤干透，严忌普通泥土栽种','喜温暖、冷凉舒适的气候，生长适温为15-25℃。极不耐寒，冬季室温必须维持在10-15℃以上。','高磷钾肥','biweekly','每两周追施一次极稀薄的兰花专用复合液肥。花期、盛夏和寒冬完全停肥。','春季和秋季','极其稀薄的平衡型兰花专用水溶肥，促进假鳞茎膨大肥硕','秋初花芽分化期连续随浇水喷施2-3次弱效高磷钾专用肥强力促花',1,'极忌浓肥生肥，严禁高浓度复合肥颗粒丢在水苔表面引发烧根','假鳞茎干瘪产生深皱纹、长期不抽新叶、花枝无力低垂甚至无法现蕾','春季（花后）','花凋谢后剪除残花梗、修剪干枯腐烂老气生根、剪除底层黄叶','花完全凋谢后用消毒剪刀从花枝最基部靠近假鳞茎叶腋处一刀平整剪断，修剪烂根需保持干燥两三天','严忌秋冬季花苞孕育抽出期大修剪，修剪根系后两三天内严禁大量浸盆大水','{\"fall\": \"花芽分化核心期。保持10℃左右合理日夜温差最有利花枝抽出。适度增加光照，连续追施2次高磷钾肥催花。\", \"spring\": \"换盆换基质与花后休剪黄金期。及时剪掉枯黄花梗，增加浇水与极薄肥水，多晒柔和明亮散射光。\", \"summer\": \"危险期。极怕高温湿热，搬到最阴凉空气对流极佳处，早晚高频喷雾，基质不干不浇，完全断肥。\", \"winter\": \"开花爆盆黄金盛期！移入温暖南向大落地窗旁，室温12-18℃，看根系变白控水，开花期完全断肥，享受巧克力花香。\"}','{\"pests\": [{\"name\": \"介壳虫/红蜘蛛\", \"symptom\": \"叶片背面或假鳞茎缝隙聚集白色硬壳小虫\", \"treatment\": \"用酒精棉球逐个擦拭，数量多时喷洒蚧必治稀释溶液\"}], \"diseases\": [{\"name\": \"软腐病/叶枯病/烂鳞茎\", \"symptom\": \"假鳞茎变黑发黏软烂伴恶臭，叶片大面积黑腐瘫软剥落\", \"treatment\": \"脱盆切除所有变黑腐烂部分，切口涂抹多菌灵，阴凉干燥处裸根晾干三天后换新水苔上盆\"}], \"prevention\": \"选用全透明多孔兰花盆与纯水苔基质，管住手避免过湿，保持室内强通风\"}','无毒','无','全株完全无毒，属于100%安全的高档家庭常绿观赏洋兰','对猫狗及儿童绝对安全，被权威机构认证对猫狗完全无毒友好，猫咪极喜欢扑咬长花枝','{\"leggy\": \"长期缺乏明亮散射光导致叶片薄弱狭长、假鳞茎瘦小中空，极难孕蕾。\", \"noBloom\": \"90%是秋季花芽分化时光照不足、缺乏高磷钾肥、缺乏日夜大温差刺激。\", \"drooping\": \"多为假鳞茎严重干瘪缺水引起（浸盆半天可恢复），若是大水后依然瘫软则是气生根全烂。\", \"mainTaboo\": \"普通粘重泥土栽种、频繁大水积水、冬季8℃以下低温、水灌入假鳞茎叶心。\", \"beginnerTip\": \"把它塞进不透气的普通瓷盆泥土里天天拼命倒大杯水，不到两星期肉质气生根全泡黑腐烂。\", \"yellowLeaves\": \"90%以上是水苔基质长期湿漉漉导致气生根缺氧黑腐，或冬季气温骤降受冻。\"}','花形绝妙奇特（神似穿黄裙翩翩起舞的吉普赛女郎），色彩金黄闪耀，自带甜蜜巧克力奇香，提升家居软装格调的顶级轻奢花艺明星','能稳定吸附室内微小浮尘净化空气，长花梗释放的芳香精油分子能天然净化室内空气异味','无食用价值','无家庭药用价值','中文名带有吉祥兰与金蝶，寓意金玉满堂、吉祥如意、步步高升、翩翩起舞、喜迎贵宾','大客厅大茶几正中、大玄关、明亮书桌台面、办公室、高档写字楼大堂、新春送礼年宵花','排水良好的盆栽土','进口优质水苔:发酵松树皮:高岭土/火山石颗粒 = 4:4:2，或100%纯水苔包裹','底部和四周带大量密集侧排气孔的兰花专用水培透明营养盆','口径12-18cm（兰花极喜紧凑侧根环境，严忌深大盆）','每1-2年春季花序凋谢后更换老化水苔和基质',5.5,6.5,'hard','slow',50,1,0,1,0,'/images/plants/oncidium.jpg',NULL,NULL,NULL,NULL,NULL,NULL,1,0,'2026-05-27 16:29:24','2026-05-27 17:07:41');
